-- Poems batch 484
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-36','看天王院牡丹','王貞白','唐','御定全唐诗','yuding','','[]','前年帝裏探春時，寺寺名花我盡知。',32,'御定全唐詩/json/885.json','["前年帝裏探春時，寺寺名花我盡知。", "今日長安已灰燼，忍隨南國對芳枝。"]'),
('yuding-37','芍藥','王貞白','唐','御定全唐诗','yuding','','[]','芍藥承春寵，何曾羨牡丹。麥秋能幾日，穀雨只微寒。',48,'御定全唐詩/json/885.json','["芍藥承春寵，何曾羨牡丹。麥秋能幾日，穀雨只微寒。", "妒態風頻起，嬌妝露欲殘。芙蓉浣紗伴，長恨隔波瀾。"]'),
('yuding-38','獨芙蓉','王貞白','唐','御定全唐诗','yuding','','[]','方塘清曉鏡，獨照玉容秋。蠹芰不相采，斂蘋空自愁。',48,'御定全唐詩/json/885.json','["方塘清曉鏡，獨照玉容秋。蠹芰不相采，斂蘋空自愁。", "日斜還顧影，風起強垂頭。芳意羨何物，雙雙鸂鶒遊。"]'),
('yuding-39','馮氏書齋小松二首','王貞白','唐','御定全唐诗','yuding','','[]','孤根生遠嶽，移植翠枝添。自秉雪霜操，任他蜂蝶嫌。',96,'御定全唐詩/json/885.json','["孤根生遠嶽，移植翠枝添。自秉雪霜操，任他蜂蝶嫌。", "微陰連迥竹，清韻入疏簾。聳勢即空碧，時人看莫厭。", "得地已經歲，清音晝夜聞。根涵舊山土，葉間近溪雲。", "野鶴望長遠，庭花笑不群。須知搖落後，眾木始能分。"]'),
('yuding-40','社日村居','張蠙','唐','御定全唐诗','yuding','','[]','鵝湖山下稻粱肥，豚阱雞棲對掩扉。',32,'御定全唐詩/json/885.json','["鵝湖山下稻粱肥，豚阱雞棲對掩扉。", "桑柘影斜春社散，家家扶得醉人歸。"]'),
('yuding-41','八月十六夜月','盧延讓','唐','御定全唐诗','yuding','','[]','十六勝三五，中天照大荒。只訛些子緣，應號沒多光。',48,'御定全唐詩/json/885.json','["十六勝三五，中天照大荒。只訛些子緣，應號沒多光。", "桂老猶全在，蟾深未煞忙。難期一年事，到曉泥詩章。"]'),
('yuding-42','冬除夜書情','盧延讓','唐','御定全唐诗','yuding','','[]','兀兀坐無味，思量誰與鄰。數星深夜火，一個遠鄉人。',48,'御定全唐詩/json/885.json','["兀兀坐無味，思量誰與鄰。數星深夜火，一個遠鄉人。", "雁翥天微雪，風號樹欲春。愁章自難過，不覺苦吟頻。"]'),
('yuding-43','觀新歲朝賀','盧延讓','唐','御定全唐诗','yuding','','[]','龍墀初立仗，鴛鷺列班行。元日燕脂色，朝天樺燭香。',48,'御定全唐詩/json/885.json','["龍墀初立仗，鴛鷺列班行。元日燕脂色，朝天樺燭香。", "表章堆玉案，繒帛滿牙床。三百年如此，無因及我唐。"]'),
('yuding-0','中秋月','曹松','唐','御定全唐诗','yuding','','[]','九十日秋色，今秋已十分。孤光吞列宿，四面絕微雲。',48,'御定全唐詩/json/886.json','["九十日秋色，今秋已十分。孤光吞列宿，四面絕微雲。", "眾木排疏影，寒流疊細紋。遙遙望丹桂，心緒更紛紛。"]'),
('yuding-1','寄方幹','曹松','唐','御定全唐诗','yuding','','[]','桐廬江水閑，終日對柴關。因想別離處，不知多少山。',48,'御定全唐詩/json/886.json','["桐廬江水閑，終日對柴關。因想別離處，不知多少山。", "釣舟春岸闊，庭樹晚煙還。莫便求棲隱，桂枝堪恨顏。"]'),
('yuding-2','宿山寺','曹松','唐','御定全唐诗','yuding','','[]','溪山盡日行，方聽遠鐘聲。入院逢僧定，登樓見月生。',48,'御定全唐詩/json/886.json','["溪山盡日行，方聽遠鐘聲。入院逢僧定，登樓見月生。", "露垂群木潤，泉落一岩清。此景關吾事，通宵寐不成。"]'),
('yuding-3','冬日登江樓','曹松','唐','御定全唐诗','yuding','','[]','高樓臨古岸，野步晚來登。江水因寒落，山雲為雪凝。',48,'御定全唐詩/json/886.json','["高樓臨古岸，野步晚來登。江水因寒落，山雲為雪凝。", "遠村雖入望，危檻不堪憑。親老未歸去，鄉愁徒自興。"]'),
('yuding-4','寄李處士','曹松','唐','御定全唐诗','yuding','','[]','僧話磻溪叟，平生重赤松。夜堂悲蟋蟀，秋水老芙蓉。',72,'御定全唐詩/json/886.json','["僧話磻溪叟，平生重赤松。夜堂悲蟋蟀，秋水老芙蓉。", "吟坐倦垂釣，閑行多倚筇。聞名來已久，未得一相逢。", "塔見移來影，鐘聞過去聲。一齋唯默坐，應笑我營營。"]'),
('yuding-5','客中立春','曹松','唐','御定全唐诗','yuding','','[]','玉燭傳佳節，陽和應此辰。土牛呈歲稔，彩燕表年春。',48,'御定全唐詩/json/886.json','["玉燭傳佳節，陽和應此辰。土牛呈歲稔，彩燕表年春。", "臘盡星回次，寒餘月建寅。梅花將柳色，偏思越鄉人。"]'),
('yuding-6','南塘暝興','曹松','唐','御定全唐诗','yuding','','[]','水色昏猶白，霞光暗漸無。風荷搖破扇，波月動連珠。',48,'御定全唐詩/json/886.json','["水色昏猶白，霞光暗漸無。風荷搖破扇，波月動連珠。", "蟋蟀啼相應，鴛鴦宿不孤。小僮頻報夜，歸步尚踟躕。"]'),
('yuding-7','送鄭穀歸宜春','曹松','唐','御定全唐诗','yuding','','[]','無成歸故國，上馬亦高歌。況是飛鳴後，殊為喜慶多。',48,'御定全唐詩/json/886.json','["無成歸故國，上馬亦高歌。況是飛鳴後，殊為喜慶多。", "暑消嵩嶽雨，涼吹洞庭波。莫使閑吟去，須期接盛科。"]'),
('yuding-8','送曾德邁歸寧宜春','曹松','唐','御定全唐诗','yuding','','[]','湘東山川有清輝，袁水詞人得意歸。幾府爭馳毛義檄，',40,'御定全唐詩/json/886.json','["湘東山川有清輝，袁水詞人得意歸。幾府爭馳毛義檄，", "想到宜陽更無事，並將歡慶奉庭闈。"]'),
('yuding-9','山泉','李洞','唐','御定全唐诗','yuding','','[]','半空飛下水，勢去響如雷。靜徹啼猿寺，高淩坐客台。',72,'御定全唐詩/json/886.json','["半空飛下水，勢去響如雷。靜徹啼猿寺，高淩坐客台。", "耳同經劍閣，身若到天臺。濺樹吹成凍，淩祠觸作灰。", "深中試楖栗，淺處落莓苔。半夜重城閉，潺湲枕上來。"]'),
('yuding-10','松','盧士衡','唐','御定全唐诗','yuding','','[]','雲外千尋好性靈，伴杉陪柏事孤貞。招呼暑氣終無分，',40,'御定全唐詩/json/886.json','["雲外千尋好性靈，伴杉陪柏事孤貞。招呼暑氣終無分，", "如逢郢匠垂搜采，為棟為梁力不輕。"]'),
('yuding-11','再游紫陽洞重題小松','盧士衡','唐','御定全唐诗','yuding','','[]','仙家種此充朝食，葉葉枝枝造化力。去年見時似鶴高，',48,'御定全唐詩/json/886.json','["仙家種此充朝食，葉葉枝枝造化力。去年見時似鶴高，", "好期逸士統貞根，昂枝點破秋苔色。尋思凡眼重花開，"]'),
('yuding-12','湘江曉望','熊皎','唐','御定全唐诗','yuding','','[]','笙歌歡罷散離筵，水色朦朧蘸宿煙。山響疏鐘何處寺，',40,'御定全唐詩/json/886.json','["笙歌歡罷散離筵，水色朦朧蘸宿煙。山響疏鐘何處寺，", "歸夢已闌風色動，孤帆仍要住無緣。"]'),
('yuding-13','早行','熊皎','唐','御定全唐诗','yuding','','[]','結束何妨早，將行四顧頻。山前猶見月，陌上未逢人。',48,'御定全唐詩/json/886.json','["結束何妨早，將行四顧頻。山前猶見月，陌上未逢人。", "遠樹動宿鳥，危橋怯病身。漸明恒自慰，應免複迷津。"]'),
('yuding-14','游嵩山','熊皎','唐','御定全唐诗','yuding','','[]','獨背焦桐訪洞天，暫攀靈跡棄塵緣。深逢野草皆疑藥，',40,'御定全唐詩/json/886.json','["獨背焦桐訪洞天，暫攀靈跡棄塵緣。深逢野草皆疑藥，", "可憐幽景堪長往，一任人間歲月遷。"]'),
('yuding-15','九華望廬山','熊皎','唐','御定全唐诗','yuding','','[]','九江山勢盡崢嶸，惟有匡廬最得名。萬疊影遮殘雪在，',40,'御定全唐詩/json/886.json','["九江山勢盡崢嶸，惟有匡廬最得名。萬疊影遮殘雪在，", "只待丹霄酬志了，白雲深處是歸程。"]'),
('yuding-16','道傍松','熊皎','唐','御定全唐诗','yuding','','[]','偃蓋當衢莫記年，獨含蒼翠鶴應憐。垂陰獨向笙歌地，',40,'御定全唐詩/json/886.json','["偃蓋當衢莫記年，獨含蒼翠鶴應憐。垂陰獨向笙歌地，", "論功只合行人賞，銷得煩蒸古道邊。"]'),
('yuding-17','月中桂','熊皎','唐','御定全唐诗','yuding','','[]','斷破重輪種者誰，銀蟾何事便相隨。莫言望夜無攀處，',40,'御定全唐詩/json/886.json','["斷破重輪種者誰，銀蟾何事便相隨。莫言望夜無攀處，", "幾回目斷雲霄外，未必姮娥惜一枝。"]'),
('yuding-18','湖上望廬山','孫魴','唐','御定全唐诗','yuding','','[]','輟棹南湖首重回，笑青吟翠向崔嵬。',32,'御定全唐詩/json/886.json','["輟棹南湖首重回，笑青吟翠向崔嵬。", "天應不許人全見，長把雲藏一半來。"]'),
('yuding-19','題梅嶺泉','孫魴','唐','御定全唐诗','yuding','','[]','梅嶺舊聞傳，林亭勢峞然。登臨真不易，幽勝恐無先。',481,'御定全唐詩/json/886.json','["梅嶺舊聞傳，林亭勢峞然。登臨真不易，幽勝恐無先。", "楚野平千里，吳江曲一邊。標形都大別，洞府豈知焉。", "飛閣橫空去，征帆落面前。南雄雉堞峻，北壯鳳台連。", "爛熳三春媚，參差百卉妍。風桃諸處錦，洛竹半溪煙。", "燕入晴梁語，鶯從暖穀遷。石根朝靄碧，簾際晚霞鮮。", "徑柳行難約，庭莎醉好眠。清明時更異，造化意疑偏。", "不獨宜韶景，尤須看暑天。藥苗繁似結，蘿蔓猛如編。", "珠亞垂枝果，冰澄汲井泉。粉牆蜩蛻落，丹檻雀雛顛。", "炎氣微茫覺，清飆左右穿。雲峰從勃起，葵葉豈勞扇。", "又見秋天麗，渾將夏日懸。紅bW著霜樹，香老臥池邊。", "菱芡誰鋪繡，莓苔自學錢。暗蟲依砌響，明月逗簾圓。", "小砌滋新菊，高軒噪暮蟬。雨聲寒颯颯，雁影曉聯聯。", "釋此何堪玩，深冬更可憐。窗中看短景，樹裏見重川。", "岡阜分明出，杉松氣概全。謳成白雪曲，吟是早梅篇。", "創制誰人解，根基太守賢。或時留皂蓋，盡日簇華筵。", "誰詠憂黎庶，狂遊泥管弦。交加豐玉食，來去迸金船。", "侍從非常客，俳諧像列仙。畫旗張赫奕，妖妓舞嬋娟。", "罷宴心猶戀，將歸興尚牽。只應愁逼夜，寧厭賞經年。", "孤賤今何幸，躋攀奈有緣。展眉驚豁達，徐步喜周旋。", "諷詠雖知苦，推功靡極玄。聊書四十韻，甘責未精專。"]'),
('yuding-20','廬山瀑布','孫魴','唐','御定全唐诗','yuding','','[]','有山來便有，萬丈落雲端。霧噴千岩濕，雷傾九夏寒。',48,'御定全唐詩/json/886.json','["有山來便有，萬丈落雲端。霧噴千岩濕，雷傾九夏寒。", "圖中僧寫去，湖上客回看。卻羨為猿鶴，飛鳴近碧湍。"]'),
('yuding-21','牡丹','孫魴','唐','御定全唐诗','yuding','','[]','意態天生異，轉看看轉新。百花休放豔，三月始為春。',48,'御定全唐詩/json/886.json','["意態天生異，轉看看轉新。百花休放豔，三月始為春。", "蝶死難離檻，鶯狂不避人。其如豪貴地，清醒複何因。"]'),
('yuding-22','主人司空後亭牡丹','孫魴','唐','御定全唐诗','yuding','','[]','佳卉挺芳辰，夭容乃絕倫。望開從隔歲，愁過即無春。',192,'御定全唐詩/json/886.json','["佳卉挺芳辰，夭容乃絕倫。望開從隔歲，愁過即無春。", "體物真英氣，餘花似庶人。蜂攢知眷戀，鳥語亦殷勤。", "況在豪華地，寧同裏巷塵。酷憐應喪德，多賞奈怡神。", "忌穢栽時土，嘗甜折處津。繞行那識倦，圍坐豈辭頻。", "入夢殊巫峽，臨池勝洛濱。樂喧絲雜竹，露漬卯連寅。", "飲興尤思滿，吟情自合新。怕風惟怯夜，憂雨不經旬。", "欄檻為良援，亭台是四鄰。雖非能伐性，爭免礙還淳。", "鬥豔何慚蜀，矜繁未讓秦。私心期一日，許近看逡巡。"]'),
('yuding-23','看牡丹二首','孫魴','唐','御定全唐诗','yuding','','[]','莫將紅粉比穠華，紅粉那堪比此花。隔院聞香誰不惜，',80,'御定全唐詩/json/886.json','["莫將紅粉比穠華，紅粉那堪比此花。隔院聞香誰不惜，", "輸我一枝和曉露，真珠簾外向人斜。", "看花長到牡丹月，萬事全忘自不知。風促乍開方可惜，", "也擬便休還改過，迢迢爭奈一年期。"]'),
('yuding-24','題未開牡丹','孫魴','唐','御定全唐诗','yuding','','[]','青苞雖小葉雖疏，貴氣高情便有餘。渾未盛時猶若此，',40,'御定全唐詩/json/886.json','["青苞雖小葉雖疏，貴氣高情便有餘。渾未盛時猶若此，", "無限風光言不得，一心留在暮春初。"]'),
('yuding-25','主人司空見和未開牡丹，輒卻奉和','孫魴','唐','御定全唐诗','yuding','','[]','把筆臨芳不自怡，首征章句促妖期。已驚常調言多鄙，',40,'御定全唐詩/json/886.json','["把筆臨芳不自怡，首征章句促妖期。已驚常調言多鄙，", "狂歌狂醉猶堪羨，大拙當時是老時。"]'),
('yuding-26','又題牡丹上主人司空','孫魴','唐','御定全唐诗','yuding','','[]','一年芳勝一年芳，愛重賢侯意異常。手辟紅房看闊狹，',40,'御定全唐詩/json/886.json','["一年芳勝一年芳，愛重賢侯意異常。手辟紅房看闊狹，", "只恐夢征他日去，又須疑向鳳池傍。"]'),
('yuding-27','牡丹落後有作','孫魴','唐','御定全唐诗','yuding','','[]','未發先愁有一朝，如今零落更魂銷。青叢別後無多色，',40,'御定全唐詩/json/886.json','["未發先愁有一朝，如今零落更魂銷。青叢別後無多色，", "明年雖道還期在，爭奈憑欄乍寂寥。"]'),
('yuding-28','柳絮詠','孫魴','唐','御定全唐诗','yuding','','[]','年年三月裏，隨處自悠揚。雨過渾疑盡，風來特地狂。',48,'御定全唐詩/json/886.json','["年年三月裏，隨處自悠揚。雨過渾疑盡，風來特地狂。", "入花蜂有礙，遮水燕無妨。苦是添離思，青門道路長。"]'),
('yuding-29','甘露寺紫薇花','孫魴','唐','御定全唐诗','yuding','','[]','蜀葵鄙下兼全落，菡萏清高且未開。赫日迸光飛蝶去，',48,'御定全唐詩/json/886.json','["蜀葵鄙下兼全落，菡萏清高且未開。赫日迸光飛蝶去，", "誰笑晚芳為賤劣，便饒春麗已塵埃。牽吟過夏惟憂盡，"]'),
('yuding-30','芳草','孫魴','唐','御定全唐诗','yuding','','[]','何處不相見，煙苗捧露心。萋萋綠遠水，苒苒在空林。',48,'御定全唐詩/json/886.json','["何處不相見，煙苗捧露心。萋萋綠遠水，苒苒在空林。", "野吹閑搖闊，遊人醉臥深。南朝古城裏，碑石又應沈。"]'),
('yuding-31','春苔','孫魴','唐','御定全唐诗','yuding','','[]','底物最牽吟，秋苔獨自尋。何時連夜雨，疊翠滿松陰。',48,'御定全唐詩/json/886.json','["底物最牽吟，秋苔獨自尋。何時連夜雨，疊翠滿松陰。", "湘岸荒祠靜，吳宮古砌深。侯門還可惜，長被馬蹄侵。"]'),
('yuding-32','老松','孫魴','唐','御定全唐诗','yuding','','[]','鬱鬱複蒼蒼，秋風韻更長。空心應有□，老葉不知霜。',48,'御定全唐詩/json/886.json','["鬱鬱複蒼蒼，秋風韻更長。空心應有□，老葉不知霜。", "子落生深澗，陰清背夕陽。如逢東岱雨，猶得覆秦王。"]'),
('yuding-33','柳','孫魴','唐','御定全唐诗','yuding','','[]','蘢蔥二月初，青軟自相紆。意態花猶少，風流木更無。',368,'御定全唐詩/json/886.json','["蘢蔥二月初，青軟自相紆。意態花猶少，風流木更無。", "影繁晴陌上，煙重古城隅。煬帝河聲裏，幾番榮又枯。", "數樹新栽在畫橋，春來猶自長長條。", "東風多事剛牽引，已解纖纖學舞腰。", "金堤堤上一林煙，況近清明二月天。", "別有數枝遙望見，畫橋南面拂秋千。", "春物牽情不奈何，就中楊柳態難過。", "也知是處無花去，爭奈看時未覺多。", "小眉初展綠條稠，露壓煙蒙不自由。", "莫是折來偏屬意，依稀相似是風流。", "九衢春霽濕雲凝，著地毿毿礙馬行。", "擬折無端拋又戀，亂穿來去羨黃鶯。", "千樹陰陰蓋禦溝，雪花金穗思悠悠。", "先朝事後應無也，惟是荒根逐碧流。", "搖盪和風恃賴春，蘸流遮路逐年新。", "顛狂絮落還堪恨，分外欺淩寂寞人。", "暖催春促吐芳芽，伴雨從風處處斜。", "莫道玄功無定配，不然爭得見桃花。", "小池前後碧江濱，窣翠拋青爛熳春。", "不是和風為抬舉，可能開眼向行人。", "深綠依依配淺黃，兩般顏色一般香。", "到頭嫋娜成何事，只解年年斷客腸。"]'),
('yuding-34','看桑','孫魴','唐','御定全唐诗','yuding','','[]','簇簇互相遮，閑看實可嗟。藉多雖是葉，栽盛不如花。',48,'御定全唐詩/json/886.json','["簇簇互相遮，閑看實可嗟。藉多雖是葉，栽盛不如花。", "春綠暗連麥，秋幹暮立鴉。舊鄉曾種得，經亂屬誰家。"]'),
('yuding-35','仙都山留題','劉昭禹','唐','御定全唐诗','yuding','','[]','林下事無非，塵中竟不知。白雲深擁我，青石合眠誰。',48,'御定全唐詩/json/886.json','["林下事無非，塵中竟不知。白雲深擁我，青石合眠誰。", "山靜搗靈藥，夜閑論古詩。此來親羽客，何日變枯髭。"]'),
('yuding-36','晚霽望岳麓','劉昭禹','唐','御定全唐诗','yuding','','[]','湘西斜日邊，峭入幾尋天。翠落重城內，屏開萬戶前。',48,'御定全唐詩/json/886.json','["湘西斜日邊，峭入幾尋天。翠落重城內，屏開萬戶前。", "崖崚危濺瀑，林罅靜通仙。誰肯功成後，相攜掃石眠。"]'),
('yuding-37','石筍','劉昭禹','唐','御定全唐诗','yuding','','[]','千古海門石，移歸吟叟居。竅腥蛟出後，形瘦浪沖餘。',48,'御定全唐詩/json/886.json','["千古海門石，移歸吟叟居。竅腥蛟出後，形瘦浪沖餘。", "工語寧無玉，僧知忽有書。好期仙者叱，變化向庭隅。"]'),
('yuding-38','傷雨後牡丹','劉昭禹','唐','御定全唐诗','yuding','','[]','廢功看不已，醉起又持杯。數日簾常卷，中宵雨忽來。',48,'御定全唐詩/json/886.json','["廢功看不已，醉起又持杯。數日簾常卷，中宵雨忽來。", "淒涼無戲蝶，零落在蒼苔。造化根難問，令人首可回。"]'),
('yuding-39','送人紅花栽','劉昭禹','唐','御定全唐诗','yuding','','[]','世上紅蕉異，因移萬雷根。艱難離瘴土，瀟灑入朱門。',48,'御定全唐詩/json/886.json','["世上紅蕉異，因移萬雷根。艱難離瘴土，瀟灑入朱門。", "葉戰青雲韻，花零宿露痕。長安多未識，誰想動吟魂。"]'),
('yuding-40','曉望','劉乙','唐','御定全唐诗','yuding','','[]','地祇逃秀境，神化或殷雷。裂漢媧補合，高峰劍躍開。',48,'御定全唐詩/json/886.json','["地祇逃秀境，神化或殷雷。裂漢媧補合，高峰劍躍開。", "即今新定業，何世不遺才。若是浮名道，須言有禍胎。"]'),
('yuding-41','山中早起','劉乙','唐','御定全唐诗','yuding','','[]','雞調扶桑枝，秋空隱少微。闊雲霞並曜，高日月爭輝。',48,'御定全唐詩/json/886.json','["雞調扶桑枝，秋空隱少微。闊雲霞並曜，高日月爭輝。", "若厥開天道，同初發帝機。以言當代事，閑辟紫宸扉。"]'),
('yuding-42','晚步','姚揆','唐','御定全唐诗','yuding','','[]','陋巷貧疑本姓顏，晚來閒步出林間。數聲長笛吹沈日，',40,'御定全唐詩/json/886.json','["陋巷貧疑本姓顏，晚來閒步出林間。數聲長笛吹沈日，", "遲回從此搜吟久，待得溪頭月上還。"]'),
('yuding-43','秋日江東晚行','姚揆','唐','御定全唐诗','yuding','','[]','迢迢驅馬過江東，此際令人恨莫窮。一撮秋煙堤上白，',40,'御定全唐詩/json/886.json','["迢迢驅馬過江東，此際令人恨莫窮。一撮秋煙堤上白，", "含思看看到梁苑，畫樓絲竹徹遙空。"]'),
('yuding-44','題陶淵明醉石','陳光','唐','御定全唐诗','yuding','','[]','片石露寒色，先生遺素風。醉眠芳草合，吟起白雲空。',48,'御定全唐詩/json/886.json','["片石露寒色，先生遺素風。醉眠芳草合，吟起白雲空。", "道出乾坤外，聲齊日月中。我知彭澤後，千載與誰同。"]'),
('yuding-45','長安新柳','陳光','唐','御定全唐诗','yuding','','[]','九陌雲初霽，皇衢柳已新。不同天苑景，先得日邊春。',48,'御定全唐詩/json/886.json','["九陌雲初霽，皇衢柳已新。不同天苑景，先得日邊春。", "色淺微含露，絲輕未惹塵。一枝方欲折，歸去及茲晨。"]'),
('yuding-46','雪晴','楊凝式','唐','御定全唐诗','yuding','','[]','春來冰未泮，冬至雪初晴。為報方袍客，豐年瑞已成。',24,'御定全唐詩/json/886.json','["春來冰未泮，冬至雪初晴。為報方袍客，豐年瑞已成。"]'),
('yuding-0','上安祿山','盧言','唐','御定全唐诗','yuding','','[]','象曰雲雷屯，大君理經綸。馬上取天下，雪中朝海神。',24,'御定全唐詩/json/887.json','["象曰雲雷屯，大君理經綸。馬上取天下，雪中朝海神。"]'),
('yuding-1','儲潭廟','裴諝','唐','御定全唐诗','yuding','','[]','江水上源急如箭，潭北轉急令目眩。中間十裏澄漫漫，',119,'御定全唐詩/json/887.json','["江水上源急如箭，潭北轉急令目眩。中間十裏澄漫漫，", "質明齋服躬往奠，牢醴豐潔精誠舉。女巫紛紛堂下儛，", "氣霾祠宇連江陰，朝日不復照翠岑。回溪口兮棹清流，", "城上樓兮危架空，登四望兮暗濛濛。不知兮千萬里，", "高垣墉兮大其門，灑掃丹雘壯神居。使過廟者之加敬，"]'),
('yuding-2','臘月中與韋戶曹游發生洞裴回之際見雙白蝙蝠…口號','任要','唐','御定全唐诗','yuding','','[]','山翠冪靈洞，洞深玄想微。一雙白蝙蝠，三度向明飛。',60,'御定全唐詩/json/887.json','["山翠冪靈洞，洞深玄想微。一雙白蝙蝠，三度向明飛。", "雖然有兩翅，了自無毛衣。若非飽石髓，那得淩□□。", "偶見歸堪說，殊勝不見歸。"]'),
('yuding-3','臘月中游發生洞裴回之際見雙白蝙蝠三飛洞門…口號','韋洪','唐','御定全唐诗','yuding','','[]','欲驗發生洞，先開冰雪行。窺臨見二翼，色素飛無聲。',60,'御定全唐詩/json/887.json','["欲驗發生洞，先開冰雪行。窺臨見二翼，色素飛無聲。", "狀類白蝙蝠，幽感騰化精。應知五馬來，啟蟄迎春榮。", "露冕□之久，鳴騶還慰情。"]'),
('yuding-4','蜀中經蠻後寄陶雍','馬乂','唐','御定全唐诗','yuding','','[]','酋馬渡瀘水，北來如鳥輕。幾年期鳳闕，一日破龜城。',72,'御定全唐詩/json/887.json','["酋馬渡瀘水，北來如鳥輕。幾年期鳳闕，一日破龜城。", "此地有征戰，誰家無死生。人悲還舊裏，鳥喜下空營。", "弟侄意初定，交朋心尚驚。自從經難後，吟苦似猿聲。"]'),
('yuding-5','沖佑觀','張紹','唐','御定全唐诗','yuding','','[]','大始未形，混沌無際。上下開運，乾坤定位。日月麗天，',250,'御定全唐詩/json/887.json','["大始未形，混沌無際。上下開運，乾坤定位。日月麗天，", "上惟立德，下無疏親。皇風蕩蕩，黔首淳淳。天下有道，", "八極神鄉，十州異境。翠阜丹丘，潛伏靈聖。惟彼武夷，", "葬日風雨，會有神仙。國步多艱，皇綱中絕。四海九州，", "赫赫烈祖，再造丕基。拱揖高讓，神人樂推。明明我後，", "拓土開疆，經天緯地。五嶺來庭，三湘清澈。四海震威，", "淹留駿馭，想像鶉居。心懸真洞，夢到華胥。乃眷名山，", "跨谷彌岡，張霄架極。珠宮寶殿，璿台玉堂。鳳翔高甍，", "七聖斯嚴，三君如在。八景靈輿，九華神蓋。清霄莫胥，", "會仙之類，名之惟新。高峰為壑，區谷成坰。皇獻頌聲，"]'),
('yuding-6','徹雲澗','鄭露','唐','御定全唐诗','yuding','','[]','延綿不可窮，寒光徹雲際。落石早雷鳴，濺空春雨細。',24,'御定全唐詩/json/887.json','["延綿不可窮，寒光徹雲際。落石早雷鳴，濺空春雨細。"]'),
('yuding-7','秋氣尚高涼','林披','唐','御定全唐诗','yuding','','[]','秋氣尚高涼，寒笛吹萬木。故人入我庭，相照不出屋。',36,'御定全唐詩/json/887.json','["秋氣尚高涼，寒笛吹萬木。故人入我庭，相照不出屋。", "山川雖遠觀，高懷不能掬。"]'),
('yuding-8','五言贈諸法師','公孫杲','唐','御定全唐诗','yuding','','[]','駕鶴排朱霧，乘鸞入紫煙。淩晨味潭菊，薄暮玩峰蓮。',48,'御定全唐詩/json/887.json','["駕鶴排朱霧，乘鸞入紫煙。淩晨味潭菊，薄暮玩峰蓮。", "玉葉低梁下，金飀引窗前。嘯傲雲霞際，留情鱗羽年。"]'),
('yuding-9','恒嶽晨望有懷','李夐','唐','御定全唐诗','yuding','','[]','二儀均四序，五嶽分九州。靈造良難測，神功匪易酬。',144,'御定全唐詩/json/887.json','["二儀均四序，五嶽分九州。靈造良難測，神功匪易酬。", "恒山北臨岱，秀崿東跨幽。澒洞鎮河朔，嵯峨冠嵩丘。", "禋祠彰舊典，壇廟列平疇。古樹侵雲密，飛泉界道流。", "從官叨佐理，銜命奉珍羞。薦玉申誠效，鏘金諒有由。", "郊原照初日，林薄委徂秋。塞近風聲厲，川長霧氣收。", "他鄉饒感激，歸望切祈求。景福如光願，私門當複侯。"]'),
('yuding-10','偶宴西蜀摩訶池','暢甫','唐','御定全唐诗','yuding','','[]','珍木郁清池，風荷左右披。淺觴寧及醉，慢舸不知移。',48,'御定全唐詩/json/887.json','["珍木郁清池，風荷左右披。淺觴寧及醉，慢舸不知移。", "蔭林簟光冷，照流簪影欹。胡為獨羈者，雪涕向漣漪。"]'),
('yuding-11','飲後獻時相','吳士矩','唐','御定全唐诗','yuding','','[]','一夕心期一種歡，那知疏散負杯盤。',32,'御定全唐詩/json/887.json','["一夕心期一種歡，那知疏散負杯盤。", "尊前數片朝雲在，不許馮公子細看。"]'),
('yuding-12','失題','吳黔','唐','御定全唐诗','yuding','','[]','故國海雲端，歸寧便整鞍。裏榮身上蒨，省罷手中蘭。',48,'御定全唐詩/json/887.json','["故國海雲端，歸寧便整鞍。裏榮身上蒨，省罷手中蘭。", "燒急平蕪廣，風悲古木寒。謝公山色在，朝夕共誰觀。"]'),
('yuding-13','題惠聚寺','崔融2','唐','御定全唐诗','yuding','','[]','人莫嫌山小，僧還愛寺靈。殿高神氣力，龍活客丹青。',24,'御定全唐詩/json/887.json','["人莫嫌山小，僧還愛寺靈。殿高神氣力，龍活客丹青。"]'),
('yuding-14','平望贈蚊','錢信','唐','御定全唐诗','yuding','','[]','安得神仙術，試為施康濟。使此平望村，如吾江子匯。',24,'御定全唐詩/json/887.json','["安得神仙術，試為施康濟。使此平望村，如吾江子匯。"]'),
('yuding-15','武康碧落觀','胡傳美','唐','御定全唐诗','yuding','','[]','仙宮碧落太微書，遺跡依然掩故居。幢節不歸天杳邈，',40,'御定全唐詩/json/887.json','["仙宮碧落太微書，遺跡依然掩故居。幢節不歸天杳邈，", "欲脫儒衣陪羽客，傷心齒發已凋疏。"]'),
('yuding-16','白雲寺','許宏','唐','御定全唐诗','yuding','','[]','踏破苔痕一徑斑，白雲飛處見青山。',32,'御定全唐詩/json/887.json','["踏破苔痕一徑斑，白雲飛處見青山。", "不知浮世塵中客，幾個能知物外閑。"]'),
('yuding-17','羅浮山','文丙','唐','御定全唐诗','yuding','','[]','羅浮多勝境，夢到固無因。知有長生藥，誰為不死人。',48,'御定全唐詩/json/887.json','["羅浮多勝境，夢到固無因。知有長生藥，誰為不死人。", "根雖盤地脈，勢自倚天津。未便甘休去，須棲老此身。"]'),
('yuding-18','牡丹','文丙','唐','御定全唐诗','yuding','','[]','萬物承春各鬥奇，百花分貴近亭池。開時若也姮娥見，',40,'御定全唐詩/json/887.json','["萬物承春各鬥奇，百花分貴近亭池。開時若也姮娥見，", "不同寒菊舒重九，只擬清香泛酒卮。"]'),
('yuding-19','蘚花','文丙','唐','御定全唐诗','yuding','','[]','寂寞人偏重，無心愧牡丹。秋風凋不得，流水泛應難。',48,'御定全唐詩/json/887.json','["寂寞人偏重，無心愧牡丹。秋風凋不得，流水泛應難。", "怪石縱教遍，幽庭一任盤。若逢公子顧，重疊是朱欄。"]'),
('yuding-20','新栽松','文丙','唐','御定全唐诗','yuding','','[]','可憐同百草，況負雪霜姿。歌舞地不尚，歲寒人自移。',48,'御定全唐詩/json/887.json','["可憐同百草，況負雪霜姿。歌舞地不尚，歲寒人自移。", "階除添冷淡，毫末入思惟。盡道生雲洞，誰知路嶮巇。"]'),
('yuding-21','柳','文丙','唐','御定全唐诗','yuding','','[]','何事動吟哦，長□翠色和。垂陰千樹少，送別一枝多。',48,'御定全唐詩/json/887.json','["何事動吟哦，長□翠色和。垂陰千樹少，送別一枝多。", "帶霧籠彭澤，搖風舞汴河。只因隋帝植，民力幾銷磨。"]'),
('yuding-22','仙岩四瀑布即事寄上秘書包監侍郎七兄吏部李侍…十四韻','路應','唐','御定全唐诗','yuding','','[]','絕境久蒙蔽，芟蘿方迨茲。樵蘇尚未及，冠冕誰能知。',168,'御定全唐詩/json/887.json','["絕境久蒙蔽，芟蘿方迨茲。樵蘇尚未及，冠冕誰能知。", "緣崖開徑小，架木度空危。水激千雷發，珠聯萬貫垂。", "陰晴狀非一，昏旦勢多奇。井識軒轅跡，壇餘漢武基。", "猿聲響深洞，岩影倒澄池。想像虯龍去，依稀羽客隨。", "玩奇目豈倦，尋異神忘疲。幹雲松作蓋，積翠薜成帷。", "含意攀丹桂，凝情顧紫芝。芸香藹芳氣，冰鏡徹圓規。", "胥念滄波遠，徒懷魏闕期。征黃應計日，莫鄙北山移。"]'),
('yuding-23','奉和郎中游仙岩四瀑布寄包秘監李吏部趙婺州中…十四韻','李縝','唐','御定全唐诗','yuding','','[]','符守分珪組，放情在丘巒。悠然造雲族，忽爾登天壇。',168,'御定全唐詩/json/887.json','["符守分珪組，放情在丘巒。悠然造雲族，忽爾登天壇。", "求古理方賾，玩奇物不殫。晴光散崖壁，瑞氣生芝蘭。", "中有四瀑水，奔流狀千般。風雲隱岩底，雨雪霏林端。", "晶晶含古色，颼颼引晨寒。澄潭見猿飲，潛穴知龍盤。", "坐憩苔石遍，仰窺杉桂攢。幽蹊創高躅，靈藥餘仙餐。", "攜賞喜康樂，示文驚建安。縑緗炳珠寶，中外貽同官。", "末調亦何為，輒陪高唱難。慚非禦徒者，還得依門欄。"]'),
('yuding-24','奉和郎中游仙山四瀑泉兼寄李吏部包秘監趙婺州齊處州','戴公懷','唐','御定全唐诗','yuding','','[]','今日永嘉守，複追山水遊。因尋莽蒼野，遂得軒轅丘。',168,'御定全唐詩/json/887.json','["今日永嘉守，複追山水遊。因尋莽蒼野，遂得軒轅丘。", "訪古事難究，覽新情屢周。溪垂綠筱暗，岩度白雲幽。", "過石奇不盡，出林香更浮。憑高擁虎節，搏險窺龍湫。", "淙潈瀉三四，奔騰千萬秋。寒驚殷雷動，暑駭繁霜流。", "沫濺群鳥外，光搖數峰頭。叢崖散滴瀝，近谷藏颼飀。", "況此特形勝，自餘非等儔。靈光掩五嶽，仙氣均十洲。", "書以謝群彥，永將敘徽猷。當思共攀陟，東南看鬥牛。"]'),
('yuding-25','奉和郎中游仙山四瀑布兼寄李吏部、包秘監判官','孟翔','唐','御定全唐诗','yuding','','[]','昔人恣探討，飛流稱石門。安知郡城側，別有神泉源。',132,'御定全唐詩/json/887.json','["昔人恣探討，飛流稱石門。安知郡城側，別有神泉源。", "疏鑿意大禹，勤求聞軒轅。悠悠幾千歲，翳薈群木繁。", "奇狀出蔽蔓，勝概畢討論。沿崖百丈落，奔注當空翻。", "下如散雨足，上擬屯雲根。變態凡幾處，靜神竟朝昏。", "渴賢寄珠玉，受馥尋蘭蓀。蘿蔦罥紫綬，岩隈駐朱轓。", "方思謝康樂，好事名空存。"]'),
('yuding-26','晚眺','崔耿','唐','御定全唐诗','yuding','','[]','江溶流落景，山色凝暮煙。衰發照秋日，壯心減昔年。',36,'御定全唐詩/json/887.json','["江溶流落景，山色凝暮煙。衰發照秋日，壯心減昔年。", "愁吟長抱膝，孰訴高高天。"]'),
('yuding-27','山下泉','宇文鼎','唐','御定全唐诗','yuding','','[]','可致清川廣，難量利物功。涓流此山下，誰識去無窮。',24,'御定全唐詩/json/887.json','["可致清川廣，難量利物功。涓流此山下，誰識去無窮。"]'),
('yuding-28','永嘉經謝公石門山作','郭密之','唐','御定全唐诗','yuding','','[]','綿境經耳目，未嘗曠躋登。一窺石門險，再滌心神懵。',120,'御定全唐詩/json/887.json','["綿境經耳目，未嘗曠躋登。一窺石門險，再滌心神懵。", "洞壑閟金澗，欹崖磐石楞。陰潭下冪冪，秀嶺上層層。", "千丈瀑流蹇，半溪風雨縆。興餘志每愜，心遠道自弘。", "乘軺廣儲峙，祗命愧才能。輟棹周氣象，捫條曆騫崩。", "忽如生羽翼，恍若將起騰。謝客今已矣，我來誰與朋。"]'),
('yuding-29','芳草','扈載','唐','御定全唐诗','yuding','','[]','幽芳無處無，幽處恨何如。倦客傷歸思，春風滿舊居。',48,'御定全唐詩/json/887.json','["幽芳無處無，幽處恨何如。倦客傷歸思，春風滿舊居。", "晚煙迷杳靄，朝露健扶疏。省傍靈光看，殘陽少皞區。"]'),
('yuding-30','任閬中下鄉檢田，登艾蕭山北望','薛光謙','唐','御定全唐诗','yuding','','[]','觀農巡井邑，長望曆山川。擁澗開新耨，緣崖指火田。',72,'御定全唐詩/json/887.json','["觀農巡井邑，長望曆山川。擁澗開新耨，緣崖指火田。", "荒村無徑陌，古戍有風煙。瓠葉縈籬長，藤花繞架懸。", "岸高攢樹石，水淨寫雲天。回首鄉關路，行歌猶喟然。"]'),
('yuding-31','府尹王侍郎准制拜嶽，因狀嵩高靈勝，寄呈三十韻','尉遲汾','唐','御定全唐诗','yuding','','[]','雄雄天之中，峻極聞維嵩。作鎮盛標格，出雲為雨風。',360,'御定全唐詩/json/887.json','["雄雄天之中，峻極聞維嵩。作鎮盛標格，出雲為雨風。", "瑞時物不癘，順澤年多豐。加高冠四方，視秩居三公。", "明朝虔昭報，頒祀歲嚴恭。署祝紆禦劄，詔賢導宸衷。", "皇皇三川守，馨德清明躬。肅徒奉蘭沐，竟夕玉華東。", "星漢耿齋戶，松泉寒壽宮。具修諒蠲吉，曙色猶蔥曚。", "端儀大圭立，興俛聲玲瓏。挹瓚椒桂馥，奏金岩壑空。", "靈歆若有答，仿佛傳祝工。卒事不遑偃，勝奇紛四叢。", "朝霞破靈嶂，錯落間蒼紅。動息形似蟻，玄黃氣如籠。", "奔傾千萬狀，群岳安比崇。日月襟袖捧，人天道路通。", "冥搜必殫竭，躋覽忘崎穹。踏翠遍諸刹，趣綿步難終。", "浮丘仙袂接，謝公屐齒窮。龍潭應下瞰，九曲當駭容。", "龍門計東豁，三台有何蹤。金象語奚應，玉人光想融。", "瑤漿與石髓，清骨宜遭逢。況是降神處，跡惟申甫同。", "周翰已洽論，伊衡亦期功。誠富東山興，須陟中台庸。", "勉促旋騑軨，未可戀雲松。散材事即異，期為蔔一峰。"]'),
('yuding-32','早春陪敕使麻先生祭岳','馬令','唐','御定全唐诗','yuding','','[]','我皇盛文物，道化天地先。鞭撻走神鬼，玉帛禮山川。',168,'御定全唐詩/json/887.json','["我皇盛文物，道化天地先。鞭撻走神鬼，玉帛禮山川。", "忽下袁州使，來遊紫洞前。青羊得處所，白鶴□時年。", "虔懇飛龍記，昭彰化鳥篇。□風半山水，□氣總雲煙。", "光抱升中日，霞明五色天。山橫翠微外，室在綠潭邊。", "緹幕灰初庪，焚林火欲然。年光著草樹，春色換山泉。", "伊水來何日，嵩岩去幾千。山疑小天下，人是會神仙。", "葉令乘鳧入，浮丘駕鶴旋。麻姑幾年歲，三見海成田。"]'),
('yuding-0','奉和郎中題仙岩瀑布十四韻','靈澈','唐','御定全唐诗','yuding','','[]','致閑在一郡，民安已三年。每懷貞士心，孫許猶差肩。',168,'御定全唐詩/json/888.json','["致閑在一郡，民安已三年。每懷貞士心，孫許猶差肩。", "采異百代後，得之古人前。捫險路坱圠，臨深聞潺湲。", "上有千歲樹，下飛百丈泉。清谷長雷雨，丹青凝霜煙。", "遙將大壑近，暗與方壺連。白石顏色寒，老藤花葉鮮。", "軒皇自茲去，喬木空依然。碧山東極海，明月高升天。", "平野生竹柏，雖遠地不偏。永願酬國恩，自將布金田。", "穆穆早朝人，英英丹陛賢。誰思滄洲意，方欲涉巨川。"]'),
('yuding-1','過商山','貫休','唐','御定全唐诗','yuding','','[]','吟緣橫翠憶天臺，嘯狖啼猿見盡猜。四個老人何處去，',40,'御定全唐詩/json/888.json','["吟緣橫翠憶天臺，嘯狖啼猿見盡猜。四個老人何處去，", "天際峰峰盡堪住，紅塵中去大悠哉。"]'),
('yuding-2','過西塞山','齊己','唐','御定全唐诗','yuding','','[]','空江平野流，風島葦颼颼。殘日銜西塞，孤帆向北洲。',48,'御定全唐詩/json/888.json','["空江平野流，風島葦颼颼。殘日銜西塞，孤帆向北洲。", "邊鴻渡漢口，楚樹出吳頭。終日高雲裏，身依片石休。"]'),
('yuding-3','中秋月','可朋','唐','御定全唐诗','yuding','','[]','登樓仍喜此宵晴，圓魄才觀思便清。海面乍浮猶隱映，',40,'御定全唐詩/json/888.json','["登樓仍喜此宵晴，圓魄才觀思便清。海面乍浮猶隱映，", "曾向洞庭湖上看，君山半霧水初平。"]'),
('yuding-4','僧院泉','修睦','唐','御定全唐诗','yuding','','[]','澄澈照人膽，深山只一般。來難窮處所，心去助波瀾。',48,'御定全唐詩/json/888.json','["澄澈照人膽，深山只一般。來難窮處所，心去助波瀾。", "砌曲夜聲苦，窗虛客夢闌。無心誰肯愛，時有老僧看。"]'),
('yuding-5','題僧院泉','修睦','唐','御定全唐诗','yuding','','[]','何處雲根新布得，歸仍半日在煙蘿。莫輕竹引經窗小，',40,'御定全唐詩/json/888.json','["何處雲根新布得，歸仍半日在煙蘿。莫輕竹引經窗小，", "從此無心戀滄海，滄海無風亦起波。"]'),
('yuding-6','嶽上作','修睦','唐','御定全唐诗','yuding','','[]','始好步青苔，蟬聲且莫催。辛勤來到此，容易便言回。',48,'御定全唐詩/json/888.json','["始好步青苔，蟬聲且莫催。辛勤來到此，容易便言回。", "遠水月未上，四方雲正開。更堪逢道侶，特地話天臺。"]'),
('yuding-7','望西山','修睦','唐','御定全唐诗','yuding','','[]','積翠異諸嶽，令人看莫休。有時經暮雨，獨得倚高樓。',48,'御定全唐詩/json/888.json','["積翠異諸嶽，令人看莫休。有時經暮雨，獨得倚高樓。", "雲外僧應老，林間水正秋。到頭歸隱處，豈在問嵩丘。"]'),
('yuding-8','題虎掊泉','修睦','唐','御定全唐诗','yuding','','[]','一自虎掊得，清聲四遠流。眾人憐爾處，長夜洗心頭。',48,'御定全唐詩/json/888.json','["一自虎掊得，清聲四遠流。眾人憐爾處，長夜洗心頭。", "出穀花隨去，背岩猿下偷。林邊落江徼，風起雨翛翛。"]'),
('yuding-9','松','修睦','唐','御定全唐诗','yuding','','[]','細韻颼颼入骨涼，影兼巢鶴過高牆。',32,'御定全唐詩/json/888.json','["細韻颼颼入骨涼，影兼巢鶴過高牆。", "盤根一種依平地，自是梧桐不久長。"]'),
('yuding-10','岳陽對柳','修睦','唐','御定全唐诗','yuding','','[]','誰此種秋色，令人看莫窮。正垂雲夢雨，不奈洞庭風。',48,'御定全唐詩/json/888.json','["誰此種秋色，令人看莫窮。正垂雲夢雨，不奈洞庭風。", "昔出長安道，獨游隋苑東。當時今日思，須信苦相同。"]'),
('yuding-11','歸山吟','清豁','唐','御定全唐诗','yuding','','[]','聚如浮沫散如雲，聚不相將散不分。',32,'御定全唐詩/json/888.json','["聚如浮沫散如雲，聚不相將散不分。", "入郭當時君是我，歸山今日我非君。"]'),
('yuding-12','遊倚帝山二首','吳筠','唐','御定全唐诗','yuding','','[]','山間非吾心，物表翼所托。振衣超煩滓，策杖追岑壑。',169,'御定全唐詩/json/888.json','["山間非吾心，物表翼所托。振衣超煩滓，策杖追岑壑。", "絕地窮gK岈，造天究盤礴。邇臨煙霞積，逖睇宇宙廓。", "俯驚白雲湧，仰駭飛泉落。苔濃鮮翠屏，松古麗丹崿。", "目冀睹喬羨，心希馭龍鶴。乃知巢由情，豈伊猿鳥樂。", "茲山何獨秀，萬仞倚昊蒼。晨躋煙霞趾，夕憩靈仙場。", "俯觀海上月，坐弄浮雲翔。松風振雅音，桂露含晴光。", "不出六合外，超然萬累忘。信彼古來士，岩棲道彌彰。"]'),
('yuding-13','翰林院望終南山','吳筠','唐','御定全唐诗','yuding','','[]','竊慕隱淪道，所歡岩穴居。誰言忝休命，遂入承明廬。',96,'御定全唐詩/json/888.json','["竊慕隱淪道，所歡岩穴居。誰言忝休命，遂入承明廬。", "物情不可易，幽中未嘗攄。幸見終南山，岧嶢淩太虛。", "青靄長不滅，白雲閑卷舒。悠然相探討，延望空躊躕。", "跡系心無極，神超興有餘。何當解維縶，永托逍遙墟。"]'),
('yuding-14','秋日彭蠡湖中觀廬山','吳筠','唐','御定全唐诗','yuding','','[]','泛舟太湖上，回瞰茲山隈。萬頃滄波中，千峰鬱崔嵬。',120,'御定全唐詩/json/888.json','["泛舟太湖上，回瞰茲山隈。萬頃滄波中，千峰鬱崔嵬。", "涼煙發爐嶠，秋日明帝台。絕巔淩大漠，懸流瀉昭回。", "穹崇石樑引，岈豁天門開。飛鳥屢隱見，白雲時往來。", "超然契清賞，目醉心悠哉。董氏出六合，王君升九垓。", "誰言曠遐祀，庶可相追陪。從此永棲托，拂衣謝浮埃。"]'),
('yuding-15','秋日望倚帝山','吳筠','唐','御定全唐诗','yuding','','[]','楚服多奇山，靈表先倚帝。孤秀白雲裏，青冥何崇麗。',96,'御定全唐詩/json/888.json','["楚服多奇山，靈表先倚帝。孤秀白雲裏，青冥何崇麗。", "秋天已晴朗，晚日更澄霽。遠峰列在目，杳與神襟契。", "倏忽遺世間，宛如再登詣。伊予抱斯志，代處人煙閉。", "何事牽俗網，悠然負芝桂。朅來從隱淪，式保羨門計。"]'),
('yuding-16','薔薇花','李冶','唐','御定全唐诗','yuding','','[]','翠融紅綻渾無力，斜倚欄幹似詫人。深處最宜香惹蝶，',40,'御定全唐詩/json/888.json','["翠融紅綻渾無力，斜倚欄幹似詫人。深處最宜香惹蝶，", "最好淩晨和露看，碧紗窗外一枝新。"]'),
('yuding-17','柳','李冶','唐','御定全唐诗','yuding','','[]','最愛纖纖曲水濱，夕陽移影過青蘋。東風又染一年綠，',40,'御定全唐詩/json/888.json','["最愛纖纖曲水濱，夕陽移影過青蘋。東風又染一年綠，", "舞腰漸重煙光老，散作飛綿惹翠裀。"]'),
('yuding-0','好時光','李隆基','唐','御定全唐诗','yuding','','[]','寶髻偏宜宮樣，蓮臉嫩，體紅香。眉黛不須張敞畫，',43,'御定全唐詩/json/889.json','["寶髻偏宜宮樣，蓮臉嫩，體紅香。眉黛不須張敞畫，", "莫倚傾國貌，嫁取個，有情郎。彼此當年少，"]'),
('yuding-1','巫山一段雲','李曄','唐','御定全唐诗','yuding','','[]','縹緲雲間質，盈盈波上身。袖羅斜舉動埃塵，明豔不勝春。',96,'御定全唐詩/json/889.json','["縹緲雲間質，盈盈波上身。袖羅斜舉動埃塵，明豔不勝春。", "翠鬢晚妝煙重，寂寂陽臺一夢。冰眸蓮臉見長新，", "蝶舞梨園雪，鶯啼柳帶煙。小池殘日豔陽天，苧蘿山又山。", "青鳥不來愁絕，忍看鴛鴦雙結。春風一等少年心，"]'),
('yuding-2','菩薩蠻','李曄','唐','御定全唐诗','yuding','','[]','登樓遙望秦宮殿，茫茫只見雙飛燕。渭水一條流，',92,'御定全唐詩/json/889.json','["登樓遙望秦宮殿，茫茫只見雙飛燕。渭水一條流，", "遠煙籠碧樹，陌上行人去。安得有英雄，迎歸大內中。", "飄飄且在三峰下，秋風往往堪沾灑。腸斷憶仙宮，", "思夢時時睡，不語長如醉。早晚是歸期，蒼穹知不知。"]'),
('yuding-3','一葉落','李存勖','唐','御定全唐诗','yuding','','[]','一葉落，搴朱箔，此時景物正蕭索。畫樓月影寒，',22,'御定全唐詩/json/889.json','["一葉落，搴朱箔，此時景物正蕭索。畫樓月影寒，"]'),
('yuding-4','如夢令','李存勖','唐','御定全唐诗','yuding','','[]','曾宴桃源深洞，一曲清歌舞鳳。長記別伊時，',20,'御定全唐詩/json/889.json','["曾宴桃源深洞，一曲清歌舞鳳。長記別伊時，"]'),
('yuding-5','陽臺夢','李存勖','唐','御定全唐诗','yuding','','[]','薄羅衫子金泥縫，困纖腰怯銖衣重。笑迎移步小蘭叢，',45,'御定全唐詩/json/889.json','["薄羅衫子金泥縫，困纖腰怯銖衣重。笑迎移步小蘭叢，", "嬌多情脈脈，羞把同心拈弄。楚天雲雨卻相和，"]'),
('yuding-6','歌頭','李存勖','唐','御定全唐诗','yuding','','[]','賞芳春，暖風飄箔。鶯啼綠樹，輕煙籠晚閣。杏桃紅，',85,'御定全唐詩/json/889.json','["賞芳春，暖風飄箔。鶯啼綠樹，輕煙籠晚閣。杏桃紅，", "臨水檻，永日逃繁暑，泛觥酌。", "露華濃，冷高梧，凋萬葉。一霎晚風，蟬聲新雨歇。", "惜惜此光陰，如流水。東籬菊殘時，歎蕭索。繁陰積，"]'),
('yuding-7','浣溪紗','李璟','唐','御定全唐诗','yuding','','[]','風壓輕雲貼水飛，乍晴池館燕爭泥，沈郎多病不勝衣。',48,'御定全唐詩/json/889.json','["風壓輕雲貼水飛，乍晴池館燕爭泥，沈郎多病不勝衣。", "沙上未聞鴻雁信，竹間時聽鷓鴣啼，此情惟有落花知。"]'),
('yuding-8','攤破浣溪沙','李璟','唐','御定全唐诗','yuding','','[]','菡萏香銷翠葉殘，西風愁起綠波間。還與韶光共憔悴，',96,'御定全唐詩/json/889.json','["菡萏香銷翠葉殘，西風愁起綠波間。還與韶光共憔悴，", "細雨夢回雞塞遠，小樓吹徹玉笙寒。多少淚珠何限恨，", "手卷真珠上玉鉤，依前春恨鎖重樓。風裏落花誰是主，", "青鳥不傳雲外信，丁香空結雨中愁。回首淥波三峽暮，"]'),
('yuding-9','漁父','李煜','唐','御定全唐诗','yuding','','[]','浪花有意千里雪，桃花無言一隊春。一壺酒，一竿身，',48,'御定全唐詩/json/889.json','["浪花有意千里雪，桃花無言一隊春。一壺酒，一竿身，", "一棹春風一葉舟，一綸繭縷一輕鉤。花滿渚，酒滿甌，"]'),
('yuding-10','憶江南','李煜','唐','御定全唐诗','yuding','','[]','（一名望江南、夢江南、江南好、夢江口、望江梅、',107,'御定全唐詩/json/889.json','["（一名望江南、夢江南、江南好、夢江口、望江梅、", "歸塞北、謝秋娘、春去也）", "多少恨，昨夜夢魂中。還似舊時游上苑，", "多少淚，沾袖複橫頤。心事莫將和淚滴，", "閑夢遠，南國正芳春。船上管弦江面綠，", "閑夢遠，南國正清秋。千里江山寒色暮，"]'),
('yuding-11','搗練子','李煜','唐','御定全唐诗','yuding','','[]','深院靜，小庭空，斷續寒砧斷續風。無奈夜長人不寐，',48,'御定全唐詩/json/889.json','["深院靜，小庭空，斷續寒砧斷續風。無奈夜長人不寐，", "雲鬢亂，晚妝殘，帶恨眉兒遠岫攢。斜托香腮春筍懶，"]'),
('yuding-12','相見歡','李煜','唐','御定全唐诗','yuding','','[]','林花謝了春紅，太匆匆。無奈朝來寒雨，晚來風。',90,'御定全唐詩/json/889.json','["林花謝了春紅，太匆匆。無奈朝來寒雨，晚來風。", "胭脂淚，相留醉，幾時重。自是人生長恨，水長東。", "無言獨上西樓，月如鉤。寂寞梧桐深院，鎖清秋。", "剪不斷，理還亂，是離愁。別是一般滋味，在心頭。"]'),
('yuding-13','長相思','李煜','唐','御定全唐诗','yuding','','[]','一重山，兩重山。山遠天高煙水寒，相思楓葉丹。',88,'御定全唐詩/json/889.json','["一重山，兩重山。山遠天高煙水寒，相思楓葉丹。", "菊花開，菊花殘。塞雁高飛人未還，一簾風月閑。", "雲一渦，玉一梭。澹澹衫兒薄薄羅，輕顰雙黛螺。", "秋風多，雨如和。簾外芭蕉三兩窠，夜長人奈何。"]'),
('yuding-14','浣溪沙','李煜','唐','御定全唐诗','yuding','','[]','紅日已高三丈透，金爐次第添香獸，紅錦地衣隨步皺。',96,'御定全唐詩/json/889.json','["紅日已高三丈透，金爐次第添香獸，紅錦地衣隨步皺。", "佳人舞點金釵溜，酒惡時拈花蕊嗅，別殿遙聞簫鼓奏。", "轉燭飄蓬一夢歸，欲尋陳跡悵人非，天教心願與身違。", "待月池台空逝水，蔭花樓閣漫斜暉，登臨不惜更沾衣。"]'),
('yuding-15','采桑子','李煜','唐','御定全唐诗','yuding','','[]','轆轤金井梧桐晚，幾樹驚秋。晝雨如愁，百尺蝦須上玉鉤。',104,'御定全唐詩/json/889.json','["轆轤金井梧桐晚，幾樹驚秋。晝雨如愁，百尺蝦須上玉鉤。", "瓊窗春斷雙蛾皺，回首邊頭。欲寄鱗游，九曲寒波不溯流。", "亭前春逐紅英盡，舞態徘徊。細雨霏微，不放雙眉時暫開。", "綠窗冷靜芳音斷，香印成灰。可奈情懷，欲睡朦朧入夢來。"]'),
('yuding-16','菩薩蠻','李煜','唐','御定全唐诗','yuding','','[]','花明月暗籠輕霧，今宵好向郎邊去。剗襪步香階，',184,'御定全唐詩/json/889.json','["花明月暗籠輕霧，今宵好向郎邊去。剗襪步香階，", "畫堂南畔見，一晌偎人顫。好為出來難，教君恣意憐。", "蓬萊院閉天臺女，畫堂晝寢無人語。拋枕翠雲光，", "潛來珠鎖動，驚覺鴛鴦夢。慢臉笑盈盈，相看無限情。", "銅簧韻脆鏘寒竹，新聲慢奏移纖玉。眼色暗相鉤，", "雨雲深繡戶，來便諧衷素。宴罷又成空，夢迷春睡中。", "人生愁恨何能免，消魂獨我情何限。故國夢重歸，", "高樓誰與上，長記秋晴望。往事已成空，還如一夢中。"]'),
('yuding-17','清平樂','李煜','唐','御定全唐诗','yuding','','[]','別來春半，觸目愁腸斷。砌下落梅如雪亂，拂了一身還滿。',47,'御定全唐詩/json/889.json','["別來春半，觸目愁腸斷。砌下落梅如雪亂，拂了一身還滿。", "雁來音信無憑，路遙歸夢難成。離恨卻如春草，"]'),
('yuding-18','喜遷鶯','李煜','唐','御定全唐诗','yuding','','[]','曉月墜，宿雲微，無語枕頻欹。夢回芳草思依依，',45,'御定全唐詩/json/889.json','["曉月墜，宿雲微，無語枕頻欹。夢回芳草思依依，", "啼鶯散，餘花亂，寂寞畫堂深院。片紅休掃盡從伊，"]'),
('yuding-19','阮郎歸','李煜','唐','御定全唐诗','yuding','','[]','東風吹水日銜山，春來長是閑。落花狼藉酒闌珊，',44,'御定全唐詩/json/889.json','["東風吹水日銜山，春來長是閑。落花狼藉酒闌珊，", "春睡覺，晚妝殘，無人整翠鬟。留連光景惜朱顏，"]'),
('yuding-20','錦堂春','李煜','唐','御定全唐诗','yuding','','[]','昨夜風兼雨，簾幃颯颯秋聲。燭殘漏滴頻欹枕，',43,'御定全唐詩/json/889.json','["昨夜風兼雨，簾幃颯颯秋聲。燭殘漏滴頻欹枕，", "世事漫隨流水，算來一夢浮生。醉鄉路穩宜頻到，"]'),
('yuding-21','應天長','李煜','唐','御定全唐诗','yuding','','[]','一鉤初月臨妝鏡，蟬鬢鳳釵慵不整。重簾靜，層樓迥，',50,'御定全唐詩/json/889.json','["一鉤初月臨妝鏡，蟬鬢鳳釵慵不整。重簾靜，層樓迥，", "柳堤芳草徑，夢斷轆轤金井。昨夜更闌酒醒，春愁過卻病。"]'),
('yuding-22','望遠行','李煜','唐','御定全唐诗','yuding','','[]','碧砌花光照眼明，朱扉長日鎮長扃。餘寒欲去夢難成，',48,'御定全唐詩/json/889.json','["碧砌花光照眼明，朱扉長日鎮長扃。餘寒欲去夢難成，", "遼陽月，秣陵砧，不傳消息但傳情。黃金台下忽然驚，"]'),
('yuding-23','浪淘沙','李煜','唐','御定全唐诗','yuding','','[]','簾外雨潺潺，春意闌珊。羅衾不耐五更寒。',128,'御定全唐詩/json/889.json','["簾外雨潺潺，春意闌珊。羅衾不耐五更寒。", "夢裏不知身是客，一晌貪歡。", "獨自暮憑闌，無限江山。別時容易見時難。", "流水落花春去也，天上人間。", "往事只堪哀，對景難排。秋風庭院蘚侵階。", "一桁珠簾閑不卷，終日誰來。", "金劍已沈埋，壯氣蒿萊。晚涼天淨月華開。", "想得玉樓瑤殿影，空照秦淮。"]'),
('yuding-24','木蘭花','李煜','唐','御定全唐诗','yuding','','[]','曉妝初了明肌雪，春殿嬪娥魚貫列。鳳簫聲斷水雲閑，',48,'御定全唐詩/json/889.json','["曉妝初了明肌雪，春殿嬪娥魚貫列。鳳簫聲斷水雲閑，", "臨風誰更飄香屑，醉拍闌幹情未切。歸時休放燭花紅，"]'),
('yuding-25','虞美人','李煜','唐','御定全唐诗','yuding','','[]','風回小院庭蕪綠，柳眼春相續。憑闌半日獨無言，',88,'御定全唐詩/json/889.json','["風回小院庭蕪綠，柳眼春相續。憑闌半日獨無言，", "笙歌未散尊罍在，池面冰初解。燭明香暗畫樓深，", "春花秋月何時了，往事知多少。小樓昨夜又東風，", "雕闌玉砌應猶在，只是朱顏改。問君能有幾多愁，"]'),
('yuding-26','一斛珠','李煜','唐','御定全唐诗','yuding','','[]','晚妝初過，沈檀輕注些兒個。向人微露丁香顆。',67,'御定全唐詩/json/889.json','["晚妝初過，沈檀輕注些兒個。向人微露丁香顆。", "一曲清歌，暫引櫻桃破。", "羅袖裛殘殷色可，杯深旋被香醪涴。", "繡床斜憑嬌無那。爛嚼紅茸，笑向檀郎唾。"]'),
('yuding-27','臨江仙','李煜','唐','御定全唐诗','yuding','','[]','櫻桃落盡春歸去，蝶翻輕粉雙飛。子規啼月小樓西。',68,'御定全唐詩/json/889.json','["櫻桃落盡春歸去，蝶翻輕粉雙飛。子規啼月小樓西。", "玉鉤羅幕，惆悵暮煙垂。", "別巷寂寥人散後，望殘煙草低迷。爐香閑嫋鳳凰兒。", "空持羅帶，回首恨依依。"]'),
('yuding-28','蝶戀花','李煜','唐','御定全唐诗','yuding','','[]','（一名一籮金、黃金縷、明月生南浦、鳳棲梧、',104,'御定全唐詩/json/889.json','["（一名一籮金、黃金縷、明月生南浦、鳳棲梧、", "鵲蹋枝、卷珠簾、魚水同歡）", "遙夜亭皋閑信步。才過清明，漸覺傷春暮。", "數點雨聲風約住，朦朧澹月雲來去。", "桃李依依香暗度。誰在秋千，笑裏輕輕語。", "一片芳心千萬緒，人間沒個安排處。"]'),
('yuding-29','破陣子','李煜','唐','御定全唐诗','yuding','','[]','四十年來家國，三千里地山河。鳳闕龍樓連霄漢，',44,'御定全唐詩/json/889.json','["四十年來家國，三千里地山河。鳳闕龍樓連霄漢，", "一旦歸為臣虜，沈腰潘鬢銷磨。最是蒼黃辭廟日，"]'),
('yuding-30','醉妝詞','王衍','唐','御定全唐诗','yuding','','[]','者邊走，那邊走，只是尋花柳。那邊走，者邊走，',22,'御定全唐詩/json/889.json','["者邊走，那邊走，只是尋花柳。那邊走，者邊走，"]'),
('yuding-31','甘州曲','王衍','唐','御定全唐诗','yuding','','[]','畫羅裙，能解束，稱腰身。柳眉桃臉不勝春。',34,'御定全唐詩/json/889.json','["畫羅裙，能解束，稱腰身。柳眉桃臉不勝春。", "薄媚足精神，可惜淪落在風塵。"]'),
('yuding-32','木蘭花','孟昶','唐','御定全唐诗','yuding','','[]','冰肌玉骨清無汗，水殿風來暗香滿。繡簾一點月窺人，',48,'御定全唐詩/json/889.json','["冰肌玉骨清無汗，水殿風來暗香滿。繡簾一點月窺人，", "起來瓊戶啟無聲，時見疏星渡河漢。屈指西風幾時來，"]'),
('yuding-0','回波樂','李景伯','唐','御定全唐诗','yuding','','[]','回波爾時酒卮，微臣職在箴規。侍宴既過三爵，',21,'御定全唐詩/json/890.json','["回波爾時酒卮，微臣職在箴規。侍宴既過三爵，"]'),
('yuding-1','回波樂','沈佺期','唐','御定全唐诗','yuding','','[]','回波爾時佺期，流向嶺外生歸。身名已蒙齒錄，',21,'御定全唐詩/json/890.json','["回波爾時佺期，流向嶺外生歸。身名已蒙齒錄，"]'),
('yuding-2','回波樂','裴談','唐','御定全唐诗','yuding','','[]','回波爾時栲栳，怕婦也是大好。外邊只有裴談，',21,'御定全唐詩/json/890.json','["回波爾時栲栳，怕婦也是大好。外邊只有裴談，"]'),
('yuding-3','舞馬詞','張說','唐','御定全唐诗','yuding','','[]','萬玉朝宗鳳扆，千金率領龍媒。眄鼓凝驕蹀躞，',126,'御定全唐詩/json/890.json','["萬玉朝宗鳳扆，千金率領龍媒。眄鼓凝驕蹀躞，", "天鹿遙征衛叔，日龍上借羲和。將共兩驂爭舞，", "彩旄八佾成行，時龍五色因方。屈膝銜杯赴節，", "帝皂龍駒沛艾，星闌驥子權奇。騰倚驤洋應節，", "二聖先天合德，群靈率土可封。擊石驂驔紫燕，", "聖君出震應籙，神馬浮河獻圖。足蹋天庭鼓舞，"]'),
('yuding-4','蹋歌詞','崔液','唐','御定全唐诗','yuding','','[]','彩女迎金屋，仙姬出畫堂。鴛鴦裁錦袖，翡翠貼花黃。',72,'御定全唐詩/json/890.json','["彩女迎金屋，仙姬出畫堂。鴛鴦裁錦袖，翡翠貼花黃。", "歌響舞分行，豔色動流光。", "庭際花微落，樓前漢已橫。金壺催夜盡，羅袖舞寒輕。", "樂笑暢歡情，未半著天明。"]'),
('yuding-5','桂殿秋','李白','唐','御定全唐诗','yuding','','[]','仙女下，董雙成，漢殿夜涼吹玉笙。曲終卻從仙官去，',48,'御定全唐詩/json/890.json','["仙女下，董雙成，漢殿夜涼吹玉笙。曲終卻從仙官去，", "河漢女，玉煉顏，雲輧往往在人間。九霄有路去無跡，"]'),
('yuding-6','清平調','李白','唐','御定全唐诗','yuding','','[]','雲想衣裳花想容，春風拂檻露華濃。若非群玉山頭見，',72,'御定全唐詩/json/890.json','["雲想衣裳花想容，春風拂檻露華濃。若非群玉山頭見，", "一枝紅豔露凝香，雲雨巫山枉斷腸。借問漢宮誰得似，", "名花傾國兩相歡，常得君王帶笑看。解得春風無限恨，"]'),
('yuding-7','連理枝','李白','唐','御定全唐诗','yuding','','[]','雪蓋宮樓閉，羅幕昏金翠。鬥壓闌幹，香心澹薄，',44,'御定全唐詩/json/890.json','["雪蓋宮樓閉，羅幕昏金翠。鬥壓闌幹，香心澹薄，", "淺畫雲垂帔，點滴昭陽淚。咫尺宸居，君恩斷絕，"]'),
('yuding-8','菩薩蠻','李白','唐','御定全唐诗','yuding','','[]','平林漠漠煙如織，寒山一帶傷心碧。暝色入高樓，',46,'御定全唐詩/json/890.json','["平林漠漠煙如織，寒山一帶傷心碧。暝色入高樓，", "玉階空佇立，宿鳥歸飛急。何處是歸程，長亭更短亭。"]'),
('yuding-9','憶秦娥','李白','唐','御定全唐诗','yuding','','[]','簫聲咽，秦娥夢斷秦樓月。秦樓月，年年柳色，灞陵傷別。',46,'御定全唐詩/json/890.json','["簫聲咽，秦娥夢斷秦樓月。秦樓月，年年柳色，灞陵傷別。", "樂游原上清秋節，咸陽古道音塵絕。音塵絕，"]'),
('yuding-10','清平樂','李白','唐','御定全唐诗','yuding','','[]','禁庭春晝，鶯羽披新繡。百草巧求花下鬥，只賭珠璣滿鬥。',235,'御定全唐詩/json/890.json','["禁庭春晝，鶯羽披新繡。百草巧求花下鬥，只賭珠璣滿鬥。", "日晚卻理殘妝，御前閑舞霓裳。誰道腰肢窈窕，", "禁闈秋夜，月探金窗罅。玉帳鴛鴦噴蘭麝，時落銀燈香灺。", "女伴莫話孤眠，六宮羅綺三千。一笑皆生百媚，", "煙深水闊，音信無由達。惟有碧天雲外月，偏照懸懸離別。", "盡日感事傷懷，愁眉似鎖難開。夜夜長留半被，", "鸞衾鳳褥，夜夜常孤宿。更被銀台紅蠟燭，學妾淚珠相續。", "花貌些子時光，拋人遠泛瀟湘。欹枕悔聽寒漏，", "畫堂晨起，來報雪花墜。高捲簾櫳看佳瑞，皓色遠迷庭砌。", "盛氣光引爐煙，素草寒生玉佩。應是天仙狂醉，"]'),
('yuding-11','欸乃曲','元結','唐','御定全唐诗','yuding','','[]','偶存名跡在人間，順俗與時未安閒。來謁大官兼問政，',120,'御定全唐詩/json/890.json','["偶存名跡在人間，順俗與時未安閒。來謁大官兼問政，", "湘江二月春水準，滿月和風宜夜行。唱橈欲過平陽戍，", "千里楓林煙雨深，無朝無暮有猿吟。倚橈靜聽曲中意，", "零陵郡北湘水東，浯溪形勝滿湘中。溪口石顛堪自逸，", "下瀧船似入深淵，上瀧船似欲升天。瀧南始到九疑郡，"]'),
('yuding-12','漁父','張志和','唐','御定全唐诗','yuding','','[]','西塞山前白鷺飛，桃花流水鱖魚肥。青箬笠，綠蓑衣，',120,'御定全唐詩/json/890.json','["西塞山前白鷺飛，桃花流水鱖魚肥。青箬笠，綠蓑衣，", "釣台漁父褐為裘，兩兩三三舴艋舟。能縱棹，慣乘流，", "霅溪灣裏釣魚翁，舴艋為家西複東。江上雪，浦邊風，", "松江蟹舍主人歡，菰飯蓴羹亦共餐。楓葉落，荻花幹，", "青草湖中月正圓，巴陵漁父棹歌連。釣車子，橛頭船，"]'),
('yuding-13','漁父','張松齡','唐','御定全唐诗','yuding','','[]','樂是風波釣是閑，草堂松檜已勝攀。太湖水，洞庭山，',24,'御定全唐詩/json/890.json','["樂是風波釣是閑，草堂松檜已勝攀。太湖水，洞庭山，"]'),
('yuding-14','章台柳','韓翃','唐','御定全唐诗','yuding','','[]','章台柳，章台柳，往日依依今在否？縱使長條似舊垂，',24,'御定全唐詩/json/890.json','["章台柳，章台柳，往日依依今在否？縱使長條似舊垂，"]'),
('yuding-15','三台','韋應物','唐','御定全唐诗','yuding','','[]','一年一年老去，明日後日花開。未報長安平定，',42,'御定全唐詩/json/890.json','["一年一年老去，明日後日花開。未報長安平定，", "冰泮寒塘水綠，雨餘百草皆生。朝來衡門無事，"]'),
('yuding-16','調笑令','韋應物','唐','御定全唐诗','yuding','','[]','胡馬，胡馬，遠放燕支山下。跑沙跑雪獨嘶，',40,'御定全唐詩/json/890.json','["胡馬，胡馬，遠放燕支山下。跑沙跑雪獨嘶，", "河漢，河漢，曉掛秋城漫漫。愁人起望相思，"]'),
('yuding-17','三台','王建','唐','御定全唐诗','yuding','','[]','魚藻池邊射鴨，芙蓉苑裏看花。日色柘袍相似，',126,'御定全唐詩/json/890.json','["魚藻池邊射鴨，芙蓉苑裏看花。日色柘袍相似，", "池北池南草綠，殿前殿后花紅。天子千秋萬歲，", "揚州橋邊小婦，長幹市里商人。三年不得消息，", "青草湖邊草色，飛猿嶺上猿聲。萬里三湘客到，", "樹頭花落花開，道上人去人來。朝愁暮愁即老，", "鬥身強健且為，頭白齒落難追。准擬百年千歲，"]'),
('yuding-18','調笑令','王建','唐','御定全唐诗','yuding','','[]','團扇，團扇，美人並來遮面。玉顏憔悴三年，',80,'御定全唐詩/json/890.json','["團扇，團扇，美人並來遮面。玉顏憔悴三年，", "蝴蝶，蝴蝶，飛上金枝玉葉。君前對舞春風，", "羅袖，羅袖，暗舞春風依舊。遙看歌舞玉樓，", "楊柳，楊柳，日暮白沙渡口。船頭江水茫茫，"]'),
('yuding-19','調笑令','戴叔倫','唐','御定全唐诗','yuding','','[]','邊草，邊草，邊草盡來兵老。山南山北雪晴，',20,'御定全唐詩/json/890.json','["邊草，邊草，邊草盡來兵老。山南山北雪晴，"]'),
('yuding-20','紇那曲','劉禹錫','唐','御定全唐诗','yuding','','[]','楊柳鬱青青，竹枝無限情。同郎一回顧，聽唱紇那聲。',48,'御定全唐詩/json/890.json','["楊柳鬱青青，竹枝無限情。同郎一回顧，聽唱紇那聲。", "蹋曲興無窮，調同辭不同。願郎千萬壽，長作主人翁。"]'),
('yuding-21','憶江南','劉禹錫','唐','御定全唐诗','yuding','','[]','春去也，多謝洛城人。弱柳從風疑舉袂，',36,'御定全唐詩/json/890.json','["春去也，多謝洛城人。弱柳從風疑舉袂，", "春去也。共惜豔陽年。猶有桃花流水上，"]'),
('yuding-22','瀟湘神','劉禹錫','唐','御定全唐诗','yuding','','[]','湘水流，湘水流，九疑雲物至今愁。若問二妃何處所，',48,'御定全唐詩/json/890.json','["湘水流，湘水流，九疑雲物至今愁。若問二妃何處所，", "斑竹枝，斑竹枝，淚痕點點寄相思。楚客欲聽瑤瑟怨，"]'),
('yuding-23','拋球樂','劉禹錫','唐','御定全唐诗','yuding','','[]','五色繡團圓，登君玳瑁筵。最宜紅燭下，偏稱落花前。',72,'御定全唐詩/json/890.json','["五色繡團圓，登君玳瑁筵。最宜紅燭下，偏稱落花前。", "上客如先起，應須贈一船。", "春早見花枝，朝朝恨發遲。及看花落後，卻憶未開時。", "幸有拋球樂，一杯君莫辭。"]'),
('yuding-24','花非花','白居易','唐','御定全唐诗','yuding','','[]','花非花，霧非霧。夜半來，天明去。來如春夢不多時，',24,'御定全唐詩/json/890.json','["花非花，霧非霧。夜半來，天明去。來如春夢不多時，"]'),
('yuding-25','憶江南','白居易','唐','御定全唐诗','yuding','','[]','江南好，風景舊曾諳。日出江花紅勝火，',54,'御定全唐詩/json/890.json','["江南好，風景舊曾諳。日出江花紅勝火，", "江南憶，最憶是杭州。山寺月中尋桂子，", "江南憶，其次憶吳宮。吳酒一杯春竹葉，"]'),
('yuding-26','如夢令','白居易','唐','御定全唐诗','yuding','','[]','前度小花靜院，不比尋常時見。見了又還休，',61,'御定全唐詩/json/890.json','["前度小花靜院，不比尋常時見。見了又還休，", "落月西窗驚起，好個匆匆些子。鬒鬢嚲輕鬆，", "頻日雅歡幽會，打得來來越z4。說著暫分飛，"]'),
('yuding-27','長相思','白居易','唐','御定全唐诗','yuding','','[]','汴水流，泗水流。流到瓜洲古渡頭，吳山點點愁。',88,'御定全唐詩/json/890.json','["汴水流，泗水流。流到瓜洲古渡頭，吳山點點愁。", "思悠悠，恨悠悠。恨到歸時方始休，月明人倚樓。", "深畫眉，淺畫眉。蟬鬢鬅鬙雲滿衣，陽臺行雨回。", "巫山高，巫山低。暮雨瀟瀟郎不歸，空房獨守時。"]'),
('yuding-28','謫仙怨','劉長卿','唐','御定全唐诗','yuding','','[]','晴川落日初低，惆悵孤舟解攜。鳥向平蕪遠近，',42,'御定全唐詩/json/890.json','["晴川落日初低，惆悵孤舟解攜。鳥向平蕪遠近，", "白雲千里萬里，明月前溪後溪。獨恨長沙謫去，"]'),
('yuding-29','廣謫仙怨','竇弘餘','唐','御定全唐诗','yuding','','[]','胡塵犯闕沖關，金輅提攜玉顏。雲雨此時蕭散，',42,'御定全唐詩/json/890.json','["胡塵犯闕沖關，金輅提攜玉顏。雲雨此時蕭散，", "傷心朝恨暮恨，回首千山萬山。獨望天邊初月，"]'),
('yuding-30','廣謫仙怨','康駢','唐','御定全唐诗','yuding','','[]','晴山礙目橫天，綠疊君王馬前。鑾輅西巡蜀國，',42,'御定全唐詩/json/890.json','["晴山礙目橫天，綠疊君王馬前。鑾輅西巡蜀國，", "曲江魂斷芳草，妃子愁凝暮煙。長笛此時吹罷，"]'),
('yuding-0','八六子','杜牧','唐','御定全唐诗','yuding','','[]','洞房深，畫屏燈照，山色凝翠沉沉。聽夜雨，冷滴芭蕉，',67,'御定全唐詩/json/891.json','["洞房深，畫屏燈照，山色凝翠沉沉。聽夜雨，冷滴芭蕉，", "鳳帳蕭疏，椒殿閑扃。", "輦路苔侵，繡簾垂，遲遲漏傳丹禁。蕣華偷悴，", "正消魂，梧桐又移翠陰。"]'),
('yuding-1','憶江南','崔懷寶','唐','御定全唐诗','yuding','','[]','平生願，願作樂中箏。得近玉人纖手子，',18,'御定全唐詩/json/891.json','["平生願，願作樂中箏。得近玉人纖手子，"]'),
('yuding-2','閑中好','鄭符','唐','御定全唐诗','yuding','','[]','閑中好，盡日松為侶。此趣人不知，輕風度僧語。',22,'御定全唐詩/json/891.json','["閑中好，盡日松為侶。此趣人不知，輕風度僧語。"]'),
('yuding-3','閑中好','段成式','唐','御定全唐诗','yuding','','[]','閑中好，塵務不縈心。坐對當窗木，看移三面陰。',22,'御定全唐詩/json/891.json','["閑中好，塵務不縈心。坐對當窗木，看移三面陰。"]'),
('yuding-4','閑中好','張希複','唐','御定全唐诗','yuding','','[]','閑中好，幽磬度聲遲。卷上論題肇，畫中僧姓支。',22,'御定全唐詩/json/891.json','["閑中好，幽磬度聲遲。卷上論題肇，畫中僧姓支。"]'),
('yuding-5','南歌子','溫庭筠','唐','御定全唐诗','yuding','','[]','手裏金鸚鵡，胸前繡鳳凰。偷眼暗形相，不如從嫁與，',168,'御定全唐詩/json/891.json','["手裏金鸚鵡，胸前繡鳳凰。偷眼暗形相，不如從嫁與，", "似帶如絲柳，團酥握雪花。簾卷玉鉤斜，九衢塵欲暮，", "倭墮低梳髻，連娟細掃眉。終日兩相思，為君憔悴盡，", "臉上金霞細，眉間翠鈿深。欹枕覆鴛衾，隔簾鶯百轉，", "撲蕊添黃子，呵花滿翠鬟。鴛枕映屏山，月明三五夜，", "轉盼如波眼，娉婷似柳腰。花裏暗相招，憶君腸欲斷，", "懶拂鴛鴦枕，休縫翡翠裙。羅帳罷爐熏，近來心更切，"]'),
('yuding-6','荷葉杯','溫庭筠','唐','御定全唐诗','yuding','','[]','一點露珠凝冷，波影，滿池塘。綠莖紅豔兩相亂，腸斷，',75,'御定全唐詩/json/891.json','["一點露珠凝冷，波影，滿池塘。綠莖紅豔兩相亂，腸斷，", "鏡水夜來秋月，如雪，採蓮時。小娘紅粉對寒浪，惆悵，", "楚女欲歸南浦，朝雨，濕愁紅。小船搖漾入花裏，波起，"]'),
('yuding-7','憶江南','溫庭筠','唐','御定全唐诗','yuding','','[]','千萬恨，恨極在天涯。山月不知心裏事，',36,'御定全唐詩/json/891.json','["千萬恨，恨極在天涯。山月不知心裏事，", "梳洗罷，獨倚望江樓。過盡千帆皆不是，"]'),
('yuding-8','蕃女怨','溫庭筠','唐','御定全唐诗','yuding','','[]','萬枝香雪開已遍，細雨雙燕。鈿蟬箏，金雀扇，',42,'御定全唐詩/json/891.json','["萬枝香雪開已遍，細雨雙燕。鈿蟬箏，金雀扇，", "磧南沙上驚雁起，飛雪千里。玉連環，金鏃箭，"]'),
('yuding-9','遐方怨','溫庭筠','唐','御定全唐诗','yuding','','[]','憑繡檻，解羅幃。未得君書，斷腸瀟湘春雁飛，',42,'御定全唐詩/json/891.json','["憑繡檻，解羅幃。未得君書，斷腸瀟湘春雁飛，", "花半拆，雨初晴。未卷珠簾，夢殘惆悵聞曉鶯，"]'),
('yuding-10','訴衷情','溫庭筠','唐','御定全唐诗','yuding','','[]','鶯語，花舞，春晝午，雨霏微。金帶枕，宮錦，鳳凰帷。',44,'御定全唐詩/json/891.json','["鶯語，花舞，春晝午，雨霏微。金帶枕，宮錦，鳳凰帷。", "柳弱燕交飛，依依。遼陽音信稀，夢中歸。"]'),
('yuding-11','定西番','溫庭筠','唐','御定全唐诗','yuding','','[]','漢使昔年離別，攀弱柳，折寒梅，上高臺。',129,'御定全唐詩/json/891.json','["漢使昔年離別，攀弱柳，折寒梅，上高臺。", "千里玉關春雪，雁來人不來。羌笛一聲愁絕，月裴回。", "海燕欲飛調羽，萱草綠，杏花紅，隔簾櫳。", "雙鬢翠霞金縷，一枝春豔濃。樓上月明三五，瑣窗中。", "細雨曉鶯春晚，人似玉，柳如眉，正相思。", "羅幕翠簾初卷，鏡中花一枝。腸斷塞門消息，雁來稀。"]'),
('yuding-12','思帝鄉','溫庭筠','唐','御定全唐诗','yuding','','[]','花花，滿枝紅似霞。羅袖畫簾腸斷，卓香車。',44,'御定全唐詩/json/891.json','["花花，滿枝紅似霞。羅袖畫簾腸斷，卓香車。", "回面共人閑語，戰篦金鳳斜。惟有阮郎春盡，不歸家。"]'),
('yuding-13','酒泉子','溫庭筠','唐','御定全唐诗','yuding','','[]','花映柳條，閑向綠萍池上。憑欄幹，窺細浪，雨蕭蕭。',197,'御定全唐詩/json/891.json','["花映柳條，閑向綠萍池上。憑欄幹，窺細浪，雨蕭蕭。", "近來音信兩疏索，洞房空寂寞。掩銀屏，垂翠箔，度春宵。", "日映紗窗，金鴨小屏山碧。故鄉春，煙靄隔，背蘭釭。", "宿妝惆悵倚高閣，千里雲影薄。草初齊，花又落，燕雙飛。", "楚女不歸，樓枕小河春水。月孤明，風又起，杏花稀。", "玉釵斜篸雲鬟重，裙上金縷鳳。八行書，千里夢，雁南飛。", "羅帶惹香，猶系別時紅豆。淚痕新，金縷舊，斷離腸。", "一雙嬌燕語雕梁，還是去年時節。綠楊濃，芳草歇，"]'),
('yuding-14','玉蝴蝶','溫庭筠','唐','御定全唐诗','yuding','','[]','秋風淒切傷離，行客未歸時。塞外草先衰，江南雁到遲。',49,'御定全唐詩/json/891.json','["秋風淒切傷離，行客未歸時。塞外草先衰，江南雁到遲。", "芙蓉凋嫩臉，楊柳墮新眉。搖落使人悲，斷腸誰得知。"]'),
('yuding-15','女冠子','溫庭筠','唐','御定全唐诗','yuding','','[]','含嬌含笑，宿翠殘紅窈窕。鬢如蟬，寒玉簪秋水，',88,'御定全唐詩/json/891.json','["含嬌含笑，宿翠殘紅窈窕。鬢如蟬，寒玉簪秋水，", "雪胸鸞鏡裏，琪樹鳳樓前。寄語青娥伴，早求仙。", "霞帔雲發，鈿鏡仙容似雪。畫愁眉，遮語回輕扇，", "玉樓相望久，花洞恨來遲。早晚乘鸞去，莫相遺。"]'),
('yuding-16','歸國遙','溫庭筠','唐','御定全唐诗','yuding','','[]','香玉，翠鳳寶釵垂s4zy。鈿筐交勝金粟，越羅春水綠。',102,'御定全唐詩/json/891.json','["香玉，翠鳳寶釵垂s4zy。鈿筐交勝金粟，越羅春水綠。", "畫堂照簾殘燭，夢餘更漏促。謝娘無限心曲，曉屏山斷續。", "雙臉，小鳳戰篦金颭豔。舞衣無力風斂，藕絲秋色染。", "錦帳繡幃斜掩，露珠清曉簟。粉心黃蕊花靨，黛眉山兩點。"]'),
('yuding-17','菩薩蠻','溫庭筠','唐','御定全唐诗','yuding','','[]','小山重疊金明滅，鬢雲欲度香腮雪。懶起畫蛾眉，',552,'御定全唐詩/json/891.json','["小山重疊金明滅，鬢雲欲度香腮雪。懶起畫蛾眉，", "照花前後鏡，花面交相映。新帖繡羅襦，雙雙金鷓鴣。", "水精簾裏頗黎枕，暖香惹夢鴛鴦錦。江上柳如煙，", "藕絲秋色淺，人勝參差剪。雙鬢隔香紅，玉釵頭上風。", "蕊黃無限當山額，宿妝隱笑紗窗隔。相見牡丹時，", "翠釵金作股，釵上蝶雙舞。心事竟誰知，月明花滿枝。", "翠翹金縷雙鸂鶒，水文細起春池碧。池上海棠梨，", "繡衫遮笑靨，煙草黏飛蝶。青瑣對芳菲，玉關音信稀。", "杏花含露團香雪，綠楊陌上多離別。燈在月朧明，", "玉鉤褰翠幕，妝淺舊眉薄。春夢正關情，鏡中蟬鬢輕。", "玉樓明月長相憶，柳絲嫋娜春無力。門外草萋萋，", "畫羅金翡翠，香燭銷成淚。花落子規啼，綠窗殘夢迷。", "鳳凰相對盤金縷，牡丹一夜經微雨。明鏡照新妝，", "畫樓相望久，闌外垂絲柳。音信不歸來，社前雙燕回。", "牡丹花謝鶯聲歇，綠楊滿院中庭月。相憶夢難成，", "翠鈿金壓臉，寂寞香閨掩。人遠淚闌幹，燕飛春又殘。", "滿宮明月梨花白，故人萬里關山隔。金雁一雙飛，", "小園芳草綠，家住越溪曲。楊柳色依依，燕歸君不歸。", "寶函鈿雀金鸂鶒，沈香閣上吳山碧。楊柳又如絲，", "畫樓音信斷，芳草江南岸。鸞鏡與花枝，此情誰得知。", "南園滿地堆輕絮，愁聞一霎清明雨。雨後卻斜陽，", "無言勻睡臉，枕上屏山掩。時節欲黃昏，無憀獨倚門。", "夜來皓月才當午，重簾悄悄無人語。深處麝煙長，", "當年還自惜，往事那堪憶。花露月明殘，錦衾知曉寒。"]'),
('yuding-18','清平樂','溫庭筠','唐','御定全唐诗','yuding','','[]','上陽春晚，宮女愁蛾淺。新歲清平思同輦，爭奈長安路遠。',94,'御定全唐詩/json/891.json','["上陽春晚，宮女愁蛾淺。新歲清平思同輦，爭奈長安路遠。", "鳳帳鴛被徒熏，寂寞花鎖千門。競把黃金買賦，", "洛陽愁絕，楊柳花飄雪。終日行人爭攀折，橋下水流嗚咽。", "上馬爭勸離觴，南浦鶯聲斷腸。愁殺平原年少，"]'),
('yuding-19','更漏子','溫庭筠','唐','御定全唐诗','yuding','','[]','柳絲長，春雨細，花外漏聲迢遞。驚塞雁，起城烏，',276,'御定全唐詩/json/891.json','["柳絲長，春雨細，花外漏聲迢遞。驚塞雁，起城烏，", "香霧薄，透簾幕，惆悵謝家池閣。紅燭背，繡簾垂，", "星斗稀，鐘鼓歇，簾外曉鶯殘月。蘭露重，柳風斜，", "虛閣上，倚闌望，還似去年惆悵。春欲暮，思無窮，", "金雀釵，紅粉面，花裏暫時相見。知我意，感君憐，", "香作穗，蠟成淚，還似兩人心意。山枕膩，錦衾寒，", "相見稀，相憶久，眉淺淡煙如柳。垂翠幕，結同心，", "城上月，白如雪，蟬鬢美人愁絕。宮樹暗，鵲橋橫，", "背江樓，臨海月，城上角聲嗚咽。堤柳動，島煙昏，", "京口路，歸帆渡，正是芳菲欲度。銀燭盡，玉繩低，", "玉爐香，紅蠟淚，偏照畫堂秋思。眉翠薄，鬢雲殘，", "梧桐樹，三更雨，不道離情正苦。一葉葉，一聲聲，"]'),
('yuding-20','河瀆神','溫庭筠','唐','御定全唐诗','yuding','','[]','河上望叢祠，廟前春雨來時。楚山無限鳥飛遲，',129,'御定全唐詩/json/891.json','["河上望叢祠，廟前春雨來時。楚山無限鳥飛遲，", "何處杜鵑啼不歇，豔紅開盡如血。蟬鬢美人愁絕，", "孤廟對寒潮，西陵風雨瀟瀟。謝娘惆悵倚蘭橈，", "暮天愁聽思歸樂，早梅香滿山郭。回首兩情蕭索，", "銅鼓賽神來，滿庭幡蓋裴回。水村江浦過風雷，", "離別櫓聲空蕭索，玉容惆悵妝薄。青麥燕飛落落，"]'),
('yuding-21','河傳','溫庭筠','唐','御定全唐诗','yuding','','[]','江畔，相喚。曉妝鮮，仙景個女採蓮。請君莫向那岸邊。',168,'御定全唐詩/json/891.json','["江畔，相喚。曉妝鮮，仙景個女採蓮。請君莫向那岸邊。", "少年，好花新滿船。", "紅袖搖曳逐風軟，垂玉腕。腸向柳絲斷。浦南歸，", "湖上，閑望。雨蕭蕭，煙浦花橋路遙。謝娘翠蛾愁不銷。", "終朝，夢魂迷晚潮。", "蕩子天涯歸棹遠，春已晚。鶯語空腸斷。若耶溪，", "同伴，相喚。杏花稀，夢裏每愁依違。仙客一去燕已飛。", "不歸，淚痕空滿衣。", "天際雲鳥引情遠，春已晚。煙靄渡南苑。雪梅香，"]'),
('yuding-22','木蘭花','溫庭筠','唐','御定全唐诗','yuding','','[]','家臨長信往來道，乳燕雙雙拂煙草。油壁車輕金犢肥，',48,'御定全唐詩/json/891.json','["家臨長信往來道，乳燕雙雙拂煙草。油壁車輕金犢肥，", "籠中嬌鳥暖猶睡，簾外落花閑不掃。衰桃一樹近前池，"]'),
('yuding-23','竹枝','皇甫松','唐','御定全唐诗','yuding','','[]','檳榔花發鷓鴣啼，雄飛煙瘴雌亦飛。',96,'御定全唐詩/json/891.json','["檳榔花發鷓鴣啼，雄飛煙瘴雌亦飛。", "木棉花盡荔支垂，千花萬花待郎歸。", "芙蓉並蒂一心連，花侵槅子眼應穿。", "筵中蠟燭淚珠紅，合歡桃核兩人同。", "斜江風起動橫波，劈開蓮子苦心多。", "山頭桃花穀底杏，兩花窈窕遙相映。"]'),
('yuding-24','摘得新','皇甫松','唐','御定全唐诗','yuding','','[]','酌一卮，須教玉笛吹。錦筵紅蠟燭，莫來遲。',64,'御定全唐詩/json/891.json','["酌一卮，須教玉笛吹。錦筵紅蠟燭，莫來遲。", "繁紅一夜經風雨，是空枝。", "摘得新，枝枝葉葉春。管弦兼美酒，最關人。", "平生都得幾十度，展香茵。"]'),
('yuding-25','採蓮子','皇甫松','唐','御定全唐诗','yuding','','[]','菡萏香連十頃陂，小姑貪戲採蓮遲。',64,'御定全唐詩/json/891.json','["菡萏香連十頃陂，小姑貪戲採蓮遲。", "晚來弄水船頭濕，更脫紅裙裹鴨兒。", "船動湖光灩灩秋，貪看年少信船流。", "無端隔水拋蓮子，遙被人知半日羞。"]'),
('yuding-26','拋球樂','皇甫松','唐','御定全唐诗','yuding','','[]','紅撥一聲飄，輕裘墜越綃。帶翻金孔雀，香滿繡蜂腰。',72,'御定全唐詩/json/891.json','["紅撥一聲飄，輕裘墜越綃。帶翻金孔雀，香滿繡蜂腰。", "少少拋分數，花枝正索饒。", "金蹙花球小，真珠繡帶垂。幾回沖蠟燭，千度入香懷。", "上客終須醉，觥盂且亂排。"]'),
('yuding-27','憶江南','皇甫松','唐','御定全唐诗','yuding','','[]','蘭燼落，屏上暗紅蕉。閑夢江南梅熟日，',36,'御定全唐詩/json/891.json','["蘭燼落，屏上暗紅蕉。閑夢江南梅熟日，", "樓上寢，殘月下簾旌。夢見秣陵惆悵事，"]'),
('yuding-28','天仙子','皇甫松','唐','御定全唐诗','yuding','','[]','晴野鷺鷥飛一隻，水葓花發秋江碧。劉郎此日別天仙，',48,'御定全唐詩/json/891.json','["晴野鷺鷥飛一隻，水葓花發秋江碧。劉郎此日別天仙，", "躑躅花開紅照水，鷓鴣飛繞青山觜。行人經歲始歸來，"]'),
('yuding-29','怨回紇','皇甫松','唐','御定全唐诗','yuding','','[]','白首南朝女，愁聽異域歌。收兵頡利國，飲馬胡盧河。',96,'御定全唐詩/json/891.json','["白首南朝女，愁聽異域歌。收兵頡利國，飲馬胡盧河。", "毳布腥膻久，穹廬歲月多。雕窠城上宿，吹笛淚滂沱。", "祖席駐征棹，開帆候信潮。隔筵桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸塵上橋。別離惆悵淚，江路濕紅蕉。"]'),
('yuding-30','酒泉子','司空圖','唐','御定全唐诗','yuding','','[]','買得杏花，十載歸來方始坼。假山西畔藥闌東，滿枝紅。',49,'御定全唐詩/json/891.json','["買得杏花，十載歸來方始坼。假山西畔藥闌東，滿枝紅。", "旋開旋落旋成空，白髮多情人更惜。黃昏把酒祝東風，"]'),
('yuding-31','生查子','韓偓','唐','御定全唐诗','yuding','','[]','侍女動妝奩，故故驚人睡。那知本未眠，背面偷垂淚。',48,'御定全唐詩/json/891.json','["侍女動妝奩，故故驚人睡。那知本未眠，背面偷垂淚。", "懶卸鳳凰釵，羞入鴛鴦被。時複見殘燈，和煙墜金穗。"]'),
('yuding-32','浣溪沙','韓偓','唐','御定全唐诗','yuding','','[]','攏鬢新收玉步搖，背燈初解繡裙腰，枕寒衾冷異香焦。',96,'御定全唐詩/json/891.json','["攏鬢新收玉步搖，背燈初解繡裙腰，枕寒衾冷異香焦。", "深院不關春寂寂，落花和雨夜迢迢，恨情殘醉卻無聊。", "宿醉離愁慢髻鬟，六銖衣薄惹輕寒，慵紅悶翠掩青鸞。", "羅襪況兼金菡萏，雪肌仍是玉琅玕，骨香腰細更沉檀。"]'),
('yuding-33','浣溪沙','張曙2','唐','御定全唐诗','yuding','','[]','枕障熏爐隔繡帷，二年終日苦相思，杏花明月始應知。',48,'御定全唐詩/json/891.json','["枕障熏爐隔繡帷，二年終日苦相思，杏花明月始應知。", "天上人間何處去，舊歡新夢覺來時，黃昏微雨畫簾垂。"]'),
('yuding-34','蔔運算元慢','鐘輻','唐','御定全唐诗','yuding','','[]','桃花院落，煙重露寒，寂寞禁煙晴晝。風拂珠簾，',59,'御定全唐詩/json/891.json','["桃花院落，煙重露寒，寂寞禁煙晴晝。風拂珠簾，", "獨倚危闌久。把玉筍偷彈，黛蛾輕鬥。一點相思，", "寫別來，容顏寄與，使知人清瘦。"]'),
('yuding-0','訴衷情','韋莊','唐','御定全唐诗','yuding','','[]','燭燼香殘簾半卷，夢初驚。花欲謝，深夜，月籠明。',84,'御定全唐詩/json/892.json','["燭燼香殘簾半卷，夢初驚。花欲謝，深夜，月籠明。", "何處按歌聲，輕輕。舞衣塵暗生，負春情。", "碧沼紅芳煙雨靜，倚蘭橈。垂玉佩，交帶，嫋纖腰。", "鴛夢隔星橋，迢迢。越羅香暗銷，墜花翹。"]'),
('yuding-1','天仙子','韋莊','唐','御定全唐诗','yuding','','[]','悵望前回夢裏期，看花不語苦尋思。露桃宮裏小腰枝，',120,'御定全唐詩/json/892.json','["悵望前回夢裏期，看花不語苦尋思。露桃宮裏小腰枝，", "深夜歸來長酩酊，扶入流蘇猶未醒。醺醺酒氣麝蘭和，", "蟾彩霜華夜不分，天外鴻聲枕上聞。繡衾香冷懶重熏，", "夢覺雲屏依舊空，杜鵑聲咽隔簾櫳。玉郎薄幸去無蹤，", "金似衣裳玉似身，眼如秋水鬢如雲。霞裙月帔一群群，"]'),
('yuding-2','江城子','韋莊','唐','御定全唐诗','yuding','','[]','恩重嬌多情易傷，漏更長，解鴛鴦。朱唇未動，',42,'御定全唐詩/json/892.json','["恩重嬌多情易傷，漏更長，解鴛鴦。朱唇未動，", "髻鬟狼藉黛眉長，出蘭房，別檀郎。角聲嗚咽，"]'),
('yuding-3','定西番','韋莊','唐','御定全唐诗','yuding','','[]','挑盡金燈紅燼，人灼灼，漏遲遲，未眠時。',86,'御定全唐詩/json/892.json','["挑盡金燈紅燼，人灼灼，漏遲遲，未眠時。", "斜倚銀屏無語，閒愁上翠眉。悶殺梧桐殘雨，滴相思。", "芳草叢生縷結，花豔豔，雨濛濛，曉庭中。", "塞遠久無音問，愁銷鏡裏紅。紫燕黃鸝猶至，恨何窮。"]'),
('yuding-4','思帝鄉','韋莊','唐','御定全唐诗','yuding','','[]','雲髻墜，鳳釵垂。髻墜釵垂無力，枕函欹。',83,'御定全唐詩/json/892.json','["雲髻墜，鳳釵垂。髻墜釵垂無力，枕函欹。", "翡翠屏深月落，漏依依。說盡人間天上，兩心知。", "春日遊，杏花吹滿頭。陌上誰家年少，足風流。", "妾擬將身嫁與，一生休。縱被無情棄，不能羞。"]'),
('yuding-5','上行杯','韋莊','唐','御定全唐诗','yuding','','[]','芳草灞陵春岸，柳煙深，滿樓弦管。一曲離聲腸寸斷。',100,'御定全唐詩/json/892.json','["芳草灞陵春岸，柳煙深，滿樓弦管。一曲離聲腸寸斷。", "今日送君千萬，紅縷玉盤金鏤盞。須勸！珍重意，莫辭滿。", "白馬玉鞭金轡，少年郎，離別容易。迢遞去程千萬里。", "惆悵異鄉雲水，滿酌一杯勸和淚。須愧！珍重意，莫辭醉。"]'),
('yuding-6','酒泉子','韋莊','唐','御定全唐诗','yuding','','[]','月落星沉，樓上美人春睡。綠雲欹，金枕膩，畫屏深。',47,'御定全唐詩/json/892.json','["月落星沉，樓上美人春睡。綠雲欹，金枕膩，畫屏深。", "子規啼破相思夢，曙色東方才動。柳煙輕，花露重，"]'),
('yuding-7','女冠子','韋莊','唐','御定全唐诗','yuding','','[]','四月十七，正是去年今日。別君時，忍淚佯低面，',88,'御定全唐詩/json/892.json','["四月十七，正是去年今日。別君時，忍淚佯低面，", "不知魂已斷，空有夢相隨。除卻天邊月，沒人知。", "昨夜夜半，枕上分明夢見。語多時，依舊桃花面，", "半羞還半喜，欲去又依依。覺來知是夢，不勝悲。"]'),
('yuding-8','浣溪沙','韋莊','唐','御定全唐诗','yuding','','[]','清曉妝成寒食天，柳球斜嫋間花鈿，捲簾直出畫堂前。',240,'御定全唐詩/json/892.json','["清曉妝成寒食天，柳球斜嫋間花鈿，捲簾直出畫堂前。", "指點牡丹初綻朵，日高猶自憑朱闌，含嚬不語恨春殘。", "欲上秋千四體慵，擬交人送又心忪，畫堂簾幕月明風。", "此夜有情誰不極，隔牆梨雪又玲瓏，玉容憔悴惹微紅。", "惆悵夢餘山月斜，孤燈照壁背紅紗，小樓高閣謝娘家。", "暗想玉容何所似，一枝春雪凍梅花，滿身香霧簇朝霞。", "綠樹藏鶯鶯正啼，柳絲斜拂白銅鞮，弄珠江上草萋萋。", "日暮飲歸何處客，繡鞍驄馬一聲嘶，滿身蘭麝醉如泥。", "夜夜相思更漏殘，傷心明月憑闌幹，想君思我錦衾寒。", "咫尺畫堂深似海，憶來惟把舊書看，幾時攜手入長安。"]'),
('yuding-9','歸國遙','韋莊','唐','御定全唐诗','yuding','','[]','春欲暮，滿地落花紅帶雨。惆悵玉籠鸚鵡，單棲無伴侶。',153,'御定全唐詩/json/892.json','["春欲暮，滿地落花紅帶雨。惆悵玉籠鸚鵡，單棲無伴侶。", "南望去程何許，問花花不語。早晚得同歸去，恨無雙翠羽。", "金翡翠，為我南飛傳我意。罨畫橋邊春水，幾年花下醉。", "別後只知相愧，淚珠難遠寄。羅幕繡幃鴛被，舊歡如夢裏。", "春欲晚，戲蝶遊蜂花爛熳。日落謝家池館，柳絲金縷斷。", "睡覺綠鬟風亂，畫屏雲雨散。閑倚博山長歎，淚流沾皓腕。"]'),
('yuding-10','菩薩蠻','韋莊','唐','御定全唐诗','yuding','','[]','紅樓別夜堪惆悵，香燈半卷流蘇帳。殘月出門時，',230,'御定全唐詩/json/892.json','["紅樓別夜堪惆悵，香燈半卷流蘇帳。殘月出門時，", "琵琶金翠羽，弦上黃鶯語。勸我早歸家，綠窗人似花。", "人人盡說江南好，遊人只合江南老。春水碧於天，", "壚邊人似月，皓腕凝雙雪。未老莫還鄉，還鄉須斷腸。", "如今卻憶江南樂，當時年少春衫薄。騎馬倚斜橋，", "翠屏金屈曲，醉入花叢宿。此度見花枝，白頭誓不歸。", "勸君今夜須沈醉，尊前莫話明朝事。珍重主人心，", "須愁春漏短，莫訴金杯滿。遇酒且呵呵，人生能幾何。", "洛陽城裏春光好，洛陽才子他鄉老。柳暗魏王堤，", "桃花春水淥，水上鴛鴦浴。凝恨對殘暉，憶君君不知。"]'),
('yuding-11','更漏子','韋莊','唐','御定全唐诗','yuding','','[]','鐘鼓寒，樓閣暝，月照古桐金井。深院閉，小庭空，',46,'御定全唐詩/json/892.json','["鐘鼓寒，樓閣暝，月照古桐金井。深院閉，小庭空，", "煙柳重，春霧薄，燈背水窗高閣。閑倚戶，暗沾衣，"]'),
('yuding-12','謁金門','韋莊','唐','御定全唐诗','yuding','','[]','春雨足，染就一溪新綠。柳外飛來雙羽玉，弄晴相對浴。',141,'御定全唐詩/json/892.json','["春雨足，染就一溪新綠。柳外飛來雙羽玉，弄晴相對浴。", "樓外翠簾高軸，倚遍闌幹幾曲。雲淡水平煙樹簇，", "春漏促，金燼暗挑殘燭。一夜簾前風撼竹，夢魂相斷續。", "有個嬌饒如玉，夜夜繡屏孤宿。閑抱琵琶尋舊曲，", "空相憶，無計得傳消息。天上嫦娥人不識，寄書何處覓。", "新睡覺來無力，不忍把君書跡。滿院落花春寂寂，"]'),
('yuding-13','清平樂','韋莊','唐','御定全唐诗','yuding','','[]','春愁南陌，故國音書隔。細雨霏霏梨花白，燕拂畫簾金額。',282,'御定全唐詩/json/892.json','["春愁南陌，故國音書隔。細雨霏霏梨花白，燕拂畫簾金額。", "盡日相望王孫，塵滿衣上淚痕。誰向橋邊吹笛，", "野花芳草，寂寞關山道。柳吐金絲鶯語早，惆悵香閨暗老。", "羅帶悔結同心，獨憑朱闌思深。夢覺半床斜月，", "何處游女，蜀國多雲雨。雲解有情花解語，窣地繡羅金縷。", "妝成不整金鈿，含羞待月秋千。住在綠槐陰裏，", "鶯啼殘月，繡閣香燈滅。門外馬嘶郎欲別，正是落花時節。", "妝成不畫蛾眉，含愁獨倚金扉。去路香塵莫掃，", "瑣窗春暮，滿地梨花雨。君不歸來情又去，紅淚散沾金縷。", "夢魂飛斷煙波，傷心不奈春何。空把金針獨坐，", "綠楊春雨，金線飄千縷。花拆香枝黃鸝語，玉勒雕鞍何處。", "碧窗望斷燕鴻，翠簾睡眼溟蒙。寶瑟誰家彈罷，"]'),
('yuding-14','喜遷鶯','韋莊','唐','御定全唐诗','yuding','','[]','人洶洶，鼓冬冬，襟袖五更風。大羅天上月朦朧，',90,'御定全唐詩/json/892.json','["人洶洶，鼓冬冬，襟袖五更風。大羅天上月朦朧，", "香滿衣，雲滿路，鸞鳳繞身飛舞。霓旌絳節一群群，", "街鼓動，禁城開，天上探人回。鳳銜金榜出雲來，", "鶯已遷，龍已化，一夜滿城車馬。家家樓上簇神仙，"]'),
('yuding-15','應天長','韋莊','唐','御定全唐诗','yuding','','[]','綠槐陰裏黃鶯語，深院無人春晝午。畫簾垂，金鳳舞，',92,'御定全唐詩/json/892.json','["綠槐陰裏黃鶯語，深院無人春晝午。畫簾垂，金鳳舞，", "碧天雲，無定處，空有夢魂來去。夜夜綠窗風雨，", "別來半歲音書絕，一寸離腸千萬結。難相見，易相別，", "暗相思，無處說，惆悵夜來煙月。想得此時情切，"]'),
('yuding-16','荷葉杯','韋莊','唐','御定全唐诗','yuding','','[]','絕代佳人難得，傾國，花下見無期。一雙愁黛遠山眉，',96,'御定全唐詩/json/892.json','["絕代佳人難得，傾國，花下見無期。一雙愁黛遠山眉，", "閑掩翠屏金鳳，殘夢，羅幕畫堂空。碧天無路信難通，", "記得那年花下，深夜，初識謝娘時。水堂西面畫簾垂，", "惆悵曉鶯殘月，相別，從此隔音塵。如今俱是異鄉人，"]'),
('yuding-17','河傳','韋莊','唐','御定全唐诗','yuding','','[]','何處，煙雨，隋堤春暮。柳色蔥蘢，畫橈金縷，',145,'御定全唐詩/json/892.json','["何處，煙雨，隋堤春暮。柳色蔥蘢，畫橈金縷，", "青娥殿腳春妝媚，輕雲裏，綽約司花妓。江都宮闕，", "春晚，風暖，錦城花滿。狂殺遊人，玉鞭金勒尋勝，", "翠蛾爭勸臨邛酒，纖纖手，拂面垂絲柳。", "歸時煙裏鐘鼓，正是黃昏，暗銷魂。", "錦浦，春女，繡衣金縷。霧薄雲輕，花深柳暗，", "玉鞭魂斷煙霞路，鶯鶯語，一望巫山雨。香塵隱映，"]'),
('yuding-18','怨王孫','韋莊','唐','御定全唐诗','yuding','','[]','錦裏，蠶市，滿街珠翠。千萬紅妝，玉蟬金雀，',44,'御定全唐詩/json/892.json','["錦裏，蠶市，滿街珠翠。千萬紅妝，玉蟬金雀，", "日斜歸去人難見，青樓遠，隊隊行雲散。不知今夜，"]'),
('yuding-19','木蘭花','韋莊','唐','御定全唐诗','yuding','','[]','獨上小樓春欲暮，愁望玉關芳草路。消息斷，不逢人，',48,'御定全唐詩/json/892.json','["獨上小樓春欲暮，愁望玉關芳草路。消息斷，不逢人，", "坐看落花空歎息，羅袂濕班紅淚滴。千山萬水不曾行，"]'),
('yuding-20','小重山','韋莊','唐','御定全唐诗','yuding','','[]','一閉昭陽春又春。夜寒宮漏永，夢君恩。',70,'御定全唐詩/json/892.json','["一閉昭陽春又春。夜寒宮漏永，夢君恩。", "臥思陳事暗消魂。羅衣濕，紅袂有啼痕。", "歌吹隔重閽。繞庭芳草綠，倚長門。萬般惆悵向誰論？", "凝情立，宮殿欲黃昏。"]'),
('yuding-21','望遠行','韋莊','唐','御定全唐诗','yuding','','[]','欲別無言倚畫屏，含恨暗傷情。謝家庭樹錦雞鳴，',45,'御定全唐詩/json/892.json','["欲別無言倚畫屏，含恨暗傷情。謝家庭樹錦雞鳴，", "人欲別，馬頻嘶，綠槐千里長堤。出門芳草路萋萋，"]'),
('yuding-22','憶江南','牛嶠','唐','御定全唐诗','yuding','','[]','銜泥燕，飛到畫堂前。占得杏梁安穩處，體輕惟有主人憐。',64,'御定全唐詩/json/892.json','["銜泥燕，飛到畫堂前。占得杏梁安穩處，體輕惟有主人憐。", "堪羨好因緣。", "紅繡被，兩兩間鴛鴦。不是鳥中偏愛爾，為緣交頸睡南塘。", "全勝薄情郎。"]'),
('yuding-23','西溪子','牛嶠','唐','御定全唐诗','yuding','','[]','捍撥雙盤金鳳，蟬鬢玉釵搖動。畫堂前，人不語，弦解語。',41,'御定全唐詩/json/892.json','["捍撥雙盤金鳳，蟬鬢玉釵搖動。畫堂前，人不語，弦解語。", "彈到昭君怨處。翠蛾愁，不抬頭。"]'),
('yuding-24','江城子','牛嶠','唐','御定全唐诗','yuding','','[]','鵁鶄飛起郡城東，碧江空，半灘風。越王宮殿，',44,'御定全唐詩/json/892.json','["鵁鶄飛起郡城東，碧江空，半灘風。越王宮殿，", "極浦煙消水鳥飛，離筵分手時，送金卮。渡口楊花，"]'),
('yuding-25','定西番','牛嶠','唐','御定全唐诗','yuding','','[]','紫塞月明千里，金甲冷，戍樓寒，夢長安。',43,'御定全唐詩/json/892.json','["紫塞月明千里，金甲冷，戍樓寒，夢長安。", "鄉思望中天闊，漏殘星亦殘。畫角數聲嗚咽，雪漫漫。"]'),
('yuding-26','望江怨','牛嶠','唐','御定全唐诗','yuding','','[]','東風急，惜別花時手頻執，羅幃愁獨入。馬嘶殘雨春蕪濕。',42,'御定全唐詩/json/892.json','["東風急，惜別花時手頻執，羅幃愁獨入。馬嘶殘雨春蕪濕。", "倚門立，寄語薄情郎，粉香和淚泣。"]'),
('yuding-27','女冠子','牛嶠','唐','御定全唐诗','yuding','','[]','綠雲高髻，點翠勻紅時世。月如眉，淺笑含雙靨，',177,'御定全唐詩/json/892.json','["綠雲高髻，點翠勻紅時世。月如眉，淺笑含雙靨，", "眼看惟恐化，魂蕩欲相隨。玉趾回嬌步，約佳期。", "錦江煙水，卓女燒春濃美。小檀霞，繡帶芙蓉帳，", "額黃侵膩發，臂釧透紅紗。柳暗鶯啼處，認郎家。", "星冠霞帔，住在蕊珠宮裏。佩丁當，明翠搖蟬翼，", "醮壇春草晝綠，藥院杏花香。青鳥傳心事，寄劉郎。", "雙飛雙舞，春晝後園鶯語。卷羅幃，錦字書封了，", "鴛鴦排寶帳，豆蔻繡連枝。不語勻珠淚，落花時。"]'),
('yuding-28','酒泉子','牛嶠','唐','御定全唐诗','yuding','','[]','記得去年，煙暖杏園花正發，雪飄香。江草綠，柳絲長。',51,'御定全唐詩/json/892.json','["記得去年，煙暖杏園花正發，雪飄香。江草綠，柳絲長。", "鈿車纖手捲簾望，眉學春山樣。鳳釵低嫋翠鬟上，落梅妝。"]'),
('yuding-29','菩薩蠻','牛嶠','唐','御定全唐诗','yuding','','[]','舞裙香暖金泥鳳，畫梁語燕驚殘夢。門外柳花飛，',322,'御定全唐詩/json/892.json','["舞裙香暖金泥鳳，畫梁語燕驚殘夢。門外柳花飛，", "愁勻紅粉淚，眉剪春山翠。何處是遼陽，錦屏春晝長。", "柳花飛處鶯聲急，晴街春色香車立。金鳳小簾開，", "今宵求夢想，難到青樓上。贏得一場愁，鴛衾誰並頭。", "玉釵風動春幡急，交枝紅杏籠煙泣。樓上望卿卿，", "熏爐蒙翠被，繡帳鴛鴦睡。何處有相知，羨他初畫眉。", "畫屏重疊巫陽翠，楚神尚有行雲意。朝暮幾般心，", "風流今古隔，虛作瞿塘客。山月照山花，夢回燈影斜。", "風簾燕舞鶯啼柳，妝台約鬢低纖手。釵重髻盤珊，", "門前行樂客，白馬嘶春色。故故墜金鞭，回頭應眼穿。", "綠雲鬢上飛金雀，愁眉斂翠春煙薄。香閣掩芙蓉，", "窗寒天欲曙，猶結同心苣。啼粉涴羅衣，問郎何日歸。", "玉爐冰簟鴛鴦錦，粉融香汗流山枕。簾外轆轤聲，", "柳陰煙漠漠，低鬢蟬釵落。須作一生拌，盡君今日歡。"]'),
('yuding-30','更漏子','牛嶠','唐','御定全唐诗','yuding','','[]','星漸稀，漏頻轉，何處輪台聲怨。香閣掩，杏花紅，',138,'御定全唐詩/json/892.json','["星漸稀，漏頻轉，何處輪台聲怨。香閣掩，杏花紅，", "挑錦字，記情事，惟願兩心相似。收淚語，背燈眠，", "春夜闌，更漏促，金燼暗挑殘燭。驚夢斷，錦屏深，", "閨草碧，望歸客，還是不知消息。孤負我，悔憐君，", "南浦情，紅粉淚，爭奈兩人深意。低翠黛，卷征衣，", "招手別，寸腸結，還是去年時節。書托雁，夢歸家，"]'),
('yuding-31','感恩多','牛嶠','唐','御定全唐诗','yuding','','[]','兩條紅粉淚，多少香閨意。強攀桃李枝，斂愁眉。',85,'御定全唐詩/json/892.json','["兩條紅粉淚，多少香閨意。強攀桃李枝，斂愁眉。", "陌上鶯啼蝶舞，柳花飛。柳花飛，願得郎心，", "自從南浦別，愁見丁香結。近來情轉深，憶鴛衾。", "幾度將書托煙雁，淚盈襟。淚盈襟，禮月求天，"]'),
('yuding-32','應天長','牛嶠','唐','御定全唐诗','yuding','','[]','玉樓春望晴煙滅，舞衫斜卷金條脫。黃鸝嬌轉聲初歇，',90,'御定全唐詩/json/892.json','["玉樓春望晴煙滅，舞衫斜卷金條脫。黃鸝嬌轉聲初歇，", "鳳釵低赴節，筵上王孫愁絕。鴛鴦對銜羅結，", "雙眉澹薄藏心事，清夜背燈嬌又醉。玉釵橫，山枕膩，", "別經時，無限意，虛道相思憔悴。莫信彩箋書裏，"]'),
('yuding-33','木蘭花','牛嶠','唐','御定全唐诗','yuding','','[]','春入橫塘搖淺浪，花落小園空惆悵。此情誰信為狂夫，',48,'御定全唐詩/json/892.json','["春入橫塘搖淺浪，花落小園空惆悵。此情誰信為狂夫，", "小玉窗前嗔燕語，紅淚滴穿金線縷。雁歸不見報郎歸，"]'),
('yuding-0','西溪子','毛文錫','唐','御定全唐诗','yuding','','[]','昨夜西溪遊賞，芳樹奇花千樣。鎖春光，金尊滿，',22,'御定全唐詩/json/893.json','["昨夜西溪遊賞，芳樹奇花千樣。鎖春光，金尊滿，"]'),
('yuding-1','何滿子','毛文錫','唐','御定全唐诗','yuding','','[]','紅粉樓前月照，碧紗窗外鶯啼。夢斷遼陽音信，',21,'御定全唐詩/json/893.json','["紅粉樓前月照，碧紗窗外鶯啼。夢斷遼陽音信，"]'),
('yuding-2','訴衷情','毛文錫','唐','御定全唐诗','yuding','','[]','桃花流水漾縱橫，春晝彩霞明。劉郎去，阮郎行，',88,'御定全唐詩/json/893.json','["桃花流水漾縱橫，春晝彩霞明。劉郎去，阮郎行，", "愁坐對雲屏，算歸程。何時攜手洞邊迎，訴衷情。", "鴛鴦交頸繡衣輕，碧沼藕花馨。偎藻荇，映蘭汀，", "思婦對心驚，想邊庭。何時解佩掩雲屏，訴衷情。"]'),
('yuding-3','中興樂','毛文錫','唐','御定全唐诗','yuding','','[]','豆蔻花繁煙豔深，丁香軟結同心。翠鬟女，相與，共淘金。',51,'御定全唐詩/json/893.json','["豆蔻花繁煙豔深，丁香軟結同心。翠鬟女，相與，共淘金。", "紅蕉葉裏猩猩語。鴛鴦浦，鏡中鸞舞。絲雨，隔荔枝陰。"]'),
('yuding-4','醉花間','毛文錫','唐','御定全唐诗','yuding','','[]','休相問，怕相問，相問還添恨。春水滿塘生，鸂鶒還相趁。',100,'御定全唐詩/json/893.json','["休相問，怕相問，相問還添恨。春水滿塘生，鸂鶒還相趁。", "昨夜雨霏霏，臨明寒一陣。偏憶戍樓人，久絕邊庭信。", "深相憶，莫相憶，相憶情難極。銀漢是紅牆，一帶遙相隔。", "金盤珠露滴，兩岸榆花白。風搖玉佩清，今夕為何夕。"]'),
('yuding-5','酒泉子','毛文錫','唐','御定全唐诗','yuding','','[]','綠樹春深，燕語鶯啼聲斷續，惠風飄蕩入芳叢，惹殘紅。',49,'御定全唐詩/json/893.json','["綠樹春深，燕語鶯啼聲斷續，惠風飄蕩入芳叢，惹殘紅。", "柳絲無力嫋煙空。金盞不辭須滿酌，海棠花下思朦朧，"]'),
('yuding-6','紗窗恨','毛文錫','唐','御定全唐诗','yuding','','[]','新春燕子還來至，一雙飛。壘巢泥濕時時墜，涴人衣。',95,'御定全唐詩/json/893.json','["新春燕子還來至，一雙飛。壘巢泥濕時時墜，涴人衣。", "後園裏、看百花發，香風拂、繡戶金扉。月照紗窗，", "雙雙蝶翅塗鉛粉，咂花心。綺窗繡戶飛來穩，畫堂陰。", "二三月、愛隨風絮，伴落花、來拂衣襟。更剪輕羅片，"]'),
('yuding-7','戀情深','毛文錫','唐','御定全唐诗','yuding','','[]','滴滴銅壺寒漏咽，醉紅樓月。宴餘香殿會鴛衾，蕩春心。',100,'御定全唐詩/json/893.json','["滴滴銅壺寒漏咽，醉紅樓月。宴餘香殿會鴛衾，蕩春心。", "真珠簾下曉光侵，鶯語隔瓊林。寶帳欲開慵起，戀情深。", "玉殿春濃花爛漫，簇神仙伴。羅裙窣地縷黃金，奏清音。", "酒闌歌罷兩沉沉，一笑動君心。永願作鴛鴦伴，戀情深。"]'),
('yuding-8','浣溪沙','毛文錫','唐','御定全唐诗','yuding','','[]','七夕年年信不違，銀河清淺白雲微，蟾光鵲影伯勞飛。',48,'御定全唐詩/json/893.json','["七夕年年信不違，銀河清淺白雲微，蟾光鵲影伯勞飛。", "每恨蟪蛄憐婺女，幾回嬌妒下鴛機，今宵嘉會兩依依。"]'),
('yuding-9','攤破浣溪沙','毛文錫','唐','御定全唐诗','yuding','','[]','春水輕波浸綠苔，枇杷洲上紫檀開。晴日眠沙鸂鶒穩，',48,'御定全唐詩/json/893.json','["春水輕波浸綠苔，枇杷洲上紫檀開。晴日眠沙鸂鶒穩，", "羅襪生塵遊女過，有人逢著弄珠回。蘭麝飄香初解佩，"]'),
('yuding-10','贊浦子','毛文錫','唐','御定全唐诗','yuding','','[]','錦帳添香睡，金爐換夕熏。懶結芙蓉帶，慵拖翡翠裙。',50,'御定全唐詩/json/893.json','["錦帳添香睡，金爐換夕熏。懶結芙蓉帶，慵拖翡翠裙。", "正是柳夭桃媚，那堪暮雨朝雲。宋玉高唐意，裁瓊欲贈君。"]'),
('yuding-11','巫山一段雲','毛文錫','唐','御定全唐诗','yuding','','[]','雨霽巫山上，雲輕映碧天。遠風吹散又相連，十二晚峰前。',104,'御定全唐詩/json/893.json','["雨霽巫山上，雲輕映碧天。遠風吹散又相連，十二晚峰前。", "暗濕啼猿樹，高籠過客船。朝朝暮暮楚江邊，幾度降神仙。", "貌掩巫山色，才過濯錦波。阿誰提筆上銀河，月裏寫嫦娥。", "薄薄施鉛粉，盈盈掛綺羅。菖蒲花役夢魂多，年代屬元和。"]'),
('yuding-12','柳含煙','毛文錫','唐','御定全唐诗','yuding','','[]','隋堤柳，汴河旁。夾岸綠陰千里，龍舟鳳舸木蘭香。',188,'御定全唐詩/json/893.json','["隋堤柳，汴河旁。夾岸綠陰千里，龍舟鳳舸木蘭香。", "錦帆張。", "因夢江南春景好，一路流蘇羽葆。笙歌未盡起橫流，", "河橋柳，占芳春。映水含煙拂路，幾回攀折贈行人，", "樂府吹為橫笛曲，能使離腸斷續。不如移植在金門，", "章台柳，近垂旒。低拂往來冠蓋，朦朧春色滿皇州，", "直與路邊江畔別，免被離人攀折。最憐京兆畫蛾眉，", "禦溝柳，占春多。半出宮牆婀娜，有時倒景醮輕羅，", "昨日金鑾巡上苑，風亞舞腰纖軟。栽培得地近皇宮，"]'),
('yuding-13','更漏子','毛文錫','唐','御定全唐诗','yuding','','[]','春夜闌，春恨切，花外子規啼月。人不見，夢難憑，',46,'御定全唐詩/json/893.json','["春夜闌，春恨切，花外子規啼月。人不見，夢難憑，", "偏怨別，是芳節，庭下丁香千結。宵霧散，曉霞暉，"]'),
('yuding-14','喜遷鶯','毛文錫','唐','御定全唐诗','yuding','','[]','芳春景，曖晴煙，喬木見鶯遷。傳枝偎葉語關關，',45,'御定全唐詩/json/893.json','["芳春景，曖晴煙，喬木見鶯遷。傳枝偎葉語關關，", "錦翼鮮，金毳軟，百轉千嬌相喚。碧紗窗曉怕聞聲，"]'),
('yuding-15','應天長','毛文錫','唐','御定全唐诗','yuding','','[]','平江波暖鴛鴦語，兩兩釣船歸極浦。蘆洲一夜風和雨，',50,'御定全唐詩/json/893.json','["平江波暖鴛鴦語，兩兩釣船歸極浦。蘆洲一夜風和雨，", "漁燈明遠渚，蘭棹今宵何處。羅袂從風輕舉，愁殺採蓮女。"]'),
('yuding-16','月宮春','毛文錫','唐','御定全唐诗','yuding','','[]','水晶宮裏桂花開，神仙探幾回。紅芳金蕊繡重台，',45,'御定全唐詩/json/893.json','["水晶宮裏桂花開，神仙探幾回。紅芳金蕊繡重台，", "玉兔銀蟾爭守護，姮娥姹女戲相偎。遙聽鈞天九奏，"]'),
('yuding-17','虞美人','毛文錫','唐','御定全唐诗','yuding','','[]','鴛鴦對浴銀塘暖，水面蒲梢短。垂楊低拂曲塵波，',88,'御定全唐詩/json/893.json','["鴛鴦對浴銀塘暖，水面蒲梢短。垂楊低拂曲塵波，", "遙思桃葉吳江碧，便是天河隔。錦鱗紅鬣影沉沉，", "寶檀金縷鴛鴦枕，綬帶盤宮錦。夕陽低映小窗明，", "玉爐香暖頻添炷，滿地飄輕絮。珠簾不卷度沈煙，"]'),
('yuding-18','臨江仙','毛文錫','唐','御定全唐诗','yuding','','[]','暮蟬聲盡落斜陽，銀蟾影掛瀟湘。黃陵廟側水茫茫。',68,'御定全唐詩/json/893.json','["暮蟬聲盡落斜陽，銀蟾影掛瀟湘。黃陵廟側水茫茫。", "楚山紅樹，煙雨隔高唐。", "岸泊漁燈風颭碎，白蘋遠散濃香。靈娥鼓瑟韻清商。", "朱弦淒切，雲散碧天長。"]'),
('yuding-19','接賢賓','毛文錫','唐','御定全唐诗','yuding','','[]','香韉鏤襜五色驄，值春景初融。流珠噴沫躞蹀，汗血流紅。',49,'御定全唐詩/json/893.json','["香韉鏤襜五色驄，值春景初融。流珠噴沫躞蹀，汗血流紅。", "少年公子能乘馭，金鑣玉轡瓏璁。為惜珊瑚鞭不下，"]'),
('yuding-20','贊成功','毛文錫','唐','御定全唐诗','yuding','','[]','海棠未坼，萬點深紅，香包緘結一重重。似含羞態，',46,'御定全唐詩/json/893.json','["海棠未坼，萬點深紅，香包緘結一重重。似含羞態，", "昨夜微雨，飄灑庭中，忽聞聲滴井邊桐。美人驚起，"]'),
('yuding-21','甘州遍','毛文錫','唐','御定全唐诗','yuding','','[]','春光好，公子愛閒遊。足風流。金鞍白馬，雕弓寶劍，',140,'御定全唐詩/json/893.json','["春光好，公子愛閒遊。足風流。金鞍白馬，雕弓寶劍，", "花蔽膝，玉銜頭。尋芳逐勝歡宴，絲竹不曾休。美人唱、", "揭調是甘州，醉紅樓。堯年舜日，樂聖永無憂。", "秋風緊，平磧雁行低。陣雲齊。蕭蕭颯颯，邊聲四起，", "青塚北，黑山西。沙飛聚散無定，往往路人迷。鐵衣冷、", "戰馬血沾蹄，破蕃奚。鳳凰詔下，步步躡丹梯。"]'),
('yuding-22','漁父','和凝','唐','御定全唐诗','yuding','','[]','白芷汀寒立鷺鷥，蘋風輕剪浪花時。煙冪冪，日遲遲，',24,'御定全唐詩/json/893.json','["白芷汀寒立鷺鷥，蘋風輕剪浪花時。煙冪冪，日遲遲，"]'),
('yuding-23','天仙子','和凝','唐','御定全唐诗','yuding','','[]','柳色披衫金縷鳳，纖手輕拈紅豆弄。翠蛾雙斂正含情，',64,'御定全唐詩/json/893.json','["柳色披衫金縷鳳，纖手輕拈紅豆弄。翠蛾雙斂正含情，", "洞口春紅飛蔌蔌，仙子含愁眉黛綠。阮郎何事不歸來？", "懶燒金，慵篆玉，流水桃花空斷續。"]'),
('yuding-24','江城子','和凝','唐','御定全唐诗','yuding','','[]','初夜含嬌入洞房，理殘妝，柳眉長。翡翠屏中，',105,'御定全唐詩/json/893.json','["初夜含嬌入洞房，理殘妝，柳眉長。翡翠屏中，", "竹裏風生月上門，理秦箏，對雲屏。輕撥朱弦，", "鬥轉星移玉漏頻，已三更，對棲鶯。歷歷花間，", "迎得郎來入繡闈，語相思，連理枝。鬢亂釵垂，", "帳裏鴛鴦交頸情，恨雞聲，天已明。愁見街前，"]'),
('yuding-25','何滿子','和凝','唐','御定全唐诗','yuding','','[]','正是破瓜年幾，含情慣得人饒。桃李精神鸚鵡舌，',43,'御定全唐詩/json/893.json','["正是破瓜年幾，含情慣得人饒。桃李精神鸚鵡舌，", "寫得魚箋無限，其如花鎖春暉。目斷巫山雲雨，"]'),
('yuding-26','望梅花','和凝','唐','御定全唐诗','yuding','','[]','春草全無消息，臘雪猶餘蹤跡。越嶺寒枝香自折，',22,'御定全唐詩/json/893.json','["春草全無消息，臘雪猶餘蹤跡。越嶺寒枝香自折，"]'),
('yuding-27','薄命女','和凝','唐','御定全唐诗','yuding','','[]','天欲曉，宮漏穿花聲繚繞，窗裏星光少。',40,'御定全唐詩/json/893.json','["天欲曉，宮漏穿花聲繚繞，窗裏星光少。", "冷露寒侵帳額，殘月光沈樹杪。夢斷錦幃空悄悄，"]'),
('yuding-28','春光好','和凝','唐','御定全唐诗','yuding','','[]','紗窗暖，畫屏閑，嚲雲鬟。睡起四肢無力，半春間。',99,'御定全唐詩/json/893.json','["紗窗暖，畫屏閑，嚲雲鬟。睡起四肢無力，半春間。", "玉指剪裁羅勝，金盤點綴酥山。窺宋深心無限事，小眉彎。", "蘋葉軟，杏花明，畫船輕。雙浴鴛鴦出綠汀，棹歌聲。", "春水無風無浪，春天半雨半晴。紅粉相隨南浦晚，幾含情。"]'),
('yuding-29','采桑子','和凝','唐','御定全唐诗','yuding','','[]','蝤蠐領上訶梨子，繡帶雙垂。椒戶閒時，競學摴蒲賭荔支。',52,'御定全唐詩/json/893.json','["蝤蠐領上訶梨子，繡帶雙垂。椒戶閒時，競學摴蒲賭荔支。", "叢頭鞋子紅編細，裙窣金絲。無事嚬眉，春思翻教阿母疑。"]'),
('yuding-30','菩薩蠻','和凝','唐','御定全唐诗','yuding','','[]','越梅半拆輕寒裏，冰清澹薄籠藍水。暖覺杏梢紅，',46,'御定全唐詩/json/893.json','["越梅半拆輕寒裏，冰清澹薄籠藍水。暖覺杏梢紅，", "閑階莎徑碧，遠夢猶堪惜。離恨又迎春，相思難重陳。"]'),
('yuding-31','喜遷鶯','和凝','唐','御定全唐诗','yuding','','[]','曉月墜，宿雲披，銀燭錦屏帷。建章鐘動玉繩低，',45,'御定全唐詩/json/893.json','["曉月墜，宿雲披，銀燭錦屏帷。建章鐘動玉繩低，", "春態淺，來雙燕，紅日漸長一線。嚴妝欲罷轉黃鸝，"]'),
('yuding-32','山花子','和凝','唐','御定全唐诗','yuding','','[]','鶯錦蟬縠馥麝臍，輕裾花草曉煙迷。鸂鶒戰金紅掌墜，',96,'御定全唐詩/json/893.json','["鶯錦蟬縠馥麝臍，輕裾花草曉煙迷。鸂鶒戰金紅掌墜，", "星靨笑偎霞臉畔，蹙金開襜襯銀泥。春思半和芳草嫩，", "銀字笙寒調正長，水文簟冷畫屏涼。玉腕重，金扼臂，", "幾度試香纖手暖，一回嘗酒絳唇光。佯弄紅絲繩拂子，"]'),
('yuding-33','臨江仙','和凝','唐','御定全唐诗','yuding','','[]','海棠香老春江晚，小樓霧縠空蒙。翠鬟初出繡簾中，',92,'御定全唐詩/json/893.json','["海棠香老春江晚，小樓霧縠空蒙。翠鬟初出繡簾中，", "碾玉釵搖鸂鶒戰，雪肌雲鬢將融。含情遙指碧波東，", "披袍窣地紅宮錦，鶯語時轉輕音。碧羅冠子穩犀簪，", "肌骨細勻紅玉軟，臉波微送春心。嬌羞不肯入鴛衾，"]'),
('yuding-34','小重山','和凝','唐','御定全唐诗','yuding','','[]','春入神京萬木芳，禁林鶯語滑、蝶飛狂。',120,'御定全唐詩/json/893.json','["春入神京萬木芳，禁林鶯語滑、蝶飛狂。", "曉花擎露妨啼妝，紅日永、風和百花香。", "煙鎖柳絲長，禦溝澄碧水、轉池塘。時時微雨洗風光，", "正是神京爛熳時，群仙初折得、郤詵枝。", "烏犀白紵最相宜，精神出、禦陌袖鞭垂。", "柳色展愁眉，管弦分響亮、探花期。光陰占斷曲江池，"]'),
('yuding-35','麥秀兩岐','和凝','唐','御定全唐诗','yuding','','[]','涼簟鋪斑竹，鴛枕並紅玉。臉蓮紅，眉柳綠，',40,'御定全唐詩/json/893.json','["涼簟鋪斑竹，鴛枕並紅玉。臉蓮紅，眉柳綠，", "羞道交回燭，未慣雙雙宿。樹連枝，魚比目，"]'),
('yuding-36','生查子','牛希濟','唐','御定全唐诗','yuding','','[]','春山煙欲收，天澹星稀小。殘月臉邊明，別淚臨清曉。',98,'御定全唐詩/json/893.json','["春山煙欲收，天澹星稀小。殘月臉邊明，別淚臨清曉。", "語已多，情未了，回首猶重道。記得綠羅裙，處處憐芳草。", "新月曲如眉，未有團圞意。紅豆不堪看，滿眼相思淚。", "終日劈桃穰，人在心兒裏。兩朵隔牆花，早晚成連理。"]'),
('yuding-37','中興樂','牛希濟','唐','御定全唐诗','yuding','','[]','池塘暖碧浸晴暉，濛濛柳絮輕飛。紅蕊凋來，醉夢還稀。',51,'御定全唐詩/json/893.json','["池塘暖碧浸晴暉，濛濛柳絮輕飛。紅蕊凋來，醉夢還稀。", "春雲空有雁歸，珠簾垂。東風寂寞，恨郎拋擲，淚濕羅衣。"]'),
('yuding-38','酒泉子','牛希濟','唐','御定全唐诗','yuding','','[]','枕轉簟涼，清曉遠鐘殘夢。月光斜，簾影動，舊爐香。',50,'御定全唐詩/json/893.json','["枕轉簟涼，清曉遠鐘殘夢。月光斜，簾影動，舊爐香。", "夢中說盡相思事，纖手勻雙淚。去年書，今日意，斷人腸。"]'),
('yuding-39','謁金門','牛希濟','唐','御定全唐诗','yuding','','[]','秋已暮，重疊關山岐路。嘶馬搖鞭何處去，曉禽霜滿樹。',47,'御定全唐詩/json/893.json','["秋已暮，重疊關山岐路。嘶馬搖鞭何處去，曉禽霜滿樹。", "夢斷禁城鐘鼓，淚滴枕檀無數。一點凝紅和薄霧，"]'),
('yuding-40','臨江仙','牛希濟','唐','御定全唐诗','yuding','','[]','峭碧參差十二峰，冷煙寒樹重重。瑤姬宮殿是仙蹤。',420,'御定全唐詩/json/893.json','["峭碧參差十二峰，冷煙寒樹重重。瑤姬宮殿是仙蹤。", "金爐珠帳，香靄晝偏濃。", "一自楚王驚夢斷，人間無路相逢。至今雲雨帶愁容。", "月斜江上，征棹動晨鐘。", "謝家仙觀寄雲岑，岩蘿拂地成陰。洞房不閉白雲深。", "當時丹灶，一粒化黃金。", "石壁霞衣猶半掛，松風長似鳴琴。時聞唳鶴起前林。", "十洲高會，何處許相尋。", "渭闕宮城秦樹凋，玉樓獨上無憀。含情不語自吹簫。", "調清和恨，天路逐風飄。", "何事乘龍人忽降，似知深意相招。三清攜手路非遙。", "世間屏障，彩筆劃嬌饒。", "江繞黃陵春廟閑，嬌鶯獨語關關。滿庭重疊綠苔斑。", "陰雲無事，四散自歸山。", "簫鼓聲稀香燼冷，月娥斂盡彎環。風流皆道勝人間，", "素洛春光瀲灩平，千重媚臉初生。淩波羅襪勢輕輕。", "煙籠日照，珠翠半分明。", "風引寶衣疑欲舞，鸞回鳳翥堪驚。也知心許恐無成。", "陳王辭賦，千載有聲名。", "柳帶搖風漢水濱，平蕪兩岸爭勻。鴛鴦對浴浪痕新。", "弄珠遊女，微笑自含春。", "輕步暗移蟬鬢動，羅裙風惹輕塵。水精宮殿豈無因。", "空勞纖手，解佩贈情人。", "洞庭波浪颭晴天，君山一點凝煙。此中真境屬神仙。"]'),
('yuding-0','相見歡','薛昭蘊','唐','御定全唐诗','yuding','','[]','羅襦繡袂香紅，畫堂中。細草平沙蕃馬、小屏風。',45,'御定全唐詩/json/894.json','["羅襦繡袂香紅，畫堂中。細草平沙蕃馬、小屏風。", "卷羅幕，憑妝閣，思無窮。暮雨輕煙魂斷、隔簾櫳。"]'),
('yuding-1','醉公子','薛昭蘊','唐','御定全唐诗','yuding','','[]','慢綰青絲發，光砑吳綾襪。床上小熏籠，韶州新退紅。',48,'御定全唐詩/json/894.json','["慢綰青絲發，光砑吳綾襪。床上小熏籠，韶州新退紅。", "叵耐無端處，撚得從頭汙。惱得眼慵開，問人閒事來。"]'),
('yuding-2','女冠子','薛昭蘊','唐','御定全唐诗','yuding','','[]','求仙去也，翠鈿金篦盡舍。入岩巒，霧卷黃羅帔，',88,'御定全唐詩/json/894.json','["求仙去也，翠鈿金篦盡舍。入岩巒，霧卷黃羅帔，", "野煙溪洞冷，林月石橋寒。靜夜松風下，禮天壇。", "雲羅霧縠，新授明威法籙。降真函，髻綰青絲發，", "往來雲過五，去住島經三。正遇劉郎使，啟瑤緘。"]'),
('yuding-3','浣溪沙','薛昭蘊','唐','御定全唐诗','yuding','','[]','紅蓼渡頭秋正雨，印沙鷗跡自成行，整鬟飄袖野風香。',384,'御定全唐詩/json/894.json','["紅蓼渡頭秋正雨，印沙鷗跡自成行，整鬟飄袖野風香。", "不語含嚬深浦裏，幾回愁煞棹船郎，燕歸帆盡水茫茫。", "鈿匣菱花錦帶垂，靜臨蘭檻卸頭時，約鬟低珥算歸期。", "花茂草青湘渚闊，夢餘空有漏依依，二年終日損芳菲。", "粉上依稀有淚痕，郡庭花落欲黃昏，遠情深恨與誰論。", "記得去年寒食日，延秋門外卓金輪，日斜人散暗銷魂。", "握手河橋柳似金，蜂須輕惹百花心，蕙風蘭思寄清琴。", "意滿便同春水滿，情深還似酒杯深，楚煙湘月兩沉沉。", "簾外三間出寺牆，滿街垂柳綠陰長，嫩紅輕翠間濃妝。", "瞥地見時猶可哥，卻來閑處暗思量，如今情事隔仙鄉。", "江館清秋纜客船，故人相送夜開筵，麝煙蘭焰簇花鈿。", "正是斷魂迷楚雨，不堪離恨咽湘弦，月高霜白水連天。", "傾國傾城恨有餘，幾多紅淚泣姑蘇，倚風凝睇雪肌膚。", "吳主山河空落日，越王宮殿半平蕪，藕花菱蔓滿平湖。", "越女淘金春水上，步搖雲鬢佩鳴璫，渚風江草又清香。", "不為遠山凝翠黛，只應含恨向斜陽，碧桃花謝憶劉郎。"]'),
('yuding-4','謁金門','薛昭蘊','唐','御定全唐诗','yuding','','[]','春滿院，疊損羅衣金線。睡覺水精簾未卷，簾前雙語燕。',47,'御定全唐詩/json/894.json','["春滿院，疊損羅衣金線。睡覺水精簾未卷，簾前雙語燕。", "斜掩金鋪一扇，滿地落花千片。早是相思腸欲斷，"]'),
('yuding-5','喜遷鶯','薛昭蘊','唐','御定全唐诗','yuding','','[]','殘蟾落，曉鐘鳴，羽化覺身輕。乍無春睡有餘酲，',135,'御定全唐詩/json/894.json','["殘蟾落，曉鐘鳴，羽化覺身輕。乍無春睡有餘酲，", "紫陌長，襟袖冷，不是人間風景。回看塵土似前生，", "金門曉，玉京春，駿馬驟輕塵。樺煙深處白衫新，", "九陌喧，千戶啟，滿袖桂香風細。杏園歡宴曲江濱，", "清明節，雨晴天，得意正當年。馬驕泥軟錦連幹，", "花色融，人競賞，儘是繡鞍朱鞅。日斜無計更留連，"]'),
('yuding-6','小重山','薛昭蘊','唐','御定全唐诗','yuding','','[]','春到長門春草青，玉階華露滴、月朧明。',120,'御定全唐詩/json/894.json','["春到長門春草青，玉階華露滴、月朧明。", "東風吹斷紫簫聲，宮漏促、簾外曉啼鶯。", "愁極夢難成，紅妝流宿淚、不勝情。手挪裙帶繞花行，", "秋到長門秋草黃，畫梁雙燕去、出宮牆。", "玉簫無複理霓裳，金蟬墜、鸞鏡掩休妝。", "憶昔在昭陽，舞衣紅綬帶、繡鴛鴦。至今猶惹禦爐香，"]'),
('yuding-7','離別難','薛昭蘊','唐','御定全唐诗','yuding','','[]','寶馬曉韝雕鞍，羅幃乍別情難。那堪春景媚，送君千萬里。',77,'御定全唐詩/json/894.json','["寶馬曉韝雕鞍，羅幃乍別情難。那堪春景媚，送君千萬里。", "半妝珠翠落，露華寒。紅蠟燭，青絲曲，偏能鉤引淚闌幹。", "良夜促，香塵綠，魂欲迷，檀眉半斂愁低。未別心先咽，"]'),
('yuding-8','荷葉杯','顧夐','唐','御定全唐诗','yuding','','[]','春盡小庭花落，寂寞，憑檻斂雙眉。忍教成病憶佳期，',216,'御定全唐詩/json/894.json','["春盡小庭花落，寂寞，憑檻斂雙眉。忍教成病憶佳期，", "歌發誰家筵上，寥亮，別恨正悠悠。蘭釭背帳月當樓，", "弱柳好花盡拆，晴陌，陌上少年郎。滿身蘭麝撲人香，", "記得那時相見，膽戰，鬢亂四肢柔。泥人無語不抬頭，", "夜久歌聲怨咽，殘月，菊冷露微微。看看濕透縷金衣，", "我憶君詩最苦，知否，字字盡關心。紅箋寫寄表情深，", "金鴨香濃鴛被，枕膩，小髻簇花鈿。腰如細柳臉如蓮，", "曲砌蝶飛煙暖，春半，花發柳垂條。花如雙臉柳如腰，", "一去又乖期信，春盡，滿院長莓苔。手挪裙帶獨裴回，"]'),
('yuding-9','甘州子','顧夐','唐','御定全唐诗','yuding','','[]','一爐龍麝錦帷傍，屏掩映，燭熒煌。禁樓刁鬥喜初長，',136,'御定全唐詩/json/894.json','["一爐龍麝錦帷傍，屏掩映，燭熒煌。禁樓刁鬥喜初長，", "每逢清夜與良晨，多悵望，足傷神。雲迷水隔意中人，", "曾如劉阮訪仙蹤，深洞客，此時逢。綺筵散後繡衾同。", "款曲見韶容。山枕上，長是怯晨鐘。", "露桃花裏小樓深，持玉盞，聽瑤琴。醉歸青瑣入鴛衾，", "紅爐深夜醉調笙，敲拍處，玉纖輕。小屏古畫岸低平，"]'),
('yuding-10','遐方怨','顧夐','唐','御定全唐诗','yuding','','[]','簾影細，簟文平。象紗籠玉指，縷金羅扇輕。',72,'御定全唐詩/json/894.json','["簾影細，簟文平。象紗籠玉指，縷金羅扇輕。", "嫩紅雙臉似花明，兩條眉黛遠山橫。", "鳳簫歇，鏡塵生。遼塞音書絕，夢魂長暗驚。", "玉郎經歲負娉婷，教人爭不恨無情。"]'),
('yuding-11','訴衷情','顧夐','唐','御定全唐诗','yuding','','[]','香滅簾垂春漏永，整鴛衾。羅帶重，雙鳳，縷黃金。',89,'御定全唐詩/json/894.json','["香滅簾垂春漏永，整鴛衾。羅帶重，雙鳳，縷黃金。", "窗外月光臨，沉沉。斷腸無處尋，負春心。", "永夜拋人何處去，絕來音。香閣掩，眉斂，月將沈。", "爭忍不相尋，怨孤衾。換我心，為你心，始知相憶深。"]'),
('yuding-12','楊柳枝','顧夐','唐','御定全唐诗','yuding','','[]','秋夜香閨思寂寥，漏迢迢。鴛幃羅幌麝煙銷，燭光搖。',48,'御定全唐詩/json/894.json','["秋夜香閨思寂寥，漏迢迢。鴛幃羅幌麝煙銷，燭光搖。", "正憶玉郎遊蕩去，無尋處。更聞簾外雨瀟瀟，滴芭蕉。"]'),
('yuding-13','醉公子','顧夐','唐','御定全唐诗','yuding','','[]','漠漠秋雲澹，紅藕香侵檻。枕倚小山屏，金鋪向晚扃。',96,'御定全唐詩/json/894.json','["漠漠秋雲澹，紅藕香侵檻。枕倚小山屏，金鋪向晚扃。", "睡起橫波慢，獨望情何限。衰柳數聲蟬，魂銷似去年。", "岸柳垂金線，雨晴鶯百轉。家住綠楊邊，往來多少年。", "馬嘶芳草遠，高樓簾半卷。斂袖翠蛾攢，相逢爾許難。"]'),
('yuding-14','酒泉子','顧夐','唐','御定全唐诗','yuding','','[]','楊柳無風，輕惹春煙殘雨。杏花愁，鶯正語，畫樓東。',335,'御定全唐詩/json/894.json','["楊柳無風，輕惹春煙殘雨。杏花愁，鶯正語，畫樓東。", "錦屏寂寞思無窮，還是不知消息。鏡塵生，珠淚滴，", "羅帶縷金，蘭麝煙凝魂斷。畫屏欹，雲鬢亂，恨難任。", "幾回垂淚滴鴛衾，薄情何處去？月臨窗，花滿樹，", "小檻日斜，風度綠窗人悄悄。翠幃閑掩舞雙鸞，舊香寒。", "別來情緒轉難判，韶顏看卻老。依稀粉上有啼痕，暗銷魂。", "黛薄紅深，約掠綠鬟雲膩。小鴛鴦，金翡翠，稱人心。", "錦鱗無處傳幽意，海燕蘭堂春又去。來年書，千點淚，", "掩卻菱花，收拾翠鈿休上面。金蟲玉燕鎖香奩，恨厭厭。", "雲鬟半墜懶重篸，淚侵山枕濕。銀燈背帳夢方酣，", "水碧風清，入檻細香紅藕膩。謝娘斂翠恨無涯，小屏斜。", "堪憎蕩子不還家，謾留羅帶結。帳深枕膩炷沉煙，", "黛怨紅羞，掩映畫堂春欲暮。殘花微雨隔青樓，思悠悠。", "芳菲時節看將度，寂寞無人還獨語。畫羅襦，香粉汙，"]'),
('yuding-15','浣溪沙','顧夐','唐','御定全唐诗','yuding','','[]','春色迷人恨正賒，可堪蕩子不還家，細風輕露著梨花。',384,'御定全唐詩/json/894.json','["春色迷人恨正賒，可堪蕩子不還家，細風輕露著梨花。", "簾外有情雙燕揚，檻前無力綠楊斜，小屏狂夢極天涯。", "紅藕香寒翠渚平，月籠虛閣夜蛩清，塞鴻驚夢兩牽情。", "寶帳玉爐殘麝冷，羅衣金縷暗塵生，小窗孤燭淚縱橫。", "荷芰風輕簾幕香，繡衣鸂鶒泳回塘，小屏閑掩舊瀟湘。", "恨入空幃鸞影獨，淚凝雙臉渚蓮光，薄情年少悔思量。", "惆悵經年別謝娘，月窗花院好風光，此時相望最情傷。", "青鳥不來傳錦字，瑤姬何處鎖蘭房，忍教魂夢兩茫茫。", "庭菊飄黃玉露濃，冷莎偎砌隱鳴蛩，何期良夜得相逢。", "背帳風搖紅蠟滴，惹香暖夢繡衾重，覺來枕上怯晨鐘。", "雲澹風高葉亂飛，小庭寒雨綠苔微，深閨人靜掩屏帷。", "粉黛暗愁金帶枕，鴛鴦空繞畫羅衣，那堪孤負不思歸。", "雁響遙天玉漏清，小紗窗外月朧明，翠幃金鴨炷香平。", "何處不歸音信斷，良宵空使夢魂驚，簟涼枕冷不勝情。", "露白蟾明又到秋，佳期幽會兩悠悠，夢牽情役幾時休。", "記得泥人微斂黛，無言斜倚小書樓。暗思前事不勝愁。"]'),
('yuding-16','更漏子','顧夐','唐','御定全唐诗','yuding','','[]','舊歡娛，新悵望，擁鼻含嚬樓上。濃柳翠，晚霞微，',46,'御定全唐詩/json/894.json','["舊歡娛，新悵望，擁鼻含嚬樓上。濃柳翠，晚霞微，", "簾半卷，屏斜掩，遠岫參差迷眼。歌滿耳，酒盈尊，"]'),
('yuding-17','應天長','顧夐','唐','御定全唐诗','yuding','','[]','瑟瑟羅裙金線縷，輕透鵝黃香畫袴。垂交帶，盤鸚鵡，',50,'御定全唐詩/json/894.json','["瑟瑟羅裙金線縷，輕透鵝黃香畫袴。垂交帶，盤鸚鵡，", "背人勻檀注，慢轉嬌波偷覷。斂黛春情暗許，倚屏慵不語。"]'),
('yuding-18','漁歌子','顧夐','唐','御定全唐诗','yuding','','[]','曉風清，幽沼綠，倚闌凝望珍禽浴。畫簾垂，翠屏曲，',48,'御定全唐詩/json/894.json','["曉風清，幽沼綠，倚闌凝望珍禽浴。畫簾垂，翠屏曲，", "好攄懷，堪寓目，身閒心靜平生足。酒杯深，光影促，"]'),
('yuding-19','河傳','顧夐','唐','御定全唐诗','yuding','','[]','燕揚晴景。小窗屏暖，鴛鴦交頸。菱花掩卻翠鬟欹，',146,'御定全唐詩/json/894.json','["燕揚晴景。小窗屏暖，鴛鴦交頸。菱花掩卻翠鬟欹，", "繡幃香斷金鸂鶒。無消息，心事空相憶。倚東風，", "曲檻，春晚。碧流紋細，綠楊絲軟。露華鮮，杏枝繁。", "鶯轉，野蕪平似剪。", "直是人間到天上，堪遊賞，醉眼疑屏障。對池塘，", "棹舉，舟去。波光渺渺，不知何處。岸花汀草共依依，", "天涯離恨江聲咽，啼猿切，此意向誰說？倚蘭橈，"]'),
('yuding-20','木蘭花','顧夐','唐','御定全唐诗','yuding','','[]','月照玉樓春漏促，颯颯風搖庭砌竹。夢驚鴛被覺來時，',192,'御定全唐詩/json/894.json','["月照玉樓春漏促，颯颯風搖庭砌竹。夢驚鴛被覺來時，", "惆悵少年游冶去，枕上兩蛾攢細綠。曉鶯簾外語花枝，", "柳映玉樓春日晚，雨細風輕煙草軟。畫堂鸚鵡語雕籠，", "香滅繡幃人寂寂，倚檻無言愁思遠。恨郎何處縱疏狂，", "月皎露華窗影細，風送菊香黏繡袂。博山爐冷水沉微，", "懶展羅衾垂玉箸，羞對菱花篸寶髻。良宵好事枉教休，", "拂水雙飛來去燕，曲檻小屏山六扇。春愁凝思結眉心，", "話別情多聲欲戰，玉箸痕留紅粉面。鎮長獨立到黃昏，"]'),
('yuding-21','虞美人','顧夐','唐','御定全唐诗','yuding','','[]','曉鶯啼破相思夢，簾卷金泥鳳。宿妝猶在酒初醒，',264,'御定全唐詩/json/894.json','["曉鶯啼破相思夢，簾卷金泥鳳。宿妝猶在酒初醒，", "香檀細畫侵桃臉，羅袂輕輕斂。佳期堪恨再難尋，", "觸簾風送景陽鐘，鴛被繡花重。曉幃初卷冷煙濃，", "起來無語理朝妝，寶匣鏡凝光。綠荷相倚滿池塘，", "翠屏閑掩垂珠箔，絲雨籠池閣。露粘紅藕咽清香，", "小金鸂鶒沈煙細，膩枕堆雲髻。淺眉微斂注檀輕，", "碧梧桐映紗窗晚，花謝鶯聲懶。小屏屈曲掩青山，", "顛狂年少輕離別，孤負春時節。畫羅紅袂有啼痕，", "深閨春色勞思想，恨共春蕪長。黃鸝嬌轉泥芳妍，", "憑闌愁立雙蛾細，柳影斜搖砌。玉郎還是不還家，", "少年豔質勝瓊英，早晚別三清。蓮冠穩篸鈿篦橫，", "遲遲少轉腰身嫋，翠靨眉心小。醮壇風急杏枝香，"]'),
('yuding-22','臨江仙','顧夐','唐','御定全唐诗','yuding','','[]','碧染長空池似鏡，倚樓閑望凝情。滿衣紅藕細香清。',208,'御定全唐詩/json/894.json','["碧染長空池似鏡，倚樓閑望凝情。滿衣紅藕細香清。", "象床珍簟，山障掩，玉琴橫。", "暗想昔時歡笑事，如今贏得愁生。博山爐暖澹煙輕。", "蟬吟人靜，殘日傍，小窗明。", "幽閨小檻春光晚，柳濃花澹鶯稀。舊歡思想尚依依。", "翠嚬紅斂，終日損芳菲。", "何事狂夫音信斷，不如梁燕猶歸。畫堂深處麝煙微。", "屏虛枕冷，風細雨霏霏。", "月色穿簾風入竹，倚屏雙黛愁時。砌花含露兩三枝。", "如啼恨臉，魂斷損容儀。", "香燼暗銷金鴨冷，可堪孤負前期。繡襦不整鬢鬟欹。", "幾多惆悵，情緒在天涯。"]'),
('yuding-23','獻衷心','顧夐','唐','御定全唐诗','yuding','','[]','繡鴛鴦帳暖，畫孔雀屏欹。人悄悄，月明時。',70,'御定全唐詩/json/894.json','["繡鴛鴦帳暖，畫孔雀屏欹。人悄悄，月明時。", "想昔年歡笑，恨今日分離。銀釭背，銅漏永，阻佳期。", "小爐煙細，虛閣簾垂。幾多心事，暗地思惟。被嬌娥牽役，"]'),
('yuding-24','女冠子','鹿虔扆','唐','御定全唐诗','yuding','','[]','鳳樓琪樹，惆悵劉郎一去。正春深，洞裏愁空結，',88,'御定全唐詩/json/894.json','["鳳樓琪樹，惆悵劉郎一去。正春深，洞裏愁空結，", "竹疏齋殿迥，松密醮壇陰。倚雲低首望，可知心。", "步虛壇上，絳節霓旌相向。引真仙，玉佩搖蟾影，", "露濃霜簡濕，風緊羽衣偏。欲留難得住，卻歸天。"]'),
('yuding-25','思越人','鹿虔扆','唐','御定全唐诗','yuding','','[]','翠屏欹，銀燭背，漏殘清夜迢迢。雙帶繡窠盤錦薦，',46,'御定全唐詩/json/894.json','["翠屏欹，銀燭背，漏殘清夜迢迢。雙帶繡窠盤錦薦，", "珊瑚枕膩鴉鬟亂，玉纖慵整雲散。苦是適來新夢見，"]'),
('yuding-26','虞美人','鹿虔扆','唐','御定全唐诗','yuding','','[]','卷荷香澹浮煙渚，綠嫩擎新雨。瑣窗疏透曉風清，',44,'御定全唐詩/json/894.json','["卷荷香澹浮煙渚，綠嫩擎新雨。瑣窗疏透曉風清，", "九疑黛色屏斜掩，枕上眉心斂。不堪相望病將成，"]'),
('yuding-27','臨江仙','鹿虔扆','唐','御定全唐诗','yuding','','[]','金鎖重門荒苑靜，綺窗愁對秋空。翠華一去寂無蹤。',136,'御定全唐詩/json/894.json','["金鎖重門荒苑靜，綺窗愁對秋空。翠華一去寂無蹤。", "玉樓歌吹，聲斷已隨風。", "煙月不知人事改，夜闌還照深宮。藕花相向野塘中。", "暗傷亡國，清露泣香紅。", "無賴曉鶯驚夢斷，起來殘酒初醒。映窗絲柳嫋煙青。", "翠簾慵卷，約砌杏花零。", "一自玉郎遊冶去，蓮凋月慘儀形。暮天微雨灑閒庭。", "手挪裙帶，無語倚雲屏。"]'),
('yuding-0','訴衷情','魏承班','唐','御定全唐诗','yuding','','[]','高歌宴罷月初盈，詩情引恨情。煙露冷，水流輕，',220,'御定全唐詩/json/895.json','["高歌宴罷月初盈，詩情引恨情。煙露冷，水流輕，", "羅帳嫋香平，恨頻生。思君無計睡還醒，隔層城。", "春深花簇小樓臺，風飄錦繡開。新睡覺，步香階，", "鬢亂墜金釵，語檀偎。臨行執手重重屬，幾千回。", "銀漢雲情玉漏長，蛩聲悄畫堂。筠簟冷，碧窗涼，", "皓月瀉寒光，割人腸。那堪獨自步池塘，對鴛鴦。", "金風輕透碧窗紗，銀釭焰影斜。欹枕臥，恨何賒，", "雲雨別吳娃，想容華。夢成幾度繞天涯，到君家。", "春情滿眼臉紅消，嬌妒索人饒。星靨小，玉璫搖，", "別後憶纖腰，夢魂勞。如今風葉又蕭蕭，恨迢迢。"]'),
('yuding-1','生查子','魏承班','唐','御定全唐诗','yuding','','[]','煙雨晚晴天，零落花無語。難話此時心，梁燕雙來去。',146,'御定全唐詩/json/895.json','["煙雨晚晴天，零落花無語。難話此時心，梁燕雙來去。", "琴韻對熏風，有恨和情撫。腸斷斷弦頻，淚滴黃金縷。", "寂寞畫堂空，深夜垂羅幕。燈暗錦屏欹，月冷珠簾薄。", "愁恨夢難成，何處貪歡樂。看看又春來，還是長蕭索。", "離別又經年，獨對芳菲景。嫁得薄情夫，長抱相思病。", "花紅柳綠間晴空，蝶舞雙雙影。羞看繡羅衣，為有金鸞並。"]'),
('yuding-2','菩薩蠻','魏承班','唐','御定全唐诗','yuding','','[]','羅裾薄薄秋波染，眉間畫得山兩點。相見綺筵時，',138,'御定全唐詩/json/895.json','["羅裾薄薄秋波染，眉間畫得山兩點。相見綺筵時，", "翠翹雲鬢動，斂態彈金鳳。宴罷入蘭房，邀人解佩璫。", "羅衣隱約金泥畫，玳筵一曲當秋夜。聲顫覷人嬌，", "酒醺紅玉軟，眉翠秋山遠。繡幌麝煙沈，誰人知兩心。", "玉容光照菱花影，沉沉臉上秋波冷。白雪一聲新，", "寶釵搖翡翠，香惹芙蓉醉。攜手入鴛衾，誰人知此心。"]'),
('yuding-3','漁歌子','魏承班','唐','御定全唐诗','yuding','','[]','柳如眉，雲似發，鮫綃霧縠籠香雪。夢魂驚，鐘漏歇，',48,'御定全唐詩/json/895.json','["柳如眉，雲似發，鮫綃霧縠籠香雪。夢魂驚，鐘漏歇，", "幾多情，無處說，落花飛絮清明節。少年郎，容易別，"]'),
('yuding-4','滿宮花','魏承班','唐','御定全唐诗','yuding','','[]','雪霏霏，風凜凜，玉郎何處狂飲？醉時想得縱風流，',92,'御定全唐詩/json/895.json','["雪霏霏，風凜凜，玉郎何處狂飲？醉時想得縱風流，", "春朝秋夜思君甚，愁見繡屏孤枕。少年何事負初心，", "寒夜長，更漏永，愁見透簾月影。王孫何處不歸來，", "金鴨無香羅帳冷，羞更雙鸞交頸。夢中幾度見兒夫，"]'),
('yuding-5','謁金門','魏承班','唐','御定全唐诗','yuding','','[]','煙水闊，人值清明時節，雨細花零鶯語切，愁腸千萬結。',189,'御定全唐詩/json/895.json','["煙水闊，人值清明時節，雨細花零鶯語切，愁腸千萬結。", "雁去音徽斷絕，有恨欲憑誰說？無事傷心猶不徹，", "春欲半，堆砌落花千片。早是潘郎長不見，忍聽雙語燕。", "飛絮晴空颺遠，風送誰家弦管？愁倚畫屏凡事懶，", "長思憶，思憶佳辰輕擲。霜月透簾澄夜色，小屏山凝碧。", "恨恨君何太極，記得嬌嬈無力。獨坐思量愁似織，", "小芙蓉，香旖旎，碧玉堂深清似水。閉寶匣，掩金鋪，", "遲遲好景煙花媚，曲渚鴛鴦眠錦翅。凝然愁望靜相思，"]'),
('yuding-6','玉樓春','魏承班','唐','御定全唐诗','yuding','','[]','寂寂畫堂梁上燕，高卷翠簾橫數扇。一庭春色惱人來，',96,'御定全唐詩/json/895.json','["寂寂畫堂梁上燕，高卷翠簾橫數扇。一庭春色惱人來，", "愁倚錦屏低雪面，淚滴繡羅金縷線。好天涼月盡傷心，", "輕斂翠蛾呈皓齒，鶯轉一枝花影裏。聲聲清迥遏行雲，", "玉斝滿斟情未已，促坐王孫公子醉。春風筵上貫珠勻，"]'),
('yuding-7','黃鐘樂','魏承班','唐','御定全唐诗','yuding','','[]','池塘煙暖草萋萋，惆悵閑宵含恨，愁坐思堪迷。',74,'御定全唐詩/json/895.json','["池塘煙暖草萋萋，惆悵閑宵含恨，愁坐思堪迷。", "遙想玉人情事遠，音容渾似隔桃溪。", "偏記同歡秋月低，簾外論心花畔，和醉暗相攜。", "何事春來君不見，夢魂長在錦江西。"]'),
('yuding-8','江城子','尹鶚','唐','御定全唐诗','yuding','','[]','裙拖碧，步飄香，織腰束素長。鬢雲光，拂面瓏璁，',23,'御定全唐詩/json/895.json','["裙拖碧，步飄香，織腰束素長。鬢雲光，拂面瓏璁，"]'),
('yuding-9','何滿子','尹鶚','唐','御定全唐诗','yuding','','[]','雲雨常陪勝會，笙歌慣逐閒遊。錦裏風光應占，',43,'御定全唐詩/json/895.json','["雲雨常陪勝會，笙歌慣逐閒遊。錦裏風光應占，", "方喜正同鴛帳，又言將往皇州。每憶良宵公子伴，"]'),
('yuding-10','醉公子','尹鶚','唐','御定全唐诗','yuding','','[]','暮煙籠蘚砌，戟門猶未閉。盡日醉尋春，歸來月滿身。',48,'御定全唐詩/json/895.json','["暮煙籠蘚砌，戟門猶未閉。盡日醉尋春，歸來月滿身。", "離鞍偎繡袂，墜巾花亂綴。何處惱佳人，檀痕衣上新。"]'),
('yuding-11','女冠子','尹鶚','唐','御定全唐诗','yuding','','[]','雙成伴侶，去去不知何處。有佳期，霞帔金絲薄，',44,'御定全唐詩/json/895.json','["雙成伴侶，去去不知何處。有佳期，霞帔金絲薄，", "懶乘丹鳳子，學跨小龍兒。叵耐天風緊，挫腰肢。"]'),
('yuding-12','菩薩蠻','尹鶚','唐','御定全唐诗','yuding','','[]','隴雲暗合秋天白，俯窗獨坐窺煙陌。樓際角重吹，',138,'御定全唐詩/json/895.json','["隴雲暗合秋天白，俯窗獨坐窺煙陌。樓際角重吹，", "荒唐難共語，明日還應去。上馬出門時，金鞭莫與伊。", "嗚嗚曉角調如語，畫樓三會喧雷鼓。枕上夢方殘，", "蛾眉應斂翠，咫尺同千里。宿酒未全消，滿懷離恨饒。", "錦茵閑襯丁香枕，銀釭燼落猶慵寢。顒坐遍紅爐，", "少年狂蕩慣，花曲長牽絆。去便不歸來，空教駿馬回。"]'),
('yuding-13','杏園芳','尹鶚','唐','御定全唐诗','yuding','','[]','嚴妝嫩臉花明，教人見了關情。含羞舉步越羅輕，稱娉婷。',49,'御定全唐詩/json/895.json','["嚴妝嫩臉花明，教人見了關情。含羞舉步越羅輕，稱娉婷。", "終朝咫尺窺香閣，迢遙似隔層城。何時休遣夢相縈，"]'),
('yuding-14','清平樂','尹鶚','唐','御定全唐诗','yuding','','[]','偎紅斂翠，盡日思閒事。髻滑鳳凰釵欲墜，雨打梨花滿地。',94,'御定全唐詩/json/895.json','["偎紅斂翠，盡日思閒事。髻滑鳳凰釵欲墜，雨打梨花滿地。", "繡衣獨倚闌幹，玉容似怯春寒。應待少年公子，", "芳年妙妓，淡拂鉛華翠。輕笑自然生百媚，爭那尊前人意。", "酒傾琥珀杯時，更堪能唱新詞。賺得王孫狂處，"]'),
('yuding-15','滿宮花','尹鶚','唐','御定全唐诗','yuding','','[]','月沉沉，人悄悄，一炷後庭香嫋。風流帝子不歸來，',46,'御定全唐詩/json/895.json','["月沉沉，人悄悄，一炷後庭香嫋。風流帝子不歸來，", "離恨多，相見少，何處醉迷三島？漏清宮樹子規啼，"]'),
('yuding-16','臨江仙','尹鶚','唐','御定全唐诗','yuding','','[]','一番荷芰生池沼，檻前風送馨香。昔年于此伴蕭娘。',136,'御定全唐詩/json/895.json','["一番荷芰生池沼，檻前風送馨香。昔年于此伴蕭娘。", "相偎佇立，牽惹敘衷腸。", "時逞笑容無限態，還如菡萏爭芳。別來虛遣思悠颺。", "慵窺往事，金鎖小蘭房。", "深秋寒夜銀河靜，月明深院中庭。西窗幽夢等閒成。", "逡巡覺後，特地恨難平。", "紅燭半條殘焰短，依稀暗背銀屏。枕前何事最傷情？", "梧桐葉上，點點露珠零。"]'),
('yuding-17','撥棹子','尹鶚','唐','御定全唐诗','yuding','','[]','風切切，深秋月，十朵芙蓉繁豔歇。小檻細腰無力，',134,'御定全唐詩/json/895.json','["風切切，深秋月，十朵芙蓉繁豔歇。小檻細腰無力，", "寸心恰似丁香結，看看瘦盡胸前雪。偏掛恨，少年拋擲。", "羞睹見，繡被堆紅閑不徹。", "丹臉膩，雙靨媚，冠子縷金裝翡翠。將一朵，瓊花堪比。", "窠窠繡，鸞鳳衣裳香窣地。", "銀台蠟燭滴紅淚，醁酒勸人教半醉。簾幕外，月華如水。", "特地向，寶帳顛狂不肯睡。"]'),
('yuding-18','秋夜月','尹鶚','唐','御定全唐诗','yuding','','[]','三秋佳節，罥晴空，凝碎露，茱萸千結。菊蕊和煙輕撚，',64,'御定全唐詩/json/895.json','["三秋佳節，罥晴空，凝碎露，茱萸千結。菊蕊和煙輕撚，", "一片豔歌聲揭。", "黃昏慵別，炷沉煙，熏繡被，翠帷同歇。醉並鴛鴦雙枕，", "窗透數條斜月。"]'),
('yuding-19','金浮圖','尹鶚','唐','御定全唐诗','yuding','','[]','繁華地，王孫富貴。玳瑁筵開，下朝無事。壓紅茵、',96,'御定全唐詩/json/895.json','["繁華地，王孫富貴。玳瑁筵開，下朝無事。壓紅茵、", "鳳舞黃金翅。玉立纖腰，一片揭天歌吹。滿目綺羅珠翠。", "和風淡蕩，偷散沉檀氣。", "堪判醉，韶光正媚。折盡牡丹，豔迷人意，", "還惜會難別易，金船更勸，勒住花驄轡。"]'),
('yuding-20','定西番','毛熙震','唐','御定全唐诗','yuding','','[]','蒼翠濃陰滿院，鶯對語，蝶交飛，戲薔薇。',43,'御定全唐詩/json/895.json','["蒼翠濃陰滿院，鶯對語，蝶交飛，戲薔薇。", "斜日倚闌風好，餘香出繡衣。未得玉郎消息，幾時歸。"]'),
('yuding-21','何滿子','毛熙震','唐','御定全唐诗','yuding','','[]','寂寞芳菲暗度，歲華如箭堪驚。緬想舊歡多少事，',88,'御定全唐詩/json/895.json','["寂寞芳菲暗度，歲華如箭堪驚。緬想舊歡多少事，", "深院空聞燕語，滿園閑落花輕。一片相思休不得，", "無語殘妝澹薄，含羞嚲袂輕盈。幾度香閨眠過曉，", "笑靨嫩疑花拆，愁眉翠斂山橫。相望只教添悵恨，"]'),
('yuding-22','女冠子','毛熙震','唐','御定全唐诗','yuding','','[]','碧桃紅杏，遲日媚籠光影。彩霞深，香暖熏鶯語，',88,'御定全唐詩/json/895.json','["碧桃紅杏，遲日媚籠光影。彩霞深，香暖熏鶯語，", "翠鬟冠玉葉，霓袖捧瑤琴。應共吹簫侶，暗相尋。", "修蛾慢臉，不語檀心一點。小山妝，蟬鬢低含綠，", "悶來深院裏，閒步落花傍。纖手輕輕整，玉爐香。"]'),
('yuding-23','酒泉子','毛熙震','唐','御定全唐诗','yuding','','[]','閑臥繡幃，慵想萬般情寵。錦檀偏，翹股重，翠雲欹。',100,'御定全唐詩/json/895.json','["閑臥繡幃，慵想萬般情寵。錦檀偏，翹股重，翠雲欹。", "暮天屏上春山碧，映香煙霧隔。蕙蘭心，魂夢役，斂蛾眉。", "鈿匣舞鸞，隱映豔紅修碧。月梳斜，雲鬢膩，粉香寒。", "曉花微斂輕呵展，嫋釵金燕軟。日初升，簾半卷，對妝殘。"]'),
('yuding-24','浣溪沙','毛熙震','唐','御定全唐诗','yuding','','[]','春暮黃鶯下砌前，水精簾影露珠懸，綺霞低映晚晴天。',336,'御定全唐詩/json/895.json','["春暮黃鶯下砌前，水精簾影露珠懸，綺霞低映晚晴天。", "弱柳萬條垂翠帶，殘紅滿地碎香鈿，蕙風飄蕩散輕煙。", "花榭香紅煙景迷，滿庭芳草綠萋萋，金鋪閑掩繡簾低。", "紫燕一雙嬌語碎，翠屏十二晚峰齊，夢魂消散醉空閨。", "晚起紅房醉欲消，綠鬟雲散嫋金翹，雪香花語不勝嬌。", "好是向人柔弱處，玉纖時急繡裙腰，春心牽惹轉無憀。", "一隻橫釵墜髻叢，靜眠珍簟起來慵，繡羅紅嫩抹蘇胸。", "羞斂細蛾魂暗斷，困迷無語思猶濃，小屏香靄碧山重。", "雲薄羅裙綬帶長，滿身新裛瑞龍香，翠鈿斜映豔梅妝。", "佯不覷人空婉約，笑和嬌語太倡狂，忍教牽恨暗形相。", "碧玉冠輕嫋燕釵，捧心無語步香階，緩移弓底繡羅鞋。", "暗想歡娛何計好，豈堪期約有時乖，日高深院正忘懷。", "半醉凝情臥繡茵，睡容無力卸羅裙，玉籠鸚鵡厭聽聞。", "慵整落釵金翡翠，象梳欹鬢月生雲，錦屏綃幌麝煙熏。"]'),
('yuding-25','後庭花','毛熙震','唐','御定全唐诗','yuding','','[]','鶯啼燕語芳菲節，瑞庭花發。昔時歡宴歌聲揭，管弦清越。',156,'御定全唐詩/json/895.json','["鶯啼燕語芳菲節，瑞庭花發。昔時歡宴歌聲揭，管弦清越。", "自從陵谷追遊歇，畫梁塵黦。傷心一片如珪月，閑鎖宮闕。", "輕盈舞伎含芳豔，競妝新臉。步搖珠翠修蛾斂，膩鬟雲染。", "歌聲慢發開檀點，繡衫斜掩。時將纖手勻紅臉，笑拈金靨。", "越羅小袖新香蒨，薄籠金釧。倚闌無語搖輕扇，半遮勻面。", "春殘日暖鶯嬌懶，滿庭花片。爭不教人長相見，畫堂深院。"]'),
('yuding-26','菩薩蠻','毛熙震','唐','御定全唐诗','yuding','','[]','梨花滿院飄香雪，高樓夜靜風箏咽。斜月照簾帷，',138,'御定全唐詩/json/895.json','["梨花滿院飄香雪，高樓夜靜風箏咽。斜月照簾帷，", "小窗燈影背，燕語驚愁態。屏掩斷香飛，行雲山外歸。", "繡簾高軸臨塘看，雨翻荷芰真珠散。殘暑晚初涼，", "無憀悲往事，爭那牽情思。光影暗相催，等閒秋又來。", "天含殘碧融春色，五陵薄幸無消息。盡日掩朱門，", "鶯啼芳樹暖，燕拂回塘滿。寂寞對屏山，相思醉夢間。"]'),
('yuding-27','清平樂','毛熙震','唐','御定全唐诗','yuding','','[]','春光欲暮，寂寞閒庭戶。粉蝶雙雙穿檻舞，簾卷晚天疏雨。',47,'御定全唐詩/json/895.json','["春光欲暮，寂寞閒庭戶。粉蝶雙雙穿檻舞，簾卷晚天疏雨。", "含愁獨倚閨幃，玉爐煙斷香微。正是銷魂時節，"]'),
('yuding-28','更漏子','毛熙震','唐','御定全唐诗','yuding','','[]','秋色清，河影淡，深戶燭寒光暗。綃幌碧，錦衾紅，',92,'御定全唐詩/json/895.json','["秋色清，河影淡，深戶燭寒光暗。綃幌碧，錦衾紅，", "更漏咽，蛩鳴切，滿院霜華如雪。新月上，薄雲收，", "煙月寒，秋夜靜，漏轉金壺初永。羅幕下，繡屏空，", "人悄悄，愁無了，思夢不成難曉。長憶得，與郎期，"]'),
('yuding-29','南歌子','毛熙震','唐','御定全唐诗','yuding','','[]','遠山愁黛碧，橫波慢臉明。膩香紅玉茜羅輕，',80,'御定全唐詩/json/895.json','["遠山愁黛碧，橫波慢臉明。膩香紅玉茜羅輕，", "鬢動行雲影，裙遮點屐聲。嬌羞愛問曲中名，", "惹恨還添恨，牽腸即斷腸。凝情不語一枝芳，", "暗想為雲女，應憐傅粉郎。晚來輕步出閨房，"]'),
('yuding-30','木蘭花','毛熙震','唐','御定全唐诗','yuding','','[]','掩朱扉，鉤翠箔，滿院鶯聲春寂寞。勻粉淚，恨檀郎，',48,'御定全唐詩/json/895.json','["掩朱扉，鉤翠箔，滿院鶯聲春寂寞。勻粉淚，恨檀郎，", "對斜暉，臨小閣，前事豈堪重想著。金帶冷，畫屏幽，"]'),
('yuding-31','小重山','毛熙震','唐','御定全唐诗','yuding','','[]','梁燕雙飛畫閣前，寂寥多少恨、懶孤眠。',70,'御定全唐詩/json/895.json','["梁燕雙飛畫閣前，寂寥多少恨、懶孤眠。", "曉來閑處想君憐，紅羅帳、金鴨冷沉煙。", "誰信損嬋娟，倚屏啼玉箸、濕香鈿。", "四支無力上秋千，群花謝、愁對豔陽天。"]'),
('yuding-32','臨江仙','毛熙震','唐','御定全唐诗','yuding','','[]','南齊天子寵嬋娟，六宮羅綺三千。潘妃嬌豔獨芳妍。',136,'御定全唐詩/json/895.json','["南齊天子寵嬋娟，六宮羅綺三千。潘妃嬌豔獨芳妍。", "椒房蘭洞，雲雨降神仙。", "縱態迷歡心不足，風流可惜當年。纖腰婉約步金蓮。", "妖君傾國，猶自至今傳。", "幽閨欲曙聞鶯轉，紅窗月影微明。好風頻謝落花聲。", "隔幃殘燭，猶照綺屏箏。", "繡被錦茵眠玉暖，炷香斜嫋煙輕。淡蛾羞斂不勝情。", "暗思閑夢，何處逐行雲。"]'),
('yuding-0','漁父','李珣','唐','御定全唐诗','yuding','','[]','水接衡門十裏餘，信船歸去臥看書。輕爵祿，慕玄虛，',72,'御定全唐詩/json/896.json','["水接衡門十裏餘，信船歸去臥看書。輕爵祿，慕玄虛，", "避世垂綸不記年，官高爭得似君閑。傾白酒，對青山，", "棹警鷗飛水濺袍，影隨潭面柳垂絛。終日醉，絕塵勞，"]'),
('yuding-1','南鄉子','李珣','唐','御定全唐诗','yuding','','[]','煙漠漠，雨淒淒，岸花零落鷓鴣啼。遠客扁舟臨野渡，',408,'御定全唐詩/json/896.json','["煙漠漠，雨淒淒，岸花零落鷓鴣啼。遠客扁舟臨野渡，", "蘭橈舉，水文開，競攜藤籠採蓮來。回塘深處遙相見，", "歸路近，扣舷歌，采真珠處水風多。曲岸小橋山月過，", "乘彩舫，過蓮塘，棹歌驚起睡鴛鴦。帶香遊女偎伴笑，", "傾綠蟻，泛紅螺，閑邀女伴簇笙歌。避暑信船輕浪裏，", "雲帶雨，浪迎風，釣翁回棹碧灣中。春酒香熟鱸魚美，", "沙月靜，水煙輕，芰荷香裏夜船行。綠鬟紅臉誰家女，", "漁市散，渡船稀，越南雲樹望中微。行客待潮天欲暮，", "攏雲髻，背犀梳，焦紅衫映綠羅裾。越王台下春風暖，", "相見處，晚晴天，刺桐花下越台前。暗裏回眸深屬意，", "攜籠去，采菱歸，碧波風起雨霏霏。趁岸小船齊棹急，", "雲髻重，葛衣輕，見人微笑亦多情。拾翠采珠能幾許，", "登畫舸，泛清波，採蓮時唱採蓮歌。攔棹聲齊羅袖斂，", "雙髻墜，小眉彎，笑隨女伴下春山。玉纖遙指花深處，", "紅豆蔻，紫玫瑰，謝娘家接越王台。一曲鄉歌齊撫掌，", "山果熟，水花香，家家風景有池塘。木蘭舟上珠簾卷，", "新月上，遠煙開，慣隨潮水采珠來。棹穿花過歸溪口，"]'),
('yuding-2','西溪子','李珣','唐','御定全唐诗','yuding','','[]','金縷翠鈿浮動，妝罷小窗圓夢。日高時，春已老，',44,'御定全唐詩/json/896.json','["金縷翠鈿浮動，妝罷小窗圓夢。日高時，春已老，", "馬上見時如夢，認得臉波相送。柳堤長，無限意，"]'),
('yuding-3','女冠子','李珣','唐','御定全唐诗','yuding','','[]','星高月午，丹桂青松深處。醮壇開，金磬敲清露，',88,'御定全唐詩/json/896.json','["星高月午，丹桂青松深處。醮壇開，金磬敲清露，", "步虛聲縹緲，想像思徘徊。曉天歸去路，指蓬萊。", "春山夜靜，愁聞洞天疏磬。玉堂虛，細霧垂珠佩，", "對花情脈脈，望月步徐徐。劉阮今何處，絕來書。"]'),
('yuding-4','中興樂','李珣','唐','御定全唐诗','yuding','','[]','後庭寂寂日初長，翩翩蝶舞紅芳。繡簾垂地，金鴨無香。',102,'御定全唐詩/json/896.json','["後庭寂寂日初長，翩翩蝶舞紅芳。繡簾垂地，金鴨無香。", "誰知春思如狂，憶蕭郎。等閒一去，程遙信斷，五嶺三湘。", "休開鸞鏡學宮妝，可能更理笙簧。倚屏凝睇，淚落成行。", "手尋裙帶鴛鴦，暗思量。忍孤前約，教人花貌，虛老風光。"]'),
('yuding-5','酒泉子','李珣','唐','御定全唐诗','yuding','','[]','寂寞青樓，風觸繡簾珠碎撼。月朦朧，花暗澹，鎖春愁。',193,'御定全唐詩/json/896.json','["寂寞青樓，風觸繡簾珠碎撼。月朦朧，花暗澹，鎖春愁。", "尋思往事依稀夢，淚臉露桃紅色重。鬢欹蟬，釵墜鳳，", "雨漬花零，紅散香凋池兩岸。別情遙，春歌斷，掩銀屏。", "孤帆早晚離三楚，閑理鈿箏愁幾許。曲中情，弦上語，", "秋雨連綿，聲散敗荷叢裏，那堪深夜枕前聽，酒初醒。", "牽愁惹思更無停，燭暗香凝天欲曙。細和煙，冷和雨，", "秋月嬋娟，皎潔碧紗窗外，照花穿竹冷沉沉，印池心。", "凝露滴，砌蛩吟。驚覺謝娘殘夢，夜深斜傍枕前來，"]'),
('yuding-6','浣溪沙','李珣','唐','御定全唐诗','yuding','','[]','入夏偏宜澹薄妝，越羅衣褪鬱金黃，翠鈿檀注助容光。',192,'御定全唐詩/json/896.json','["入夏偏宜澹薄妝，越羅衣褪鬱金黃，翠鈿檀注助容光。", "相見無言還有恨，幾回判卻又思量，月窗香徑夢悠颺。", "晚出閒庭看海棠，風流學得內家妝，小釵橫戴一枝芳。", "鏤玉梳斜雲鬢膩，縷金衣透雪肌香，暗思何事立殘陽。", "訪舊傷離欲斷魂，無因重見玉樓人，六街微雨鏤香塵。", "早為不逢巫峽夢，那堪虛度錦江春，遇花傾酒莫辭頻。", "紅藕花香到檻頻，可堪閑憶似花人，舊歡如夢絕音塵。", "翠疊畫屏山隱隱，冷鋪文簟水潾潾，斷魂何處一蟬新。"]'),
('yuding-7','巫山一段雲','李珣','唐','御定全唐诗','yuding','','[]','有客經巫峽，停橈向水湄。楚王曾此夢瑤姬，一夢杳無期。',104,'御定全唐詩/json/896.json','["有客經巫峽，停橈向水湄。楚王曾此夢瑤姬，一夢杳無期。", "塵暗珠簾卷，香銷翠幄垂。西風回首不勝悲，暮雨灑空祠。", "古廟依青嶂，行宮枕碧流。水聲山色鎖妝樓，往事思悠悠。", "雲雨朝還暮，煙花春複秋。啼猿何必近孤舟，行客自多愁。"]'),
('yuding-8','菩薩蠻','李珣','唐','御定全唐诗','yuding','','[]','回塘風起波文細，刺桐花裏門斜閉。殘日照平蕪，',138,'御定全唐詩/json/896.json','["回塘風起波文細，刺桐花裏門斜閉。殘日照平蕪，", "征帆何處客，相見還相隔。不語欲魂銷，望中煙水遙。", "等閒將度三春景，簾垂碧砌參差影。曲檻日初斜，", "恨君容易處，又話瀟湘去。凝思倚屏山，淚流紅臉斑。", "隔簾微雨雙飛燕，砌花零落紅深淺。撚得寶箏調，", "楚天雲外路，動便經年去。香斷畫屏深，舊歡何處尋。"]'),
('yuding-9','漁歌子','李珣','唐','御定全唐诗','yuding','','[]','楚山青，湘水淥，春風澹蕩看不足。草芊芊，花簇簇，',192,'御定全唐詩/json/896.json','["楚山青，湘水淥，春風澹蕩看不足。草芊芊，花簇簇，", "信浮沉，無管束，釣回乘月歸灣曲。酒盈尊，雲滿屋，", "荻花秋，瀟湘夜，橘洲佳景如屏畫。碧煙中，明月下，", "水為鄉，蓬作舍，魚羹稻飯常餐也。酒盈杯，書滿架，", "柳垂絲，花滿樹，鶯啼楚岸春天暮。棹輕舟，出深浦，", "罷垂綸，還酌醑，孤村遙指雲遮處。下長汀，臨深渡，", "九疑山，三湘水，蘆花時節秋風起。水雲間，山月裏，", "鼓清琴，傾淥蟻，扁舟自得逍遙志。任東西，無定止，"]'),
('yuding-10','望遠行','李珣','唐','御定全唐诗','yuding','','[]','春日遲遲思寂寥，行客關山路遙。瓊窗時聽語鶯嬌，',92,'御定全唐詩/json/896.json','["春日遲遲思寂寥，行客關山路遙。瓊窗時聽語鶯嬌，", "休暈繡，罷吹簫，貌逐殘花暗凋。同心猶結舊裙腰，", "露滴幽庭落葉時，愁聚蕭娘柳眉。玉郎一去負佳期，", "屏半掩，枕斜欹，蠟淚無言對垂。吟跫斷續漏頻移，"]'),
('yuding-11','河傳','李珣','唐','御定全唐诗','yuding','','[]','去去，何處，迢迢巴楚，山水相連。朝雲暮雨，',101,'御定全唐詩/json/896.json','["去去，何處，迢迢巴楚，山水相連。朝雲暮雨，", "愁腸豈異丁香結，因離別，故國音書絕。想佳人花下。", "對明月春風，恨應同。", "春暮，微雨，送君南浦，愁斂雙蛾。落花深處，", "臨流更把同心結。情哽咽，後會何時節？不堪回首相望，"]'),
('yuding-12','虞美人','李珣','唐','御定全唐诗','yuding','','[]','金籠鶯報天將曙，驚起分飛處。夜來潛與玉郎期，',44,'御定全唐詩/json/896.json','["金籠鶯報天將曙，驚起分飛處。夜來潛與玉郎期，", "映花避月遙相送，膩髻偏垂鳳。卻回嬌步入香閨，"]'),
('yuding-13','臨江仙','李珣','唐','御定全唐诗','yuding','','[]','簾卷池心小閣虛，暫涼閒步徐徐。芰荷經雨半凋疏。',136,'御定全唐詩/json/896.json','["簾卷池心小閣虛，暫涼閒步徐徐。芰荷經雨半凋疏。", "拂堤垂柳，蟬噪夕陽餘。", "不語低鬟幽思遠，玉釵斜墜雙魚。幾回偷看寄來書。", "離情別恨，相隔欲何如。", "鶯報簾前暖日紅，玉爐殘麝猶濃。起來閨思尚疏慵。", "別愁春夢，誰解此情悰。", "強整嬌姿臨寶鏡，小池一朵芙蓉。舊歡無處再尋蹤。", "更堪回顧，屏畫九疑峰。"]'),
('yuding-14','定風波','李珣','唐','御定全唐诗','yuding','','[]','志在煙霞慕隱淪，功成歸看五湖春。一葉舟中吟複醉，',310,'御定全唐詩/json/896.json','["志在煙霞慕隱淪，功成歸看五湖春。一葉舟中吟複醉，", "花島為鄰鷗作侶，深處，經年不見市朝人。", "已得希夷微妙旨，潛喜，荷衣蕙帶絕纖塵。", "十載逍遙物外居，白雲流水似相於。乘興有時攜短棹，", "到處等閒邀鶴伴，春岸，野花香氣撲琴書。", "更飲一杯紅霞酒，回首，半鉤新月貼清虛。", "又見辭巢燕子歸，阮郎何事絕音徽。簾外西風黃葉落，", "愁坐算程千萬里，頻跂，等閒經歲兩相違。", "聽鵲憑龜無定處，不知，淚痕流在畫羅衣。", "雁過秋空夜未央，隔窗煙月鎖蓮塘。往事豈堪容易想，", "縱有回文重疊意，誰寄？解鬟臨鏡泣殘妝。", "沉水香消金鴨冷，愁永，候蟲聲接杵聲長。", "簾外煙和月滿庭，此時閑坐若為情。小閣擁爐殘酒醒，", "惟恨玉人芳信阻，雲雨，屏帷寂寞夢難成。", "鬥轉更闌心杳杳，將曉，銀釭斜照綺琴橫。"]'),
('yuding-15','南歌子','歐陽炯','唐','御定全唐诗','yuding','','[]','錦帳銀燈影，紗窗玉漏聲。迢迢永夜夢難成，',20,'御定全唐詩/json/896.json','["錦帳銀燈影，紗窗玉漏聲。迢迢永夜夢難成，"]'),
('yuding-16','漁父','歐陽炯','唐','御定全唐诗','yuding','','[]','擺脫塵機上釣船，免教榮辱有流年。無系絆，沒愁煎，',48,'御定全唐詩/json/896.json','["擺脫塵機上釣船，免教榮辱有流年。無系絆，沒愁煎，", "風浩寒溪照膽明，小君山上玉蟾生。荷露墜，翠煙輕，"]'),
('yuding-17','巫山一段雲','歐陽炯','唐','御定全唐诗','yuding','','[]','絳闕登真子。飄飄禦彩鸞。碧虛風雨佩光寒，斂袂下雲端。',104,'御定全唐詩/json/896.json','["絳闕登真子。飄飄禦彩鸞。碧虛風雨佩光寒，斂袂下雲端。", "月帳朝霞薄，星冠玉蕊攢。遠遊蓬島降人間，特地拜龍顏。", "春去秋來也，愁心似醉醺。去時邀約早回輪，及去又何曾。", "歌扇花光黦，衣珠滴淚新。恨身翻不作車塵，萬里得隨君。"]'),
('yuding-18','春光好','歐陽炯','唐','御定全唐诗','yuding','','[]','天初暖，日初長，好春光。萬匯此時皆得意，競芬芳。',450,'御定全唐詩/json/896.json','["天初暖，日初長，好春光。萬匯此時皆得意，競芬芳。", "筍迸苔錢嫩綠，花偎雪塢濃香。誰把金絲裁剪卻，掛斜陽。", "花滴露，柳搖煙，豔陽天。雨霽山櫻紅欲爛，穀鶯遷。", "飲處交飛玉斝，游時倒把金鞭，風颭九衢榆葉動，簇青錢。", "胸鋪雪，臉分蓮，理繁弦。纖指飛翻金鳳語，轉嬋娟。", "嘈囋如敲玉佩，清泠似滴香泉。曲罷問郎名個甚，想夫憐。", "磧香散，渚水融，暖空蒙。飛絮悠揚遍虛空，惹輕風。", "柳眼煙來點綠，花心日與妝紅。黃雀錦鸞相對舞，近簾櫳。", "雞樹綠，鳳池清，滿神京。玉兔宮前金榜出，列仙名。", "疊雪羅袍接武，團花駿馬嬌行。開宴錦江遊爛熳，柳煙輕。", "芳叢繡，綠筵張，兩心狂。空遣橫波傳意緒，對笙簧。", "雖似安仁擲果，未聞韓壽分香。流水桃花情不已，待劉郎。", "垂繡幔，掩雲屏，思盈盈。雙枕珊瑚無限情，翠釵橫。", "幾見纖纖動處，時聞款款嬌聲。卻出錦屏妝面了，理秦箏。", "金轡響，玉鞭長，映垂楊。堤上采花筵上醉，滿衣香。", "無處不攜弦管，直應占斷春光。年少王孫何處好，競尋芳。", "蘋葉嫩，杏花明，畫船輕。雙浴鴛鴦出綠汀，棹歌聲。", "春水無風無浪，春來半雨半晴。紅粉相隨南浦晚，莫辭行。"]'),
('yuding-19','西江月','歐陽炯','唐','御定全唐诗','yuding','','[]','月映長江秋水，分明冷浸星河。淺沙汀上白雲多，',88,'御定全唐詩/json/896.json','["月映長江秋水，分明冷浸星河。淺沙汀上白雲多，", "扁舟倒影寒潭，煙光遠罩輕波。笛聲何處響漁歌，", "水上鴛鴦比翼，巧將繡作羅衣。鏡中重畫遠山眉，", "細雀穩簪雲髻，含羞時想佳期。臉邊紅豔對花枝，"]'),
('yuding-20','赤棗子','歐陽炯','唐','御定全唐诗','yuding','','[]','夜悄悄，燭熒熒，金爐香盡酒初醒。春睡起來回雪面，',48,'御定全唐詩/json/896.json','["夜悄悄，燭熒熒，金爐香盡酒初醒。春睡起來回雪面，", "蓮臉薄，柳眉長，等閒無事莫思量。每一見時明月夜，"]'),
('yuding-21','女冠子','歐陽炯','唐','御定全唐诗','yuding','','[]','薄妝桃臉，滿面縱橫花靨。豔情多，綬帶盤金縷，',88,'御定全唐詩/json/896.json','["薄妝桃臉，滿面縱橫花靨。豔情多，綬帶盤金縷，", "含羞眉乍斂，微語笑相和。不會頻偷眼，意如何？", "秋宵秋月，一朵荷花初發。照前池，搖曳熏香夜，", "蕊中千點淚，心裏萬條絲。恰似輕盈女，好風姿。"]'),
('yuding-22','更漏子','歐陽炯','唐','御定全唐诗','yuding','','[]','玉闌幹，金甃井，月照碧梧桐影。獨自個，立多時，',91,'御定全唐詩/json/896.json','["玉闌幹，金甃井，月照碧梧桐影。獨自個，立多時，", "一向，凝情望，待得不成模樣。雖叵耐，又尋思，", "三十六宮秋夜永，露華點滴高梧。丁丁玉漏咽銅壺，", "紅線毯，博山爐，香風暗觸流蘇。羊車一去長青蕪，"]'),
('yuding-23','定風波','歐陽炯','唐','御定全唐诗','yuding','','[]','暖日閑窗映碧紗，小池春水浸晴霞。數樹海棠紅欲盡，',62,'御定全唐詩/json/896.json','["暖日閑窗映碧紗，小池春水浸晴霞。數樹海棠紅欲盡，", "獨憑繡床方寸亂，腸斷，淚珠穿破臉邊花。", "鄰舍女郎相借問，音信，教人羞道未還家。"]'),
('yuding-24','木蘭花','歐陽炯','唐','御定全唐诗','yuding','','[]','兒家夫婿心容易，身又不來書不寄。閒庭獨立鳥關關，',144,'御定全唐詩/json/896.json','["兒家夫婿心容易，身又不來書不寄。閒庭獨立鳥關關，", "悶向綠紗窗下睡，睡又不成愁已至。今年卻憶去年春，", "日照玉樓花似錦，樓上醉和春色寢。綠楊風送小鶯聲，", "堪愛晚來韶景甚，寶柱秦箏方再品。青蛾紅臉笑來迎，", "春早玉樓煙雨夜，簾外櫻桃花半謝。錦屏香冷繡衾寒，", "侵曉鵲聲來砌下，鸞鏡殘妝紅粉罷。黛眉雙點不成描，"]'),
('yuding-25','清平樂','歐陽炯','唐','御定全唐诗','yuding','','[]','春來街砌，春雨如絲細。春地滿飄紅杏蒂，春燕舞隨風勢。',47,'御定全唐詩/json/896.json','["春來街砌，春雨如絲細。春地滿飄紅杏蒂，春燕舞隨風勢。", "春幡細縷春繒，春閨一點春燈。自是春心撩亂，"]'),
('yuding-26','菩薩蠻','歐陽炯','唐','御定全唐诗','yuding','','[]','曉來中酒和春睡，四支無力雲鬟墜。斜臥臉波春，',184,'御定全唐詩/json/896.json','["曉來中酒和春睡，四支無力雲鬟墜。斜臥臉波春，", "日高猶未起，為戀鴛鴦被。鸚鵡語金籠，道兒還是慵。", "紅爐暖閣佳人睡，隔簾飛雪添寒氣。小院奏笙歌，", "酒傾金盞滿，蘭燭重開宴。公子醉如泥，天街聞馬嘶。", "翠眉雙臉新妝薄，幽閨斜卷青羅幕。寒食百花時，", "雙雙梁燕語，蝶舞相隨去。腸斷正思君，閑眠冷繡茵。", "畫屏繡閣三秋雨，香唇膩臉偎人語。語罷欲天明，", "曉街鐘鼓絕，嗔道如今別。特地氣長籲，倚屏彈淚珠。"]'),
('yuding-27','浣溪沙','歐陽炯','唐','御定全唐诗','yuding','','[]','落絮殘鶯半日天，玉柔花醉只思眠，惹窗映竹滿爐煙。',144,'御定全唐詩/json/896.json','["落絮殘鶯半日天，玉柔花醉只思眠，惹窗映竹滿爐煙。", "獨掩畫屏愁不語，斜欹瑤枕髻鬟偏，此時心在阿誰邊？", "天碧羅衣拂地垂，美人初著更相宜，宛風如舞透香肌。", "獨坐含嚬吹鳳竹，園中緩步折花枝，有情無力泥人時。", "相見休言有淚珠，酒闌重得敘歡娛，鳳屏鴛枕宿金鋪。", "蘭麝細香聞喘息，綺羅纖縷見肌膚，此時還恨薄情無。"]'),
('yuding-28','三字令','歐陽炯','唐','御定全唐诗','yuding','','[]','春欲盡，日遲遲，牡丹時。羅幌卷，翠簾垂。彩箋書，',48,'御定全唐詩/json/896.json','["春欲盡，日遲遲，牡丹時。羅幌卷，翠簾垂。彩箋書，", "人不在，燕空歸，負佳期。香燼落，枕函欹。月分明，"]'),
('yuding-29','南鄉子','歐陽炯','唐','御定全唐诗','yuding','','[]','嫩草如煙，石榴花發海南天。日暮江亭春影淥，鴛鴦浴，',198,'御定全唐詩/json/896.json','["嫩草如煙，石榴花發海南天。日暮江亭春影淥，鴛鴦浴，", "畫舸停橈，槿花籬外竹橫橋。水上游上沙上女，回顧，", "岸遠沙平，日斜歸路晚霞明。孔雀自憐金翠尾，臨水，", "洞口誰家，木蘭船系木蘭花。紅袖女郎相引去，游南浦，", "二八花鈿，胸前如雪臉如蓮。耳墜金鐶穿瑟瑟，霞衣窄，", "路入南中，桄榔葉暗蓼花紅。兩岸人家微雨後，收紅豆，", "袖斂鮫綃，采香深洞笑相邀。藤杖枝頭蘆酒滴，鋪葵席，", "翡翠鵁鶄，白蘋香裏小沙汀。島上陰陰秋雨色，蘆花撲，"]'),
('yuding-30','獻衷心','歐陽炯','唐','御定全唐诗','yuding','','[]','見好花顏色，爭笑東風。雙臉上，晚妝同。閉小樓深合，',47,'御定全唐詩/json/896.json','["見好花顏色，爭笑東風。雙臉上，晚妝同。閉小樓深合，", "情未已，信曾通，滿衣猶自染檀紅。恨不如雙燕，"]'),
('yuding-31','賀明朝','歐陽炯','唐','御定全唐诗','yuding','','[]','憶昔花間初識面，紅袖半遮妝臉。輕轉石榴裙帶，',117,'御定全唐詩/json/896.json','["憶昔花間初識面，紅袖半遮妝臉。輕轉石榴裙帶，", "碧梧桐鎖深深院，誰料得兩情，何日教繾綣。", "羨春來雙燕，飛到玉樓，朝暮相見。", "憶昔花間相見後，只憑纖手，暗拋紅豆。人前不解，", "碧羅衣上蹙金繡，睹對對鴛鴦，空裛淚痕透。", "想韶顏非久，終是為伊，只恁偷瘦。"]'),
('yuding-32','江城子','歐陽炯','唐','御定全唐诗','yuding','','[]','晚日金陵岸草平，落霞明，水無情。六代繁華，',21,'御定全唐詩/json/896.json','["晚日金陵岸草平，落霞明，水無情。六代繁華，"]'),
('yuding-33','鳳樓春','歐陽炯','唐','御定全唐诗','yuding','','[]','鳳髻綠雲叢，深掩房櫳。錦書通，夢中相見覺來慵。',94,'御定全唐詩/json/896.json','["鳳髻綠雲叢，深掩房櫳。錦書通，夢中相見覺來慵。", "勻面淚，臉珠融。因想玉郎何處去，對淑景誰同。", "小樓中，春思無窮。倚闌凝望，暗牽愁緒，柳花飛起東風。", "斜日照簾，羅幌香冷粉屏空。海棠零落，鶯語殘紅。"]'),
('yuding-34','生查子','歐陽彬2','唐','御定全唐诗','yuding','','[]','竟日畫堂歡，入夜重開宴。剪燭蠟煙香，促席花光顫。',48,'御定全唐詩/json/896.json','["竟日畫堂歡，入夜重開宴。剪燭蠟煙香，促席花光顫。", "待得月華來，滿院如鋪練。門外簇驊騮，直待更深散。"]'),
('yuding-0','虞美人','閻選','唐','御定全唐诗','yuding','','[]','粉融紅膩蓮房綻，臉動雙波慢。小魚銜玉鬢釵橫，',88,'御定全唐詩/json/897.json','["粉融紅膩蓮房綻，臉動雙波慢。小魚銜玉鬢釵橫，", "偷期錦浪荷深處，一夢雲兼雨。臂留檀印齒痕香，", "楚腰蠐領團香玉，鬢疊深深綠。月蛾星眼笑微頻，", "水紋簟映青紗帳，霧罩秋波上。一枝嬌臥醉芙蓉，"]'),
('yuding-1','臨江仙','閻選','唐','御定全唐诗','yuding','','[]','雨停荷芰逗濃香，岸邊蟬噪垂楊。物華空有舊池塘。',136,'御定全唐詩/json/897.json','["雨停荷芰逗濃香，岸邊蟬噪垂楊。物華空有舊池塘。", "不逢仙子，何處夢襄王。", "珍簟對欹鴛枕冷，此來塵暗淒涼。欲憑危檻恨偏長。", "藕花珠綴，猶似汗凝妝。", "十二高峰天外寒，竹梢輕拂仙壇。寶衣行雨在雲端。", "畫簾深殿，香霧冷風殘。", "欲問楚王何處去，翠屏猶掩金鸞。猿啼明月照空灘。", "孤舟行客，驚夢亦艱難。"]'),
('yuding-2','浣溪沙','閻選','唐','御定全唐诗','yuding','','[]','寂寞流蘇冷繡茵，倚屏山枕惹香塵，小庭花露泣濃春。',48,'御定全唐詩/json/897.json','["寂寞流蘇冷繡茵，倚屏山枕惹香塵，小庭花露泣濃春。", "劉阮信非仙洞客，嫦娥終是月中人，此生無路訪東鄰。"]'),
('yuding-3','八拍蠻','閻選','唐','御定全唐诗','yuding','','[]','雲鎖嫩黃煙柳細，風吹紅蒂雪梅殘。光影不勝閨閣恨，',48,'御定全唐詩/json/897.json','["雲鎖嫩黃煙柳細，風吹紅蒂雪梅殘。光影不勝閨閣恨，", "愁鎖黛眉煙易慘，淚飄紅臉粉難勻。憔悴不知緣底事，"]'),
('yuding-4','河傳','閻選','唐','御定全唐诗','yuding','','[]','秋雨秋雨，無晝無夜，滴滴霏霏。暗燈涼簟怨分離，',49,'御定全唐詩/json/897.json','["秋雨秋雨，無晝無夜，滴滴霏霏。暗燈涼簟怨分離，", "西風稍急喧窗竹，停又續，膩臉懸雙玉。幾回邀約雁來時，"]'),
('yuding-5','謁金門','閻選','唐','御定全唐诗','yuding','','[]','美人浴，碧沼蓮開芬馥。雙髻綰雲顏似玉，素娥輝淡綠。',47,'御定全唐詩/json/897.json','["美人浴，碧沼蓮開芬馥。雙髻綰雲顏似玉，素娥輝淡綠。", "雅態芳姿閑淑，雪映鈿裝金斛。水濺青絲珠斷續，"]'),
('yuding-6','定風波','閻選','唐','御定全唐诗','yuding','','[]','江水沉沉帆影過，遊魚到晚透寒波。渡口雙雙飛白鳥，',62,'御定全唐詩/json/897.json','["江水沉沉帆影過，遊魚到晚透寒波。渡口雙雙飛白鳥，", "扁舟短棹歸蘭浦，人去，蕭蕭竹徑透青莎。", "深夜無風新雨歇，涼月，露迎珠顆入圓荷。"]'),
('yuding-7','竹枝','孫光憲','唐','御定全唐诗','yuding','','[]','門前春水白蘋花，岸上無人小艇斜，商女經過江欲暮，',40,'御定全唐詩/json/897.json','["門前春水白蘋花，岸上無人小艇斜，商女經過江欲暮，", "楊柳在身垂意緒，藕花落盡見蓮心。"]'),
('yuding-8','浣溪沙','孫光憲','唐','御定全唐诗','yuding','','[]','蓼岸風多橘柚香，江邊一望楚天長，片帆煙際閃孤光。',576,'御定全唐詩/json/897.json','["蓼岸風多橘柚香，江邊一望楚天長，片帆煙際閃孤光。", "目送征鴻飛杳杳，思隨流水去茫茫，蘭紅波碧憶瀟湘。", "桃杏風香簾幕閑，謝家門戶約花關，畫梁幽語燕初還。", "繡閣數行題了壁，曉屏一枕酒醒山，卻疑身是夢雲間。", "花漸凋疏不耐風，畫簾垂地晚堂空，墮階縈蘚舞愁紅。", "膩粉半粘金靨子，殘香猶暖繡熏籠，蕙心無處與人同。", "攬鏡無言淚欲流，凝情半日懶梳頭，一庭疏雨濕春愁。", "楊柳只知傷怨別，杏花應信損嬌羞，淚沾魂斷軫離憂。", "半踏長裾宛約行，晚簾疏處見分明，此時堪恨昧平生。", "早是銷魂殘燭影，更愁聞著品弦聲，杳無消息若為情。", "蘭沐初休曲檻前，暖風遲日洗頭天，濕雲新斂未梳蟬。", "翠袂半將遮粉臆，寶釵長欲墜香肩，此時模樣不禁憐。", "風遞殘香出繡簾，團窠金鳳舞襜襜，落花微雨恨相兼。", "何處去來狂太甚，空推宿酒睡無厭，爭教人不別猜嫌。", "輕打銀箏墜燕泥，斷絲高罥畫樓西，花冠閑上午牆啼。", "粉籜半開新竹徑，紅苞盡落舊桃蹊，不堪終日閉深閨。", "烏帽斜欹倒佩魚，靜街偷步訪仙居，隔牆應認打門初。", "將見客時微掩斂，得人憐處且生疏，低頭羞問壁邊書。", "風撼芳菲滿院香，四簾慵卷日初長，鬢雲垂枕響微鍠。", "春夢未成愁寂寂，佳期難會信茫茫，萬般心，千點淚，", "碧玉衣裳白玉人，翠眉紅臉小腰身，瑞雲飛雨逐行雲。", "除卻弄珠兼解佩，便隨西子與東鄰，是誰容易比真真。", "何事相逢不展眉，苦將情分惡猜疑，眼前行止想應知。", "半恨半嗔回面處，和嬌和淚泥人時，萬般饒得為憐伊。"]'),
('yuding-9','河傳','孫光憲','唐','御定全唐诗','yuding','','[]','太平天子，等閒遊戲，疏河千里。柳如絲，偎倚。',188,'御定全唐詩/json/897.json','["太平天子，等閒遊戲，疏河千里。柳如絲，偎倚。", "綠波春水，長淮風不起。", "如花殿腳三千女，爭雲雨，何處留人住？錦帆風，", "柳拖金縷，著煙籠霧，濛濛落絮。鳳凰舟上楚女，", "龍爭虎戰分中土。人無主，桃葉江南渡。襞花箋，", "花落，煙薄。謝家池閣，寂寞春深。翠蛾輕斂意沈吟，", "玉爐香斷霜灰冷，簾鋪影，梁燕歸紅杏。晚來天，", "風颭，波斂。團荷閃閃，珠傾露點。木蘭舟上，", "大堤狂殺襄陽客。煙波隔，渺渺湖光白。身已歸，"]'),
('yuding-10','菩薩蠻','孫光憲','唐','御定全唐诗','yuding','','[]','月華如水籠香砌，金鐶碎撼門初閉。寒影墮高簷，',230,'御定全唐詩/json/897.json','["月華如水籠香砌，金鐶碎撼門初閉。寒影墮高簷，", "碧煙輕嫋嫋，紅戰燈花笑。即此是高唐，掩屏秋夢長。", "花冠頻鼓牆頭翼，東方澹白連窗色。門外早鶯聲，", "薄寒籠醉態，依舊鉛華在。握手送人歸，半拖金縷衣。", "小庭花落無人掃，疏香滿地東風老。春晚信沉沉，", "曉堂屏六扇，眉共湘山遠。爭奈別離心，近來尤不禁。", "青岩碧洞經朝雨，隔花相喚南溪去。一隻木蘭船，", "扣船驚翡翠，嫩玉抬香臂。紅日欲沈西，煙中遙解觿。", "木綿花映叢祠小，越禽聲裏春光曉。銅鼓與蠻歌，", "客帆風正急，茜袖偎檣立。極浦幾回頭，煙波無限愁。"]'),
('yuding-11','河瀆神','孫光憲','唐','御定全唐诗','yuding','','[]','汾水碧依依，黃雲落葉初飛。翠娥一去不言歸，',86,'御定全唐詩/json/897.json','["汾水碧依依，黃雲落葉初飛。翠娥一去不言歸，", "四壁陰森排古畫，依舊瓊輪羽駕。小殿沉沉清夜，", "江上草芊芊，春晚湘妃廟前。一方卵色楚南天，", "獨倚朱闌情不極，魂斷終朝相憶。兩槳不知消息，"]'),
('yuding-12','虞美人','孫光憲','唐','御定全唐诗','yuding','','[]','紅窗寂寂無人語，暗淡梨花雨。繡羅紋地粉新描，',100,'御定全唐詩/json/897.json','["紅窗寂寂無人語，暗淡梨花雨。繡羅紋地粉新描，", "天涯一去無消息，終日長相憶。教人相憶幾時休？", "不堪棖觸別離愁，淚還流。", "好風微揭簾旌起，金翼鸞相倚。翠簷愁聽乳禽聲，", "畫堂流水空相翳，一穗香搖曳。教人無處寄相思，"]'),
('yuding-13','後庭花','孫光憲','唐','御定全唐诗','yuding','','[]','景陽鐘動宮鶯轉，露涼金殿。輕飆吹起瓊花綻，玉葉如剪。',100,'御定全唐詩/json/897.json','["景陽鐘動宮鶯轉，露涼金殿。輕飆吹起瓊花綻，玉葉如剪。", "晚來高閣上，珠簾卷，見墜香千片。修蛾慢臉陪雕輦，", "石城依舊空江國，故宮春色。七尺青絲芳草綠，絕世難得。", "玉英凋落盡，更何人識，野棠如織。只是教人添怨憶，"]'),
('yuding-14','生查子','孫光憲','唐','御定全唐诗','yuding','','[]','寂寞掩朱門，正是天將暮。暗澹小庭中，滴滴梧桐雨。',350,'御定全唐詩/json/897.json','["寂寞掩朱門，正是天將暮。暗澹小庭中，滴滴梧桐雨。", "繡工夫，牽心緒，配盡鴛鴦縷。待得沒人時，偎倚論私語。", "暖日策花驄，嚲鞚垂楊陌。芳草惹煙青，落絮隨風白。", "誰家繡轂動香塵，隱映神仙客。狂殺玉鞭郎，咫尺音容隔。", "金井墮高梧，玉殿籠斜月。永巷寂無人，斂態愁堪絕。", "玉爐寒，香燼滅，還似君恩歇。翠輦不歸來，幽恨將誰說？", "春病與春愁，何事年年有。半為枕前人，半為花間酒。", "醉金尊，攜玉手，共作鴛鴦偶。倒載臥雲屏，雪面腰如柳。", "為惜美人嬌，長有如花笑。半醉倚紅妝，轉語傳青鳥。", "眷方深，憐恰好，唯恐相逢少。似這一般情，肯信春光老。", "清曉牡丹芳，紅豔凝金蕊。乍占錦江春，永認笙歌地。", "感人心，為物瑞，爛熳煙花裏。戴上玉釵時，迥與凡花異。", "密雨阻佳期，盡日凝然坐。簾外正淋漓，不覺愁如鎖。", "夢難裁，心欲破，淚逐簷聲墮。想得玉人情，也合思量我。"]'),
('yuding-15','臨江仙','孫光憲','唐','御定全唐诗','yuding','','[]','霜拍井梧幹葉墮，翠幃雕檻初寒。薄鉛殘黛稱花冠。',136,'御定全唐詩/json/897.json','["霜拍井梧幹葉墮，翠幃雕檻初寒。薄鉛殘黛稱花冠。", "含情無語，延佇倚闌幹。", "杳杳征輪何處去？離愁別恨千般。不堪心緒正多端。", "鏡奩長掩，無意對孤鸞。", "暮雨淒淒深院閉，燈前凝坐初更。玉釵低壓鬢雲橫。", "半垂羅幕，相映燭光明。", "終是有心投漢佩，低頭但理秦箏。燕雙鸞偶不勝情。", "只愁明發，將逐楚雲行。"]'),
('yuding-16','酒泉子','孫光憲','唐','御定全唐诗','yuding','','[]','空磧無邊，萬里陽關道路。馬蕭蕭，人去去，隴雲愁。',150,'御定全唐詩/json/897.json','["空磧無邊，萬里陽關道路。馬蕭蕭，人去去，隴雲愁。", "香貂舊制戎衣窄，胡霜千里白。綺羅心，魂夢隔，上高樓。", "曲檻小樓，正是鶯花二月。思無憀，愁欲絕，鬱離襟。", "展屏空對瀟湘水，眼前千萬里。淚掩紅，眉斂翠，恨沉沉。", "斂態窗前，嫋嫋雀釵拋頸。燕成雙，鸞對影，偶新知。", "玉纖澹拂眉山小，鏡中嗔共照。翠連娟，紅縹緲，早妝時。"]'),
('yuding-17','清平樂','孫光憲','唐','御定全唐诗','yuding','','[]','愁腸欲斷，正是青春半。連理分枝鸞失伴，又是一場離散。',94,'御定全唐詩/json/897.json','["愁腸欲斷，正是青春半。連理分枝鸞失伴，又是一場離散。", "掩鏡無語眉低，思隨芳草淒淒。憑仗東風吹夢，", "等閒無語，春恨如何去？終是疏狂留不住，花暗柳濃何處。", "盡日目斷魂飛，晚窗斜界殘暉。長恨朱門薄暮，"]'),
('yuding-18','更漏子','孫光憲','唐','御定全唐诗','yuding','','[]','聽寒更，聞遠雁，半夜蕭娘深院。扃繡戶，下珠簾，',276,'御定全唐詩/json/897.json','["聽寒更，聞遠雁，半夜蕭娘深院。扃繡戶，下珠簾，", "人語靜，香閨冷，紅幕半垂清影。雲雨態，蕙蘭心，", "今夜期，來日別，相對只堪愁絕。偎粉面，撚瑤簪，", "銀箭落，霜華薄，牆外曉雞咿喔。聽付屬，惡情悰，", "燭熒煌，香旖旎，閑放一堆鴛被。慵就寢，獨無憀，", "不會得，這心力，判了依前還憶。空自怨，奈伊何，", "掌中珠，心上氣，愛惜豈將容易。花下月，枕前人，", "交頸語，合歡身，便同比目金鱗。連繡枕，臥紅茵，", "對秋深，離恨苦，數夜滿庭風雨。凝想坐，斂愁眉，", "紅窗靜，畫簾垂，魂消地角天涯。和淚聽，斷腸窺，", "求君心，風韻別，渾似一團煙月。歌皓齒，舞紅籌，", "能婉媚，解嬌羞，王孫忍不攀留。惟我恨，未綢繆，"]'),
('yuding-19','女冠子','孫光憲','唐','御定全唐诗','yuding','','[]','蕙風芝露，壇際殘香輕度。蕊珠宮，苔點分圓碧，',88,'御定全唐詩/json/897.json','["蕙風芝露，壇際殘香輕度。蕊珠宮，苔點分圓碧，", "品流巫峽外，名籍紫微中。真侶墉城會，夢魂通。", "淡花瘦玉，依約神仙妝束。佩瓊文，瑞露通宵貯，", "碧紗籠絳節，黃藕冠濃雲。勿以吹簫伴，不同群。"]'),
('yuding-20','風流子','孫光憲','唐','御定全唐诗','yuding','','[]','茅舍槿籬溪曲，雞犬自南自北。菰葉長，水葓開，',66,'御定全唐詩/json/897.json','["茅舍槿籬溪曲，雞犬自南自北。菰葉長，水葓開，", "樓倚長衢欲暮，瞥見神仙伴侶。微傅粉，攏梳頭，", "金絡玉銜嘶馬，系向綠楊陰下。朱戶掩，繡簾垂，"]'),
('yuding-21','定西番','孫光憲','唐','御定全唐诗','yuding','','[]','雞祿山前游騎，邊草白，朔天明，馬蹄輕。',86,'御定全唐詩/json/897.json','["雞祿山前游騎，邊草白，朔天明，馬蹄輕。", "鵲面弓離短韔，彎來月欲成。一隻鳴髇雲外，曉鴻驚。", "帝子枕前秋夜，霜幄冷，月華明，正三更。", "何處戍樓寒笛，夢殘聞一聲。遙想漢關萬里，淚縱橫。"]'),
('yuding-22','何滿子','孫光憲','唐','御定全唐诗','yuding','','[]','冠劍不隨君去，江河還共恩深。歌袖半遮眉黛慘，',22,'御定全唐詩/json/897.json','["冠劍不隨君去，江河還共恩深。歌袖半遮眉黛慘，"]'),
('yuding-23','玉蝴蝶','孫光憲','唐','御定全唐诗','yuding','','[]','春欲盡，景仍長，滿園花正黃。粉翅兩悠颺，翩翩過短牆。',52,'御定全唐詩/json/897.json','["春欲盡，景仍長，滿園花正黃。粉翅兩悠颺，翩翩過短牆。", "鮮飆暖，牽遊伴，飛去立殘芳。無語對蕭娘，舞衫沉麝香。"]'),
('yuding-24','八拍蠻','孫光憲','唐','御定全唐诗','yuding','','[]','孔雀尾拖金線長，怕人飛起入丁香。越女沙頭爭拾翠，',24,'御定全唐詩/json/897.json','["孔雀尾拖金線長，怕人飛起入丁香。越女沙頭爭拾翠，"]'),
('yuding-25','思帝鄉','孫光憲','唐','御定全唐诗','yuding','','[]','如何，遣情情更多？永日水堂簾下，斂羞蛾。',44,'御定全唐詩/json/897.json','["如何，遣情情更多？永日水堂簾下，斂羞蛾。", "六幅羅裙窣地，微行曳碧波。看盡滿池疏雨，打團荷。"]'),
('yuding-26','上行杯','孫光憲','唐','御定全唐诗','yuding','','[]','草草離亭鞍馬，從遠道、此地分襟。燕宋秦吳千萬里。',97,'御定全唐詩/json/897.json','["草草離亭鞍馬，從遠道、此地分襟。燕宋秦吳千萬里。", "無辭一醉。野棠開，江草濕，佇立，沾泣，征騎駸駸。", "離棹逡巡欲動，臨極浦、故人相送。去住心情知不共。", "金船滿捧。綺羅愁，絲管咽，回別，帆影滅，江浪如雪。"]'),
('yuding-27','謁金門','孫光憲','唐','御定全唐诗','yuding','','[]','留不得，留得也應無益。白紵春衫如雪色，揚州初去日。',48,'御定全唐詩/json/897.json','["留不得，留得也應無益。白紵春衫如雪色，揚州初去日。", "輕別離，甘拋擲，江上滿帆風疾。卻羨彩鴛三十六，"]'),
('yuding-28','思越人','孫光憲','唐','御定全唐诗','yuding','','[]','古台平，芳草遠，館娃宮外春深。翠黛空留千載恨，',92,'御定全唐詩/json/897.json','["古台平，芳草遠，館娃宮外春深。翠黛空留千載恨，", "綺羅無複當時事，露花點滴香淚。惆悵遙天橫淥水，", "渚蓮枯，宮樹老，長洲廢苑蕭條。想像玉人空處所，", "經春初敗秋風起，紅蘭綠蕙愁死。一片風流傷心地，"]'),
('yuding-29','望梅花','孫光憲','唐','御定全唐诗','yuding','','[]','數枝開與短牆平，見雪萼，紅跗相映。引起誰人邊塞情。',45,'御定全唐詩/json/897.json','["數枝開與短牆平，見雪萼，紅跗相映。引起誰人邊塞情。", "簾外欲三更，吹斷離愁月正明。空聽隔江聲。"]'),
('yuding-30','漁歌子','孫光憲','唐','御定全唐诗','yuding','','[]','草芊芊，波漾漾，湖邊草色連波漲。沿蓼岸，泊楓汀，',96,'御定全唐詩/json/897.json','["草芊芊，波漾漾，湖邊草色連波漲。沿蓼岸，泊楓汀，", "扣舷歌，聯極望，槳聲伊軋知何向。黃鵠叫，白鷗眠，", "泛流螢，明又滅，夜涼水冷東灣闊。風浩浩，笛寥寥，", "杜若洲，香鬱烈，一聲宿雁霜時節。經霅水。過松江，"]'),
('yuding-31','定風波','孫光憲','唐','御定全唐诗','yuding','','[]','簾拂疏香斷碧絲，淚衫還滴繡黃鸝。上國獻書人不在，',63,'御定全唐詩/json/897.json','["簾拂疏香斷碧絲，淚衫還滴繡黃鸝。上國獻書人不在，", "春日自長心自促，翻覆，年來年去負前期。", "應是秦雲兼楚雨，留住，向花枝誇說月中枝。"]'),
('yuding-32','南歌子','孫光憲','唐','御定全唐诗','yuding','','[]','豔冶青樓女，風流似楚真。驪珠美玉未為珍，',80,'御定全唐詩/json/897.json','["豔冶青樓女，風流似楚真。驪珠美玉未為珍，", "舞袖頻回雪，歌聲幾動塵。慢凝秋水顧情人，", "映月論心處，偎花見面時。倚郎和袖撫香肌，", "解佩君非晚，虛襟我未遲。願如連理合歡枝，"]'),
('yuding-33','應天長','孫光憲','唐','御定全唐诗','yuding','','[]','翠凝仙豔非凡有，窈窕年華方十九。鬢如雲，腰似柳，',46,'御定全唐詩/json/897.json','["翠凝仙豔非凡有，窈窕年華方十九。鬢如雲，腰似柳，", "醉瑤台，攜玉手，共燕此宵相偶。魂斷晚窗分首，"]'),
('yuding-34','遐方怨','孫光憲','唐','御定全唐诗','yuding','','[]','紅綬帶，錦香囊。為表花前意，殷勤贈玉郎。',71,'御定全唐詩/json/897.json','["紅綬帶，錦香囊。為表花前意，殷勤贈玉郎。", "此時更役心腸，轉添秋夜夢魂狂。", "思豔質，想嬌妝。願早傳金盞，同歡臥醉鄉。", "任人猜妒惡猜防，到頭須使似鴛鴦。"]'),
('yuding-0','浣溪沙','張泌','唐','御定全唐诗','yuding','','[]','鈿轂香車過柳堤，樺煙分處馬頻嘶，為他沉醉不成泥。',432,'御定全唐詩/json/898.json','["鈿轂香車過柳堤，樺煙分處馬頻嘶，為他沉醉不成泥。", "花滿驛亭香露細，杜鵑聲斷玉蟾低，含情無語倚樓西。", "馬上凝情憶舊遊，照花淹竹小溪流，鈿箏羅幕玉搔頭。", "早是出門長帶月，可堪分袂又經秋，晚風斜日不勝愁。", "獨立寒階望月華，露濃香泛小庭花，繡屏愁背一燈斜。", "雲雨自從分散後，人間無路到仙家，但憑魂夢訪天涯。", "依約殘眉理舊黃，翠鬟拋擲一簪長，暖風晴日罷朝妝。", "閑折海棠看又拈，玉纖無力惹餘香，此情誰會倚斜陽。", "翡翠屏開繡幄紅，謝娥無力曉妝慵，錦帷鴛被宿香濃。", "微雨小庭春寂寞，燕飛鶯語隔簾櫳，杏花凝恨倚東風。", "花月香寒悄夜塵，綺筵幽會暗傷神，嬋娟依約畫屏人。", "人不見時還暫語，令才拋後愛微嚬，越羅巴錦不勝春。", "偏戴花冠白玉簪，睡容新起意沈吟，翠鈿金縷鎮眉心。", "小檻日斜風悄悄，隔簾零落杏花陰，斷香輕碧鎖愁深。", "晚逐香車入鳳城，東風斜揭繡簾輕，慢回嬌眼笑盈盈。", "消息未通何計是，便須佯醉且隨行，依稀聞道太狂生。", "小市東門欲雪天，眾中依約見神仙，蕊黃香畫貼金蟬。", "飲散黃昏人草草，醉容無語立門前，馬嘶塵烘一街煙。"]'),
('yuding-1','臨江仙','張泌','唐','御定全唐诗','yuding','','[]','煙收湘渚秋江靜，蕉花露泣愁紅。五雲雙鶴去無蹤。',68,'御定全唐詩/json/898.json','["煙收湘渚秋江靜，蕉花露泣愁紅。五雲雙鶴去無蹤。", "幾回魂斷，凝望向長空。", "翠竹暗留珠淚怨，閑調寶瑟波中。花鬟月鬢綠雲重。", "古祠深殿，香冷雨和風。"]'),
('yuding-2','女冠子','張泌','唐','御定全唐诗','yuding','','[]','露花煙草，寂寞五雲三島。正春深，貌減潛銷玉，',44,'御定全唐詩/json/898.json','["露花煙草，寂寞五雲三島。正春深，貌減潛銷玉，", "竹疏虛檻靜，松密醮壇陰。何事劉郎去，信沉沉。"]'),
('yuding-3','河傳','張泌','唐','御定全唐诗','yuding','','[]','渺莽雲水，惆悵暮帆，去程迢遞。夕陽芳草，千里萬里，',100,'御定全唐詩/json/898.json','["渺莽雲水，惆悵暮帆，去程迢遞。夕陽芳草，千里萬里，", "夢魂悄斷煙波裏。心如醉，相見何處是？錦屏香冷無睡，", "紅杏，交枝相映，密密濛濛。一庭濃豔倚東風，香融，", "斜陽似共春光語，蝶爭舞，更引流鶯妒。魂銷千片玉樽前，"]'),
('yuding-4','酒泉子','張泌','唐','御定全唐诗','yuding','','[]','春雨打窗，驚夢覺來天氣曉。畫堂深，紅焰小，背蘭缸。',96,'御定全唐詩/json/898.json','["春雨打窗，驚夢覺來天氣曉。畫堂深，紅焰小，背蘭缸。", "酒香噴鼻懶開缸，惆悵更無人共醉。舊巢中，新燕子，", "紫陌青門，三十六宮春色，禦溝輦路暗相通，杏園風。", "咸陽沽酒寶釵空，笑指未央歸去，插花走馬落殘紅，"]'),
('yuding-5','生查子','張泌','唐','御定全唐诗','yuding','','[]','相見稀，喜相見，相見還相遠。檀畫荔支紅，金蔓蜻蜓軟。',52,'御定全唐詩/json/898.json','["相見稀，喜相見，相見還相遠。檀畫荔支紅，金蔓蜻蜓軟。", "魚雁疏，芳信斷，花落庭陰晚。可惜玉肌膚，消瘦成慵懶。"]'),
('yuding-6','思越人','張泌','唐','御定全唐诗','yuding','','[]','燕雙飛，鶯百轉，越波堤下長橋。鬥鈿花筐金匣恰，',46,'御定全唐詩/json/898.json','["燕雙飛，鶯百轉，越波堤下長橋。鬥鈿花筐金匣恰，", "東風澹蕩慵無力，黛眉愁聚春碧。滿地落花無消息，"]'),
('yuding-7','滿宮花','張泌','唐','御定全唐诗','yuding','','[]','花正芳，樓似綺，寂寞上陽宮裏。鈿籠金鎖睡鴛鴦，',46,'御定全唐詩/json/898.json','["花正芳，樓似綺，寂寞上陽宮裏。鈿籠金鎖睡鴛鴦，", "嬌豔輕盈香雪膩，細雨黃鶯雙起。東風惆悵欲清明，"]'),
('yuding-8','柳枝','張泌','唐','御定全唐诗','yuding','','[]','膩粉瓊妝透碧紗，雪休誇。金鳳搔頭墜鬢斜，發交加。',48,'御定全唐詩/json/898.json','["膩粉瓊妝透碧紗，雪休誇。金鳳搔頭墜鬢斜，發交加。", "倚著雲屏新睡覺，思夢笑。紅腮隱出枕函花，有些些。"]'),
('yuding-9','南歌子','張泌','唐','御定全唐诗','yuding','','[]','柳色遮樓暗，桐花落砌香。畫堂開處遠風涼，',60,'御定全唐詩/json/898.json','["柳色遮樓暗，桐花落砌香。畫堂開處遠風涼，", "岸柳拖煙綠，庭花照日紅。數聲蜀魄入簾櫳，", "錦薦紅鸂鶒，羅衣繡鳳凰。綺疏飄雪北風狂，"]'),
('yuding-10','江城子','張泌','唐','御定全唐诗','yuding','','[]','碧闌幹外小中庭，雨初晴，曉鶯聲。飛絮落花，',65,'御定全唐詩/json/898.json','["碧闌幹外小中庭，雨初晴，曉鶯聲。飛絮落花，", "浣花溪上見卿卿，臉波秋水明。黛眉輕，綠雲高綰，", "窄羅衫子薄羅裙，小腰身，晚妝新。每到花時，"]'),
('yuding-11','河瀆神','張泌','唐','御定全唐诗','yuding','','[]','古樹噪寒鴉，滿庭楓葉蘆花。晝燈當午隔輕紗，',43,'御定全唐詩/json/898.json','["古樹噪寒鴉，滿庭楓葉蘆花。晝燈當午隔輕紗，", "門外往來祈賽客，翩翩帆落天涯。回首隔江煙火，"]'),
('yuding-12','蝴蝶兒','張泌','唐','御定全唐诗','yuding','','[]','蝴蝶兒，晚春時。阿嬌初著淡黃衣，倚窗學畫伊。',48,'御定全唐詩/json/898.json','["蝴蝶兒，晚春時。阿嬌初著淡黃衣，倚窗學畫伊。", "還似花間見，雙雙對對飛。無端和淚拭燕脂，惹教雙翅垂。"]'),
('yuding-13','如夢令','馮延巳','唐','御定全唐诗','yuding','','[]','塵拂玉台鸞鏡，鳳髻不堪重整。綃帳泣流蘇，',20,'御定全唐詩/json/898.json','["塵拂玉台鸞鏡，鳳髻不堪重整。綃帳泣流蘇，"]'),
('yuding-14','三台令','馮延巳','唐','御定全唐诗','yuding','','[]','春色，春色，依舊青門紫陌。日斜柳暗花嫣，',60,'御定全唐詩/json/898.json','["春色，春色，依舊青門紫陌。日斜柳暗花嫣，", "明月，明月，照得離人愁絕。更深影入空床，", "南浦，南浦，翠鬟離人何處。當時攜手高樓，"]'),
('yuding-15','歸國謠','馮延巳','唐','御定全唐诗','yuding','','[]','何處笛？深夜夢回情脈脈，竹風簷雨寒窗隔。',120,'御定全唐詩/json/898.json','["何處笛？深夜夢回情脈脈，竹風簷雨寒窗隔。", "離人幾歲無消息，今頭白，不眠特地重相憶。", "春豔豔，江上晚山三四點，柳絲如剪花如染。", "香閨寂寂門半掩，愁眉斂，淚珠滴破胭脂臉。", "江水碧，江上何人吹玉笛，扁舟遠送瀟湘客。", "蘆花千里霜月白，傷行色，來朝便是關山隔。"]'),
('yuding-16','長相思','馮延巳','唐','御定全唐诗','yuding','','[]','紅滿枝，綠滿枝，宿雨厭厭睡起遲，閒庭花影移。',44,'御定全唐詩/json/898.json','["紅滿枝，綠滿枝，宿雨厭厭睡起遲，閒庭花影移。", "憶歸期，數歸期。夢見雖多相見稀，相逢知幾時。"]'),
('yuding-17','相見歡','馮延巳','唐','御定全唐诗','yuding','','[]','曉窗夢到昭華，向瓊家。欹枕殘妝一朵，臥枝花。',45,'御定全唐詩/json/898.json','["曉窗夢到昭華，向瓊家。欹枕殘妝一朵，臥枝花。", "情極處，卻無語，玉釵斜。翠閣銀屏回首，已天涯。"]'),
('yuding-18','拋球樂','馮延巳','唐','御定全唐诗','yuding','','[]','酒罷歌餘興未闌，小橋清水共盤桓。波搖梅蕊傷心白，',144,'御定全唐詩/json/898.json','["酒罷歌餘興未闌，小橋清水共盤桓。波搖梅蕊傷心白，", "逐勝歸來雨未晴，樓前風重草煙輕。穀鶯語軟花邊過，", "梅落新春入後庭，眼前風物可無情？曲池波晚冰還合，", "霜積秋山萬樹紅，倚岩樓上掛朱櫳。白雲天遠重重恨，", "盡日登高興未殘，紅樓人散獨盤桓。一鉤冷霧懸珠箔，", "坐對高樓千萬山，雁飛秋色滿闌幹。燒殘紅燭暮雲合，"]'),
('yuding-19','點絳唇','馮延巳','唐','御定全唐诗','yuding','','[]','蔭綠圍紅，夢瓊家在桃源住。畫橋當路，臨水開朱戶。',50,'御定全唐詩/json/898.json','["蔭綠圍紅，夢瓊家在桃源住。畫橋當路，臨水開朱戶。", "柳徑春深，行到關情處。顰不語，意憑風絮，吹向郎邊去。"]'),
('yuding-20','酒泉子','馮延巳','唐','御定全唐诗','yuding','','[]','庭下花飛。月照妝樓春事晚，珠簾風，蘭燭燼，怨空閨。',192,'御定全唐詩/json/898.json','["庭下花飛。月照妝樓春事晚，珠簾風，蘭燭燼，怨空閨。", "迢迢何處寄相思。玉箸零零腸斷，屏幃深，更漏永，", "芳草長川。柳映危橋橋下路，歸鴻飛，行人去，碧山邊。", "風微煙淡雨蕭然。隔岸馬嘶何處？九回腸，雙臉淚，", "春色融融。飛燕乍來鶯未語，小桃寒，垂柳晚，玉樓空。", "天長煙遠恨重重。消息燕鴻歸去，枕前燈，窗外月，", "深院空幃。廊下風簾驚宿燕，香印灰，蘭燭灺，覺來時。", "月明人自搗寒衣。剛愛無端惆悵，階前行，闌外立，"]'),
('yuding-21','采桑子','馮延巳','唐','御定全唐诗','yuding','','[]','小庭雨過春將盡，片片花飛。獨折殘枝，無語憑闌只自知。',624,'御定全唐詩/json/898.json','["小庭雨過春將盡，片片花飛。獨折殘枝，無語憑闌只自知。", "玉堂香暖珠簾卷，雙燕來歸。君約佳期，肯信韶華得幾時。", "馬嘶人語春風岸，芳草綿綿。楊柳橋邊，落日高樓酒旆懸。", "舊愁新恨知多少，目斷遙天。獨立花前，更聽笙歌滿畫船。", "西風半夜簾櫳冷，遠夢初歸。夢過金扉，花謝窗前夜合枝。", "昭陽殿裏新翻曲，未有人知。偷取笙吹，驚覺寒蛩到曉啼。", "酒闌睡覺天香暖，繡戶慵開。香印成灰，獨背寒屏理舊眉。", "朦朧卻向燈前臥，窗月徘徊。曉夢初回，一夜東風綻早梅。", "小堂深靜無人到，滿院春風。惆悵牆東，一樹櫻桃帶雨紅。", "愁心似醉兼如病，欲語還慵。日暮疏鐘，雙燕歸棲畫閣中。", "畫堂燈暖簾櫳卷，禁漏丁丁。雨罷寒生，一夜西窗夢不成。", "玉娥重起添香印，回倚孤屏。不語含情，水調何人吹笛聲。", "笙歌放散人歸去，獨宿江樓。月上雲收，一半珠簾掛玉鉤。", "起來檢點經遊地，處處新愁。憑仗東流，將取離心過橘州。", "昭陽記得神仙侶，獨自承恩。水殿燈昏，羅幕輕寒夜正春。", "如今別館添蕭索，滿面啼痕。舊約猶存，忍把金環別與人。", "微風簾幕清明近，花落春殘。尊酒留歡，添盡羅衣怯夜寒。", "愁顏恰似燒殘燭，珠淚闌幹。也欲高拌，爭奈相逢情萬般。", "畫堂昨夜愁無睡，風雨淒淒。林鵲爭棲，落盡燈花雞未啼。", "年光往事如流水，休說情迷。玉箸雙垂，只是金籠鸚鵡知。", "寒蟬欲報三秋候，寂靜幽居。葉落閑階，月透簾櫳遠夢回。", "昭陽舊恨依前在，休說當時。玉笛才吹，滿袖猩猩血又垂。", "洞房深夜笙歌散，簾幕重重。斜月朦朧，雨過殘花落地紅。", "昔年無限傷心事，依舊東風。獨倚梧桐，閑想閑思到曉鐘。"]'),
('yuding-22','菩薩蠻','馮延巳','唐','御定全唐诗','yuding','','[]','金波遠逐行雲去，疏星時作銀河渡。花影臥秋千，',368,'御定全唐詩/json/898.json','["金波遠逐行雲去，疏星時作銀河渡。花影臥秋千，", "玉箏彈未徹，鳳髻黃釵脫。憶夢翠蛾低，微風吹繡衣。", "畫堂昨夜西風過，繡簾時拂朱門鎖。驚夢不成雲，", "金爐煙嫋嫋，燭暗紗窗曉。殘日尚彎環，玉箏和淚彈。", "梅花吹入誰家笛，行雲半夜凝空碧。欹枕不成眠，", "聲隨幽怨絕，空斷澄霜月。月影下重簷，輕風花滿簾。", "回廊遠砌生秋草，夢魂千里青門道。鸚鵡怨長更，", "羅幃中夜起，霜月清如水。玉露不成圓，寶箏悲斷弦。", "嬌鬟堆枕釵橫鳳，溶溶春水楊花夢。紅燭淚闌幹，", "錦壺催畫箭，玉佩天涯遠。和淚試嚴妝，落梅飛夜霜。", "西風嫋嫋淩歌扇，秋期正與行雲遠。花葉脫霜紅，", "蘭閨人在否，千里重樓暮。翠被已銷香，夢隨寒漏長。", "沉沉朱戶橫金鎖，紗窗月影隨花過。燭淚欲闌幹，", "寶釵橫翠鳳，千里香屏夢。雲雨已荒涼，江南春草長。", "欹鬟墮髻搖雙槳，採蓮晚出清江上。顧影約流萍，", "相逢顰翠黛，笑把珠璫解。家住柳陰中，畫橋東複東。"]'),
('yuding-23','謁金門','馮延巳','唐','御定全唐诗','yuding','','[]','風乍起，吹皺一池春水。閑引鴛鴦芳徑裏，手挪紅杏蕊。',94,'御定全唐詩/json/898.json','["風乍起，吹皺一池春水。閑引鴛鴦芳徑裏，手挪紅杏蕊。", "鬥鴨闌幹獨倚，碧玉搔頭斜墜。終日望君君不至，", "楊柳陌，寶馬嘶空無跡。新著荷衣人未識，年年江海客。", "夢覺巫山春色，醉眼飛花狼藉。起舞不辭無氣力，"]'),
('yuding-24','清平樂','馮延巳','唐','御定全唐诗','yuding','','[]','深冬寒月，庭戶凝霜雪。風雁過時魂斷絕，塞管數聲嗚咽。',141,'御定全唐詩/json/898.json','["深冬寒月，庭戶凝霜雪。風雁過時魂斷絕，塞管數聲嗚咽。", "披衣獨立披香，流蘇亂結愁腸。往事總堪惆悵，", "雨晴煙晚，綠水新池滿。雙燕飛來垂柳院，小閣畫簾高卷。", "黃昏獨倚朱闌，西南新月眉彎。砌下落花風起，", "西園春早，夾徑抽新草。冰散漪瀾生碧沼，寒在梅花先老。", "與君同飲金杯，飲餘相取徘徊。次第小桃將發，"]'),
('yuding-25','更漏子','馮延巳','唐','御定全唐诗','yuding','','[]','風帶寒，枝正好，蘭蕙無端先老。情悄悄，夢依依，',138,'御定全唐詩/json/898.json','["風帶寒，枝正好，蘭蕙無端先老。情悄悄，夢依依，", "褰羅幕，憑朱閣，不獨堪悲搖落。月東出，雁南飛，", "夜初長，人近別，夢覺一窗殘月。鸚鵡臥，蟪蛄鳴，", "紅蠟燭，彈棋局，床上畫屏山綠。褰繡幌，倚瑤琴，", "玉爐煙，紅燭淚，偏對畫堂秋思。眉翠薄，鬢雲殘，", "梧桐樹，三更雨，不道離情最苦。一葉葉，一聲聲，"]'),
('yuding-26','喜遷鶯','馮延巳','唐','御定全唐诗','yuding','','[]','宿鶯啼，鄉夢斷，春樹曉朦朧。殘燈和燼閉朱櫳，',90,'御定全唐詩/json/898.json','["宿鶯啼，鄉夢斷，春樹曉朦朧。殘燈和燼閉朱櫳，", "香已寒，燈已絕，忽憶去年離別。石城花雨倚江樓，", "霧濛濛，風淅淅，楊柳帶疏煙。飄飄輕絮滿南園，", "燕初飛，鶯已老，拂面春風長好。相逢攜酒且高歌，"]'),
('yuding-27','阮郎歸','馮延巳','唐','御定全唐诗','yuding','','[]','南園春半踏青時，風和聞馬嘶。青梅如豆柳如絲，',88,'御定全唐詩/json/898.json','["南園春半踏青時，風和聞馬嘶。青梅如豆柳如絲，", "花露重，草煙低，人家簾幕垂。秋千慵困解羅衣，", "角聲吹斷隴梅枝，孤窗月影低。塞鴻無限欲驚飛，", "尋斷夢，掩深閨，行人去路迷。門前楊柳綠陰齊，"]'),
('yuding-28','賀聖朝','馮延巳','唐','御定全唐诗','yuding','','[]','金絲帳暖牙床穩，懷香方寸，輕顰輕笑，汗珠微透，',48,'御定全唐詩/json/898.json','["金絲帳暖牙床穩，懷香方寸，輕顰輕笑，汗珠微透，", "雲鬟斜墜，春應未已，不勝嬌困。半欹犀枕，亂纏珠被，"]'),
('yuding-29','應天長','馮延巳','唐','御定全唐诗','yuding','','[]','石城山下桃花綻，宿雨初晴雲未散。南去棹，北飛雁，',50,'御定全唐詩/json/898.json','["石城山下桃花綻，宿雨初晴雲未散。南去棹，北飛雁，", "倚樓情緒懶，惆悵春心無限。燕度蒹葭風晚，欲歸愁滿面。"]'),
('yuding-30','醉花間','馮延巳','唐','御定全唐诗','yuding','','[]','獨立階前星又月，簾櫳偏皎潔。霜樹盡空枝，腸斷丁香結。',104,'御定全唐詩/json/898.json','["獨立階前星又月，簾櫳偏皎潔。霜樹盡空枝，腸斷丁香結。", "夜深寒不寐，疑恨何曾歇。憑闌幹欲折，兩條玉箸為君垂，", "月落霜繁深院閉，洞房人正睡。桐樹倚雕簷，金井臨瑤砌。", "曉風寒不啻，獨立城憔悴。閒愁渾未已，離人心緒自無端，"]'),
('yuding-31','芳草渡','馮延巳','唐','御定全唐诗','yuding','','[]','梧桐落，蓼花秋。煙初冷，雨才收，蕭條風物正堪愁。',71,'御定全唐詩/json/898.json','["梧桐落，蓼花秋。煙初冷，雨才收，蕭條風物正堪愁。", "人去後，多少恨，在心頭。", "燕鴻遠，羌笛怨，渺渺澄波一片。山如黛，月如鉤。", "笙歌散，夢魂斷，倚高樓。"]'),
('yuding-32','南鄉子','馮延巳','唐','御定全唐诗','yuding','','[]','細雨濕流光，芳草年年與恨長。煙鎖鳳樓無限事，茫茫。',132,'御定全唐詩/json/898.json','["細雨濕流光，芳草年年與恨長。煙鎖鳳樓無限事，茫茫。", "鸞鏡鴛衾兩斷腸。", "魂夢任悠揚，睡起楊花滿繡床。薄幸不來門半掩，斜陽。", "負你殘春淚幾行。", "細雨泣秋風，金鳳花殘滿地紅。閑蹙黛眉慵不語，情緒。", "寂寞相思知幾許。", "玉枕擁孤衾，挹恨還聞歲月深。簾捲曲房誰共醉，憔悴。", "惆悵秦樓彈粉淚。"]'),
('yuding-33','舞春風','馮延巳','唐','御定全唐诗','yuding','','[]','嚴妝才罷怨春風，粉牆畫壁宋家東。蕙蘭有恨枝尤綠，',48,'御定全唐詩/json/898.json','["嚴妝才罷怨春風，粉牆畫壁宋家東。蕙蘭有恨枝尤綠，", "燕燕巢兒羅幕卷，鶯鶯啼處鳳樓空。少年薄幸知何處，"]'),
('yuding-34','虞美人','馮延巳','唐','御定全唐诗','yuding','','[]','玉鉤鸞柱調鸚鵡，宛轉留春語。雲屏冷落畫堂空，',88,'御定全唐詩/json/898.json','["玉鉤鸞柱調鸚鵡，宛轉留春語。雲屏冷落畫堂空，", "搴簾燕子低飛去，拂鏡塵鶯舞。不知今夜月眉彎，", "春風拂拂橫秋水，掩映遙相對。只知長作碧窗期，", "銀屏夢與飛鸞遠，只有珠簾卷。楊花零落月溶溶，"]'),
('yuding-35','臨江仙','馮延巳','唐','御定全唐诗','yuding','','[]','冷紅飄起桃花片，青春意緒闌珊。高樓簾幕卷輕寒。',68,'御定全唐詩/json/898.json','["冷紅飄起桃花片，青春意緒闌珊。高樓簾幕卷輕寒。", "酒餘人散，獨自倚闌幹。", "夕陽千里連芳草，風光愁殺王孫。徘徊飛盡碧天雲。", "鳳城何處，明月照黃昏。"]'),
('yuding-36','蝶戀花','馮延巳','唐','御定全唐诗','yuding','','[]','窗外寒雞天欲曙，香印成灰，坐起渾無緒。',420,'御定全唐詩/json/898.json','["窗外寒雞天欲曙，香印成灰，坐起渾無緒。", "庭際高梧凝宿霧，捲簾雙鵲驚飛去。", "屏上羅衣閑繡縷，一晌關情，憶遍江南路。", "夜夜夢魂休謾語，已知前事無情處。", "蕭索清秋珠淚墜，枕簟微涼，輾轉渾無寐。", "殘酒欲醒中夜起，月明如練天如水。", "階下寒聲啼絡緯，庭樹金風，悄悄重門閉。", "可惜舊歡攜手地，思量一夕成憔悴。", "幾度鳳樓同飲宴，此夕相逢，卻勝當時見。", "低語前歡頻轉面，雙眉斂恨春山遠。", "蠟燭淚流羌笛怨，偷整羅衣，欲唱情猶懶。", "醉裏不辭金爵滿，陽關一曲腸千斷。", "幾日行雲何處去，忘了歸來，不道春將暮。", "百草千花寒食路，香車系在誰家樹。", "淚眼倚樓頻獨語，雙燕飛來，陌上相逢否？", "撩亂春愁如柳絮，悠悠夢裏無尋處。", "六曲闌幹偎碧樹，楊柳風輕，展盡黃金縷。", "誰把鈿箏移玉柱，穿簾海燕雙飛去。", "滿眼遊絲兼落絮，紅杏開時，一霎清明雨。", "濃醉覺來鶯亂語，驚殘好夢無尋處。", "誰道閒情拋棄久，每到春來，惆悵還依舊。", "日日花前常病酒，不辭鏡裏朱顏瘦。", "河畔青蕪堤上柳，為問新愁，何事年年有。", "獨立小樓風滿袖，平林新月人歸後。"]'),
('yuding-37','壽山曲','馮延巳','唐','御定全唐诗','yuding','','[]','銅壺滴漏初盡，高合雞鳴半空。催啟五門金鎖，',42,'御定全唐詩/json/898.json','["銅壺滴漏初盡，高合雞鳴半空。催啟五門金鎖，", "鴛瓦數行曉日，鸞旗百尺春風。侍臣舞蹈重拜，"]'),
('yuding-38','思越人','馮延巳','唐','御定全唐诗','yuding','','[]','酒醒情懷惡，金縷褪，玉肌如削。寒食過卻，海棠零落。',50,'御定全唐詩/json/898.json','["酒醒情懷惡，金縷褪，玉肌如削。寒食過卻，海棠零落。", "乍倚遍，闌幹煙淡薄，翠幕簾櫳畫閣。春睡著，覺來失，"]'),
('yuding-39','上行杯','馮延巳','唐','御定全唐诗','yuding','','[]','落梅暑雨消殘粉，雲重煙深寒食近。羅幕遮香，',42,'御定全唐詩/json/898.json','["落梅暑雨消殘粉，雲重煙深寒食近。羅幕遮香，", "春山顛倒釵橫鳳，飛絮入簾春睡重。夢裏佳期，"]'),
('yuding-40','薄命妾','馮延巳','唐','御定全唐诗','yuding','','[]','春日宴，綠酒一杯歌一遍。再拜陳三願。',40,'御定全唐詩/json/898.json','["春日宴，綠酒一杯歌一遍。再拜陳三願。", "一願郎君千歲，二願妾身長健。三願如同梁上燕，"]'),
('yuding-41','金錯刀','馮延巳','唐','御定全唐诗','yuding','','[]','雙玉鬥，百瓊壺，佳人歡飲笑喧呼。麒麟欲畫時難偶，',96,'御定全唐詩/json/898.json','["雙玉鬥，百瓊壺，佳人歡飲笑喧呼。麒麟欲畫時難偶，", "歌婉轉，醉模糊，高燒銀燭臥流蘇。只銷幾覺懵騰睡，", "日融融，草芊芊，黃鶯求友啼林前。柳條嫋嫋拖金線，", "鳩逐婦，燕穿簾，狂蜂浪蝶相翩翩。春光堪賞還堪玩，"]'),
('yuding-42','憶江南','馮延巳','唐','御定全唐诗','yuding','','[]','去歲迎春樓上月，正是西窗，夜涼時節。',136,'御定全唐詩/json/898.json','["去歲迎春樓上月，正是西窗，夜涼時節。", "玉人貪睡墜釵雲，粉消妝薄見天真。", "人非風月長依舊，破鏡塵箏一夢經年瘦。", "今宵簾幕揚花陰，空餘枕淚獨傷心。", "今日相逢花未發，正是去年，別離時節。", "東風次第有花開，恁時須約卻重來。", "重來不怕花堪折，只恐明年花發人離別。", "別離若向百花時，東風彈淚有誰知？"]'),
('yuding-43','木蘭花','徐昌圖','唐','御定全唐诗','yuding','','[]','沉檀煙起盤紅霧，一箭霜風吹繡戶。漢宮花面學梅妝，',48,'御定全唐詩/json/898.json','["沉檀煙起盤紅霧，一箭霜風吹繡戶。漢宮花面學梅妝，", "長垂夾幕孤鸞舞，旋炙銀笙雙鳳語。紅窗酒病嚼寒冰，"]'),
('yuding-44','臨江仙','徐昌圖','唐','御定全唐诗','yuding','','[]','飲散離亭西去，浮生常恨飄蓬。回頭煙柳漸重重。',68,'御定全唐詩/json/898.json','["飲散離亭西去，浮生常恨飄蓬。回頭煙柳漸重重。", "淡雲孤雁遠，寒日暮天紅。", "今夜畫船何處，潮平淮月朦朧。酒醒人靜奈愁濃。", "殘燈孤枕夢，輕浪五更風。"]'),
('yuding-45','河傳','徐昌圖','唐','御定全唐诗','yuding','','[]','秋光滿目，風清露白，蓮紅水綠。何處夢回，',42,'御定全唐詩/json/898.json','["秋光滿目，風清露白，蓮紅水綠。何處夢回，", "採蓮調穩，吳侶聲相續，倚棹吳江曲。鷺起暮天，"]'),
('yuding-46','拋球樂','徐鉉','唐','御定全唐诗','yuding','','[]','歌舞送飛球，金觥碧玉籌。管弦桃李月，簾幕鳳凰樓。',72,'御定全唐詩/json/898.json','["歌舞送飛球，金觥碧玉籌。管弦桃李月，簾幕鳳凰樓。", "一笑千場醉，浮生任白頭。", "灼灼傅花枝，紛紛度畫旗。不知紅燭下，照見彩球飛。", "借勢因期克，巫山暮雨歸。"]'),
('yuding-0','木蘭花','庾傳素','唐','御定全唐诗','yuding','','[]','木蘭紅豔多情態，不似凡花人不愛。移來孔雀檻邊栽，',48,'御定全唐詩/json/899.json','["木蘭紅豔多情態，不似凡花人不愛。移來孔雀檻邊栽，", "是何芍藥爭風彩，自共牡丹長作對。若教為女嫁東風，"]'),
('yuding-1','生查子','劉侍讀','唐','御定全唐诗','yuding','','[]','深秋更漏長，滴盡銀台燭。獨步出幽閨，月晃波澄綠。',48,'御定全唐詩/json/899.json','["深秋更漏長，滴盡銀台燭。獨步出幽閨，月晃波澄綠。", "菱荷風乍觸，一對鴛鴦宿。虛棹玉釵驚，驚起還相續。"]'),
('yuding-2','木蘭花','許岷','唐','御定全唐诗','yuding','','[]','小庭日晚花零落，倚戶無聊妝臉薄。寶箏金鴨任生塵，',96,'御定全唐詩/json/899.json','["小庭日晚花零落，倚戶無聊妝臉薄。寶箏金鴨任生塵，", "有時覷著同心結，萬恨千愁無處說。當初不合盡饒伊，", "江南日暖芭蕉展，美人折得親裁剪。書成小簡寄情人，", "其中撚破相思字，卻恐郎疑蹤不似。若還猜妾倩人書，"]'),
('yuding-3','菩薩蠻','林楚翹','唐','御定全唐诗','yuding','','[]','畫堂春晝垂珠箔，臥來揉惹金釵落。簟滑枕頭移，',46,'御定全唐詩/json/899.json','["畫堂春晝垂珠箔，臥來揉惹金釵落。簟滑枕頭移，", "笑拖嬌眼慢，羅袖籠花面。重道好郎君，人前莫惱人。"]'),
('yuding-4','一片子','無名氏','唐','御定全唐诗','yuding','','[]','柳色青山映，梨花雪鳥藏。綠窗桃李下，閑坐歎春芳。',24,'御定全唐詩/json/899.json','["柳色青山映，梨花雪鳥藏。綠窗桃李下，閑坐歎春芳。"]'),
('yuding-5','塞姑','無名氏','唐','御定全唐诗','yuding','','[]','昨日盧梅塞口，整見諸人鎮守。都護三年不歸，',21,'御定全唐詩/json/899.json','["昨日盧梅塞口，整見諸人鎮守。都護三年不歸，"]'),
('yuding-6','醉公子','無名氏','唐','御定全唐诗','yuding','','[]','門外猧兒吠，知是蕭郎至。剗襪下香階，冤家今夜醉。',48,'御定全唐詩/json/899.json','["門外猧兒吠，知是蕭郎至。剗襪下香階，冤家今夜醉。", "扶得入羅幃，不肯脫羅衣。醉則從他醉，還勝獨睡時。"]'),
('yuding-7','菩薩蠻','無名氏','唐','御定全唐诗','yuding','','[]','牡丹含露真珠顆，美人折向庭前過。含笑問檀郎，',46,'御定全唐詩/json/899.json','["牡丹含露真珠顆，美人折向庭前過。含笑問檀郎，", "檀郎故相惱，須道花枝好。一面發嬌嗔，碎挪花打人。"]'),
('yuding-8','賀聖朝','無名氏','唐','御定全唐诗','yuding','','[]','白露點，曉星明滅，秋風落葉。故址頹垣，冷煙衰草，',48,'御定全唐詩/json/899.json','["白露點，曉星明滅，秋風落葉。故址頹垣，冷煙衰草，", "長安道上行客，依舊利深名切。改變容顏，消磨今古，"]'),
('yuding-9','虞美人','無名氏','唐','御定全唐诗','yuding','','[]','帳中草草軍情變，月下旌旗亂。褫衣推枕愴離情，',44,'御定全唐詩/json/899.json','["帳中草草軍情變，月下旌旗亂。褫衣推枕愴離情，", "撫騅欲下重相顧，豔態花無主。手中蓮鍔凜秋霜，"]'),
('yuding-10','後庭宴','無名氏','唐','御定全唐诗','yuding','','[]','千里故鄉，十年華屋，亂魂飛過屏山簇。',72,'御定全唐詩/json/899.json','["千里故鄉，十年華屋，亂魂飛過屏山簇。", "眼重眉褪不勝春，菱花知我銷香玉。", "雙雙燕子歸來，應解笑人幽獨。斷歌零舞，遺恨清江曲。", "萬樹綠低迷，一庭紅fQ簌。"]'),
('yuding-11','擷芳詞','無名氏','唐','御定全唐诗','yuding','','[]','風搖盪，雨蒙茸，翠條柔弱花頭重。春衫窄，香肌濕。',58,'御定全唐詩/json/899.json','["風搖盪，雨蒙茸，翠條柔弱花頭重。春衫窄，香肌濕。", "記得年時，共伊曾摘。", "都如夢，何曾共，可憐孤似釵頭鳳。關山隔，晚雲碧，"]'),
('yuding-12','魚游春水','無名氏','唐','御定全唐诗','yuding','','[]','秦樓東風裏，燕子還來尋舊壘。餘寒猶峭，紅日薄侵羅綺。',105,'御定全唐詩/json/899.json','["秦樓東風裏，燕子還來尋舊壘。餘寒猶峭，紅日薄侵羅綺。", "嫩草方抽碧玉茵，媚柳輕窣黃金縷。鶯轉上林，魚游春水。", "幾曲闌幹遍倚，又是一番新桃李。佳人應怪歸遲，梅妝淚洗。", "鳳簫聲絕沉孤雁，望斷清波無雙鯉。雲山萬重，寸心千里。"]'),
('yuding-13','阿那曲','楊貴妃','唐','御定全唐诗','yuding','','[]','羅袖動香香不已，紅蕖嫋嫋秋煙裏。輕雲嶺下乍搖風，',24,'御定全唐詩/json/899.json','["羅袖動香香不已，紅蕖嫋嫋秋煙裏。輕雲嶺下乍搖風，"]'),
('yuding-14','樂游曲','閩後陳氏','唐','御定全唐诗','yuding','','[]','龍舟搖曳東複東，採蓮湖上紅更紅。波淡淡，水溶溶，',48,'御定全唐詩/json/899.json','["龍舟搖曳東複東，採蓮湖上紅更紅。波淡淡，水溶溶，", "西湖南湖鬥彩舟，青蒲紫蓼滿中洲。波渺渺，水悠悠，"]'),
('yuding-15','楊柳枝','柳氏','唐','御定全唐诗','yuding','','[]','楊柳枝，芳菲節，可恨年年贈離別。一葉隨風忽報秋，',24,'御定全唐詩/json/899.json','["楊柳枝，芳菲節，可恨年年贈離別。一葉隨風忽報秋，"]'),
('yuding-16','字字雙','王麗真女郎','唐','御定全唐诗','yuding','','[]','床頭錦衾斑複斑，架上朱衣殷複殷。空庭明月閑複閑，',24,'御定全唐詩/json/899.json','["床頭錦衾斑複斑，架上朱衣殷複殷。空庭明月閑複閑，"]'),
('yuding-17','菩薩蠻','耿玉真','唐','御定全唐诗','yuding','','[]','玉京人去秋蕭索，畫簷鵲起梧桐落。欹枕悄無言，',46,'御定全唐詩/json/899.json','["玉京人去秋蕭索，畫簷鵲起梧桐落。欹枕悄無言，", "背燈唯暗泣，甚處砧聲急。眉黛遠山攢，芭蕉生暮寒。"]'),
('yuding-18','句','不詳','唐','御定全唐诗','yuding','','[]','庭空客散人歸後，畫堂半掩朱簾。林風淅淅夜厭厭，',206,'御定全唐詩/json/899.json','["庭空客散人歸後，畫堂半掩朱簾。林風淅淅夜厭厭，", "春光鎮在人空老，新愁往恨何窮。金窗力困起還慵。", "一聲羌笛，驚起醉怡容。（李後主《臨江仙》。", "前後兩調，各逸其半）", "尋春須是陽春早，看花莫待花枝老。", "帝鄉煙雨鎖春愁，故國山川空淚眼。（吳越王錢俶。", "《木蘭花》）", "金鳳欲飛遭掣搦，情脈脈。看即玉樓雲雨隔。", "桃李不須誇爛熳，已輸了風吹一半。", "學著荷衣還可喜，年少多來有幾？自古閒愁無際。", "初離蜀道心將碎，離恨綿綿。春日如年，馬上時時聞杜鵑。"]'),
('yuding-0','梧桐影','呂岩','唐','御定全唐诗','yuding','','[]','落日斜，秋風冷。今夜故人來不來，教人立盡梧桐影。',24,'御定全唐詩/json/900.json','["落日斜，秋風冷。今夜故人來不來，教人立盡梧桐影。"]'),
('yuding-1','憶江南','呂岩','唐','御定全唐诗','yuding','','[]','淮南法，秋石最堪誇。位應乾坤白露節，',234,'御定全唐詩/json/900.json','["淮南法，秋石最堪誇。位應乾坤白露節，", "王陽術，得秘是黃牙。萬蕊初生將此類，", "黃帝術，玄妙美金花。玉液初凝紅粉見，", "長生術，玄要補泥丸。彭祖得之年八百，", "陰丹訣，三五合玄圖。二八應機堪采運，", "長生術，初九秘潛龍。慎勿從高宜作客，", "修身客，莫誤入迷津。氣術金丹傳在世，", "還丹訣，九九最幽玄。三性本同一體內，", "長生藥，不用問他人。八卦九宮看掌上，", "學道客，修養莫遲遲。光景斯須如夢裏，", "治生客，審細察微言。百歲夢中看即過，", "瑤池上，瑞霧靄群仙。素練金童鏘鳳板，", "沉醉處，縹渺玉京山。唱徹步虛清燕罷，"]'),
('yuding-2','西江月','呂岩','唐','御定全唐诗','yuding','','[]','著意黃庭歲久，留心金碧年深。為憂白髮鬢相侵，',88,'御定全唐詩/json/900.json','["著意黃庭歲久，留心金碧年深。為憂白髮鬢相侵，", "秘要俱皆覽過，神仙奧旨重吟。至人親指水中金，", "任是聰明志士，常迷東灶黃庭。參同大易事分明，", "若遇高人指引，都來不費功程。北方坎子是金精，"]'),
('yuding-3','沁園春','呂岩','唐','御定全唐诗','yuding','','[]','七返還丹，在我先須，煉已待時。正一陽初動，',132,'御定全唐詩/json/900.json','["七返還丹，在我先須，煉已待時。正一陽初動，", "當時，自飲刀圭，又誰信無中就養兒。辨水源清濁，", "火宅牽纏，夜去明來，早晚擔憂。奈今日茫然，", "休休，及早回頭，把往日風流一筆鉤。但粗衣淡飯，", "詩曲文章，任汝空留，數千萬篇。奈日推一日，", "凡間，只戀塵緣，又誰信壺中別有天。這道本無情，"]'),
('yuding-4','卜運算元','呂岩','唐','御定全唐诗','yuding','','[]','心空道亦空，風靜林還靜。卷盡浮雲月自明，中有山河影。',52,'御定全唐詩/json/900.json','["心空道亦空，風靜林還靜。卷盡浮雲月自明，中有山河影。", "供養及修行，舊話成重省。豆爆生蓮火裏時，痛撥寒灰冷。"]'),
('yuding-5','步蟾宮','呂岩','唐','御定全唐诗','yuding','','[]','坎離幹兌逢子午，須認取，自家根祖。地雷震動山頭雨，',50,'御定全唐詩/json/900.json','["坎離幹兌逢子午，須認取，自家根祖。地雷震動山頭雨，", "捉得金精牢閉錮，煉甲庚，要生龍虎。待他問汝甚人傳，"]'),
('yuding-6','滿庭芳','呂岩','唐','御定全唐诗','yuding','','[]','大道淵源，高真隱秘，風流豈可知聞。先天一氣，',60,'御定全唐詩/json/900.json','["大道淵源，高真隱秘，風流豈可知聞。先天一氣，", "幽微處，無中產有，澗畔虎龍吟。", "壺中，真造化，天精地髓，陰魄陽魂。運周天水火，"]'),
('yuding-7','酹江月','呂岩','唐','御定全唐诗','yuding','','[]','仙風道骨，顛倒運乾坤，平分時節。金木相交坎離位，',73,'御定全唐詩/json/900.json','["仙風道骨，顛倒運乾坤，平分時節。金木相交坎離位，", "仙花朵秀，聖男靈女扳折。", "霄漢此夜中秋，銀蟾離海，浪卷千層雪。此是天關地軸，", "倚天長嘯，洞中無限風月。"]'),
('yuding-8','水龍吟','呂岩','唐','御定全唐诗','yuding','','[]','目前咫尺長生路，多少愚人不悟。愛河浪闊，洪波風緊，',84,'御定全唐詩/json/900.json','["目前咫尺長生路，多少愚人不悟。愛河浪闊，洪波風緊，", "煉金丹換了，凡胎濁骨。免輪回，三塗苦。", "萬事澄心定意，聚真陽、都歸一處。分明認得，", "知蓬萊自有，神仙伴侶。同攜手，朝天去。"]'),
('yuding-9','豆葉黃','呂岩','唐','御定全唐诗','yuding','','[]','二月江南山水路，李花零落春無主。一個魚兒無覓處，',24,'御定全唐詩/json/900.json','["二月江南山水路，李花零落春無主。一個魚兒無覓處，"]'),
('yuding-10','浪淘沙','呂岩','唐','御定全唐诗','yuding','','[]','我有屋三椽，住在靈源。無遮四壁任蕭然。',64,'御定全唐詩/json/900.json','["我有屋三椽，住在靈源。無遮四壁任蕭然。", "萬象森羅為斗拱，瓦蓋青天。無漏得多年，結就因緣。", "修成功行滿三千。降得火龍伏得虎，陸路神仙。"]'),
('yuding-11','蘇幕遮','呂岩','唐','御定全唐诗','yuding','','[]','天不高，地不大。惟有真心，物物俱含載。',76,'御定全唐詩/json/900.json','["天不高，地不大。惟有真心，物物俱含載。", "不用之時全體在。用即拈來，萬象周沙界。", "虛無中，塵色內。儘是還丹，歷歷堪收采。", "這個鼎爐解不解。養就靈烏，飛出光明海。"]'),
('yuding-12','雨中花','呂岩','唐','御定全唐诗','yuding','','[]','三百年間，功標青史，幾多俱委埃塵。悟黃粱棄事，',46,'御定全唐詩/json/900.json','["三百年間，功標青史，幾多俱委埃塵。悟黃粱棄事，", "蓬萊願應仙舉，誰知會合仙賓。遙想望，吹笙玉殿，"]'),
('yuding-13','促拍滿路花','呂岩','唐','御定全唐诗','yuding','','[]','西風吹渭水，落葉滿長安。茫茫塵世裏，獨清閒。',90,'御定全唐詩/json/900.json','["西風吹渭水，落葉滿長安。茫茫塵世裏，獨清閒。", "自然爐鼎，虎繞與龍盤。九轉丹砂就，一粒刀圭，", "任萬釘寶帶貂蟬，富貴欲熏天。黃粱炊未熟，夢驚殘。", "是非海裏，直道作人難。袖手江南去，白蘋紅蓼，"]'),
('yuding-14','六麼令','呂岩','唐','御定全唐诗','yuding','','[]','東與西，眼與眉。偃月爐中運坎離，靈砂且上飛。',38,'御定全唐詩/json/900.json','["東與西，眼與眉。偃月爐中運坎離，靈砂且上飛。", "最幽微，是天機，你休癡，你不知。"]'),
('yuding-15','漢宮春','呂岩','唐','御定全唐诗','yuding','','[]','橫笛聲沉，倚危樓紅日，江轉天斜。黃塵邊火澒洞，',60,'御定全唐詩/json/900.json','["橫笛聲沉，倚危樓紅日，江轉天斜。黃塵邊火澒洞，", "飛空一劍，東風猶自天涯。", "情知道山中好，早翠囂含隱，瑤草新芽。青溪故人信斷，"]'),
('yuding-16','憶江南','伊用昌','唐','御定全唐诗','yuding','','[]','江南鼓，梭肚兩頭欒。釘著不知侵骨髓，',18,'御定全唐詩/json/900.json','["江南鼓，梭肚兩頭欒。釘著不知侵骨髓，"]'),
('yuding-17','句','伊用昌','唐','御定全唐诗','yuding','','[]','暫遊大庾，白鶴飛來誰共語？嶺畔人家，曾見寒梅幾度花。',52,'御定全唐詩/json/900.json','["暫遊大庾，白鶴飛來誰共語？嶺畔人家，曾見寒梅幾度花。", "春來春去，人在落花流水處。花滿前蹊，藏盡神仙人不知。"]'),
('shijing-0','关雎','佚名','先秦','诗经','shijing','','[]','关关雎鸠，在河之洲。窈窕淑女，君子好逑。',100,'诗经/shijing.json','["关关雎鸠，在河之洲。窈窕淑女，君子好逑。", "参差荇菜，左右流之。窈窕淑女，寤寐求之。", "求之不得，寤寐思服。悠哉悠哉，辗转反侧。", "参差荇菜，左右采之。窈窕淑女，琴瑟友之。", "参差荇菜，左右芼之。窈窕淑女，钟鼓乐之。"]'),
('shijing-1','葛覃','佚名','先秦','诗经','shijing','','[]','葛之覃兮，施于中谷，维叶萋萋。黄鸟于飞，集于灌木，其鸣喈喈。',90,'诗经/shijing.json','["葛之覃兮，施于中谷，维叶萋萋。黄鸟于飞，集于灌木，其鸣喈喈。", "葛之覃兮，施于中谷，维叶莫莫。是刈是濩，为絺为绤，服之无斁。", "言告师氏，言告言归。薄污我私，薄浣我衣。害浣害否，归宁父母。"]'),
('shijing-2','卷耳','佚名','先秦','诗经','shijing','','[]','采采卷耳，不盈顷筐。嗟我怀人，置彼周行。',86,'诗经/shijing.json','["采采卷耳，不盈顷筐。嗟我怀人，置彼周行。", "陟彼崔嵬，我马虺隤。我姑酌彼金罍，维以不永怀。", "陟彼高冈，我马玄黄。我姑酌彼兕觥，维以不永伤。", "陟彼砠矣，我马瘏矣，我仆痡矣，云何吁矣。"]'),
('shijing-3','樛木','佚名','先秦','诗经','shijing','','[]','南有樛木，葛藟累之。乐只君子，福履绥之。',60,'诗经/shijing.json','["南有樛木，葛藟累之。乐只君子，福履绥之。", "南有樛木，葛藟荒之。乐只君子，福履将之。", "南有樛木，葛藟萦之。乐只君子，福履成之。"]'),
('shijing-4','螽斯','佚名','先秦','诗经','shijing','','[]','螽斯羽，诜诜兮。宜尔子孙，振振兮。',51,'诗经/shijing.json','["螽斯羽，诜诜兮。宜尔子孙，振振兮。", "螽斯羽，薨薨兮。宜尔子孙。绳绳兮。", "螽斯羽，揖揖兮。宜尔子孙，蛰蛰兮。"]'),
('shijing-5','桃夭','佚名','先秦','诗经','shijing','','[]','桃之夭夭，灼灼其华。之子于归，宜其室家。',60,'诗经/shijing.json','["桃之夭夭，灼灼其华。之子于归，宜其室家。", "桃之夭夭，有蕡其实。之子于归，宜其家室。", "桃之夭夭，其叶蓁蓁。之子于归，宜其家人。"]'),
('shijing-6','兔罝','佚名','先秦','诗经','shijing','','[]','肃肃兔罝，椓之丁丁。赳赳武夫，公侯干城。',60,'诗经/shijing.json','["肃肃兔罝，椓之丁丁。赳赳武夫，公侯干城。", "肃肃兔罝，施于中逵。赳赳武夫，公侯好仇。", "肃肃免罝，施于中林。赳赳武夫，公侯腹心。"]'),
('shijing-7','芣苡','佚名','先秦','诗经','shijing','','[]','采采芣苡，薄言采之。采采芣苡，薄言有之。',60,'诗经/shijing.json','["采采芣苡，薄言采之。采采芣苡，薄言有之。", "采采芣苡，薄言掇之。采采芣苡，薄言捋之。", "采采芣苡，薄言袺之。采采芣苡，薄言襭之。"]'),
('shijing-8','汉广','佚名','先秦','诗经','shijing','','[]','南有乔木，不可休息。汉有游女，不可求思。汉之广矣，不可泳思。江之永矣，不可方思。',120,'诗经/shijing.json','["南有乔木，不可休息。汉有游女，不可求思。汉之广矣，不可泳思。江之永矣，不可方思。", "翘翘错薪，言刈其楚。之子于归，言秣其马。汉之广矣，不可泳思。江之永矣，不可方思。", "翘翘错薪，言刈其蒌。之子于归。言秣其驹。汉之广矣，不可泳思。江之永矣，不可方思。"]'),
('shijing-9','汝坟','佚名','先秦','诗经','shijing','','[]','遵彼汝坟，伐其条枚。未见君子，惄如调饥。',60,'诗经/shijing.json','["遵彼汝坟，伐其条枚。未见君子，惄如调饥。", "遵彼汝坟，伐其条肄。既见君子，不我遐弃。", "鲂鱼赪尾，王室如毁。虽则如毁，父母孔迩。"]'),
('shijing-10','麟之趾','佚名','先秦','诗经','shijing','','[]','麟之趾，振振公子，于嗟麟兮。',42,'诗经/shijing.json','["麟之趾，振振公子，于嗟麟兮。", "麟之定，振振公姓，于嗟麟兮。", "麟之角，振振公族，于嗟麟兮。"]'),
('shijing-11','鹊巢','佚名','先秦','诗经','shijing','','[]','维鹊有巢，维鸠居之。之子于归，百两御之。',60,'诗经/shijing.json','["维鹊有巢，维鸠居之。之子于归，百两御之。", "维鹊有巢，维鸠方之。之子于归，百两将之。", "维鹊有巢，维鸠盈之。之子于归，百两成之。"]'),
('shijing-12','采蘩','佚名','先秦','诗经','shijing','','[]','于以采蘩？于沼于沚。于以用之？公侯之事。',60,'诗经/shijing.json','["于以采蘩？于沼于沚。于以用之？公侯之事。", "于以采蘩？于涧之中。于以用之？公侯之宫。", "被之僮僮，夙夜在公。被之祁祁，薄言还归。"]'),
('shijing-13','草虫','佚名','先秦','诗经','shijing','','[]','喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。亦既见止，亦既觏止，我心则降。',105,'诗经/shijing.json','["喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。亦既见止，亦既觏止，我心则降。", "陟彼南山，言采其蕨。未见君子，忧心惙惙。亦既见止，亦既觏止，我心则说。", "陟彼南山，言采其薇。未见君子，我心伤悲。亦既见止，亦既觏止，我心则夷。"]'),
('shijing-14','采蘋','佚名','先秦','诗经','shijing','','[]','于以采蘋？南涧之滨。于以采藻？于彼行潦。',60,'诗经/shijing.json','["于以采蘋？南涧之滨。于以采藻？于彼行潦。", "于以盛之？维筐及筥。于以湘之？维锜及釜。", "于以奠之？宗室牖下。谁其尸之？有齐季女。"]'),
('shijing-15','甘棠','佚名','先秦','诗经','shijing','','[]','蔽芾甘棠，勿翦勿伐，召伯所茇。',45,'诗经/shijing.json','["蔽芾甘棠，勿翦勿伐，召伯所茇。", "蔽芾甘棠，勿翦勿败，召伯所憩。", "蔽芾甘棠，勿翦勿拜，召伯所说。"]'),
('shijing-16','行露','佚名','先秦','诗经','shijing','','[]','厌浥行露，岂不夙夜，谓行多露。',83,'诗经/shijing.json','["厌浥行露，岂不夙夜，谓行多露。", "谁谓雀无角？何以穿我屋？谁谓女无家？何以速我狱？虽速我狱，室家不足！", "谁谓鼠无牙？何以穿我墉？谁谓女无家？何以速我讼？虽速我讼，亦不女从！"]'),
('shijing-17','羔羊','佚名','先秦','诗经','shijing','','[]','羔羊之皮，素丝五紽。退食自公，委蛇委蛇。',60,'诗经/shijing.json','["羔羊之皮，素丝五紽。退食自公，委蛇委蛇。", "羔羊之革，素丝五緎。委蛇委蛇，自公退食。", "羔羊之缝，素丝五总。委蛇委蛇，退食自公。"]'),
('shijing-18','殷其雷','佚名','先秦','诗经','shijing','','[]','殷其雷，在南山之阳。何斯违斯，莫敢或遑？振振君子，归哉归哉！',90,'诗经/shijing.json','["殷其雷，在南山之阳。何斯违斯，莫敢或遑？振振君子，归哉归哉！", "殷其雷，在南山之侧。何斯违斯，莫敢遑息？振振君子，归哉归哉！", "殷其雷，在南山之下。何斯违斯，莫或遑处？振振君子，归哉归哉！"]'),
('shijing-19','摽有梅','佚名','先秦','诗经','shijing','','[]','摽有梅，其实七兮。求我庶士，迨其吉兮。',57,'诗经/shijing.json','["摽有梅，其实七兮。求我庶士，迨其吉兮。", "摽有梅，其实三兮。求我庶士，迨其今兮。", "摽有梅，顷筐塈之。求我庶士，迨其谓之。"]'),
('shijing-20','小星','佚名','先秦','诗经','shijing','','[]','嘒彼小星，三五在东。肃肃宵征，夙夜在公。寔命不同！',50,'诗经/shijing.json','["嘒彼小星，三五在东。肃肃宵征，夙夜在公。寔命不同！", "嘒彼小星，维参与昴。肃肃宵征，抱衾与裯。寔命不犹！"]'),
('shijing-21','江有汜','佚名','先秦','诗经','shijing','','[]','江有汜，之子归，不我以。不我以，其后也悔。',63,'诗经/shijing.json','["江有汜，之子归，不我以。不我以，其后也悔。", "江有渚，之子归，不我与。不我与，其后也处。", "江有沱，之子归，不我过。不我过，其啸也歌。"]'),
('shijing-22','野有死麕','佚名','先秦','诗经','shijing','','[]','野有死麕，白茅包之。有女怀春，吉士诱之。',58,'诗经/shijing.json','["野有死麕，白茅包之。有女怀春，吉士诱之。", "林有朴樕，野有死鹿。白茅纯束，有女如玉。", "舒而脱脱兮，无感我帨兮，无使尨也吠。"]'),
('shijing-23','何彼襛矣','佚名','先秦','诗经','shijing','','[]','何彼襛矣，唐棣之华？曷不肃雍？王姬之车。',60,'诗经/shijing.json','["何彼襛矣，唐棣之华？曷不肃雍？王姬之车。", "何彼襛矣，华如桃李？平王之孙，齐侯之子。", "其钓维何？维丝伊缗。齐侯之子，平王之孙。"]'),
('shijing-24','驺虞','佚名','先秦','诗经','shijing','','[]','彼茁者葭，壹发五豝，于嗟乎驺虞！',32,'诗经/shijing.json','["彼茁者葭，壹发五豝，于嗟乎驺虞！", "彼茁者蓬，壹发五豵，于嗟乎驺虞！"]'),
('shijing-25','柏舟','佚名','先秦','诗经','shijing','','[]','泛彼柏舟，亦泛其流。耿耿不寐，如有隐忧。微我无酒，以敖以游。',150,'诗经/shijing.json','["泛彼柏舟，亦泛其流。耿耿不寐，如有隐忧。微我无酒，以敖以游。", "我心匪鉴，不可以茹。亦有兄弟，不可以据。薄言往诉，逢彼之怒。", "我心匪石，不可转也。我心匪席，不可卷也。威仪棣棣，不可选也。", "忧心悄悄，愠于群小。觏闵既多，受侮不少。静言思之，寤辟有摽。", "日居月诸，胡迭而微？心之忧矣，如匪浣衣。静言思之，不能奋飞。"]'),
('shijing-26','绿衣','佚名','先秦','诗经','shijing','','[]','绿兮衣兮，绿衣黄裹。心之忧矣，曷维其已！',80,'诗经/shijing.json','["绿兮衣兮，绿衣黄裹。心之忧矣，曷维其已！", "绿兮衣兮，绿衣黄裳。心之忧矣，曷维其亡！", "绿兮丝兮，女所治兮。我思古人，俾无訧兮！", "絺兮绤兮，凄其以风。我思古人，实获我心！"]'),
('shijing-27','燕燕','佚名','先秦','诗经','shijing','','[]','燕燕于飞，差池其羽。之子于归，远送于野。瞻望弗及，泣涕如雨。',120,'诗经/shijing.json','["燕燕于飞，差池其羽。之子于归，远送于野。瞻望弗及，泣涕如雨。", "燕燕于飞，颉之颃之。之子于归，远于将之。瞻望弗及，伫立以泣。", "燕燕于飞，下上其音。之子于归，远送于南。瞻望弗及，实劳我心。", "仲氏任只，其心塞渊。终温且惠，淑慎其身。先君之思，以勖寡人。"]'),
('shijing-28','日月','佚名','先秦','诗经','shijing','','[]','日居月诸，照临下土。乃如之人兮，逝不古处？胡能有定？宁不我顾。',123,'诗经/shijing.json','["日居月诸，照临下土。乃如之人兮，逝不古处？胡能有定？宁不我顾。", "日居月诸，下土是冒。乃如之人兮，逝不相好。胡能有定？宁不我报。", "日居月诸，出自东方。乃如之人兮，德音无良。胡能有定？俾也可忘。", "日居月诸，东方自出。父兮母兮，畜我不卒。胡能有定？报我不述。"]'),
('shijing-29','终风','佚名','先秦','诗经','shijing','','[]','终风且暴，顾我则笑，谑浪笑敖，中心是悼。',80,'诗经/shijing.json','["终风且暴，顾我则笑，谑浪笑敖，中心是悼。", "终风且霾，惠然肯来，莫往莫来，悠悠我思。", "终风且曀，不日有曀，寤言不寐，愿言则嚏。", "曀曀其阴，虺虺其雷，寤言不寐，愿言则怀。"]'),
('shijing-30','击鼓','佚名','先秦','诗经','shijing','','[]','击鼓其镗，踊跃用兵。土国城漕，我独南行。',100,'诗经/shijing.json','["击鼓其镗，踊跃用兵。土国城漕，我独南行。", "从孙子仲，平陈与宋。不我以归，忧心有忡。", "爰居爰处？爰丧其马？于以求之？于林之下。", "死生契阔，与子成说。执子之手，与子偕老。", "于嗟阔兮，不我活兮。于嗟洵兮，不我信兮。"]'),
('shijing-31','凯风','佚名','先秦','诗经','shijing','','[]','凯风自南，吹彼棘心。棘心夭夭，母氏劬劳。',80,'诗经/shijing.json','["凯风自南，吹彼棘心。棘心夭夭，母氏劬劳。", "凯风自南，吹彼棘薪。母氏圣善，我无令人。", "爰有寒痊？在浚之下。有子七人，母氏劳苦。", "睍睆黄鸟，载好其音。有子七人，莫慰母心。"]'),
('shijing-32','雄雉','佚名','先秦','诗经','shijing','','[]','雄雉于飞，泄泄其羽。我之怀矣，自诒伊阻。',80,'诗经/shijing.json','["雄雉于飞，泄泄其羽。我之怀矣，自诒伊阻。", "雄雉于飞，下上其音。展矣君子，实劳我心。", "瞻彼日月，悠悠我思。道之云远，曷云能来？", "百尔君子，不知德行。不忮不求，何用不臧。"]'),
('shijing-33','匏有苦叶','佚名','先秦','诗经','shijing','','[]','匏有苦叶，济有深涉。深则厉，浅则揭。',80,'诗经/shijing.json','["匏有苦叶，济有深涉。深则厉，浅则揭。", "有瀰济盈，有鷕雉鸣。济盈不濡轨，雉鸣求其牡。", "雍雍鸣雁，旭日始旦。士如归妻，迨冰未泮。", "招招舟子，人涉卬否。不涉卬否，卬须我友。"]'),
('shijing-34','谷风','佚名','先秦','诗经','shijing','','[]','习习谷风，以阴以雨。黾勉同心，不宜有怒。采葑采菲，无以下体？德音莫违，及尔同死。',242,'诗经/shijing.json','["习习谷风，以阴以雨。黾勉同心，不宜有怒。采葑采菲，无以下体？德音莫违，及尔同死。", "行道迟迟，中心有违。不远伊迩，薄送我畿。谁谓荼苦，其甘如荠。宴尔新婚，如兄如弟。", "泾以渭浊，湜湜其沚。宴尔新婚，不我屑以。毋逝我梁，毋发我笱。我躬不阅，遑恤我后。", "就其深矣，方之舟之。就其浅矣，泳之游之。何有何亡，黾勉求之。凡民有丧，匍匐救之。", "不我能畜，反以我为仇。既阻我德，贾用不售。昔育恐育鞫，及尔颠覆。既生既育，比予于毒。", "我有旨蓄，亦以御冬。宴尔新婚，以我御穷。有洸有溃，既诒我肄。不念昔者，伊余来塈。"]'),
('shijing-35','式微','佚名','先秦','诗经','shijing','','[]','式微，式微，胡不归？微君之故，胡为乎中露！',42,'诗经/shijing.json','["式微，式微，胡不归？微君之故，胡为乎中露！", "式微，式微，胡不归？微君之躬，胡为乎泥中！"]'),
('shijing-36','旄丘','佚名','先秦','诗经','shijing','','[]','旄丘之葛兮，何诞之节兮。叔兮伯兮，何多日也？',82,'诗经/shijing.json','["旄丘之葛兮，何诞之节兮。叔兮伯兮，何多日也？", "何其处也？必有与也！何其久也？必有以也！", "狐裘蒙戎，匪车不东。叔兮伯兮，靡所与同。", "琐兮尾兮，流离之子。叔兮伯兮，褎如充耳。"]'),
('shijing-37','简兮','佚名','先秦','诗经','shijing','','[]','简兮简兮，方将万舞。日之方中，在前上处。',89,'诗经/shijing.json','["简兮简兮，方将万舞。日之方中，在前上处。", "硕人俣俣，公庭万舞。有力如虎，执辔如组。", "左手执龠，右手秉翟。赫如渥赭，公言锡爵。", "山有榛，隰有苓。云谁之思？西方美人。彼美人兮，西方之人兮。"]'),
('shijing-38','泉水','佚名','先秦','诗经','shijing','','[]','毖彼泉水，亦流于淇。有怀于卫，靡日不思。娈彼诸姬，聊与之谋。',121,'诗经/shijing.json','["毖彼泉水，亦流于淇。有怀于卫，靡日不思。娈彼诸姬，聊与之谋。", "出宿于泲，饮饯于祢。女子有行，远父母兄弟，问我诸姑，遂及伯姊。", "出宿于干，饮饯于言。载脂载辖，还车言迈。遄臻于卫，不瑕有害？", "我思肥泉，兹之永叹。思须与漕，我心悠悠。驾言出游，以写我忧。"]'),
('shijing-39','北门','佚名','先秦','诗经','shijing','','[]','出自北门，忧心殷殷。终窭且贫，莫知我艰。已焉哉！天实为之，谓之何哉！',110,'诗经/shijing.json','["出自北门，忧心殷殷。终窭且贫，莫知我艰。已焉哉！天实为之，谓之何哉！", "王事适我，政事一埤益我。我入自外，室人交遍谪我。已焉哉！天实为之，谓之何哉！", "王事敦我，政事一埤遗我。我入自外，室人交遍摧我。已焉哉！天实为之，谓之何哉！"]'),
('shijing-40','北风','佚名','先秦','诗经','shijing','','[]','北风其凉，雨雪其雱。惠而好我，携手同行。其虚其邪？既亟只且！',90,'诗经/shijing.json','["北风其凉，雨雪其雱。惠而好我，携手同行。其虚其邪？既亟只且！", "北风其喈，雨雪其霏。惠而好我，携手同归。其虚其邪？既亟只且！", "莫赤匪狐，莫黑匪乌。惠而好我，携手同车。其虚其邪？既亟只且！"]'),
('shijing-41','静女','佚名','先秦','诗经','shijing','','[]','静女其姝，俟我于城隅。爱而不见，搔首踟蹰。',62,'诗经/shijing.json','["静女其姝，俟我于城隅。爱而不见，搔首踟蹰。", "静女其娈，贻我彤管。彤管有炜，说怿女美。", "自牧归荑，洵美且异。匪女之为美，美人之贻。"]'),
('shijing-42','新台','佚名','先秦','诗经','shijing','','[]','新台有泚，河水瀰瀰。燕婉之求，蘧篨不鲜。',60,'诗经/shijing.json','["新台有泚，河水瀰瀰。燕婉之求，蘧篨不鲜。", "新台有洒，河水浼浼。燕婉之求，蘧篨不殄。", "鱼网之设，鸿则离之。燕婉之求，得此戚施。"]'),
('shijing-43','二子乘舟','佚名','先秦','诗经','shijing','','[]','二子乘舟，泛泛其景。愿言思子，中心养养！',40,'诗经/shijing.json','["二子乘舟，泛泛其景。愿言思子，中心养养！", "二子乘舟，泛泛其逝。愿言思子，不瑕有害？"]'),
('shijing-44','柏舟','佚名','先秦','诗经','shijing','','[]','泛彼柏舟，在彼中河。髧彼两髦，实维我仪。之死矢靡它。母也天只，不谅人只！',72,'诗经/shijing.json','["泛彼柏舟，在彼中河。髧彼两髦，实维我仪。之死矢靡它。母也天只，不谅人只！", "泛彼柏舟，在彼河侧。髧彼两髦，实维我特。之死矢靡慝。母也天只，不谅人只！"]'),
('shijing-45','墙有茨','佚名','先秦','诗经','shijing','','[]','墙有茨，不可扫也。中冓之言，不可道也。所可道也，言之丑也。',87,'诗经/shijing.json','["墙有茨，不可扫也。中冓之言，不可道也。所可道也，言之丑也。", "墙有茨，不可襄也。中冓之言，不可详也。所可详也，言之长也。", "墙有茨，不可束也。中冓之言，不可读也。所可读也，言之辱也。"]'),
('shijing-46','君子偕老','佚名','先秦','诗经','shijing','','[]','君子偕老，副笄六珈。委委佗佗，如山如河，象服是宜。子之不淑，云如之何？',125,'诗经/shijing.json','["君子偕老，副笄六珈。委委佗佗，如山如河，象服是宜。子之不淑，云如之何？", "玼兮玼兮，其之翟也。鬒发如云，不屑髢也。玉之瑱也，象之揥也，扬且之晳也。胡然而天也！胡然而帝也。", "瑳兮瑳兮，其之展也。蒙彼绉絺，是绁袢也。子之清扬，扬且之颜也。展如之人兮，邦之媛也！"]'),
('shijing-47','桑中','佚名','先秦','诗经','shijing','','[]','爰采唐矣？沬之乡矣。云谁之思？美孟姜矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。',120,'诗经/shijing.json','["爰采唐矣？沬之乡矣。云谁之思？美孟姜矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。", "爰采麦矣？沬之北矣。云谁之思？美孟弋矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。", "爰采葑矣？沬之东矣。云谁之思？美孟庸矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。"]'),
('shijing-48','鹑之奔奔','佚名','先秦','诗经','shijing','','[]','鹑之奔奔，鹊之彊彊。人之无良，我以为兄！',40,'诗经/shijing.json','["鹑之奔奔，鹊之彊彊。人之无良，我以为兄！", "鹊之彊彊，鹑之奔奔。人之无良，我以为君！"]'),
('shijing-49','定之方中','佚名','先秦','诗经','shijing','','[]','定之方中，作于楚宫。揆之以日，作于楚室。树之榛栗，椅桐梓漆，爰伐琴桑。',105,'诗经/shijing.json','["定之方中，作于楚宫。揆之以日，作于楚室。树之榛栗，椅桐梓漆，爰伐琴桑。", "升彼虚矣，以望楚矣。望楚与堂，景山与京。降观于桑，卜云其吉，终然允臧。", "灵雨既零，命彼倌人，星言夙驾，说于桑田。匪直也人，秉心塞渊，騋牝三千。"]'),
('shijing-50','蝃蝀','佚名','先秦','诗经','shijing','','[]','蝃蝀在东，莫之敢指。女子有行，远父母兄弟。',63,'诗经/shijing.json','["蝃蝀在东，莫之敢指。女子有行，远父母兄弟。", "朝隮于西，崇朝其雨。女子有行，远兄弟父母。", "乃如之人也，怀婚姻也。大无信也，不知命也！"]'),
('shijing-51','相鼠','佚名','先秦','诗经','shijing','','[]','相鼠有皮，人而无仪！人而无仪，不死何为？',60,'诗经/shijing.json','["相鼠有皮，人而无仪！人而无仪，不死何为？", "相鼠有齿，人而无止！人而无止，不死何俟？", "相鼠有体，人而无礼，人而无礼！胡不遄死？"]'),
('shijing-52','干旄','佚名','先秦','诗经','shijing','','[]','孑孑干旄，在浚之郊。素丝纰之，良马四之。彼姝者子，何以畀之？',90,'诗经/shijing.json','["孑孑干旄，在浚之郊。素丝纰之，良马四之。彼姝者子，何以畀之？", "孑孑干旟，在浚之都。素丝组之，良马五之。彼姝者子，何以予之？", "孑孑干旌，在浚之城。素丝祝之，良马六之。彼姝者子，何以告之？"]'),
('shijing-53','载驰','佚名','先秦','诗经','shijing','','[]','载驰载驱，归唁卫侯。驱马悠悠，言至于漕。大夫跋涉，我心则忧。',141,'诗经/shijing.json','["载驰载驱，归唁卫侯。驱马悠悠，言至于漕。大夫跋涉，我心则忧。", "既不我嘉，不能旋反。视尔不臧，我思不远。", "既不我嘉，不能旋济？视尔不臧，我思不閟。", "陟彼阿丘，言采其蝱。女子善怀，亦各有行。许人尤之，众稚且狂。", "我行其野，芃芃其麦。控于大邦，谁因谁极？大夫君子，无我有尤。百尔所思，不如我所之。"]'),
('shijing-54','淇奥','佚名','先秦','诗经','shijing','','[]','瞻彼淇奥，绿竹猗猗。有匪君子，如切如磋，如琢如磨，瑟兮僴兮，赫兮咺兮。有匪君子，终不可谖兮。',137,'诗经/shijing.json','["瞻彼淇奥，绿竹猗猗。有匪君子，如切如磋，如琢如磨，瑟兮僴兮，赫兮咺兮。有匪君子，终不可谖兮。", "瞻彼淇奥，绿竹青青。有匪君子，充耳秀莹，会弁如星。瑟兮僴兮。赫兮咺兮，有匪君子，终不可谖兮。", "瞻彼淇奥，绿竹如箦。有匪君子，如金如锡，如圭如璧。宽兮绰兮，猗重较兮。善戏谑兮，不为虐兮。"]'),
('shijing-55','考槃','佚名','先秦','诗经','shijing','','[]','考槃在涧，硕人之宽。独寐寤言，永矢弗谖。',60,'诗经/shijing.json','["考槃在涧，硕人之宽。独寐寤言，永矢弗谖。", "考槃在阿，硕人之薖。独寐寤歌，永矢弗过。", "考槃在六，硕人之轴。独寐寤宿，永矢弗告。"]'),
('shijing-56','硕人','佚名','先秦','诗经','shijing','','[]','硕人其颀，衣锦褧衣。齐侯之子，卫侯之妻。东宫之妹，邢侯之姨，谭公维私。',140,'诗经/shijing.json','["硕人其颀，衣锦褧衣。齐侯之子，卫侯之妻。东宫之妹，邢侯之姨，谭公维私。", "手如柔荑，肤如凝脂，领如蝤蛴，齿如瓠犀，螓首蛾眉，巧笑倩兮，美目盼兮。", "硕人敖敖，说于农郊。四牡有骄，朱幩镳镳。翟茀以朝。大夫夙退，无使君劳。", "河水洋洋，北流活活。施罛濊濊，鳣鲔发发。葭菼揭揭，庶姜孽孽，庶士有朅。"]'),
('shijing-57','氓','佚名','先秦','诗经','shijing','','[]','氓之蚩蚩，抱布贸丝。匪来贸丝，来即我谋。送子涉淇，至于顿丘。匪我愆期，子无良媒。将子无怒，秋以为期。',300,'诗经/shijing.json','["氓之蚩蚩，抱布贸丝。匪来贸丝，来即我谋。送子涉淇，至于顿丘。匪我愆期，子无良媒。将子无怒，秋以为期。", "乘彼垝垣，以望复关。不见复关，泣涕涟涟。既见复关，载笑载言。尔卜尔筮，体无咎言。以尔车来，以我贿迁。", "桑之未落，其叶沃若。于嗟鸠兮！无食桑葚。于嗟女兮！无与士耽。士之耽兮，犹可说也。女之耽兮，不可说也。", "桑之落矣，其黄而陨。自我徂尔，三岁食贫。淇水汤汤，渐车帷裳。女也不爽，士二其行。士也罔极，二三其德。", "三岁为妇，靡室劳矣。夙兴夜寐，靡有朝矣。言既遂矣，至于暴矣。兄弟不知，咥其笑矣。静言思之，躬自悼矣。", "及尔偕老，老使我怨。淇则有岸，隰则有泮。总角之宴，言笑晏晏，信誓旦旦，不思其反。反是不思，亦已焉哉！"]'),
('shijing-58','竹竿','佚名','先秦','诗经','shijing','','[]','籊籊竹竿，以钓于淇。岂不尔思？远莫致之。',81,'诗经/shijing.json','["籊籊竹竿，以钓于淇。岂不尔思？远莫致之。", "泉源在左，淇水在右。女子有行，远兄弟父母。", "淇水在右，泉源在左。巧笑之瑳，佩玉之傩。", "淇水滺滺，桧楫松舟。驾言出游，以写我忧。"]'),
('shijing-59','芄兰','佚名','先秦','诗经','shijing','','[]','芄兰之支，童子佩觿。虽则佩觿，能不我知。容兮遂兮，垂带悸兮。',60,'诗经/shijing.json','["芄兰之支，童子佩觿。虽则佩觿，能不我知。容兮遂兮，垂带悸兮。", "芄兰之叶，童子佩韘。虽则佩韘，能不我甲。容兮遂兮，垂带悸兮。"]'),
('shijing-60','河广','佚名','先秦','诗经','shijing','','[]','谁谓河广？一苇杭之。谁谓宋远？跂予望之。',40,'诗经/shijing.json','["谁谓河广？一苇杭之。谁谓宋远？跂予望之。", "谁谓河广？曾不容刀。谁谓宋远？曾不崇朝。"]'),
('shijing-61','伯兮','佚名','先秦','诗经','shijing','','[]','伯兮朅兮，邦之桀兮。伯也执殳，为王前驱。',80,'诗经/shijing.json','["伯兮朅兮，邦之桀兮。伯也执殳，为王前驱。", "自伯之东，首如飞蓬。岂无膏沐？谁适为容！", "其雨其雨，杲杲出日。愿言思伯，甘心首疾。", "焉得谖草？言树之背。愿言思伯。使我心痗。"]'),
('shijing-62','有狐','佚名','先秦','诗经','shijing','','[]','有狐绥绥，在彼淇梁。心之忧矣，之子无裳。',60,'诗经/shijing.json','["有狐绥绥，在彼淇梁。心之忧矣，之子无裳。", "有狐绥绥，在彼淇厉。心之忧矣，之子无带。", "有狐绥绥，在彼淇侧。心之忧矣，之子无服。"]'),
('shijing-63','木瓜','佚名','先秦','诗经','shijing','','[]','投我以木瓜，报之以琼琚。匪报也，永以为好也！',66,'诗经/shijing.json','["投我以木瓜，报之以琼琚。匪报也，永以为好也！", "投我以木桃，报之以琼瑶。匪报也，永以为好也！", "投我以木李，报之以琼九。匪报也，永以为好也！"]'),
('shijing-64','黍离','佚名','先秦','诗经','shijing','','[]','彼黍离离，彼稷之苗。行迈靡靡，中心摇摇。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？',147,'诗经/shijing.json','["彼黍离离，彼稷之苗。行迈靡靡，中心摇摇。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？", "彼黍离离，彼稷之穗。行迈靡靡，中心如醉。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？", "彼黍离离，彼稷之实。行迈靡靡，中心如噎。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？"]'),
('shijing-65','君子于役','佚名','先秦','诗经','shijing','','[]','君子于役，不知其期。曷至哉？鸡栖于埘。日之夕矣，羊牛下来。君子于役，如之何勿思！',80,'诗经/shijing.json','["君子于役，不知其期。曷至哉？鸡栖于埘。日之夕矣，羊牛下来。君子于役，如之何勿思！", "君子于役，不日不月。曷其有佸？鸡栖于桀。日之夕矣，羊牛下括。君子于役，苟无饥渴？"]'),
('shijing-66','君子阳阳','佚名','先秦','诗经','shijing','','[]','君子阳阳，左执簧，右招我由房，其乐只且！',40,'诗经/shijing.json','["君子阳阳，左执簧，右招我由房，其乐只且！", "君子陶陶，左执翿，右招我由敖，其乐只且！"]'),
('shijing-67','扬之水','佚名','先秦','诗经','shijing','','[]','扬之水，不流束薪。彼其之子，不与我戍申。怀哉怀哉，曷月予还归哉？',96,'诗经/shijing.json','["扬之水，不流束薪。彼其之子，不与我戍申。怀哉怀哉，曷月予还归哉？", "扬之水，不流束楚。彼其之子，不与我戍甫。怀哉怀哉，曷月予还归哉？", "扬之水，不流束蒲。彼其之子，不与我戍许。怀哉怀哉，曷月予还归哉？"]'),
('shijing-68','中谷有蓷','佚名','先秦','诗经','shijing','','[]','中谷有蓷，暵其干矣。有女仳离，慨其叹矣。慨其叹矣，遇人之艰难矣。',94,'诗经/shijing.json','["中谷有蓷，暵其干矣。有女仳离，慨其叹矣。慨其叹矣，遇人之艰难矣。", "中谷有蓷，暵其修矣。有女仳离，条其歗矣。条其歗矣，遇人之不淑矣。", "中谷有蓷，暵其湿矣。有女仳离，啜其泣矣。啜其泣矣，何嗟及矣。"]'),
('shijing-69','兔爰','佚名','先秦','诗经','shijing','','[]','有兔爰爰，雉离于罗。我生之初，尚无为；我生之后，逢此百罹。尚寐无吪。',102,'诗经/shijing.json','["有兔爰爰，雉离于罗。我生之初，尚无为；我生之后，逢此百罹。尚寐无吪。", "有兔爰爰，雉离于罦。我生之初，尚无造；我生之后，逢此百忧。尚寐无觉。", "有兔爰爰，雉离于罿。我生之初，尚无庸；我生之后，逢此百凶。尚寐无聪。"]'),
('shijing-70','葛藟','佚名','先秦','诗经','shijing','','[]','绵绵葛藟，在河之浒。终远兄弟，谓他人父。谓他人父，亦莫我顾！',90,'诗经/shijing.json','["绵绵葛藟，在河之浒。终远兄弟，谓他人父。谓他人父，亦莫我顾！", "绵绵葛爰，在河之藟。终远兄弟，谓他人母。谓他人母，亦莫我有！", "绵绵葛藟，在河之漘。终远兄弟，谓他人昆。谓他人昆，亦莫我闻！"]'),
('shijing-71','采葛','佚名','先秦','诗经','shijing','','[]','彼采葛兮，一日不见，如三月兮！',45,'诗经/shijing.json','["彼采葛兮，一日不见，如三月兮！", "彼采萧兮，一日不见，如三秋兮！", "彼采艾兮！一日不见，如三岁兮！"]'),
('shijing-72','大车','佚名','先秦','诗经','shijing','','[]','大车槛槛，毳衣如菼。岂不尔思？畏子不敢。',60,'诗经/shijing.json','["大车槛槛，毳衣如菼。岂不尔思？畏子不敢。", "大车啍啍，毳衣如璊，岂不尔思？畏子不奔。", "谷则异室，死则同穴。谓予不信，有如皎日。"]'),
('shijing-73','丘中有麻','佚名','先秦','诗经','shijing','','[]','丘中有麻，彼留子嗟。彼留子嗟，将其来施施。',61,'诗经/shijing.json','["丘中有麻，彼留子嗟。彼留子嗟，将其来施施。", "丘中有麦，彼留子国。彼留子国，将其来食。", "丘中有李，彼留之子。彼留之子，贻我佩九。"]'),
('shijing-74','缁衣','佚名','先秦','诗经','shijing','','[]','缁衣之宜兮，敝予又改为兮。适子之馆兮。还予授子之粲兮。',81,'诗经/shijing.json','["缁衣之宜兮，敝予又改为兮。适子之馆兮。还予授子之粲兮。", "缁衣之好兮，敝予又改造兮。适子之馆兮，还予授子之粲兮。", "缁衣之席兮，敝予又改作兮。适子之馆兮，还予授子之粲兮。"]'),
('shijing-75','将仲子','佚名','先秦','诗经','shijing','','[]','将仲子兮，无逾我里，无折我树杞。岂敢爱之？畏我父母。仲可怀也，父母之言亦可畏也。',121,'诗经/shijing.json','["将仲子兮，无逾我里，无折我树杞。岂敢爱之？畏我父母。仲可怀也，父母之言亦可畏也。", "将仲子兮，无逾我墙，无折我树桑。岂敢爱之？畏我诸兄。仲可怀也，诸兄之言亦可畏也。", "将仲子兮，无逾我园，无折我树檀。岂敢爱之？畏人之多言。仲可怀也，人之多言亦可畏也。"]'),
('shijing-76','叔于田','佚名','先秦','诗经','shijing','','[]','叔于田，巷无居人。岂无居人？不如叔也。洵美且仁。',72,'诗经/shijing.json','["叔于田，巷无居人。岂无居人？不如叔也。洵美且仁。", "叔于狩，巷无饮酒。岂无饮酒？不如叔也。洵美且好。", "叔适野，巷无服马。岂无服马？不如叔也。洵美且武。"]'),
('shijing-77','大叔于田','佚名','先秦','诗经','shijing','','[]','叔于田，乘乘马。执辔如组，两骖如舞。叔在薮，火烈具举。襢裼暴虎，献于公所。将叔勿狃，戒其伤女。',141,'诗经/shijing.json','["叔于田，乘乘马。执辔如组，两骖如舞。叔在薮，火烈具举。襢裼暴虎，献于公所。将叔勿狃，戒其伤女。", "叔于田，乘乘黄。两服上襄，两骖雁行。叔在薮，火烈具扬。叔善射忌，又良御忌。抑罄控忌，抑纵送忌。", "叔于田，乘乘鸨。两服齐首，两骖如手。叔在薮，火烈具阜。叔马慢忌，叔发罕忌，抑释掤忌，抑鬯弓忌。"]'),
('shijing-78','清人','佚名','先秦','诗经','shijing','','[]','清人在彭，驷介旁旁。二矛重英，河上乎翱翔。',62,'诗经/shijing.json','["清人在彭，驷介旁旁。二矛重英，河上乎翱翔。", "清人在消，驷介麃麃。二矛重乔，河上乎逍遥。", "清人在轴，驷介陶陶。左旋右抽，中军作好。"]'),
('shijing-79','羔裘','佚名','先秦','诗经','shijing','','[]','羔裘如濡，洵直且侯。彼其之子，舍命不渝。',60,'诗经/shijing.json','["羔裘如濡，洵直且侯。彼其之子，舍命不渝。", "羔裘豹饰，孔武有力。彼其之子，邦之司直。", "羔裘晏兮，三英粲兮。彼其之子，邦之彦兮。"]'),
('shijing-80','遵大路','佚名','先秦','诗经','shijing','','[]','遵大路兮，掺执子之袪兮。无我恶兮，不蓵故也！',44,'诗经/shijing.json','["遵大路兮，掺执子之袪兮。无我恶兮，不蓵故也！", "遵大路兮，掺执子之手兮。无我魗兮，不蓵好也！"]'),
('shijing-81','女曰鸡鸣','佚名','先秦','诗经','shijing','','[]','女曰鸡鸣，士曰昧旦。子兴视夜，明星有烂。将翱将翔，弋凫与雁。',96,'诗经/shijing.json','["女曰鸡鸣，士曰昧旦。子兴视夜，明星有烂。将翱将翔，弋凫与雁。", "弋言加之，与子宜之。宜言饮酒，与子偕老。琴瑟在御，莫不静好。", "知子之来之，杂佩以赠之。知子之顺之，杂佩以问之。知子之好之，杂佩以报之。"]'),
('shijing-82','有女同车','佚名','先秦','诗经','shijing','','[]','有女同车，颜如舜华。将翱将翔，佩玉琼琚。彼美孟姜，洵美且都。',60,'诗经/shijing.json','["有女同车，颜如舜华。将翱将翔，佩玉琼琚。彼美孟姜，洵美且都。", "有女同行，颜如舜英。将翱将翔，佩玉将将。彼美孟姜，德音不忘。"]'),
('shijing-83','山有扶苏','佚名','先秦','诗经','shijing','','[]','山有扶苏，隰有荷华。不见子都，乃见狂且。',40,'诗经/shijing.json','["山有扶苏，隰有荷华。不见子都，乃见狂且。", "山有乔松，隰有游龙，不见子充，乃见狡童。"]'),
('shijing-84','萚兮','佚名','先秦','诗经','shijing','','[]','萚兮萚兮，风其吹女。叔兮伯兮，倡予和女。',40,'诗经/shijing.json','["萚兮萚兮，风其吹女。叔兮伯兮，倡予和女。", "萚兮萚兮，风其漂女。叔兮伯兮，倡予要女。"]'),
('shijing-85','狡童','佚名','先秦','诗经','shijing','','[]','彼狡童兮，不与我言兮。维子之故，使我不能餐兮。',46,'诗经/shijing.json','["彼狡童兮，不与我言兮。维子之故，使我不能餐兮。", "彼狡童兮，不与我食兮。维子之故，使我不能息兮。"]'),
('shijing-86','褰裳','佚名','先秦','诗经','shijing','','[]','子惠思我，褰裳涉溱。子不我思，岂无他人？狂童之狂也且！',54,'诗经/shijing.json','["子惠思我，褰裳涉溱。子不我思，岂无他人？狂童之狂也且！", "子惠思我，褰裳涉洧。子不我思，岂无他士？狂童之狂也且！"]'),
('shijing-87','丰','佚名','先秦','诗经','shijing','','[]','子之丰兮，俟我乎巷兮，悔予不送兮。',74,'诗经/shijing.json','["子之丰兮，俟我乎巷兮，悔予不送兮。", "子之昌兮，俟我乎堂兮，悔予不将兮。", "衣锦褧衣，裳锦褧裳。叔兮伯兮，驾予与行。", "裳锦褧裳，衣锦褧衣。叔兮伯兮，驾予与归。"]'),
('shijing-88','东门之墠','佚名','先秦','诗经','shijing','','[]','东门之墠，茹藘在阪。其室则迩，其人甚远。',40,'诗经/shijing.json','["东门之墠，茹藘在阪。其室则迩，其人甚远。", "东门之栗，有践家室。岂不尔思？子不我即！"]'),
('shijing-89','风雨','佚名','先秦','诗经','shijing','','[]','风雨凄凄，鸡鸣喈喈，既见君子。云胡不夷？',60,'诗经/shijing.json','["风雨凄凄，鸡鸣喈喈，既见君子。云胡不夷？", "风雨潇潇，鸡鸣胶胶。既见君子，云胡不瘳？", "风雨如晦，鸡鸣不已。既见君子，云胡不喜？"]'),
('shijing-90','子衿','佚名','先秦','诗经','shijing','','[]','青青子衿，悠悠我心。纵我不往，子宁不嗣音？',61,'诗经/shijing.json','["青青子衿，悠悠我心。纵我不往，子宁不嗣音？", "青青子佩，悠悠我思。纵我不往，子宁不来？", "挑兮达兮，在城阙兮。一日不见，如三月兮。"]'),
('shijing-91','扬之水','佚名','先秦','诗经','shijing','','[]','扬之水，不流束楚。终鲜兄弟，维予与女。无信人之言，人实诳女。',60,'诗经/shijing.json','["扬之水，不流束楚。终鲜兄弟，维予与女。无信人之言，人实诳女。", "扬之水，不流束薪。终鲜兄弟，维予二人。无信人之言，人实不信。"]'),
('shijing-92','出其东门','佚名','先秦','诗经','shijing','','[]','出其东门，有女如云。虽则如云。匪我思存。缟衣綦巾，聊乐我员。',60,'诗经/shijing.json','["出其东门，有女如云。虽则如云。匪我思存。缟衣綦巾，聊乐我员。", "出其闉阇，有女如荼。虽则如荼，匪我思且。缟衣茹藘，聊可与娱。"]'),
('shijing-93','野有蔓草','佚名','先秦','诗经','shijing','','[]','野有蔓草，零露漙兮。有美一人，清扬婉兮。邂逅相遇，适我愿兮。',60,'诗经/shijing.json','["野有蔓草，零露漙兮。有美一人，清扬婉兮。邂逅相遇，适我愿兮。", "野有蔓草，零露瀼瀼。有美一人，婉如清扬。邂逅相遇，与子偕臧。"]'),
('shijing-94','溱洧','佚名','先秦','诗经','shijing','','[]','溱与洧，方涣涣兮。士与女，方秉蕳兮。女曰观乎？士曰既且。且往观乎？',116,'诗经/shijing.json','["溱与洧，方涣涣兮。士与女，方秉蕳兮。女曰观乎？士曰既且。且往观乎？", "洧之外，洵訏且乐。维士与女，伊其相谑，赠之以勺药。", "溱与洧，浏其清矣。士与女，殷其盈矣。女曰观乎？士曰既且。且往观乎？", "洧之外，洵訏且乐。维士与女，伊其将谑，赠之以勺药。"]'),
('shijing-95','鸡鸣','佚名','先秦','诗经','shijing','','[]','鸡既鸣矣，朝既盈矣。匪鸡则鸣，苍蝇之声。',63,'诗经/shijing.json','["鸡既鸣矣，朝既盈矣。匪鸡则鸣，苍蝇之声。", "东方明矣，朝既昌矣。匪东方则明，月出之光。", "虫飞薨薨，甘与子同梦。会且归矣，无庶予子憎。"]'),
('shijing-96','还','佚名','先秦','诗经','shijing','','[]','子之还兮，遭我乎狃之间兮。并驱从两肩兮，揖我谓我儇兮。',81,'诗经/shijing.json','["子之还兮，遭我乎狃之间兮。并驱从两肩兮，揖我谓我儇兮。", "子之茂兮，遭我乎狃之道兮。并驱从两牡兮，揖我谓我好兮。", "子之昌兮，遭我乎狃之阳兮。并驱从两狼兮，揖我谓我臧兮。"]'),
('shijing-97','着','佚名','先秦','诗经','shijing','','[]','俟我于着乎而，充耳以素乎而，尚之以琼华乎而。',66,'诗经/shijing.json','["俟我于着乎而，充耳以素乎而，尚之以琼华乎而。", "俟我于庭乎而，充耳以青乎而，尚之以琼莹乎而。", "俟我于堂乎而，充耳以黄乎而，尚之以琼英乎而。"]'),
('shijing-98','东方之日','佚名','先秦','诗经','shijing','','[]','东方之日兮，彼姝者子，在我室兮。在我室兮，履我即兮。',52,'诗经/shijing.json','["东方之日兮，彼姝者子，在我室兮。在我室兮，履我即兮。", "东方之月兮，彼姝者子，在我闼兮。在我闼兮，履我发兮。"]'),
('shijing-99','东方未明','佚名','先秦','诗经','shijing','','[]','东方未明，颠倒衣裳。颠之倒之，自公召之。',60,'诗经/shijing.json','["东方未明，颠倒衣裳。颠之倒之，自公召之。", "东方未晞，颠倒裳衣。倒之颠之，自公令之。", "折柳樊圃，狂夫瞿瞿。不能辰夜，不夙则莫。"]'),
('shijing-100','南山','佚名','先秦','诗经','shijing','','[]','南山崔崔，雄狐绥绥。鲁道有荡，齐子由归。既曰归止，曷又怀止？',124,'诗经/shijing.json','["南山崔崔，雄狐绥绥。鲁道有荡，齐子由归。既曰归止，曷又怀止？", "葛屦五两，冠緌双止。鲁道有荡，齐子庸止。既曰庸止，曷又从止？", "蓺麻如之何？衡从其亩。取妻如之何？必告父母。既曰告止，曷又鞠止？", "析薪如之何？匪斧不克。取妻如之何？匪媒不得。既曰得止，曷又极止？"]'),
('shijing-101','甫田','佚名','先秦','诗经','shijing','','[]','无田甫田，维莠骄骄。无思远人，劳心忉忉。',60,'诗经/shijing.json','["无田甫田，维莠骄骄。无思远人，劳心忉忉。", "无田甫田，维莠桀桀。无思远人，劳心怛怛。", "婉兮娈兮。总角丱兮。未几见兮，突而弁兮！"]'),
('shijing-102','卢令','佚名','先秦','诗经','shijing','','[]','卢令令，其人美且仁。',30,'诗经/shijing.json','["卢令令，其人美且仁。", "卢重环，其人美且鬈。", "卢重鋂，其人美且偲。"]'),
('shijing-103','敝笱','佚名','先秦','诗经','shijing','','[]','敝笱在梁，其鱼鲂鳏。齐子归止，其从如云。',60,'诗经/shijing.json','["敝笱在梁，其鱼鲂鳏。齐子归止，其从如云。", "敝笱在梁，其鱼鲂鱮。齐子归止，其从如雨。", "敝笱在梁，其鱼唯唯。齐子归止，其从如水。"]'),
('shijing-104','载驱','佚名','先秦','诗经','shijing','','[]','载驱薄薄，簟茀朱鞹。鲁道有荡，齐子发夕。',80,'诗经/shijing.json','["载驱薄薄，簟茀朱鞹。鲁道有荡，齐子发夕。", "四骊济济，垂辔沵沵。鲁道有荡，齐子岂弟。", "汶水汤汤，行人彭彭。鲁道有荡，齐子翱翔。", "汶水滔滔，行人儦儦。鲁道有荡，齐了游敖。"]'),
('shijing-105','猗嗟','佚名','先秦','诗经','shijing','','[]','猗嗟昌兮，颀而长兮。抑若扬兮，美目扬兮。巧趋跄兮，射则臧兮。',90,'诗经/shijing.json','["猗嗟昌兮，颀而长兮。抑若扬兮，美目扬兮。巧趋跄兮，射则臧兮。", "猗嗟名兮，美目清兮。仪既成兮，终日射侯，不出正兮，展我甥兮。", "猗嗟娈兮，清扬婉兮。舞则选兮，射则贯兮，四矢反兮，以御乱兮。"]'),
('shijing-106','葛屦','佚名','先秦','诗经','shijing','','[]','纠纠葛屦，可以履霜？掺掺女手，可以缝裳？要之襋之，好人服之。',55,'诗经/shijing.json','["纠纠葛屦，可以履霜？掺掺女手，可以缝裳？要之襋之，好人服之。", "好人提提，宛然左辟，佩其象揥。维是褊心，是以为刺。"]'),
('shijing-107','汾沮洳','佚名','先秦','诗经','shijing','','[]','彼汾沮洳，言采其莫。彼其之子，美无度。美无度，殊异乎公路。',87,'诗经/shijing.json','["彼汾沮洳，言采其莫。彼其之子，美无度。美无度，殊异乎公路。", "彼汾一方，言采其桑。彼其之子，美如英。美如英，殊异乎公行。", "彼汾一曲，言采其藚。彼其之子，美如玉。美如玉，殊异乎公族。"]'),
('shijing-108','园有桃','佚名','先秦','诗经','shijing','','[]','园有桃，其实之肴。心之忧矣，我歌且谣。不知我者，谓我士也骄。',121,'诗经/shijing.json','["园有桃，其实之肴。心之忧矣，我歌且谣。不知我者，谓我士也骄。", "彼人是哉，子曰何其？心之忧矣，其谁知之？其谁知之，盖亦勿思！", "园有棘，其实之食。心之忧矣，聊以行国。不知我者，谓我士也罔极。", "彼人是哉，子曰何其？心之忧矣，其谁知之？其谁知之，盖亦勿思！"]'),
('shijing-109','陟岵','佚名','先秦','诗经','shijing','','[]','陟彼岵兮，瞻望父兮。父曰：嗟！予子行役，夙夜无已。上慎旃哉，犹来！无止！',108,'诗经/shijing.json','["陟彼岵兮，瞻望父兮。父曰：嗟！予子行役，夙夜无已。上慎旃哉，犹来！无止！", "陟彼屺兮，瞻望母兮。母曰：嗟！予季行役，夙夜无寐。上慎旃哉，犹来！无弃！", "陟彼冈兮，瞻望兄兮。兄曰：嗟！予弟行役，夙夜必偕。上慎旃哉，犹来！无死！"]'),
('shijing-110','十亩之间','佚名','先秦','诗经','shijing','','[]','十亩之间兮，桑者闲闲兮，行与子还兮。',36,'诗经/shijing.json','["十亩之间兮，桑者闲闲兮，行与子还兮。", "十亩之外兮，桑者泄泄兮，行与子逝兮。"]'),
('shijing-111','伐檀','佚名','先秦','诗经','shijing','','[]','坎坎伐檀兮，置之河之干兮。河水清且涟猗。不稼不穑，胡取禾三百廛兮？',171,'诗经/shijing.json','["坎坎伐檀兮，置之河之干兮。河水清且涟猗。不稼不穑，胡取禾三百廛兮？", "不狩不猎，胡瞻尔庭有县貆兮？彼君子兮，不素餐兮！", "坎坎伐辐兮，置之河之侧兮。河水清且直猗。不稼不穑，胡取禾三百亿兮？", "不狩不猎，胡瞻尔庭有县特兮？彼君子兮，不素食兮！", "坎坎伐轮兮，置之河之漘兮。河水清且沦猗。不稼不穑，胡取禾三百囷兮？", "不狩不猎，胡瞻尔庭有县鹑兮？彼君子兮，不素飧兮！"]'),
('shijing-112','硕鼠','佚名','先秦','诗经','shijing','','[]','硕鼠硕鼠，无食我黍！三岁贯女，莫我肯顾。逝将去女，适彼乐土。乐土乐土，爰得我所。',120,'诗经/shijing.json','["硕鼠硕鼠，无食我黍！三岁贯女，莫我肯顾。逝将去女，适彼乐土。乐土乐土，爰得我所。", "硕鼠硕鼠，无食我麦！三岁贯女，莫我肯德。逝将去女，适彼乐国。乐国乐国，爰得我直。", "硕鼠硕鼠，无食我苗！三岁贯女，莫我肯劳。逝将去女，适彼乐郊。乐郊乐郊，谁之永号？"]'),
('shijing-113','蟋蟀','佚名','先秦','诗经','shijing','','[]','蟋蟀在堂，岁聿其莫。今我不乐，日月其除。无已大康，职思其居。好乐无荒，良士瞿瞿。',120,'诗经/shijing.json','["蟋蟀在堂，岁聿其莫。今我不乐，日月其除。无已大康，职思其居。好乐无荒，良士瞿瞿。", "蟋蟀在堂，岁聿其逝。今我不乐，日月其迈。无已大康，职思其外。好乐无荒，良士蹶蹶。", "蟋蟀在堂，役车其休。今我不乐，日月其慆。无以大康。职思其忧。好乐无荒，良士休休。"]'),
('shijing-114','山有枢','佚名','先秦','诗经','shijing','','[]','山有枢，隰有榆。子有衣裳，弗曳弗娄。子有车马，弗驰弗驱。宛其死矣，他人是愉。',115,'诗经/shijing.json','["山有枢，隰有榆。子有衣裳，弗曳弗娄。子有车马，弗驰弗驱。宛其死矣，他人是愉。", "山有栲，隰有杻。子有廷内，弗洒弗扫。子有钟鼓，弗鼓弗考。宛其死矣，他人是保。", "山有漆，隰有栗。子有酒食，何不日鼓瑟？且以喜乐，且以永日。宛其死矣，他人入室。"]'),
('shijing-115','扬之水','佚名','先秦','诗经','shijing','','[]','扬之水，白石凿凿。素衣朱襮，从子于沃。既见君子，云何不乐？',78,'诗经/shijing.json','["扬之水，白石凿凿。素衣朱襮，从子于沃。既见君子，云何不乐？", "扬之水，白石皓皓。素衣朱绣，从子于鹄。既见君子，云何其忧？", "扬之水，白石粼粼。我闻有命，不敢以告人。"]'),
('shijing-116','椒聊','佚名','先秦','诗经','shijing','','[]','椒聊之实，蕃衍盈升。彼其之子，硕大无朋。椒聊且，远条且。',56,'诗经/shijing.json','["椒聊之实，蕃衍盈升。彼其之子，硕大无朋。椒聊且，远条且。", "椒聊之实，蕃衍盈匊。彼其之子，硕大且笃。椒聊且，远条且。"]'),
('shijing-117','绸缪','佚名','先秦','诗经','shijing','','[]','绸缪束薪，三星在天。今夕何夕，见此良人？子兮子兮，如此良人何？',93,'诗经/shijing.json','["绸缪束薪，三星在天。今夕何夕，见此良人？子兮子兮，如此良人何？", "绸缪束刍，三星在隅。今夕何夕，见此邂逅？子兮子兮，如此邂逅何？", "绸缪束楚，三星在户。今夕何夕，见此粲者？子兮子兮，如此粲者何？"]'),
('shijing-118','杕杜','佚名','先秦','诗经','shijing','','[]','有杕之杜，其叶湑湑。独行踽踽。岂无他人？不如我同父。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？',92,'诗经/shijing.json','["有杕之杜，其叶湑湑。独行踽踽。岂无他人？不如我同父。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？", "有杕之杜，其叶箐箐。独行睘睘。岂无他人？不如我同姓。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？"]'),
('shijing-119','羔裘','佚名','先秦','诗经','shijing','','[]','羔裘豹祛，自我人居居。岂无他人？维子之故。',42,'诗经/shijing.json','["羔裘豹祛，自我人居居。岂无他人？维子之故。", "羔裘豹褎，自我人究究。岂无他人？维子之好。"]'),
('shijing-120','鸨羽','佚名','先秦','诗经','shijing','','[]','肃肃鸨羽，集于苞栩。王事靡盬，不能蓺稷黍。父母何怙？悠悠苍天，曷其有所？',108,'诗经/shijing.json','["肃肃鸨羽，集于苞栩。王事靡盬，不能蓺稷黍。父母何怙？悠悠苍天，曷其有所？", "肃肃鸨翼，集于苞棘。王事靡盬，不能蓺黍稷。父母何食？悠悠苍天，曷其有极？", "肃肃鸨行，集于苞桑，王事靡盬，不能蓺稻梁。父母何尝？悠悠苍天，曷其有常？"]'),
('shijing-121','无衣','佚名','先秦','诗经','shijing','','[]','岂曰无衣七兮？不如子之衣，安且吉兮！',36,'诗经/shijing.json','["岂曰无衣七兮？不如子之衣，安且吉兮！", "岂曰无衣六兮？不如子之衣，安且燠兮！"]'),
('shijing-122','有杕之杜','佚名','先秦','诗经','shijing','','[]','有杕之杜，生于道左。彼君子兮，噬肯适我？中心好之，曷饮食之？',60,'诗经/shijing.json','["有杕之杜，生于道左。彼君子兮，噬肯适我？中心好之，曷饮食之？", "有杕之杜，生于道周。彼君子兮，噬肯来游？中心好之，曷饮食之？"]'),
('shijing-123','葛生','佚名','先秦','诗经','shijing','','[]','葛生蒙楚，蔹蔓于野。予美亡此，谁与？独处？',99,'诗经/shijing.json','["葛生蒙楚，蔹蔓于野。予美亡此，谁与？独处？", "葛生蒙棘，蔹蔓于域。予美亡此，谁与？独息？", "角枕粲兮，锦衾烂兮。予美亡此，谁与？独旦？", "夏之日，冬之夜。百岁之后，归于其居。", "冬之夜，夏之日。百岁之后，归于其室。"]'),
('shijing-124','采苓','佚名','先秦','诗经','shijing','','[]','采苓采苓，首阳之巅。人之为言，苟亦无信。舍旃舍旃，苟亦无然。人之为言，胡得焉？',117,'诗经/shijing.json','["采苓采苓，首阳之巅。人之为言，苟亦无信。舍旃舍旃，苟亦无然。人之为言，胡得焉？", "采苦采苦，首阳之下。人之为言，苟亦无与。舍旃舍旃，苟亦无然。人之为言，胡得焉？", "采葑采葑，首阳之东。人之为言，苟亦无从。舍旃舍旃，苟亦无然。人之为言，胡得焉？"]'),
('shijing-125','车邻','佚名','先秦','诗经','shijing','','[]','有车邻邻，有马白颠。未见君子，寺人之令。',76,'诗经/shijing.json','["有车邻邻，有马白颠。未见君子，寺人之令。", "阪有漆，隰有栗。既见君子，并坐鼓瑟。今者不乐，逝者其耋。", "阪有桑，隰有杨。既见君子，并坐鼓簧。今者不乐，逝者其亡。"]'),
('shijing-126','驷驖','佚名','先秦','诗经','shijing','','[]','驷驖孔阜，六辔在手。公之媚子，从公于狩。',60,'诗经/shijing.json','["驷驖孔阜，六辔在手。公之媚子，从公于狩。", "奉时辰牡，辰牡孔硕。公曰左之，舍拔则获。", "游于北园，四马既闲。輶车鸾镳，载猃歇骄。"]'),
('shijing-127','小戎','佚名','先秦','诗经','shijing','','[]','小戎俴收，五楘梁辀。游环胁驱，阴靷鋈续。文茵畅毂，驾我骐馵。',151,'诗经/shijing.json','["小戎俴收，五楘梁辀。游环胁驱，阴靷鋈续。文茵畅毂，驾我骐馵。", "言念君子，温其如玉。在其板屋，乱我心曲。", "四牡孔阜，六辔在手。骐骝是中，騧骊是骖。龙盾之合，鋈以觼軜。", "言念君子，温其在邑。方何为期？胡然我念之！", "俴驷孔群，厹矛鋈錞。蒙伐有苑，虎韔镂膺。交韔二弓，竹闭绲縢。", "言念君子，载寝载兴。厌厌良人，秩秩德音。"]'),
('shijing-128','蒹葭','佚名','先秦','诗经','shijing','','[]','蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。',123,'诗经/shijing.json','["蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。", "蒹葭萋萋，白露未晞。所谓伊人，在水之湄。溯洄从之，道阻且跻。溯游从之，宛在水中坻。", "蒹葭采采，白露未已。所谓伊人，在水之涘。溯洄从之，道阻且右。溯游从之，宛在水中沚。"]'),
('shijing-129','终南','佚名','先秦','诗经','shijing','','[]','终南何有？有条有梅。君子至止，锦衣狐裘。颜如渥丹，其君也哉！',60,'诗经/shijing.json','["终南何有？有条有梅。君子至止，锦衣狐裘。颜如渥丹，其君也哉！", "终南何有？有纪有堂。君子至止，黻衣绣裳。佩玉将将，寿考不忘！"]'),
('shijing-130','黄鸟','佚名','先秦','诗经','shijing','','[]','交交黄鸟，止于棘。谁从穆公？子车奄息。维此奄息，百夫之特。',174,'诗经/shijing.json','["交交黄鸟，止于棘。谁从穆公？子车奄息。维此奄息，百夫之特。", "临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！", "交交黄鸟，止于桑。谁从穆公？子车仲行。维此仲行，百夫之防。", "临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！", "交交黄鸟，止于楚。谁从穆公？子车针虎。维此针虎，百夫之御。", "临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！"]'),
('shijing-131','晨风','佚名','先秦','诗经','shijing','','[]','鴥彼晨风，郁彼北林。未见君子，忧心钦钦。如何如何，忘我实多！',90,'诗经/shijing.json','["鴥彼晨风，郁彼北林。未见君子，忧心钦钦。如何如何，忘我实多！", "山有苞栎，隰有六駮。未见君子，忧心靡乐。如何如何，忘我实多！", "山有苞棣，隰有树檖。未见君子，忧心如醉。如何如何，忘我实多！"]'),
('shijing-132','无衣','佚名','先秦','诗经','shijing','','[]','岂曰无衣？与子同袍。王于兴师，修我戈矛。与子同仇！',75,'诗经/shijing.json','["岂曰无衣？与子同袍。王于兴师，修我戈矛。与子同仇！", "岂曰无衣？与子同泽。王于兴师，修我矛戟。与子偕作！", "岂曰无衣？与子同裳。王于兴师，修我甲兵。与子偕行！"]'),
('shijing-133','渭阳','佚名','先秦','诗经','shijing','','[]','我送舅氏，曰至渭阳。何以赠之？路车乘黄。',40,'诗经/shijing.json','["我送舅氏，曰至渭阳。何以赠之？路车乘黄。", "我送舅氏，悠悠我思。何以赠之？琼瑰玉佩。"]'),
('shijing-134','权舆','佚名','先秦','诗经','shijing','','[]','于我乎，夏屋渠渠，今也每食无余。于嗟乎，不承权舆！',50,'诗经/shijing.json','["于我乎，夏屋渠渠，今也每食无余。于嗟乎，不承权舆！", "于我乎，每食四簋，今也每食不饱。于嗟乎，不承权舆！"]'),
('shijing-135','宛丘','佚名','先秦','诗经','shijing','','[]','子之汤兮，宛丘之上兮。洵有情兮，而无望兮。',61,'诗经/shijing.json','["子之汤兮，宛丘之上兮。洵有情兮，而无望兮。", "坎其击鼓，宛丘之下。无冬无夏，值其鹭羽。", "坎其击缶，宛丘之道。无冬无夏，值其鹭翿。"]'),
('shijing-136','东门之枌','佚名','先秦','诗经','shijing','','[]','东门之枌，宛丘之栩。子仲之子，婆娑其下。',60,'诗经/shijing.json','["东门之枌，宛丘之栩。子仲之子，婆娑其下。", "穀旦于差，南方之原。不绩其麻，市也婆娑。", "穀旦于逝，越以鬷迈。视尔如荍，贻我握椒。"]'),
('shijing-137','衡门','佚名','先秦','诗经','shijing','','[]','衡门之下，可以栖迟。泌之洋洋，可以乐饥。',60,'诗经/shijing.json','["衡门之下，可以栖迟。泌之洋洋，可以乐饥。", "岂其食鱼，必河之鲂？岂其取妻，必齐之姜？", "岂其食鱼，必河之鲤？岂其取妻，必宋之子？"]'),
('shijing-138','东门之池','佚名','先秦','诗经','shijing','','[]','东门之池，可以沤麻。彼美淑姬，可与晤歌。',60,'诗经/shijing.json','["东门之池，可以沤麻。彼美淑姬，可与晤歌。", "东门之池，可以沤纻。彼美淑姬，可与晤语。", "东门之池，可以沤菅。彼美淑姬，可与晤言。"]'),
('shijing-139','东门之杨','佚名','先秦','诗经','shijing','','[]','东门之杨，其叶牂牂。昏以为期，明星煌煌。',40,'诗经/shijing.json','["东门之杨，其叶牂牂。昏以为期，明星煌煌。", "东门之杨，其叶肺肺。昏以为期，明星晢晢。"]'),
('shijing-140','墓门','佚名','先秦','诗经','shijing','','[]','墓门有棘，斧以斯之。夫也不良，国人知之。知而不已，谁昔然矣。',60,'诗经/shijing.json','["墓门有棘，斧以斯之。夫也不良，国人知之。知而不已，谁昔然矣。", "墓门有梅，有鸮萃止。夫也不良，歌以讯之。讯予不顾，颠倒思予。"]'),
('shijing-141','防有鹊巢','佚名','先秦','诗经','shijing','','[]','防有鹊巢，邛有旨苕。谁侜予美？心焉忉忉。',40,'诗经/shijing.json','["防有鹊巢，邛有旨苕。谁侜予美？心焉忉忉。", "中唐有甓，邛有旨鷊。谁侜予美？心焉惕惕。"]'),
('shijing-142','月出','佚名','先秦','诗经','shijing','','[]','月出皎兮。佼人僚兮。舒窈纠兮。劳心悄兮。',60,'诗经/shijing.json','["月出皎兮。佼人僚兮。舒窈纠兮。劳心悄兮。", "月出皓兮。佼人懰兮。舒忧受兮。劳心慅兮。", "月出照兮。佼人燎兮。舒夭绍兮。劳心惨兮。"]'),
('shijing-143','株林','佚名','先秦','诗经','shijing','','[]','胡为乎株林？从夏南！匪适株林，从夏南！',39,'诗经/shijing.json','["胡为乎株林？从夏南！匪适株林，从夏南！", "驾我乘马，说于株野。乘我乘驹，朝食于株！"]'),
('shijing-144','泽陂','佚名','先秦','诗经','shijing','','[]','彼泽之陂，有蒲与荷。有美一人，伤如之何？寤寐无为，涕泗滂沱。',90,'诗经/shijing.json','["彼泽之陂，有蒲与荷。有美一人，伤如之何？寤寐无为，涕泗滂沱。", "彼泽之陂，有蒲与蕳。有美一人，硕大且卷。寤寐无为，中心悁悁。", "彼泽之陂，有蒲菡萏。有美一人，硕大且俨。寤寐无为，辗转伏枕。"]'),
('shijing-145','羔裘','佚名','先秦','诗经','shijing','','[]','羔裘逍遥，狐裘以朝。岂不尔思？劳心忉忉。',60,'诗经/shijing.json','["羔裘逍遥，狐裘以朝。岂不尔思？劳心忉忉。", "羔裘翱翔，狐裘在堂。岂不尔思？我心忧伤。", "羔裘如膏，日出有曜。岂不尔思？中心是悼。"]'),
('shijing-146','素冠','佚名','先秦','诗经','shijing','','[]','庶见素冠兮，棘人栾栾兮。劳心慱慱兮。',56,'诗经/shijing.json','["庶见素冠兮，棘人栾栾兮。劳心慱慱兮。", "庶见素衣兮，我心伤悲兮。聊与子同归兮。", "庶见素韠兮，我心蕴结兮。聊与子如一兮。"]'),
('shijing-147','隰有苌楚','佚名','先秦','诗经','shijing','','[]','隰有苌楚，猗傩其枝，夭之沃沃，乐子之无知。',63,'诗经/shijing.json','["隰有苌楚，猗傩其枝，夭之沃沃，乐子之无知。", "隰有苌楚，猗傩其华，夭之沃沃。乐子之无家。", "隰有苌楚，猗傩其实，夭之沃沃。乐子之无室。"]'),
('shijing-148','匪风','佚名','先秦','诗经','shijing','','[]','匪风发兮，匪车偈兮。顾瞻周道，中心怛兮。',60,'诗经/shijing.json','["匪风发兮，匪车偈兮。顾瞻周道，中心怛兮。", "匪风飘兮，匪车嘌兮。顾瞻周道，中心吊兮。", "谁能亨鱼？溉之釜鬵。谁将西归？怀之好音。"]'),
('shijing-149','蜉蝣','佚名','先秦','诗经','shijing','','[]','蜉蝣之羽，衣裳楚楚。心之忧矣，于我归处。',60,'诗经/shijing.json','["蜉蝣之羽，衣裳楚楚。心之忧矣，于我归处。", "蜉蝣之翼，采采衣服。心之忧矣，于我归息。", "蜉蝣掘阅，麻衣如雪。心之忧矣，于我归说。"]'),
('shijing-150','候人','佚名','先秦','诗经','shijing','','[]','彼候人兮，何戈与祋。彼其之子，三百赤芾。',80,'诗经/shijing.json','["彼候人兮，何戈与祋。彼其之子，三百赤芾。", "维鹈在梁，不濡其翼。彼其之子，不称其服。", "维鹈在梁，不濡其咮。彼其之子，不遂其媾。", "荟兮蔚兮，南山朝隮。婉兮娈兮，季女斯饥。"]'),
('shijing-151','鳲鸠','佚名','先秦','诗经','shijing','','[]','鳲鸠在桑，其子七兮。淑人君子，其仪一兮。其仪一兮，心如结兮。',120,'诗经/shijing.json','["鳲鸠在桑，其子七兮。淑人君子，其仪一兮。其仪一兮，心如结兮。", "鳲鸠在桑，其子在梅。淑人君子，其带伊丝。其带伊丝，其弁伊骐。", "鳲鸠在桑，其子在棘。淑人君子，其仪不忒。其仪不忒，正是四国。", "鳲鸠在桑，其子在榛。淑人君子，正是国人，正是国人。胡不万年？"]'),
('shijing-152','下泉','佚名','先秦','诗经','shijing','','[]','冽彼下泉，浸彼苞稂。忾我寤叹，念彼周京。',80,'诗经/shijing.json','["冽彼下泉，浸彼苞稂。忾我寤叹，念彼周京。", "冽彼下泉，浸彼苞萧。忾我寤叹，念彼京周。", "冽彼下泉，浸彼苞蓍。忾我寤叹，念彼京师。", "芃芃黍苗，阴雨膏之。四国有王，郇伯劳之。"]'),
('shijing-153','七月','佚名','先秦','诗经','shijing','','[]','七月流火，九月授衣。一之日觱发，二之日栗烈。无衣无褐，何以卒岁？',472,'诗经/shijing.json','["七月流火，九月授衣。一之日觱发，二之日栗烈。无衣无褐，何以卒岁？", "三之日于耜，四之日举趾。同我妇子，馌彼南亩。田畯至喜。", "七月流火，九月授衣。春日载阳，有鸣仓庚。女执懿筐，遵彼微行，爰求柔桑。", "春日迟迟，采蘩祁祁。女心伤悲，殆及公子同归。", "七月流火，八月萑苇。蚕月条桑，取彼斧斨。以伐远扬，猗彼女桑。", "七月鸣鵙，八月载绩。载玄载黄，我朱孔阳，为公子裳。", "四月秀葽，五月鸣蜩。八月其获，十月陨萚。一之日于貉，取彼狐狸，为公子裘。", "二之日其同，载缵武功。言私其豵，献豜于公。", "五月斯螽动股，六月莎鸡振羽。七月在野，八月在宇，九月在户，十月蟋蟀，入我床下。", "穹窒熏鼠，塞向墐户。嗟我妇子，曰为改岁，入此室处。", "六月食郁及薁，七月亨葵及菽。八月剥枣，十月获稻。为此春酒，以介眉寿。", "七月食瓜，八月断壶，九月叔苴，采荼薪樗。食我农夫。", "九月筑场圃，十月纳禾稼。黍稷重穋，禾麻菽麦。嗟我农夫，我稼既同，上入执宫功。", "昼尔于茅，宵尔索綯，亟其乘屋，其始播百谷。", "二之日凿冰冲冲，三之日纳于凌阴。四之日其蚤，献羔祭韭。九月肃霜，十月涤场。", "朋酒斯飨，曰杀羔羊，跻彼公堂。称彼兕觥：万寿无疆！"]'),
('shijing-154','鸱鸮','佚名','先秦','诗经','shijing','','[]','鸱鸮鸱鸮，既取我子，无毁我室。恩斯勤斯，鬻子之闵斯。',107,'诗经/shijing.json','["鸱鸮鸱鸮，既取我子，无毁我室。恩斯勤斯，鬻子之闵斯。", "迨天之未阴雨，彻彼桑土，绸缪牖户。今女下民，或敢侮予？", "予手拮据，予所捋荼。予所蓄租，予口卒瘏，曰予未有室家。", "予羽谯谯，予尾翛翛，予室翘翘。风雨所漂摇，予维音哓哓！"]'),
('shijing-155','东山','佚名','先秦','诗经','shijing','','[]','我徂东山，慆慆不归。我来自东，零雨其濛。我东曰归，我心西悲。',241,'诗经/shijing.json','["我徂东山，慆慆不归。我来自东，零雨其濛。我东曰归，我心西悲。", "制彼裳衣，勿士行枚。蜎蜎者蠋，烝在桑野。敦彼独宿，亦在车下。", "我徂东山，慆慆不归。我来自东，零雨其濛。果臝之实，亦施于宇。", "伊威在室，蠨蛸在户。町畽鹿场，熠耀宵行。不可畏也，伊可怀也。", "我徂东山，慆慆不归。我来自东，零雨其濛。鹳鸣于垤，妇叹于室。", "洒扫穹窒，我征聿至。有敦瓜苦，烝在栗薪。自我不见，于今三年。", "我徂东山，慆慆不归。我来自东，零雨其濛。仓庚于飞，熠耀其羽。", "之子于归，皇驳其马。亲结其缡，九十其仪。其新孔嘉，其旧如之何？"]'),
('shijing-156','破斧','佚名','先秦','诗经','shijing','','[]','既破我斧，又缺我斨。周公东征，四国是皇。哀我人斯，亦孔之将。',90,'诗经/shijing.json','["既破我斧，又缺我斨。周公东征，四国是皇。哀我人斯，亦孔之将。", "既破我斧，又缺我锜。周公东征，四国是遒。哀我人斯，亦孔之嘉。", "既破我斧，又缺我銶。周公东征，四国是遒。哀我人斯，亦孔之休。"]'),
('shijing-157','伐柯','佚名','先秦','诗经','shijing','','[]','伐柯如何？匪斧不克。取妻如何？匪媒不得。',40,'诗经/shijing.json','["伐柯如何？匪斧不克。取妻如何？匪媒不得。", "伐柯伐柯，其则不远。我觏之子，笾豆有践。"]'),
('shijing-158','九罭','佚名','先秦','诗经','shijing','','[]','九罭之鱼，鳟鲂。我觏之子，衮衣绣裳。',69,'诗经/shijing.json','["九罭之鱼，鳟鲂。我觏之子，衮衣绣裳。", "鸿飞遵渚，公归无所，于女信处。鸿飞遵六，公归不复，于女信宿。", "是以有衮衣兮，无以我公归兮，无使我心悲兮。"]'),
('shijing-159','狼跋','佚名','先秦','诗经','shijing','','[]','狼跋其胡，载疐其尾。公孙硕肤，赤舄几几。',40,'诗经/shijing.json','["狼跋其胡，载疐其尾。公孙硕肤，赤舄几几。", "狼疐其尾，载跋其胡。公孙硕肤，德音不瑕？"]'),
('shijing-160','鹿鸣','佚名','先秦','诗经','shijing','','[]','呦呦鹿鸣，食野之苹。我有嘉宾，鼓瑟吹笙。吹笙鼓簧，承筐是将。人之好我，示我周行。',127,'诗经/shijing.json','["呦呦鹿鸣，食野之苹。我有嘉宾，鼓瑟吹笙。吹笙鼓簧，承筐是将。人之好我，示我周行。", "呦呦鹿鸣，食野之蒿。我有嘉宾，德音孔昭。视民不恌，君子是则是效。我有旨酒，嘉宾式燕以敖。", "呦呦鹿鸣，食野之芩。我有嘉宾，鼓瑟鼓琴。鼓瑟鼓琴，和乐且湛。我有旨酒，以燕乐嘉宾之心。"]'),
('shijing-161','四牡','佚名','先秦','诗经','shijing','','[]','四牡騑騑，周道倭迟。岂不怀归？王事靡盬，我心伤悲。',125,'诗经/shijing.json','["四牡騑騑，周道倭迟。岂不怀归？王事靡盬，我心伤悲。", "四牡騑騑，啴啴骆马。岂不怀归？王事靡盬，不遑启处。", "翩翩者鵻，载飞载下，集于苞栩。王事靡盬，不遑将父。", "翩翩者鵻，载飞载止，集于苞杞。王事靡盬，不遑将母。", "驾彼四骆，载骤骎骎。岂不怀归？是用作歌，将母来谂。"]'),
('shijing-162','皇皇者华','佚名','先秦','诗经','shijing','','[]','皇皇者华，于彼原隰。駪駪征夫，每怀靡及。',100,'诗经/shijing.json','["皇皇者华，于彼原隰。駪駪征夫，每怀靡及。", "我马维驹，六辔如濡。载驰载驱，周爰咨诹。", "我马维骐，六辔如丝。载驰载驱，周爰咨谋。", "我马维骆，六辔沃若。载驰载驱，周爰咨度。", "我马维骃，六辔既均。载驰载驱，周爰咨询。"]'),
('shijing-163','棠棣','佚名','先秦','诗经','shijing','','[]','棠棣之华，鄂不韡韡。凡今之人，莫如兄弟。',161,'诗经/shijing.json','["棠棣之华，鄂不韡韡。凡今之人，莫如兄弟。", "死丧之威，兄弟孔怀。原隰裒矣，兄弟求矣。", "脊令在原，兄弟急难。每有良朋，况也永叹。", "兄弟阋于墙，外御其务。每有良朋，烝也无戎。", "丧乱既平，既安且宁。虽有兄弟，不如友生？", "傧尔笾豆，饮酒之饫。兄弟既具，和乐且孺。", "妻子好合，如鼓瑟琴。兄弟既翕，和乐且湛。", "宜尔室家，乐尔妻帑。是究是图，亶其然乎？"]'),
('shijing-164','伐木','佚名','先秦','诗经','shijing','','[]','伐木丁丁，鸟鸣嘤嘤。出自幽谷，迁于乔木。嘤其鸣矣，求其友声。',180,'诗经/shijing.json','["伐木丁丁，鸟鸣嘤嘤。出自幽谷，迁于乔木。嘤其鸣矣，求其友声。", "相彼鸟矣，犹求友声。矧伊人矣，不求友生？神之听之，终和且平。", "伐木许许，酾酒有藇！既有肥羜，以速诸父。宁适不来，微我弗顾。", "于粲洒扫，陈馈八簋。既有肥牡，以速诸舅。宁适不来，微我有咎。", "伐木于阪，酾酒有衍。笾豆有践，兄弟无远。民之失德，乾餱以愆。", "有酒湑我，无酒酤我。坎坎鼓我，蹲蹲舞我。迨我暇矣，饮此湑矣。"]'),
('shijing-165','天保','佚名','先秦','诗经','shijing','','[]','天保定尔，亦孔之固。俾尔单厚，何福不除？俾尔多益，以莫不庶。',185,'诗经/shijing.json','["天保定尔，亦孔之固。俾尔单厚，何福不除？俾尔多益，以莫不庶。", "天保定尔，俾尔戬穀。罄无不宜，受天百禄。降尔遐福，维日不足。", "天保定尔，以莫不兴。如山如阜，如冈如陵，如川之方至，以莫不增。", "吉蠲为饎，是用孝享。禴祠烝尝，于公先王。君曰：卜尔，万寿无疆。", "神之吊矣，诒尔多福。民之质矣，日用饮食。群黎百姓，遍为尔德。", "如月之恒，如日之升。如南山之寿，不骞不崩。如松柏之茂，无不尔或承。"]'),
('shijing-166','采薇','佚名','先秦','诗经','shijing','','[]','采薇采薇，薇亦作止。曰归曰归，岁亦莫止。靡室靡家，玁狁之故。不遑启居，玁狁之故。',240,'诗经/shijing.json','["采薇采薇，薇亦作止。曰归曰归，岁亦莫止。靡室靡家，玁狁之故。不遑启居，玁狁之故。", "采薇采薇，薇亦柔止。曰归曰归，心亦忧止。忧心烈烈，载饥载渴。我戍未定，靡使归聘。", "采薇采薇，薇亦刚止。曰归曰归，岁亦阳止。王事靡盬，不遑启处。忧心孔疚，我行不来！", "彼尔维何？维常之华。彼路斯何？君子之车。戎车既驾，四牡业业。岂敢定居？一月三捷。", "驾彼四牡，四牡骙骙。君子所依，小人所腓。四牡翼翼，象弭鱼服。岂不日戒？玁狁孔棘！", "昔我往矣，杨柳依依。今我来思，雨雪霏霏。行道迟迟，载渴载饥。我心伤悲，莫知我哀！"]'),
('shijing-167','出车','佚名','先秦','诗经','shijing','','[]','我出我车，于彼牧矣。自天子所，谓我来矣。召彼仆夫，谓之载矣。王事多难，维其棘矣。',240,'诗经/shijing.json','["我出我车，于彼牧矣。自天子所，谓我来矣。召彼仆夫，谓之载矣。王事多难，维其棘矣。", "我出我车，于彼郊矣。设此旐矣，建彼旄矣。彼旟旐斯，胡不旆旆？忧心悄悄，仆夫况瘁。", "王命南仲，往城于方。出车彭彭，旂旐央央。天子命我，城彼朔方。赫赫南仲，玁狁于襄。", "昔我往矣，黍稷方华。今我来思，雨雪载途。王事多难，不遑启居。岂不怀归？畏此简书。", "喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。既见君子，我心则降。赫赫南仲，薄伐西戎。", "春日迟迟，卉木萋萋。仓庚喈喈，采蘩祁祁。执讯获丑，薄言还归。赫赫南仲，玁狁于夷。"]'),
('shijing-168','杕杜','佚名','先秦','诗经','shijing','','[]','有杕之杜，有睆其实。王事靡盬，继嗣我日。日月阳止，女心伤止，征夫遑止。',140,'诗经/shijing.json','["有杕之杜，有睆其实。王事靡盬，继嗣我日。日月阳止，女心伤止，征夫遑止。", "有杕之杜，其叶萋萋。王事靡盬，我心伤悲。卉木萋止，女心悲止，征夫归止！", "陟彼北山，言采其杞。王事靡盬，忧我父母。檀车幝幝，四牡痯痯，征夫不远！", "匪载匪来，忧心孔疚。斯逝不至，而多为恤。卜筮偕止，会言近止，征夫迩止！"]'),
('shijing-169','鱼丽','佚名','先秦','诗经','shijing','','[]','鱼丽于罶，鲿鲨。君子有酒，旨且多。',81,'诗经/shijing.json','["鱼丽于罶，鲿鲨。君子有酒，旨且多。", "鱼丽于罶，鲂鳢。君子有酒，多且旨。", "鱼丽于罶，鰋鲤。君子有酒，旨且有。物其多矣，", "维其嘉矣！物其旨矣，维其偕矣！物其有矣，维其时矣！"]'),
('shijing-170','南有嘉鱼','佚名','先秦','诗经','shijing','','[]','南有嘉鱼，烝然罩罩。君子有酒，嘉宾式燕以乐。',88,'诗经/shijing.json','["南有嘉鱼，烝然罩罩。君子有酒，嘉宾式燕以乐。", "南有嘉鱼，烝然汕汕。君子有酒，嘉宾式燕以衎。", "南有樛木，甘瓠累之。君子有酒，嘉宾式燕绥之。", "翩翩者鵻，烝然来思。君子有酒，嘉宾式燕又思。"]'),
('shijing-171','南山有台','佚名','先秦','诗经','shijing','','[]','南山有台，北山有莱。乐只君子，邦家之基。乐只君子，万寿无期。',150,'诗经/shijing.json','["南山有台，北山有莱。乐只君子，邦家之基。乐只君子，万寿无期。", "南山有桑，北山有杨。乐只君子，邦家之光。乐只君子，万寿无疆。", "南山有杞，北山有李。乐只君子，民之父母。乐只君子，德音不已。", "南山有栲，北山有杻。乐只君子，遐不眉寿。乐只君子，德音是茂。", "南山有枸，北山有楰。乐只君子，遐不黄耇。乐只君子，保艾尔后。"]'),
('shijing-172','蓼萧','佚名','先秦','诗经','shijing','','[]','蓼彼萧斯，零露湑兮。既见君子，我心写兮。燕笑语兮，是以有誉处兮。',122,'诗经/shijing.json','["蓼彼萧斯，零露湑兮。既见君子，我心写兮。燕笑语兮，是以有誉处兮。", "蓼彼萧斯，零露瀼瀼。既见君子，为龙为光。其德不爽，寿考不忘。", "蓼彼萧斯，零露泥泥。既见君子，孔燕岂弟。宜兄宜弟，令德寿岂。", "蓼彼萧斯，零露浓浓。既见君子，鞗革忡忡。和鸾雍雍，万福攸同。"]'),
('shijing-173','湛露','佚名','先秦','诗经','shijing','','[]','湛湛露斯，匪阳不晞。厌厌夜饮，不醉无归。',80,'诗经/shijing.json','["湛湛露斯，匪阳不晞。厌厌夜饮，不醉无归。", "湛湛露斯，在彼丰草。厌厌夜饮，在宗载考。", "湛湛露斯，在彼杞棘。显允君子，莫不令德。", "其桐其椅，其实离离。岂弟君子，莫不令仪。"]'),
('shijing-174','彤弓','佚名','先秦','诗经','shijing','','[]','彤弓弨兮，受言藏之。我有嘉宾，中心贶之。钟鼓既设，一朝飨之。',90,'诗经/shijing.json','["彤弓弨兮，受言藏之。我有嘉宾，中心贶之。钟鼓既设，一朝飨之。", "彤弓弨兮，受言载之。我有嘉宾，中心喜之。钟鼓既设，一朝右之。", "彤弓弨兮，受言櫜之。我有嘉宾，中心好之。钟鼓既设，一朝酬之。"]'),
('shijing-175','菁菁者莪','佚名','先秦','诗经','shijing','','[]','菁菁者莪，在彼中阿。既见君子，乐且有仪。',80,'诗经/shijing.json','["菁菁者莪，在彼中阿。既见君子，乐且有仪。", "菁菁者莪，在彼中沚。既见君子，我心则喜。", "菁菁者莪，在彼中陵。既见君子，锡我百朋。", "泛泛杨舟，载沉载浮。既见君子，我心则休。"]'),
('shijing-176','六月','佚名','先秦','诗经','shijing','','[]','六月栖栖，戎车既饬。四牡骙骙，载是常服。玁狁孔炽，我是用急。王于出征，以匡王国。',240,'诗经/shijing.json','["六月栖栖，戎车既饬。四牡骙骙，载是常服。玁狁孔炽，我是用急。王于出征，以匡王国。", "比物四骊，闲之维则。维此六月，既成我服。我服既成，于三十里。王于出征，以佐天子。", "四牡修广，其大有颙。薄伐玁狁，以奏肤公。有严有翼，共武之服。共武之服，以定王国。", "玁狁匪茹，整居焦获。侵镐及方，至于泾阳。织文鸟章，白旆央央。元戎十乘，以先启行。", "戎车既安，如轾如轩。四牡既佶，既佶且闲。薄伐玁狁，至于大原。文武吉甫，万邦为宪。", "吉甫燕喜，既多受祉。来归自镐，我行永久。饮御诸友，炰鳖脍鲤。侯谁在矣？张仲孝友。"]'),
('shijing-177','采芑','佚名','先秦','诗经','shijing','','[]','薄言采芑，于彼新田，呈此菑亩。方叔涖止，其车三千。师干之试，方叔率止。',240,'诗经/shijing.json','["薄言采芑，于彼新田，呈此菑亩。方叔涖止，其车三千。师干之试，方叔率止。", "乘其四骐，四骐翼翼。路车有奭，簟茀鱼服，钩膺鞗革。", "薄言采芑，于彼新田，于此中乡。方叔涖止，其车三千。旂旐央央，方叔率止。", "约軧错衡，八鸾玱玱。服其命服，朱芾斯皇，有玱葱珩。", "鴥彼飞隼，其飞戾天，亦集爰止。方叔涖止，其车三千。师干之试，方叔率止。", "钲人伐鼓，陈师鞠旅。显允方叔，伐鼓渊渊，振旅阗阗。", "蠢尔蛮荆，大邦为仇。方叔元老，克壮其犹。方叔率止，执讯获丑。戎车啴啴，", "啴啴焞焞，如霆如雷。显允方叔，征伐玁狁，蛮荆来威。"]'),
('shijing-178','车攻','佚名','先秦','诗经','shijing','','[]','我车既攻，我马既同。四牡庞庞，驾言徂东。',160,'诗经/shijing.json','["我车既攻，我马既同。四牡庞庞，驾言徂东。", "田车既好，田牡孔阜。东有甫草，驾言行狩。", "之子于苗，选徒嚣嚣。建旐设旄，搏兽于敖。", "驾彼四牡，四牡奕奕。赤芾金舄，会同有绎。", "决拾既佽，弓矢既调。射夫既同，助我举柴。", "四黄既驾，两骖不猗。不失其驰，舍矢如破。", "萧萧马鸣，悠悠旆旌。徒御不惊，大庖不盈。", "之子于征，有闻无声。允矣君子，展也大成。"]'),
('shijing-179','吉日','佚名','先秦','诗经','shijing','','[]','吉日维戊，既伯既祷。田车既好，四牡孔阜。升彼大阜，从其群丑。',120,'诗经/shijing.json','["吉日维戊，既伯既祷。田车既好，四牡孔阜。升彼大阜，从其群丑。", "吉日庚午，既差我马。兽之所同，麀鹿麌麌。漆沮之从，天子之所。", "瞻彼中原，其祁孔有。儦儦俟俟，或群或友。悉率左右，以燕天子。", "既张我弓，既挟我矢。发彼小豝，殪此大兕。以御宾客，且以酌醴。"]'),
('shijing-180','鸿雁','佚名','先秦','诗经','shijing','','[]','鸿雁于飞，肃肃其羽。之子于征，劬劳于野。爰及矜人，哀此鳏寡。',90,'诗经/shijing.json','["鸿雁于飞，肃肃其羽。之子于征，劬劳于野。爰及矜人，哀此鳏寡。", "鸿雁于飞，集于中泽。之子于垣，百堵皆作。虽则劬劳，其究安宅？", "鸿雁于飞，哀鸣嗷嗷。维此哲人，谓我劬劳。维彼愚人，谓我宣骄。"]'),
('shijing-181','庭燎','佚名','先秦','诗经','shijing','','[]','夜如何其？夜未央，庭燎之光。君子至止，鸾声将将。',72,'诗经/shijing.json','["夜如何其？夜未央，庭燎之光。君子至止，鸾声将将。", "夜如何其？夜未艾，庭燎晣晣。君子至止，鸾声哕哕。", "夜如何其？夜乡晨，庭燎有辉。君子至止，言观其旂。"]'),
('shijing-182','沔水','佚名','先秦','诗经','shijing','','[]','沔彼流水，朝宗于海。鴥彼飞隼，载飞载止。嗟我兄弟，邦人诸友。莫肯念乱，谁无父母？',110,'诗经/shijing.json','["沔彼流水，朝宗于海。鴥彼飞隼，载飞载止。嗟我兄弟，邦人诸友。莫肯念乱，谁无父母？", "沔彼流水，其流汤汤。鴥彼飞隼，载飞载扬。念彼不迹，载起载行。心之忧矣，不可弭忘。", "鴥彼飞隼，率彼中陵。民之讹言，宁莫之惩？我友敬矣，谗言其兴。"]'),
('shijing-183','鹤鸣','佚名','先秦','诗经','shijing','','[]','鹤鸣于九皋，声闻于野。鱼潜在渊，或在于渚。乐彼之园，爰有树檀，其下维萚。他山之石，可以为错。',92,'诗经/shijing.json','["鹤鸣于九皋，声闻于野。鱼潜在渊，或在于渚。乐彼之园，爰有树檀，其下维萚。他山之石，可以为错。", "鹤鸣于九皋，声闻于天。鱼在于渚，或潜在渊。乐彼之园，爰有树檀，其下维谷。他山之石，可以攻玉。"]'),
('shijing-184','祈父','佚名','先秦','诗经','shijing','','[]','祈父，予王之爪牙。胡转予于恤，靡所止居？',59,'诗经/shijing.json','["祈父，予王之爪牙。胡转予于恤，靡所止居？", "祈父，予王之爪士。胡转予于恤，靡所厎止？", "祈父，亶不聪。胡转予于恤？有母之尸饔。"]'),
('shijing-185','白驹','佚名','先秦','诗经','shijing','','[]','皎皎白驹，食我场苗。絷之维之，以永今朝。所谓伊人，于焉逍遥？',121,'诗经/shijing.json','["皎皎白驹，食我场苗。絷之维之，以永今朝。所谓伊人，于焉逍遥？", "皎皎白驹，食我场藿。絷之维之，以永今夕。所谓伊人，于焉嘉客？", "皎皎白驹，贲然来思。尔公尔侯，逸豫无期？慎尔优游，勉尔遁思。", "皎皎白驹，在彼空谷。生刍一束，其人如玉。毋金玉尔音，而有遐心。"]'),
('shijing-186','黄鸟','佚名','先秦','诗经','shijing','','[]','黄鸟黄鸟，无集于穀，无啄我粟。此邦之人，不我肯穀。言旋言归，复我邦族。',105,'诗经/shijing.json','["黄鸟黄鸟，无集于穀，无啄我粟。此邦之人，不我肯穀。言旋言归，复我邦族。", "黄鸟黄鸟，无集于桑，无啄我粱。此邦之人，不可与明。言旋言归，复我诸兄。", "黄鸟黄鸟，无集于栩，无啄我黍。此邦之人，不可与处。言旋言归，复我诸父。"]'),
('shijing-187','我行其野','佚名','先秦','诗经','shijing','','[]','我行其野，蔽芾其樗。婚姻之故，言就尔居。尔不我畜，复我邦家。',90,'诗经/shijing.json','["我行其野，蔽芾其樗。婚姻之故，言就尔居。尔不我畜，复我邦家。", "我行其野，言采其蓫。婚姻之故，言就尔宿。尔不我畜，言归斯复。", "我行其野，言采其葍。不思旧姻，求尔新特。成不以富，亦祗以异。"]'),
('shijing-188','斯干','佚名','先秦','诗经','shijing','','[]','秩秩斯干，幽幽南山。如竹苞矣，如松茂矣。兄及弟矣，式相好矣，无相犹矣。',267,'诗经/shijing.json','["秩秩斯干，幽幽南山。如竹苞矣，如松茂矣。兄及弟矣，式相好矣，无相犹矣。", "似续妣祖，筑室百堵，西南其户。爰居爰处，爰笑爰语。", "约之阁阁，椓之橐橐。风雨攸除，鸟鼠攸去，君子攸芋。", "如跂斯翼，如矢斯棘，如鸟斯革，如翚斯飞，君子攸跻。", "殖殖其庭，有觉其楹。哙哙其正，哕哕其冥。君子攸宁。", "下莞上簟，乃安斯寝。乃寝乃兴，乃占我梦。吉梦维何？维熊维罴，维虺维蛇。", "大人占之：维熊维罴，男子之祥；维虺维蛇，女子之祥。", "乃生男子，载寝之床。载衣之裳，载弄之璋。其泣喤喤，朱芾斯皇，室家君王。", "乃生女子，载寝之地。载衣之裼，载弄之瓦。无非无仪，唯酒食是议，无父母诒罹。"]'),
('shijing-189','无羊','佚名','先秦','诗经','shijing','','[]','谁谓尔无羊？三百维群。谁谓尔无牛？九十其犉。尔羊来思，其角濈濈。尔牛来思，其耳湿湿。',162,'诗经/shijing.json','["谁谓尔无羊？三百维群。谁谓尔无牛？九十其犉。尔羊来思，其角濈濈。尔牛来思，其耳湿湿。", "或降于阿，或饮于池，或寝或讹。尔牧来思，何蓑何笠，或负其餱。三十维物，尔牲则具。", "尔牧来思，以薪以蒸，以雌以雄。尔羊来思，矜矜兢兢，不骞不崩。麾之以肱，毕来既升。", "牧人乃梦，众维鱼矣，旐维旟矣，大人占之；众维鱼矣，实维丰年；旐维旟矣，室家溱溱。"]'),
('shijing-190','节南山','佚名','先秦','诗经','shijing','','[]','节彼南山，维石岩岩。赫赫师尹，民具尔瞻。忧心如惔，不敢戏谈。国既卒斩，何用不监！',322,'诗经/shijing.json','["节彼南山，维石岩岩。赫赫师尹，民具尔瞻。忧心如惔，不敢戏谈。国既卒斩，何用不监！", "节彼南山，有实其猗。赫赫师尹，不平谓何。天方荐瘥，丧乱弘多。民言无嘉，惨莫惩嗟。", "尹氏大师，维周之氐；秉国之钧，四方是维。天子是毗，俾民不迷。不吊昊天，不宜空我师。", "弗躬弗亲，庶民弗信。弗问弗仕，勿罔君子。式夷式已，无小人殆。琐琐姻亚，则无膴仕。", "昊天不佣，降此鞠訩。昊天不惠，降此大戾。君子如届，俾民心阕。君子如夷，恶怒是违。", "不吊昊天，乱靡有定。式月斯生，俾民不宁。忧心如酲，谁秉国成？不自为政，卒劳百姓。", "驾彼四牡，四牡项领。我瞻四方，蹙蹙靡所骋。", "方茂尔恶，相尔矛矣。既夷既怿，如相酬矣。", "昊天不平，我王不宁。不惩其心，覆怨其正。", "家父作诵，以究王訩。式讹尔心，以畜万邦。"]'),
('shijing-191','正月','佚名','先秦','诗经','shijing','','[]','正月繁霜，我心忧伤。民之讹言，亦孔之将。念我独兮，忧心京京。哀我小心，癙忧以痒。',476,'诗经/shijing.json','["正月繁霜，我心忧伤。民之讹言，亦孔之将。念我独兮，忧心京京。哀我小心，癙忧以痒。", "父母生我，胡俾我瘉？不自我先，不自我后。好言自口，莠言自口。忧心愈愈，是以有侮。", "忧心惸惸，念我无禄。民之无辜，并其臣仆。哀我人斯，于何从禄？瞻乌爰止？于谁之屋？", "瞻彼中林，侯薪侯蒸。民今方殆，视天梦梦。既克有定，靡人弗胜。有皇上帝，伊谁云憎？", "谓山盖卑，为冈为陵。民之讹言，宁莫之惩。召彼故老，讯之占梦。具曰予圣，谁知乌之雌雄！", "谓天盖高，不敢不局。谓地盖厚，不敢不蹐。维号斯言，有伦有脊。哀今之人，胡为虺蜴？", "瞻彼阪田，有菀其特。天之杌我，如不我克。彼求我则，如不我得。执我仇仇，亦不我力。", "心之忧矣，如或结之。今兹之正，胡然厉矣？燎之方扬，宁或灭之？赫赫宗周，褒姒灭之！", "终其永怀，又窘阴雨。其车既载，乃弃尔辅。载输尔载，将伯助予！", "无弃尔辅，员于尔辐。屡顾尔仆，不输尔载。终逾绝险，曾是不意。", "鱼在于沼，亦匪克乐。潜虽伏矣，亦孔之炤。忧心惨惨，念国之为虐！", "彼有旨酒，又有嘉肴。洽比其邻，婚姻孔云。念我独兮，忧心殷殷。", "佌佌彼有屋，蔌蔌方有谷。民今之无禄，天夭是椓。哿矣富人，哀此惸独。"]'),
('shijing-192','十月之交','佚名','先秦','诗经','shijing','','[]','十月之交，朔月辛卯。日有食之，亦孔之丑。彼月而微，此日而微；今此下民，亦孔之哀。',327,'诗经/shijing.json','["十月之交，朔月辛卯。日有食之，亦孔之丑。彼月而微，此日而微；今此下民，亦孔之哀。", "日月告凶，不用其行。四国无政，不用其良。彼月而食，则维其常；此日而食，于何不臧。", "烨烨震电，不宁不令。百川沸腾，山冢崒崩。高岸为谷，深谷为陵。哀今之人，胡惨莫惩？", "皇父卿士，番维司徒，家伯维宰，仲允膳夫，棸子内史，蹶维趣马，楀维师氏。醘妻煽方处。", "抑此皇父，岂曰不时？胡为我作，不即我谋？彻我墙屋，田卒污莱。曰予不戕，礼则然矣。", "皇父孔圣，作都于向。择三有事，亶侯多藏。不慭遗一老，俾守我王。择有车马，以居徂向。", "黾勉从事，不敢告劳。无罪无辜，谗口嚣嚣。下民之孽，匪降自天。噂沓背憎，职竞由人。", "悠悠我里，亦孔之痗。四方有羡，我独居忧。民莫不逸，我独不敢休。天命不彻，我不敢效我友自逸。"]'),
('shijing-193','雨无正','佚名','先秦','诗经','shijing','','[]','浩浩昊天，不骏其德。降丧饥馑，斩伐四国。旻天疾威，弗虑弗图。舍彼有罪，既伏其辜。若此无罪，沦胥以铺。',278,'诗经/shijing.json','["浩浩昊天，不骏其德。降丧饥馑，斩伐四国。旻天疾威，弗虑弗图。舍彼有罪，既伏其辜。若此无罪，沦胥以铺。", "周宗既灭，靡所止戾。正大夫离居，莫知我勚。三事大夫，莫肯夙夜。邦君诸侯，莫肯朝夕。庶曰式臧，覆出为恶。", "如何昊天，辟言不信。如彼行迈，则靡所臻。凡百君子，各敬尔身。胡不相畏，不畏于天？", "戎成不退，饥成不遂。曾我暬御，惨惨日瘁。凡百君子，莫肯用讯。听言则答，谮言则退。", "哀哉不能言，匪舌是出，维躬是瘁。哿矣能言，巧言如流，俾躬处休！", "维曰予仕，孔棘且殆。云不何使，得罪于天子；亦云可使，怨及朋友。", "谓尔迁于王都。曰予未有室家。鼠思泣血，无言不疾。昔尔出居，谁从作尔室？"]'),
('shijing-194','小旻','佚名','先秦','诗经','shijing','','[]','旻天疾威，敷于下土。谋犹回遹，何日斯沮？谋臧不从，不臧覆用。我视谋犹，亦孔之邛。',239,'诗经/shijing.json','["旻天疾威，敷于下土。谋犹回遹，何日斯沮？谋臧不从，不臧覆用。我视谋犹，亦孔之邛。", "潝潝訿訿，亦孔之哀。谋之其臧，则具是违。谋之不臧，则具是依。我视谋犹，伊于胡厎。", "我龟既厌，不我告犹。谋夫孔多，是用不集。发言盈庭，谁敢执其咎？如匪行迈谋，是用不得于道。", "哀哉为犹，匪先民是程，匪大犹是经。维迩言是听，维迩言是争。如彼筑室于道谋，是用不溃于成。", "国虽靡止，或圣或否。民虽靡膴，或哲或谋，或肃或艾。如彼泉流，无沦胥以败。", "不敢暴虎，不敢冯河。人知其一，莫知其他。战战兢兢，如临深渊，如履薄冰。"]'),
('shijing-195','小宛','佚名','先秦','诗经','shijing','','[]','宛彼鸣鸠，翰飞戾天。我心忧伤，念昔先人。明发不寐，有怀二人。',181,'诗经/shijing.json','["宛彼鸣鸠，翰飞戾天。我心忧伤，念昔先人。明发不寐，有怀二人。", "人之齐圣，饮酒温克。彼昏不知，一醉日富。各敬尔仪，天命不又。", "中原有菽，庶民采之。螟蛉有子，蜾蠃负之。教诲尔子，式穀似之。", "题彼脊令，载飞载鸣。我日斯迈，而月斯征。夙兴夜寐，毋忝尔所生。", "交交桑扈，率场啄粟。哀我填寡，宜岸宜狱。握粟出卜，自何能穀？", "温温恭人，如集于木。惴惴小心，如临于谷。战战兢兢，如履薄冰。"]'),
('shijing-196','小弁','佚名','先秦','诗经','shijing','','[]','弁彼鸴斯，归飞提提。民莫不穀，我独于罹。何辜于天？我罪伊何？心之忧矣，云如之何？',322,'诗经/shijing.json','["弁彼鸴斯，归飞提提。民莫不穀，我独于罹。何辜于天？我罪伊何？心之忧矣，云如之何？", "踧踧周道，鞫为茂草。我心忧伤，惄焉如捣。假寐永叹，维忧用老。心之忧矣，疢如疾首。", "维桑与梓，必恭敬止。靡瞻匪父，靡依匪母。不属于毛？不罹于里？天之生我，我辰安在？", "菀彼柳斯，鸣蜩嘒嘒，有漼者渊，萑苇淠淠。譬彼舟流，不知所届，心之忧矣，不遑假寐。", "鹿斯之奔，维足伎伎。雉之朝雊，尚求其雌。譬彼坏木，疾用无枝。心之忧矣，宁莫之知？", "相彼投兔，尚或先之。行有死人，尚或墐之。君子秉心，维其忍之。心之忧矣，涕既陨之。", "君子信谗，如或酬之。君子不惠，不舒究之。伐木掎矣，析薪扡矣。舍彼有罪，予之佗矣。", "莫高匪山，莫浚匪泉。君子无易由言，耳属于垣。无逝我梁，无发我笱。我躬不阅，遑恤我后。"]'),
('shijing-197','巧言','佚名','先秦','诗经','shijing','','[]','悠悠昊天，曰父母且。无罪无辜，乱如此幠。昊天已威，予慎无罪。昊天大幠，予慎无辜。',241,'诗经/shijing.json','["悠悠昊天，曰父母且。无罪无辜，乱如此幠。昊天已威，予慎无罪。昊天大幠，予慎无辜。", "乱之初生，僭始既涵。乱之又生，君子信谗。君子如怒，乱庶遄沮。君子如祉，乱庶遄已。", "君子屡盟，乱是用长。君子信盗，乱是用暴。盗言孔甘，乱是用餤。匪其止共，维王之邛。", "奕奕寝庙，君子作之。秩秩大猷，圣人莫之。他人有心，予忖度之。跃跃毚兔，遇犬获之。", "荏染柔木，君子树之。往来行言，心焉数之。蛇蛇硕言，出自口矣。巧言如簧，颜之厚矣。", "彼何人斯？居河之麋。无拳无勇，职为乱阶。既微且尰，尔勇伊何？为犹将多，尔居徒几何？"]'),
('shijing-198','何人斯','佚名','先秦','诗经','shijing','','[]','彼何人斯？其心孔艰。胡逝我梁，不入我门？伊谁云从？维暴之云。',239,'诗经/shijing.json','["彼何人斯？其心孔艰。胡逝我梁，不入我门？伊谁云从？维暴之云。", "二人从行，谁为此祸？胡逝我梁，不入唁我？始者不如今，云不我可", "彼何人斯？胡逝我陈？我闻其声，不见其身。不愧于人？不畏于天？", "彼何人斯？其为飘风。胡不自北？胡不自南？胡逝我梁？絺搅我心。", "尔之安行，亦不遑舍。尔之亟行，遑脂尔车。一者之来，云何其盱。", "尔还而入，我心易也。还而不入，否难知也。一者之来，俾我絺也。", "伯氏吹埙，仲氏吹篪。及尔如贯，谅不我郑出此三物，以诅尔斯。", "为鬼为蜮，则不可得。有靦面目，视人罔极。作此好歌，以极反侧。"]'),
('shijing-199','巷伯','佚名','先秦','诗经','shijing','','[]','萋兮斐兮，成是贝锦。彼谮人者，亦已大甚！',175,'诗经/shijing.json','["萋兮斐兮，成是贝锦。彼谮人者，亦已大甚！", "哆兮侈兮，成是南箕。彼谮人者，谁适与谋。", "缉缉翩翩，谋欲谮人。慎尔言也，谓尔不信。", "捷捷幡幡，谋欲谮言。岂不尔受？既其女迁。", "骄人好好，劳人草草。苍天苍天，视彼骄人，矜此劳人。", "彼谮人者，谁适与谋？取彼谮人，投畀豺虎。豺虎不食，投畀有北。有北不受，投畀有昊！", "杨园之道，猗于亩丘。寺人孟子，作为此诗。凡百君子，敬而听之。"]'),
('shijing-200','谷风','佚名','先秦','诗经','shijing','','[]','习习谷风，维风及雨。将恐将惧，维予与女。将安将乐，女转弃予。',90,'诗经/shijing.json','["习习谷风，维风及雨。将恐将惧，维予与女。将安将乐，女转弃予。", "习习谷风，维风及颓。将恐将惧，置予于怀。将安将乐，弃予如遗。", "习习谷风，维山崔嵬。无草不死，无木不萎。忘我大德，思我小怨。"]'),
('shijing-201','蓼莪','佚名','先秦','诗经','shijing','','[]','蓼蓼者莪，匪莪伊蒿。哀哀父母，生我劬劳。',162,'诗经/shijing.json','["蓼蓼者莪，匪莪伊蒿。哀哀父母，生我劬劳。", "蓼蓼者莪，匪莪伊蔚。哀哀父母，生我劳瘁。", "瓶之罄矣，维罍之耻。鲜民之生，不如死之久矣。无父何怙？无母何恃？出则衔恤，入则靡至。", "父兮生我，母兮鞠我。抚我畜我，长我育我，顾我复我，出入腹我。欲报之德。昊天罔极！", "南山烈烈，飘风发发。民莫不穀，我独何害！南山律律，飘风弗弗。民莫不穀，我独不卒！"]'),
('shijing-202','大东','佚名','先秦','诗经','shijing','','[]','有饛簋飧，有捄棘匕。周道如砥，其直如矢。君子所履，小人所视。眷言顾之，潸焉出涕。',283,'诗经/shijing.json','["有饛簋飧，有捄棘匕。周道如砥，其直如矢。君子所履，小人所视。眷言顾之，潸焉出涕。", "小东大东，杼柚其空。纠纠葛屦，可以履霜。佻佻公子，行彼周行。既往既来，使我心疚。", "有冽氿泉，无浸获薪。契契寤叹，哀我惮人。薪是获薪，尚可载也。哀我惮人，亦可息也。", "东人之子，职劳不来。西人之子，粲粲衣服。舟人之子，熊罴是裘。私人之子，百僚是试。", "或以其酒，不以其浆。鞙鞙佩璲，不以其长。维天有汉，监亦有光。跂彼织女，终日七襄。", "虽则七襄，不成报章。睆彼牵牛，不以服箱。东有启明，西有长庚。有捄天毕，载施之行。", "维南有箕，不可以簸扬。维北有斗，不可以挹酒浆。维南有箕，载翕其舌。维北有斗，西柄之揭。"]'),
('shijing-203','四月','佚名','先秦','诗经','shijing','','[]','四月维夏，六月徂署。先祖匪人，胡宁忍予？',160,'诗经/shijing.json','["四月维夏，六月徂署。先祖匪人，胡宁忍予？", "秋日凄凄，百卉具腓。乱离瘼矣，爰其适归？", "冬日烈烈，飘风发发。民莫不穀，我独何害？", "山有嘉卉，侯栗侯梅。废为残贼，莫知其尤！", "相彼泉水，载清载浊。我日构祸，曷云能穀？", "滔滔江汉，南国之纪。尽瘁以仕，宁莫我有？", "匪鹑匪鸢，翰飞戾天。匪鳣匪鲔，潜逃于渊。", "山有蕨薇，隰有杞桋。君子作歌，维以告哀。"]'),
('shijing-204','北山','佚名','先秦','诗经','shijing','','[]','陟彼北山，言采其杞。偕偕士子，朝夕从事。王事靡盬，忧我父母。',163,'诗经/shijing.json','["陟彼北山，言采其杞。偕偕士子，朝夕从事。王事靡盬，忧我父母。", "溥天之下，莫非王土；率土之滨，莫非王臣。大夫不均，我从事独贤。", "四牡彭彭，王事傍傍。嘉我未老，鲜我方将。旅力方刚，经营四方。", "或燕燕居息，或尽瘁事国；或息偃在床，或不已于行。", "或不知叫号，或惨惨劬劳；或栖迟偃仰，或王事鞅掌。", "或湛乐饮酒，或惨惨畏咎；或出入风议，或靡事不为。"]'),
('shijing-205','无将大车','佚名','先秦','诗经','shijing','','[]','无将大车，祇自尘兮。无思百忧，祇自疧兮。',60,'诗经/shijing.json','["无将大车，祇自尘兮。无思百忧，祇自疧兮。", "无将大车，维尘冥冥。无思百忧，不出于颎。", "无将大车，维尘雍兮。无思百忧，祇自重兮。"]'),
('shijing-206','小明','佚名','先秦','诗经','shijing','','[]','明明上天，照临下土。我征徂西，至于艽野。二月初吉，载离寒暑。',240,'诗经/shijing.json','["明明上天，照临下土。我征徂西，至于艽野。二月初吉，载离寒暑。", "心之忧矣，其毒大苦。念彼共人，涕零如雨。岂不怀归？畏此罪罟！", "昔我往矣，日月方除。曷云其还？岁聿云莫。念我独兮，我事孔庶。", "心之忧矣，惮我不暇。念彼共人，眷眷怀顾！岂不怀归？畏此谴怒。", "昔我往矣，日月方奥。曷云其还？政事愈蹙。岁聿云莫，采萧获菽。", "心之忧矣，自诒伊戚。念彼共人，兴言出宿。岂不怀归？畏此反覆。", "嗟尔君子，无恒安处。靖共尔位，正直是与。神之听之，式穀以女。", "嗟尔君子，无恒安息。靖共尔位，好是正直。神之听之，介尔景福。"]'),
('shijing-207','鼓钟','佚名','先秦','诗经','shijing','','[]','鼓钟将将，淮水汤汤，忧心且伤。淑人君子，怀允不忘。',100,'诗经/shijing.json','["鼓钟将将，淮水汤汤，忧心且伤。淑人君子，怀允不忘。", "鼓钟喈喈，淮水湝湝，忧心且悲。淑人君子，其德不回。", "鼓钟伐鼛，淮有三洲，忧心且妯。淑人君子，其德不犹。", "鼓钟钦钦，鼓瑟鼓琴，笙磬同音。以雅以南，以龠不僭。"]'),
('shijing-208','楚茨','佚名','先秦','诗经','shijing','','[]','楚楚者茨，言抽其棘，自昔何为？我蓺黍稷。我黍与与，我稷翼翼。',360,'诗经/shijing.json','["楚楚者茨，言抽其棘，自昔何为？我蓺黍稷。我黍与与，我稷翼翼。", "我仓既盈，我庾维亿。以为酒食，以享以祀，以妥以侑，以介景福。", "济济跄跄，絜尔牛羊，以往烝尝。或剥或亨，或四或将。祝祭于祊，", "祀事孔明。先祖是皇，神保是飨。孝孙有庆，报以介福，万寿无疆！", "执爨踖踖，为俎孔硕，或燔或炙。君妇莫莫，为豆孔庶。为宾为客，", "献酬交错。礼仪卒度，笑语卒获。神保是格，报以介福，万寿攸酢！", "我孔戁矣，式礼莫愆。工祝致告，徂赉孝孙。苾芬孝祀，神嗜饮食。", "卜尔百福，如几如式。既齐既稷，既匡既敕。永锡尔极，时万时亿！", "礼仪既备，钟鼓既戒，孝孙徂位，工祝致告，神具醉止，皇尸载起。", "鼓钟送尸，神保聿归。诸宰君妇，废彻不迟。诸父兄弟，备言燕私。", "乐具入奏，以绥后禄。尔肴既将，莫怨具庆。既醉既饱，小大稽首。", "神嗜饮食，使君寿考。孔惠孔时，维其尽之。子子孙孙，勿替引之！"]'),
('shijing-209','信南山','佚名','先秦','诗经','shijing','','[]','信彼南山，维禹甸之。畇畇原隰，曾孙田之。我疆我理，南东其亩。',181,'诗经/shijing.json','["信彼南山，维禹甸之。畇畇原隰，曾孙田之。我疆我理，南东其亩。", "上天同云。雨雪雰雰，益之以霡霂。既优既渥，既沾既足。生我百谷。", "疆埸翼翼，黍稷彧彧。曾孙之穑，以为酒食。畀我尸宾，寿考万年。", "中田有庐，疆埸有瓜。是剥是菹，献之皇祖。曾孙寿考，受天之祜。", "祭以清酒，从以骍牡，享于祖考。执其鸾刀，以启其毛，取其血膋。", "是烝是享，苾苾芬芬。祀事孔明，先祖是皇。报以介福。万寿无疆。"]'),
('shijing-210','甫田','佚名','先秦','诗经','shijing','','[]','倬彼甫田，岁取十千。我取其陈，食我农人。自古有年。',204,'诗经/shijing.json','["倬彼甫田，岁取十千。我取其陈，食我农人。自古有年。", "今适南亩，或耘或耔。黍稷薿薿，攸介攸止，烝我髦士。", "以我齐明，与我牺羊，以社以方。我田既臧，农夫之庆。", "琴瑟击鼓，以御田祖。以祈甘雨，以介我稷黍，以穀我士女。", "曾孙来止，以其妇子。馌彼南亩，田畯至喜。攘其左右，", "尝其旨否。禾易长亩，终善且有。曾孙不怒，农夫克敏。", "曾孙之稼，如茨如梁。曾孙之庾，如坻如京。乃求千斯仓，", "乃求万斯箱。黍稷稻粱，农夫之庆。报以介福，万寿无疆。"]'),
('shijing-211','大田','佚名','先秦','诗经','shijing','','[]','大田多稼，既种既戒，既备乃事。以我覃耜，俶载南亩。',174,'诗经/shijing.json','["大田多稼，既种既戒，既备乃事。以我覃耜，俶载南亩。", "播厥百谷，既庭且硕，曾孙是若。", "既方既皂，既坚既好，不稂不莠。去其螟螣，及其蟊贼，", "无害我田稚。田祖有神，秉畀炎火。", "有渰萋萋，兴雨祈祈。雨我公田，遂及我私。彼有不获稚，", "此有不敛穧，彼有遗秉，此有滞穗，伊寡妇之利。", "曾孙来止，以其妇子。馌彼南亩，田畯至喜。来方禋祀，", "以其骍黑，与其黍稷。以享以祀，以介景福。"]'),
('shijing-212','瞻彼洛矣','佚名','先秦','诗经','shijing','','[]','瞻彼洛矣，维水泱泱。君子至止，福禄如茨。韎韐有奭，以作六师。',90,'诗经/shijing.json','["瞻彼洛矣，维水泱泱。君子至止，福禄如茨。韎韐有奭，以作六师。", "瞻彼洛矣，维水泱泱。君子至止，鞸琫有珌。君子万年，保其家室。", "瞻彼洛矣，维水泱泱。君子至止，福禄既同。君子万年，保其家邦。"]'),
('shijing-213','裳裳者华','佚名','先秦','诗经','shijing','','[]','裳裳者华，其叶湑兮。我觏之子，我心写兮。我心写兮，是以有誉处兮。',125,'诗经/shijing.json','["裳裳者华，其叶湑兮。我觏之子，我心写兮。我心写兮，是以有誉处兮。", "裳裳者华，芸其黄矣。我觏之子，维其有章矣。维其有章矣，是以有庆矣。", "裳裳者华，或黄或白。我觏之子，乘其四骆。乘其四骆，六辔沃若。", "左之左之，君子宜之。右之右之，君子有之。维其有之，是以似之。"]'),
('shijing-214','桑扈','佚名','先秦','诗经','shijing','','[]','交交桑扈，有莺其羽。君子乐胥，受天之祜。',80,'诗经/shijing.json','["交交桑扈，有莺其羽。君子乐胥，受天之祜。", "交交桑扈，有莺其领。君子乐胥，万邦之屏。", "之屏之翰，百辟为宪。不戢不难，受福不那。", "兕觥其觩，旨酒思柔。彼交匪敖，万福来求。"]'),
('shijing-215','鸳鸯','佚名','先秦','诗经','shijing','','[]','鸳鸯于飞，毕之罗之。君子万年，福禄宜之。',80,'诗经/shijing.json','["鸳鸯于飞，毕之罗之。君子万年，福禄宜之。", "鸳鸯在梁，戢其左翼。君子万年，", "宜其遐福。乘马在厩，摧之秣之。君子万年，福禄艾之。", "乘马在厩，秣之摧之。君子万年，福禄绥之。"]'),
('shijing-216','頍弁','佚名','先秦','诗经','shijing','','[]','有頍者弁，实维伊何？尔酒既旨，尔肴既嘉。岂伊异人？兄弟匪他。',180,'诗经/shijing.json','["有頍者弁，实维伊何？尔酒既旨，尔肴既嘉。岂伊异人？兄弟匪他。", "茑与女萝，施于松柏。未见君子，忧心奕奕；既见君子，庶几说怿。", "有頍者弁，实维何期？尔酒既旨，尔肴既时。岂伊异人？兄弟具来。", "茑与女萝，施于松上。未见君子，忧心怲怲；既见君子，庶几有臧。", "有頍者弁，实维在首。尔酒既旨，尔肴既阜。岂伊异人？兄弟甥舅。", "如彼雨雪，先集维霰。死丧无日，无几相见。乐酒今夕，君子维宴。"]'),
('shijing-217','车舝','佚名','先秦','诗经','shijing','','[]','间关车之舝兮，思娈季女逝兮。匪饥匪渴，德音来括。虽无好友？式燕且喜。',155,'诗经/shijing.json','["间关车之舝兮，思娈季女逝兮。匪饥匪渴，德音来括。虽无好友？式燕且喜。", "依彼平林，有集维鷮。辰彼硕女，令德来教。式燕且誉，好尔无射。", "虽无旨酒？式饮庶几。虽无嘉肴？式食庶几。虽无德与女？式歌且舞？", "陟彼高冈，析其柞薪。析其柞薪，其叶湑兮。鲜我觏尔，我心写兮。", "高山仰止，景行行止。四牡騑騑，六辔如琴。觏尔新婚，以慰我心。"]'),
('shijing-218','青蝇','佚名','先秦','诗经','shijing','','[]','营营青蝇，止于樊。岂弟君子，无信谗言。',57,'诗经/shijing.json','["营营青蝇，止于樊。岂弟君子，无信谗言。", "营营青蝇，止于棘。谗人罔极，交乱四国。", "营营青蝇，止于榛。谗人罔极，构我二人。"]'),
('shijing-219','宾之初筵','佚名','先秦','诗经','shijing','','[]','宾之初筵，左右秩秩。笾豆有楚，殽核维旅。酒既和旨，饮酒孔偕。',350,'诗经/shijing.json','["宾之初筵，左右秩秩。笾豆有楚，殽核维旅。酒既和旨，饮酒孔偕。", "钟鼓既设，举酬逸逸。大侯既抗，弓矢斯张。射夫既同，献尔发功。", "发彼有的，以祈尔爵。", "籥舞笙鼓，乐既和奏。烝衎烈祖，以洽百礼。百礼既至，有壬有林。", "锡尔纯嘏，子孙其湛。其湛曰乐，各奏尔能。宾载手仇，室人入又。", "酌彼康爵，以奏尔时。", "宾之初筵，温温其恭。其未醉止，威仪反反。曰既醉止，威仪幡幡。", "舍其坐迁，屡舞仙仙。其未醉止，威仪抑抑。曰既醉止，威仪抑抑。", "是曰既醉，不知其秩。", "宾既醉止，载号载呶。乱我笾豆，屡舞僛僛。是曰既醉，不知其邮。", "侧弁之俄，屡舞傞傞。既醉而出，并受其福。醉而不出，是谓伐德。", "饮酒孔嘉，维其令仪。", "凡此饮酒，或醉或否。既立之监，或佐之史。彼醉不臧，不醉反耻。", "式勿从谓，无俾大怠。匪言勿言，匪由勿语。由醉之言，俾出童羖。", "三爵不识，矧敢多又。"]'),
('shijing-220','鱼藻','佚名','先秦','诗经','shijing','','[]','鱼在在藻，有颁其首。王在在镐，岂乐饮酒。',60,'诗经/shijing.json','["鱼在在藻，有颁其首。王在在镐，岂乐饮酒。", "鱼在在藻，有莘其尾。王在在镐，饮酒乐岂。", "鱼在在藻，依于其蒲。王在在镐，有那其居。"]'),
('shijing-221','采菽','佚名','先秦','诗经','shijing','','[]','采菽采菽，筐之莒之。君子来朝，何锡予之？虽无予之？路车乘马。又何予之？玄衮及黼。',201,'诗经/shijing.json','["采菽采菽，筐之莒之。君子来朝，何锡予之？虽无予之？路车乘马。又何予之？玄衮及黼。", "觱沸槛泉，言采其芹。君子来朝，言观其旂。其旂淠淠，鸾声嘒嘒。载骖载驷，君子所届。", "赤芾在股，邪幅在下。彼交匪纾，天子所予。乐只君子，天子命之。乐只君子，福禄申之。", "维柞之枝，其叶蓬蓬。乐只君子，殿天子之邦。乐只君子，万福攸同。平平左右，亦是率从。", "汎汎杨舟，绋纚维之。乐只君子，天子葵之。乐只君子，福禄膍之。优哉游哉，亦是戾矣。"]'),
('shijing-222','角弓','佚名','先秦','诗经','shijing','','[]','骍骍角弓，翩其反矣。兄弟婚姻，无胥远矣。',164,'诗经/shijing.json','["骍骍角弓，翩其反矣。兄弟婚姻，无胥远矣。", "尔之远矣，民胥然矣。尔之教矣，民胥效矣。", "此令兄弟，绰绰有裕。不令兄弟，交相为愈。", "民之无良，相怨一方。受爵不让，至于已斯亡。", "老马反为驹，不顾其后。如食宜饇，如酌孔取。", "毋教猱升木，如涂涂附。君子有徽猷，小人与属。", "雨雪瀌瀌，见晛曰消。莫肯下遗，式居娄骄。", "雨雪浮浮，见晛曰流。如蛮如髦，我是用忧。"]'),
('shijing-223','菀柳','佚名','先秦','诗经','shijing','','[]','有菀者柳，不尚息焉。上帝甚蹈，无自暱焉。俾予靖之，后予极焉。',90,'诗经/shijing.json','["有菀者柳，不尚息焉。上帝甚蹈，无自暱焉。俾予靖之，后予极焉。", "有菀者柳，不尚愒焉。上帝甚蹈，无自瘵焉。俾予靖之，后予迈焉。", "有鸟高飞，亦傅于天。彼人之心，于何其臻。曷予靖之，居以凶矜。"]'),
('shijing-224','都人士','佚名','先秦','诗经','shijing','','[]','彼都人士，狐裘黄黄。其容不改，出言有章。行归于周，万民所望。',150,'诗经/shijing.json','["彼都人士，狐裘黄黄。其容不改，出言有章。行归于周，万民所望。", "彼都人士，台笠缁撮。彼君子女，绸直如发。我不见兮，我心不说。", "彼都人士，充耳琇实。彼君子女，谓之尹吉。我不见兮，我心苑结。", "彼都人士，垂带而厉。彼君子女，卷发如虿。我不见兮，言从之迈。", "匪伊垂之，带则有余。匪伊卷之，发则有旟。我不见兮，云何盱矣。"]'),
('shijing-225','采绿','佚名','先秦','诗经','shijing','','[]','终朝采绿，不盈一匊。予发曲局，薄言归沐。',80,'诗经/shijing.json','["终朝采绿，不盈一匊。予发曲局，薄言归沐。", "终朝采蓝，不盈一襜。五日为期，六日不詹。", "之子于狩，言韔其弓。之子于钓，言纶之绳。", "其钓维何？维鲂及鱮。维鲂及鱮，薄言观者。"]'),
('shijing-226','黍苗','佚名','先秦','诗经','shijing','','[]','芃芃黍苗，阴雨膏之。悠悠南行，召伯劳之。',100,'诗经/shijing.json','["芃芃黍苗，阴雨膏之。悠悠南行，召伯劳之。", "我任我辇，我车我牛。我行既集，盖云归哉。", "我徒我御，我师我旅。我行既集，盖云归处。", "肃肃谢功，召伯营之。烈烈征师，召伯成之。", "原隰既平，泉流既清。召伯有成，王心则宁。"]'),
('shijing-227','隰桑','佚名','先秦','诗经','shijing','','[]','隰桑有阿，其叶有难。既见君子，其乐如何。',80,'诗经/shijing.json','["隰桑有阿，其叶有难。既见君子，其乐如何。", "隰桑有阿，其叶有沃。既见君子，云何不乐。", "隰桑有阿，其叶有幽。既见君子，德音孔胶。", "心乎爱矣，遐不谓矣？中心藏之，何日忘之！"]'),
('shijing-228','白华','佚名','先秦','诗经','shijing','','[]','白华菅兮，白茅束兮。之子之远，俾我独兮。',160,'诗经/shijing.json','["白华菅兮，白茅束兮。之子之远，俾我独兮。", "英英白云，露彼菅茅。天步艰难，之子不犹。", "滮池北流，浸彼稻田。啸歌伤怀，念彼硕人。", "樵彼桑薪，卬烘于煁。维彼硕人，实劳我心。", "鼓钟于宫，声闻于外。念子懆懆，视我迈迈。", "有鹙在梁，有鹤在林。维彼硕人，实劳我心。", "鸳鸯在梁，戢其左翼。之子无良，二三其德。", "有扁斯石，履之卑兮。之子之远，俾我疧兮。"]'),
('shijing-229','绵蛮','佚名','先秦','诗经','shijing','','[]','绵蛮黄鸟，止于丘阿。道之云远，我劳如何。饮之食之，教之诲之。命彼后车，谓之载之。',120,'诗经/shijing.json','["绵蛮黄鸟，止于丘阿。道之云远，我劳如何。饮之食之，教之诲之。命彼后车，谓之载之。", "绵蛮黄鸟，止于丘隅。岂敢惮行，畏不能趋。饮之食之。教之诲之。命彼后车，谓之载之。", "绵蛮黄鸟，止于丘侧。岂敢惮行，畏不能极。饮之食之，教之诲之。命彼后车，谓之载之。"]'),
('shijing-230','瓠叶','佚名','先秦','诗经','shijing','','[]','幡幡瓠叶，采之亨之。君子有酒，酌言尝之。',80,'诗经/shijing.json','["幡幡瓠叶，采之亨之。君子有酒，酌言尝之。", "有兔斯首，炮之燔之。君子有酒，酌言献之。", "有兔斯首，燔之炙之。君子有酒，酌言酢之。", "有兔斯首，燔之炮之。君子有酒，酌言酬之。"]'),
('shijing-231','渐渐之石','佚名','先秦','诗经','shijing','','[]','渐渐之石，维其高矣。山川悠远，维其劳矣。武人东征，不遑朝矣。',90,'诗经/shijing.json','["渐渐之石，维其高矣。山川悠远，维其劳矣。武人东征，不遑朝矣。", "渐渐之石，维其卒矣。山川悠远，曷其没矣？武人东征，不遑出矣。", "有豕白蹢，烝涉波矣。月离于毕，俾滂沱矣。武人东征，不皇他矣。"]'),
('shijing-232','苕之华','佚名','先秦','诗经','shijing','','[]','苕之华，芸其黄矣。心之忧矣，维其伤矣！',58,'诗经/shijing.json','["苕之华，芸其黄矣。心之忧矣，维其伤矣！", "苕之华，其叶青青。知我如此，不如无生！", "牂羊坟首，三星在罶。人可以食，鲜可以饱！"]'),
('shijing-233','何草不黄','佚名','先秦','诗经','shijing','','[]','何草不黄？何日不行？何人不将？经营四方。',80,'诗经/shijing.json','["何草不黄？何日不行？何人不将？经营四方。", "何草不玄？何人不矜？哀我征夫，独为匪民。", "匪兕匪虎，率彼旷野。哀我征夫，朝夕不暇。", "有芃者狐，率彼幽草。有栈之车，行彼周道。"]'),
('shijing-234','文王','佚名','先秦','诗经','shijing','','[]','文王在上，于昭于天。周虽旧邦，其命维新。有周不显，帝命不时。文王陟降，在帝左右。',284,'诗经/shijing.json','["文王在上，于昭于天。周虽旧邦，其命维新。有周不显，帝命不时。文王陟降，在帝左右。", "亹亹文王，令闻不已。陈锡哉周，侯文王孙子。文王孙子，本支百世，凡周之士，不显亦世。", "世之不显，厥犹翼翼。思皇多士，生此王国。王国克生，维周之桢；济济多士，文王以宁。", "穆穆文王，于缉熙敬止。假哉天命。有商孙子。商之孙子，其丽不亿。上帝既命，侯于周服。", "侯服于周，天命靡常。殷士肤敏。裸将于京。厥作裸将，常服黼冔。王之荩臣。无念尔祖。", "无念尔祖，聿修厥德。永言配命，自求多福。殷之未丧师，克配上帝。宜鉴于殷，骏命不易！", "命之不易，无遏尔躬。宣昭义问，有虞殷自天。上天之载，无声无臭。仪刑文王，万邦作孚。"]'),
('shijing-235','大明','佚名','先秦','诗经','shijing','','[]','明明在下，赫赫在上。天难忱斯，不易维王。天位殷适，使不挟四方。',281,'诗经/shijing.json','["明明在下，赫赫在上。天难忱斯，不易维王。天位殷适，使不挟四方。", "挚仲氏任，自彼殷商，来嫁于周，曰嫔于京。乃及王季，维德之行。", "大任有身，生此文王。维此文王，小心翼翼。昭事上帝，聿怀多福。厥德不回，以受方国。", "天监在下，有命既集。文王初载，天作之合。在洽之阳，在渭之涘。", "文王嘉止，大邦有子。大邦有子，伣天之妹。文定厥祥，亲迎于渭。造舟为梁，不显其光。", "有命自天，命此文王。于周于京，缵女维莘。长子维行，笃生武王。保右命尔，燮伐大商。", "殷商之旅，其会如林。矢于牧野，维予侯兴。上帝临女，无二尔心。", "牧野洋洋，檀车煌煌，驷騵彭彭。维师尚父，时维鹰扬。凉彼武王，四伐大商，会朝清明。"]'),
('shijing-236','绵','佚名','先秦','诗经','shijing','','[]','绵绵瓜瓞。民之初生，自土沮漆。古公亶父，陶复陶冗，未有家室。',278,'诗经/shijing.json','["绵绵瓜瓞。民之初生，自土沮漆。古公亶父，陶复陶冗，未有家室。", "古公亶父，来朝走马。率西水浒，至于岐下。爰及姜女，聿来胥宇。", "周原膴膴，堇荼如饴。爰始爰谋，爰契我龟，曰止曰时，筑室于兹。", "乃慰乃止，乃左乃右，乃疆乃理，乃宣乃亩。自西徂东，周爰执事。", "乃召司空，乃召司徒，俾立室家。其绳则直，缩版以载，作庙翼翼。", "捄之陾陾，度之薨薨，筑之登登，削屡冯冯。百堵皆兴，鼛鼓弗胜。", "乃立皋门，皋门有伉。乃立应门，应门将将。乃立冢土，戎丑攸行。", "四不殄厥愠，亦不陨厥问。柞棫拔矣，行道兑矣。混夷駾矣，维其喙矣！", "虞芮质厥成，文王蹶厥生。予曰有疏附，予曰有先后。予曰有奔奏，予曰有御侮！"]'),
('shijing-237','棫朴','佚名','先秦','诗经','shijing','','[]','芃芃棫朴，薪之槱之。济济辟王，左右趣之。',100,'诗经/shijing.json','["芃芃棫朴，薪之槱之。济济辟王，左右趣之。", "济济辟王，左右奉璋。奉璋峨峨，髦士攸宜。", "淠彼泾舟，烝徒楫之。周王于迈，六师及之。", "倬彼云汉，为章于天。周王寿考，遐不作人？", "追琢其章，金玉其相。勉勉我王，纲纪四方。"]'),
('shijing-238','旱麓','佚名','先秦','诗经','shijing','','[]','瞻彼旱麓，榛楛济济。岂弟君子，干禄岂弟。',120,'诗经/shijing.json','["瞻彼旱麓，榛楛济济。岂弟君子，干禄岂弟。", "瑟彼玉瓒，黄流在中。岂弟君子，福禄攸降。", "鸢飞戾天，鱼跃于渊。岂弟君子，遐不作人？", "清酒既载，骍牡既备。以享以祀，以介景福。", "瑟彼柞棫，民所燎矣。岂弟君子，神所劳矣。", "莫莫葛藟，施于条枚。岂弟君子，求福不回。"]'),
('shijing-239','思齐','佚名','先秦','诗经','shijing','','[]','思齐大任，文王之母，思媚周姜，京室之妇。大姒嗣徽音，则百斯男。',125,'诗经/shijing.json','["思齐大任，文王之母，思媚周姜，京室之妇。大姒嗣徽音，则百斯男。", "惠于宗公，神罔时怨，神罔时恫。刑于寡妻，至于兄弟，以御于家邦。", "雍雍在宫，肃肃在庙。不显亦临，无射亦保。", "四戎疾不殄，烈假不瑕。不闻亦式，不谏亦入。四成人有德，小子有造。古之人无斁，誉髦斯士。"]'),
('shijing-240','皇矣','佚名','先秦','诗经','shijing','','[]','皇矣上帝，临下有赫。监观四方，求民之莫。维此二国，其政不获。',489,'诗经/shijing.json','["皇矣上帝，临下有赫。监观四方，求民之莫。维此二国，其政不获。", "维彼四国，爰究爰度。上帝耆之，憎其式廓。乃眷西顾，此维与宅。", "作之屏之，其菑其翳。修之平之，其灌其栵。启之辟之，其柽其椐。", "攘之剔之，其檿其柘。帝迁明德，串夷载路。天立厥配，受命既固。", "帝省其山，柞棫斯拔，松柏斯兑。帝作邦作对，自大伯王季。维此王季，", "因心则友。则友其兄，则笃其庆，载锡之光。受禄无丧，奄有四方。", "维此王季，帝度其心。貊其德音，其德克明。克明克类，克长克君。", "王此大邦，克顺克比。比于文王，其德靡悔。既受帝祉，施于孙子。", "帝谓文王：无然畔援，无然歆羡，诞先登于岸。密人不恭，敢距大邦，", "侵阮徂共。王赫斯怒，爰整其旅，以按徂旅。以笃于周祜，以对于天下。", "依其在京，侵自阮疆。陟我高冈，无矢我陵。我陵我阿，无饮我泉，", "我泉我池。度其鲜原，居岐之阳，在渭之将。万邦之方，下民之王。", "帝谓文王：予怀明德，不大声以色，不长夏以革。不识不知，顺帝之则。", "帝谓文王：訽尔仇方，同尔弟兄。以尔钩援，与尔临冲，以伐崇墉。", "临冲闲闲，崇墉言言。执讯连连，攸馘安安。是类是禡，是致是附，", "四方以无侮。临冲茀茀，崇墉仡仡。是伐是四，是绝是忽。四方以无拂。"]'),
('shijing-241','灵台','佚名','先秦','诗经','shijing','','[]','经始灵台，经之营之。庶民攻之，不日成之。经始勿亟，庶民子来。',100,'诗经/shijing.json','["经始灵台，经之营之。庶民攻之，不日成之。经始勿亟，庶民子来。", "王在灵囿，麀鹿攸伏。麀鹿濯濯，白鸟翯翯。王在灵沼，于牣鱼跃。", "虡业维枞，贲鼓维镛。于论鼓钟，于乐辟雍。", "于论鼓钟，于乐辟雍。鼍鼓逢逢。矇瞍奏公。"]'),
('shijing-242','下武','佚名','先秦','诗经','shijing','','[]','下武维周，世有哲王。三后在天，王配于京。',120,'诗经/shijing.json','["下武维周，世有哲王。三后在天，王配于京。", "王配于京，世德作求。永言配命，成王之孚。", "成王之孚，下土之式。永言孝思，孝思维则。", "媚兹一人，应侯顺德。永言孝思，昭哉嗣服。", "昭兹来许，绳其祖武。于万斯年，受天之祜。", "受天之祜，四方来贺。于万斯年，不遐有佐。"]'),
('shijing-243','文王有声','佚名','先秦','诗经','shijing','','[]','文王有声，遹骏有声。遹求厥宁，遹观厥成。文王烝哉！',201,'诗经/shijing.json','["文王有声，遹骏有声。遹求厥宁，遹观厥成。文王烝哉！", "文王受命，有此武功。既伐于崇，作邑于丰。文王烝哉！", "筑城伊淢，作丰伊匹。匪棘其欲，遹追来孝。王后烝哉！", "王公伊濯，维丰之垣。四方攸同，王后维翰。王后烝哉！", "丰水东注，维禹之绩。四方攸同，皇王维辟。皇王烝哉！", "镐京辟雍，自西自东，自南自北，无思不服。皇王烝哉！", "考卜维王，宅是镐京。维龟正之，武王成之。武王烝哉！", "丰水有芑，武王岂不仕？诒厥孙谋，以燕翼子。武王烝哉！"]'),
('shijing-244','生民','佚名','先秦','诗经','shijing','','[]','厥初生民，时维姜嫄。生民如何？克禋克祀，以弗无子。',368,'诗经/shijing.json','["厥初生民，时维姜嫄。生民如何？克禋克祀，以弗无子。", "履帝武敏歆，攸介攸止，载震载夙。载生载育，时维后稷。", "诞弥厥月，先生如达。不拆不副，无菑无害。以赫厥灵。", "上帝不宁，不康禋祀，居然生子。", "诞寘之隘巷，牛羊腓字之。诞寘之平林，会伐平林。", "诞寘之寒冰，鸟覆翼之。鸟乃去矣，后稷呱矣。", "实覃实訏，厥声载路。诞实匍匐，克岐克嶷。以就口食。", "蓺之荏菽，荏菽旆旆。禾役穟穟，麻麦幪幪，瓜瓞唪唪。", "诞后稷之穑，有相之道。茀厥丰草，种之黄茂。实方实苞，实种实褎。", "实发实秀，实坚实好。实颖实栗，即有邰家室。", "诞降嘉种，维秬维秠，维穈维芑。恒之秬秠，是获是亩。", "恒之穈芑，是任是负。以归肇祀。", "诞我祀如何？或舂或揄，或簸或蹂。释之叟叟，烝之浮浮。", "载谋载惟。取萧祭脂，取羝以軷，载燔载烈，以兴嗣岁。", "卬盛于豆，于豆于登。其香始升，上帝居歆。胡臭亶时。", "后稷肇祀。庶无罪悔，以迄于今。"]'),
('shijing-245','行苇','佚名','先秦','诗经','shijing','','[]','敦彼行苇，牛羊勿践履。方苞方体，维叶泥泥。',163,'诗经/shijing.json','["敦彼行苇，牛羊勿践履。方苞方体，维叶泥泥。", "戚戚兄弟，莫远具尔。或四之筵，或授之几。", "四筵设席，授几有缉御。或献或酢，洗爵奠斝。", "醓醢以荐，或燔或炙。嘉肴脾臄，或歌或咢。", "敦弓既坚，四鍭既均，舍矢既均，序宾以贤。", "敦弓既句，既挟四鍭。四鍭如树，序宾以不侮。", "曾孙维主，酒醴维醽，酌以大斗，以祈黄耇。", "黄耇台背，以引以翼。寿考维祺，以介景福。"]'),
('shijing-246','既醉','佚名','先秦','诗经','shijing','','[]','既醉以酒，既饱以德。君子万年，介尔景福。',161,'诗经/shijing.json','["既醉以酒，既饱以德。君子万年，介尔景福。", "既醉以酒，尔肴既将。君子万年，介尔昭明。", "昭明有融，高朗令终，令终有俶。公尸嘉告。", "其告维何？笾豆静嘉。朋友攸摄，摄以威仪。", "威仪孔时，君子有孝子。孝子不匮，永锡尔类。", "其类维何？室家之壶。君子万年，永锡祚胤。", "其胤维何？天被尔禄。君子万年，景命有仆。", "其仆维何？厘尔女士。厘尔女士，从以孙子。"]'),
('shijing-247','凫鹥','佚名','先秦','诗经','shijing','','[]','凫鹥在泾，公尸在燕来宁。尔酒既清，尔肴既馨。公尸燕饮，福禄来成。',160,'诗经/shijing.json','["凫鹥在泾，公尸在燕来宁。尔酒既清，尔肴既馨。公尸燕饮，福禄来成。", "凫鹥在沙，公尸来燕来宜。尔酒既多，尔肴既嘉。公尸燕饮，福禄来为。", "凫鹥在渚，公尸来燕来处。尔酒既湑，尔肴伊脯。公尸燕饮，福禄来下。", "凫鹥在潀，公尸来燕来宗，既燕于宗，福禄攸降。公尸燕饮，福禄来崇。", "凫鹥在亹，公尸来止熏熏。旨酒欣欣，燔炙芬芬。公尸燕饮，无有后艰。"]'),
('shijing-248','假乐','佚名','先秦','诗经','shijing','','[]','假乐君子，显显令德，宜民宜人。受禄于天，保右命之，自天申之。',120,'诗经/shijing.json','["假乐君子，显显令德，宜民宜人。受禄于天，保右命之，自天申之。", "千禄百福，子孙千亿。穆穆皇皇，宜君宜王。不愆不忘，率由旧章。", "威仪抑抑，德音秩秩。无怨无恶，率由群匹。受福无疆，四方之纲。", "之纲之纪，燕及朋友。百辟卿士，媚于天子。不解于位，民之攸塈。"]'),
('shijing-249','公刘','佚名','先秦','诗经','shijing','','[]','笃公刘，匪居匪康。乃埸乃疆，乃积乃仓；乃裹餱粮，于橐于囊。',294,'诗经/shijing.json','["笃公刘，匪居匪康。乃埸乃疆，乃积乃仓；乃裹餱粮，于橐于囊。", "思辑用光，弓矢斯张；干戈戚扬，爰方启行。", "笃公刘，于胥斯原。既庶既繁，既顺乃宣，而无永叹。陟则在巘，", "复降在原。何以舟之？维玉及瑶，鞞琫容刀。", "笃公刘，逝彼百泉。瞻彼溥原，乃陟南冈。乃觏于京，京师之野。", "于时处处，于时庐旅，于时言言，于时语语。", "笃公刘，于京斯依。跄跄济济，俾筵俾几。既登乃依，乃造其曹。", "执豕于牢，酌之用匏。食之饮之，君之宗之。", "笃公刘，既溥既长。既景乃冈，相其阴阳，观其流泉。其军三单，", "度其隰原。彻田为粮，度其夕阳。豳居允荒。", "笃公刘，于豳斯馆。涉渭为乱，取厉取锻，止基乃理。爰众爰有，", "夹其皇涧。溯其过涧。止旅乃密，芮鞫之即。"]'),
('shijing-250','泂酌','佚名','先秦','诗经','shijing','','[]','泂酌彼行潦，挹彼注兹，可以餴饎。岂弟君子，民之父母。',78,'诗经/shijing.json','["泂酌彼行潦，挹彼注兹，可以餴饎。岂弟君子，民之父母。", "泂酌彼行潦，挹彼注兹，可以濯罍。岂弟君子，民之攸归。", "泂酌彼行潦，挹彼注兹，可以濯溉。岂弟君子，民之攸墍。"]'),
('shijing-251','卷阿','佚名','先秦','诗经','shijing','','[]','有卷者阿，飘风自南。岂弟君子，来游来歌，以矢其音。',286,'诗经/shijing.json','["有卷者阿，飘风自南。岂弟君子，来游来歌，以矢其音。", "伴奂尔游矣，优游尔休矣。岂弟君子，俾尔弥尔性，似先公酋矣。", "尔土宇昄章，亦孔之厚矣。岂弟君子，俾尔弥尔性，百神尔主矣。", "尔受命长矣，茀禄尔康矣。岂弟君子，俾尔弥尔性，纯嘏尔常矣。", "有冯有翼，有孝有德，以引以翼。岂弟君子，四方为则。", "颙颙卬卬，如圭如璋，令闻令望。岂弟君子，四方为纲。", "凤凰于飞，翙翙其羽，亦集爰止。蔼蔼王多吉士，维君子使，媚于天子。", "凤凰于飞，翙翙其羽，亦傅于天。蔼蔼王多吉人，维君子命，媚于庶人。", "凤凰鸣矣，于彼高冈。梧桐生矣，于彼朝阳。菶菶萋萋，雍雍喈喈。", "君子之车，既庶且多。君子之马，既闲且驰。矢诗不多，维以遂歌。"]'),
('shijing-252','民劳','佚名','先秦','诗经','shijing','','[]','民亦劳止，汔可小康。惠此中国，以绥四方。无纵诡随，以谨无良。',250,'诗经/shijing.json','["民亦劳止，汔可小康。惠此中国，以绥四方。无纵诡随，以谨无良。", "式遏寇虐，憯不畏明。柔远能迩，以定我王。", "民亦劳止，汔可小休。惠此中国，以为民逑。无纵诡随，以谨惛怓。", "式遏寇虐，无俾民忧。无弃尔劳，以为王休。", "民亦劳止，汔可小息。惠此京师，以绥四国。无纵诡随，以谨罔极。", "式遏寇虐，无俾作慝。敬慎威仪，以近有德。", "民亦劳止，汔可小愒。惠此中国，俾民忧泄。无纵诡随，以谨丑厉。", "式遏寇虐，无俾正败。戎虽小子，而式弘大。", "民亦劳止，汔可小安。惠此中国，国无有残。无纵诡随，以谨缱绻。", "式遏寇虐，无俾正反。王欲玉女，是用大谏。"]'),
('shijing-253','板','佚名','先秦','诗经','shijing','','[]','上帝板板，下民卒瘅。出话不然，为犹不远。',323,'诗经/shijing.json','["上帝板板，下民卒瘅。出话不然，为犹不远。", "靡圣管管。不实于亶。犹之未远，是用大谏。", "天之方难，无然宪宪。天之方蹶，无然泄泄。", "辞之辑矣，民之洽矣。辞之怿矣，民之莫矣。", "我虽异事，及尔同僚。我即尔谋，听我嚣嚣。", "我言维服，勿以为笑。先民有言，询于刍荛。", "天之方虐，无然谑谑。老夫灌灌，小子蹻蹻。", "匪我言耄，尔用忧谑。多将熇熇，不可救药。", "天之方懠。无为夸毗。威仪卒迷，善人载尸。", "民之方殿屎，则莫我敢葵？丧乱蔑资，曾莫惠我师？", "天之牖民，如埙如篪，如璋如圭，如取如携。", "携无曰益，牖民孔易。民之多辟，无自立辟。", "价人维藩，大师维垣，大邦维屏，大宗维翰，", "怀德维宁，宗子维城。无俾城坏，无独斯畏。", "敬天之怒，无敢戏豫。敬天之渝，无敢驰驱。", "昊天曰明，及尔出王。昊天曰旦，及尔游衍。"]'),
('shijing-254','荡','佚名','先秦','诗经','shijing','','[]','荡荡上帝，下民之辟。疾威上帝，其命多辟。',333,'诗经/shijing.json','["荡荡上帝，下民之辟。疾威上帝，其命多辟。", "天生烝民，其命匪谌。靡不有初，鲜克有终。", "文王曰咨，咨汝殷商。曾是彊御？曾是掊克？", "曾是在位？曾是在服？天降滔德，女兴是力。", "文王曰咨，咨女殷商。而秉义类，彊御多怼。", "流言以对。寇攘式内。侯作侯祝，靡届靡究。", "文王曰咨，咨女殷商。女炰烋于中国。敛怨以为德。", "不明尔德，时无背无侧。尔德不明，以无陪无卿。", "文王曰咨，咨女殷商。天不湎尔以酒，不义从式。", "既衍尔止。靡明靡晦。式号式呼。俾昼作夜。", "文王曰咨，咨女殷商。如蜩如螗，如沸如羹。", "小大近丧，人尚乎由行。内奰于中国，覃及鬼方。", "文王曰咨，咨女殷商。匪上帝不时，殷不用旧。", "虽无老成人，尚有典刑。曾是莫听，大命以倾。", "文王曰咨，咨女殷商。人亦有言：颠沛之揭，", "枝叶未有害，本实先拨。殷鉴不远，在夏后之世。"]'),
('shijing-255','抑','佚名','先秦','诗经','shijing','','[]','抑抑威仪，维德之隅。人亦有言：靡哲不愚，庶人之愚，亦职维疾。',584,'诗经/shijing.json','["抑抑威仪，维德之隅。人亦有言：靡哲不愚，庶人之愚，亦职维疾。", "哲人之愚，亦维斯戾。无竞维人，四方其训之。有觉德行，四国顺之。", "訏谟定命，远犹辰告。敬慎威仪，维民之则。其在于今，兴迷乱于政。", "颠覆厥德，荒湛于酒。女虽湛乐从，弗念厥绍。罔敷求先王，克共明刑。", "四皇天弗尚，如彼泉流，无沦胥以亡。夙兴夜寐，洒扫庭内，维民之章。", "修尔车马，弓矢戎兵，用戒戎作，用逷蛮方。质尔人民，谨尔侯度，用戒不虞。", "慎尔出话，敬尔威仪，无不柔嘉。白圭之玷，尚可磨也；斯言之玷，不可为也！", "无易由言，无曰苟矣，莫扪朕舌，言不可逝矣。无言不仇，无德不报。", "惠于朋友，庶民小子。子孙绳绳，万民靡不承。视尔友君子，辑柔尔颜，不遐有愆。", "相在尔室，尚不愧于屋漏。无曰不显，莫予云觏。神之格思，不可度思，矧可射思！", "辟尔为德，俾臧俾嘉。淑慎尔止，不愆于仪。不僭不贼，鲜不为则。投我以桃，报之以李。", "彼童而角，实虹小子。荏染柔木，言缗之丝。温温恭人，维德之基。", "其维哲人，告之话言，顺德之行。其维愚人，覆谓我僭。民各有心。", "于乎小子，未知臧否。匪手携之，言示之事。匪面命之，言提其耳。", "借曰未知，亦既抱子。民之靡盈，谁夙知而莫成？昊天孔昭，我生靡乐。", "视尔梦梦，我心惨惨。诲尔谆谆，听我藐藐。匪用为教，覆用为虐。", "借曰未知，亦聿既耄。于乎，小子，告尔旧止。听用我谋，庶无大悔。", "天方艰难，曰丧厥国。取譬不远，昊天不忒。回遹其德，俾民大棘。"]'),
('shijing-256','桑柔','佚名','先秦','诗经','shijing','','[]','菀彼桑柔，其下侯旬，捋采其刘，瘼此下民。不殄心忧，仓兄填兮。倬彼昊天，宁不我矜？',562,'诗经/shijing.json','["菀彼桑柔，其下侯旬，捋采其刘，瘼此下民。不殄心忧，仓兄填兮。倬彼昊天，宁不我矜？", "四牡骙骙，旟旐有翩。乱生不夷，靡国不泯。民靡有黎，具祸以烬。于乎有哀，国步斯频。", "国步灭资，天不我将。靡所止疑，云徂何往？君子实维，秉心无竞。谁生厉阶，至今为梗？", "忧心殷殷，念我土宇。我生不辰，逢天僤怒。自西徂东，靡所定处。多我觏痻，孔棘我圉。", "为谋为毖，乱况斯削。告尔忧恤，诲尔序爵。谁能执热，逝不以濯？其何能淑，载胥及溺。", "如彼溯风，亦孔之僾。民有肃心，荓云不逮。好是稼穑，力民代食。稼穑维宝，代食维好？", "天降丧乱，灭我立王。降此蟊贼，稼穑卒痒。哀恫中国，具赘卒荒。靡有旅力，以念穹苍。", "维此惠君，民人所瞻。秉心宣犹，考慎其相。维彼不顺，自独俾臧。自有肺肠，俾民卒狂。", "瞻彼中林，甡甡其鹿。朋友已谮，不胥以穀。人亦有言：进退维谷。", "维此圣人，瞻言百里。维彼愚人，覆狂以喜。匪言不能，胡斯畏忌？", "维此良人，弗求弗迪。维彼忍心，是顾是复。民之贪乱，宁为荼毒。", "大风有隧，有空大谷。维此良人，作为式穀。维彼不顺，征以中垢。", "大风有隧，贪人败类。听言则对，诵言如醉。匪用其良，复俾我悖。", "嗟尔朋友，予岂不知而作。如彼飞虫，时亦弋获。既之阴女，反予来赫。", "民之罔极，职凉善背。为民不利，如云不克。民之回遹，职竞用力。", "民之未戾，职盗为寇。凉曰不可，覆背善詈。虽曰匪予，既作尔歌！"]'),
('shijing-257','云汉','佚名','先秦','诗经','shijing','','[]','倬彼云汉，昭回于天。王曰：于乎！何辜今之人？天降丧乱，饥馑荐臻。',404,'诗经/shijing.json','["倬彼云汉，昭回于天。王曰：于乎！何辜今之人？天降丧乱，饥馑荐臻。", "靡神不举，靡爱斯牲。圭壁既卒，宁莫我听？", "旱既大甚，蕴隆虫虫。不殄禋祀，自郊徂宫。上下奠瘗，靡神不宗。", "后稷不克，上帝不临。耗斁下土，宁丁我梗", "旱既大甚，则不可推。兢兢业业，如霆如雷。周余黎民，靡有孑遗。", "昊天上帝，则不我遗。胡不相畏？先祖于摧。", "旱既大甚，则不可沮。赫赫炎炎，云我无所。大命近止，靡瞻靡顾。", "群公先正，则不我助。父母先祖，胡宁忍予？", "旱既大甚，涤涤山川。旱魃为虐，如惔如焚。我心惮暑，忧心如熏。", "群公先正，则不我闻。昊天上帝，宁俾我遁？", "旱既大甚，黾勉畏去。胡宁瘨我以旱？憯不知其故。祈年孔夙，方社不莫。", "昊天上帝，则不我虞。", "敬恭明神，宜无悔怒。旱既大甚，散无友纪。鞫哉庶正，疚哉冢宰。", "趣马师氏，膳夫左右。靡人不周。无不能止，瞻卬昊天，云如何里！", "瞻卬昊天，有嘒其星。大夫君子，昭假无赢。大命近止，无弃尔成。", "何求为我。以戾庶正。瞻卬昊天，曷惠其宁？"]'),
('shijing-258','崧高','佚名','先秦','诗经','shijing','','[]','崧高维岳，骏极于天。维岳降神，生甫及申。维申及甫，维周之翰。四国于蕃。四方于宣。',323,'诗经/shijing.json','["崧高维岳，骏极于天。维岳降神，生甫及申。维申及甫，维周之翰。四国于蕃。四方于宣。", "亹亹申伯，王缵之事。于邑于谢，南国是式。王命召伯，定申伯之宅。登是南邦，世执其功。", "王命申伯，式是南邦。因是谢人，以作尔庸。王命召伯，彻申伯土田。王命傅御，迁其私人。", "申伯之功，召伯是营。有俶其城，寝庙既成。既成藐藐，王锡申伯。四牡蹻蹻，钩膺濯濯。", "王遣申伯，路车乘马。我图尔居，莫如南土。锡尔介圭，以作尔宝。往近王舅，南土是保。", "申伯信迈，王饯于郿。申伯还南，谢于诚归。王命召伯，彻申伯土疆。以峙其粻，式遄其行。", "申伯番番，既入于谢。徒御啴啴。周邦咸喜，戎有良翰。不显申伯，王之元舅，文武是宪。", "申伯之德，柔惠且直。揉此万邦，闻于四国。吉甫作诵，其诗孔硕。其风四好，以赠申伯。"]'),
('shijing-259','烝民','佚名','先秦','诗经','shijing','','[]','天生烝民，有物有则。民之秉彝，好是懿德。天监有周，昭假于下。保兹天子，生仲山甫。',333,'诗经/shijing.json','["天生烝民，有物有则。民之秉彝，好是懿德。天监有周，昭假于下。保兹天子，生仲山甫。", "仲山甫之德，柔嘉维则。令仪令色。小心翼翼。古训是式。威仪是力。天子是若，明命使赋。", "王命仲山甫，式是百辟，缵戎祖考，王躬是保。出纳王命，王之喉舌。赋政于外，四方爰发。", "肃肃王命，仲山甫将之。邦国若否，仲山甫明之。既明且哲，以保其身。夙夜匪解，以事一人。", "人亦有言，柔则茹之，刚则吐之。维仲山甫，柔亦不茹，刚亦不吐。不侮矜寡，不畏强御。", "人亦有言，德輶如毛，民鲜克举之。我仪图之，维仲山甫举之。爱莫助之。衮职有阙，维仲山甫补之。", "仲山甫出祖。四牡业业。征夫捷捷，每怀靡及。四牡彭彭，八鸾锵锵。王命仲山甫，城彼东方。", "四牡骙骙，八鸾喈喈。仲山甫徂齐，式遄其归。吉甫作诵，穆如清风。仲山甫永怀，以慰其心。"]'),
('shijing-260','韩奕','佚名','先秦','诗经','shijing','','[]','奕奕梁山，维禹甸之，有倬其道。',362,'诗经/shijing.json','["奕奕梁山，维禹甸之，有倬其道。", "韩侯受命，王亲命之：缵戎祖考，无废朕命。", "夙夜匪解，虔共尔位，朕命不易。", "粲不庭方，以佐戎辟。四牡奕奕，孔修且张。", "韩侯入觐，以其介圭，入觐于王。", "王锡韩侯，淑旂绥章，簟茀错衡。", "玄衮赤舄，钩膺镂锡，鞹鞃浅幭，鞗革金厄。", "韩侯出祖，出宿于屠。显父饯之，清酒百壶。", "其殽维何？炰鳖鲜鱼。其蔌维何？维笋及蒲。", "其赠维何？乘马路车。笾豆有且。侯氏燕胥。", "韩侯取妻，汾王之甥，蹶父之子。", "韩侯迎止，于蹶之里。", "百两彭彭，八鸾锵锵，不显其光。", "诸娣从之，祁祁如云。韩侯顾之，烂其盈门。", "蹶父孔武，靡国不到。为韩姞相攸，莫如韩乐。", "孔乐韩土，川泽訏訏，鲂鱮甫甫，麀鹿噳噳。", "有熊有罴，有猫有虎。庆既令居，韩姞燕誉。", "溥彼韩城，燕师所完。以先祖受命，因时百蛮。", "王锡韩侯，其追其貊。奄受北国，因以其伯。", "实墉实壑，实亩实藉。献其貔皮，赤豹黄罴。"]'),
('shijing-261','江汉','佚名','先秦','诗经','shijing','','[]','江汉浮浮，武夫滔滔。匪安匪游，淮夷来求。既出我车，既设我旟。匪安匪舒，淮夷来铺。',241,'诗经/shijing.json','["江汉浮浮，武夫滔滔。匪安匪游，淮夷来求。既出我车，既设我旟。匪安匪舒，淮夷来铺。", "江汉汤汤，武夫洸洸。经营四方，告成于王。四方既平，王国庶定。时靡有争，王心载宁。", "江汉之浒，王命召虎：式辟四方，彻我疆土。匪疚匪棘，王国来极。于疆于理，至于南海。", "王命召虎：来旬来宣。文武受命，召公维翰。无曰予小子，召公是似。肇敏戎公，用锡尔祉。", "厘尔圭瓒，秬鬯一卣。告于文人，锡山土田。于周受命，自召祖命，虎拜稽首：天子万年！", "虎拜稽首，对扬王休。作召公考：天子万寿！明明天子，令闻不已，矢其文德，洽此四国。"]'),
('shijing-262','常武','佚名','先秦','诗经','shijing','','[]','赫赫明明。王命卿士，南仲大祖，大师皇父。整我六师，以修我戎。既敬既戒，惠此南国。',241,'诗经/shijing.json','["赫赫明明。王命卿士，南仲大祖，大师皇父。整我六师，以修我戎。既敬既戒，惠此南国。", "王谓尹氏，命程伯休父，左右陈行。戒我师旅，率彼淮浦，省此徐土。不留不处，三事就绪。", "赫赫业业，有严天子。王舒保作，匪绍匪游。徐方绎骚，震惊徐方。如雷如霆，徐方震惊。", "王奋厥武，如震如怒。进厥虎臣，阚如虓虎。铺敦淮濆，仍执丑虏。截彼淮浦，王师之所。", "王旅啴啴，如飞如翰。如江如汉，如山之苞。如川之流，绵绵翼翼。不测不克，濯征徐国。", "王犹允塞，徐方既来。徐方既同，天子之功。四方既平，徐方来庭。徐方不回，王曰还归。"]'),
('shijing-263','瞻卬','佚名','先秦','诗经','shijing','','[]','瞻卬昊天，则不我惠。孔填不宁，降此大厉。邦靡有定，士民其瘵。',311,'诗经/shijing.json','["瞻卬昊天，则不我惠。孔填不宁，降此大厉。邦靡有定，士民其瘵。", "蟊贼蟊疾，靡有夷届。罪罟不收，靡有夷瘳。", "人有土田，女反有之。人有民人，女覆夺之。此宜无罪，女反收之。", "彼宜有罪，女覆说之。", "哲夫成城，哲妇倾城。懿厥哲妇，为枭为鸱。妇有长舌，维厉之阶。", "乱匪降自天，生自妇人。匪教匪诲，时维妇寺。", "鞫人忮忒。谮始竞背。岂曰不极？伊胡为慝？如贾三倍，君子是识。", "妇无公事，休其蚕织。", "天何以剌？何神不富？舍尔介狄，维予胥忌。不吊不祥，威仪不类。", "人之云亡，邦国殄瘁。", "天之降罔，维其优矣。人之云亡，心之忧矣。天之降罔，维其几矣。", "人之云亡，心之悲矣。", "觱沸槛泉，维其深矣。心之忧矣，宁自今矣？不自我先，不自我后。", "藐藐昊天，无不克巩。无忝皇祖，式救尔后。"]'),
('shijing-264','召旻','佚名','先秦','诗经','shijing','','[]','旻天疾威，天笃降丧。瘨我饥馑，民卒流亡。我居圉卒荒。',209,'诗经/shijing.json','["旻天疾威，天笃降丧。瘨我饥馑，民卒流亡。我居圉卒荒。", "天降罪罟，蟊贼内讧。昏椓靡共，溃溃回遹，实靖夷我邦。", "皋皋訿訿，曾不知其玷。兢兢业业，孔填不宁，我位孔贬。", "如彼岁旱，草不溃茂，如彼栖苴。我相此邦，无不溃止。", "维昔之富不如时，维今之疚不如兹。彼疏斯粺，胡不自替？职兄斯引。", "池之竭矣，不云自频。泉之竭矣，不云自中。溥斯害矣，职兄斯弘，不灾我躬。", "昔先王受命，有如召公，日辟国百里，今也日蹙国百里。于乎哀哉！维今之人，不尚有旧！"]'),
('shijing-265','清庙','佚名','先秦','诗经','shijing','','[]','于穆清庙，肃雍显相。济济多士，秉文之德。对越在天，骏奔走在庙。不显不承，无射于人斯。',42,'诗经/shijing.json','["于穆清庙，肃雍显相。济济多士，秉文之德。对越在天，骏奔走在庙。不显不承，无射于人斯。"]'),
('shijing-266','维天之命','佚名','先秦','诗经','shijing','','[]','维天之命，于穆不已。于乎不显，文王之德之纯。假以溢我，我其收之。骏惠我文王，曾孙笃之。',43,'诗经/shijing.json','["维天之命，于穆不已。于乎不显，文王之德之纯。假以溢我，我其收之。骏惠我文王，曾孙笃之。"]'),
('shijing-267','维清','佚名','先秦','诗经','shijing','','[]','维清缉熙，文王之典。肇禋，迄用有成，维周之祯。',23,'诗经/shijing.json','["维清缉熙，文王之典。肇禋，迄用有成，维周之祯。"]'),
('shijing-268','烈文','佚名','先秦','诗经','shijing','','[]','烈文辟公，锡兹祉福。惠我无疆，子孙保之。无封靡于尔邦，维王其崇之。',74,'诗经/shijing.json','["烈文辟公，锡兹祉福。惠我无疆，子孙保之。无封靡于尔邦，维王其崇之。", "念兹戎功，继序其皇之。无竞维人，四方其训之。不显维德，百辟其刑之。于乎，前王不忘！"]'),
('shijing-269','天作','佚名','先秦','诗经','shijing','','[]','天作高山，大王荒之。彼作矣，文王康之。彼徂矣，岐有夷之行。子孙保之。',34,'诗经/shijing.json','["天作高山，大王荒之。彼作矣，文王康之。彼徂矣，岐有夷之行。子孙保之。"]'),
('shijing-270','昊天有成命','佚名','先秦','诗经','shijing','','[]','昊天有成命，二后受之。成王不敢康，夙夜基命宥密。于缉熙！单厥心，四其靖之。',37,'诗经/shijing.json','["昊天有成命，二后受之。成王不敢康，夙夜基命宥密。于缉熙！单厥心，四其靖之。"]'),
('shijing-271','我将','佚名','先秦','诗经','shijing','','[]','我将我享，维羊维牛，维天其右之。仪式刑文王之典，日靖四方。',54,'诗经/shijing.json','["我将我享，维羊维牛，维天其右之。仪式刑文王之典，日靖四方。", "伊嘏文王，既右飨之。我其夙夜，畏天之威，于时保之。"]'),
('shijing-272','时迈','佚名','先秦','诗经','shijing','','[]','时迈其邦，昊天其子之，实右序有周。薄言震之，莫不震叠。怀柔百神，及河乔岳，允王维后。',77,'诗经/shijing.json','["时迈其邦，昊天其子之，实右序有周。薄言震之，莫不震叠。怀柔百神，及河乔岳，允王维后。", "明昭有周，式序在位。载戢干戈，载橐弓矢。我求懿德，四于时夏，允王保之。"]'),
('shijing-273','执竞','佚名','先秦','诗经','shijing','','[]','执竞武王，无竞维烈。不显成康，上帝是皇。自彼成康，奄有四方，斤斤其明。',70,'诗经/shijing.json','["执竞武王，无竞维烈。不显成康，上帝是皇。自彼成康，奄有四方，斤斤其明。", "钟鼓喤喤，磬莞将将，降福穰穰。降福简简，威仪反反。既醉既饱，福禄来反。"]'),
('shijing-274','思文','佚名','先秦','诗经','shijing','','[]','思文后稷，克配彼天。立我烝民，莫菲尔极。贻我来牟，帝命率育，无此疆尔界。陈常于时夏。',42,'诗经/shijing.json','["思文后稷，克配彼天。立我烝民，莫菲尔极。贻我来牟，帝命率育，无此疆尔界。陈常于时夏。"]'),
('shijing-275','臣工','佚名','先秦','诗经','shijing','','[]','嗟嗟臣工，敬尔在公。王厘尔成，来咨来茹。嗟嗟保介，维莫之春，亦又何求？如何新畲？',75,'诗经/shijing.json','["嗟嗟臣工，敬尔在公。王厘尔成，来咨来茹。嗟嗟保介，维莫之春，亦又何求？如何新畲？", "于皇来牟，将受厥明。明昭上帝，迄用康年。命我众人：庤乃钱镈，奄观铚艾。"]'),
('shijing-276','噫嘻','佚名','先秦','诗经','shijing','','[]','噫嘻成王，既昭假尔。率时农夫，播厥百谷。骏发尔私，终三十里。亦服尔耕，十千维耦。',40,'诗经/shijing.json','["噫嘻成王，既昭假尔。率时农夫，播厥百谷。骏发尔私，终三十里。亦服尔耕，十千维耦。"]'),
('shijing-277','振鹭','佚名','先秦','诗经','shijing','','[]','振鹭于飞，于彼西雍。我客戾止，亦有斯容。在彼无恶，在此无斁。庶几夙夜，以永终誉。',40,'诗经/shijing.json','["振鹭于飞，于彼西雍。我客戾止，亦有斯容。在彼无恶，在此无斁。庶几夙夜，以永终誉。"]'),
('shijing-278','丰年','佚名','先秦','诗经','shijing','','[]','丰年多黍多稌，亦有高廪，万亿及秭。为酒为醴，烝畀祖妣。以洽百礼，降福孔皆。',37,'诗经/shijing.json','["丰年多黍多稌，亦有高廪，万亿及秭。为酒为醴，烝畀祖妣。以洽百礼，降福孔皆。"]'),
('shijing-279','有瞽','佚名','先秦','诗经','shijing','','[]','有瞽有瞽，在周之庭。设业设虡，崇牙树羽。应田县鼓，鞉磬柷圉。既备',65,'诗经/shijing.json','["有瞽有瞽，在周之庭。设业设虡，崇牙树羽。应田县鼓，鞉磬柷圉。既备", "乃奏，箫管备举。喤喤厥声，肃雍和鸣，先祖是听。我客戾止，永观厥成。"]'),
('shijing-280','潜','佚名','先秦','诗经','shijing','','[]','猗与漆沮，潜有多鱼。有鳣有鲔，鲦鲿鰋鲤。以享以祀，以介景福。',30,'诗经/shijing.json','["猗与漆沮，潜有多鱼。有鳣有鲔，鲦鲿鰋鲤。以享以祀，以介景福。"]'),
('shijing-281','雝','佚名','先秦','诗经','shijing','','[]','有来雝雝，至止肃肃。相维辟公，天子穆穆。于荐广牡，相予四祀。假哉皇考！绥予孝子。',80,'诗经/shijing.json','["有来雝雝，至止肃肃。相维辟公，天子穆穆。于荐广牡，相予四祀。假哉皇考！绥予孝子。", "宣哲维人，文武维后。燕及皇天，克昌厥后。绥我眉寿，介以繁祉，既右烈考，亦右文母。"]'),
('shijing-282','载见','佚名','先秦','诗经','shijing','','[]','载见辟王，曰求厥章。龙旂阳阳，和铃央央。鞗革有鸧，休有烈光。率见昭考，以孝以享。',72,'诗经/shijing.json','["载见辟王，曰求厥章。龙旂阳阳，和铃央央。鞗革有鸧，休有烈光。率见昭考，以孝以享。", "以介眉寿，永言保之，思皇多祜。烈文辟公，绥以多福，俾缉熙于纯嘏。"]'),
('shijing-283','有客','佚名','先秦','诗经','shijing','','[]','有客有客，亦白其马。有萋有且，敦琢其旅。有客宿宿，有客信信。',60,'诗经/shijing.json','["有客有客，亦白其马。有萋有且，敦琢其旅。有客宿宿，有客信信。", "言授之絷，以絷其马。薄言追之，左右绥之。既有淫威，降福孔夷。"]'),
('shijing-284','武','佚名','先秦','诗经','shijing','','[]','于皇武王！无竞维烈。允文文王，克开厥后。嗣武受之，胜殷遏刘，耆定尔功。',35,'诗经/shijing.json','["于皇武王！无竞维烈。允文文王，克开厥后。嗣武受之，胜殷遏刘，耆定尔功。"]'),
('shijing-285','闵予小子','佚名','先秦','诗经','shijing','','[]','闵予小子，遭家不造，嬛嬛在疚。于乎皇考，永世克孝。',56,'诗经/shijing.json','["闵予小子，遭家不造，嬛嬛在疚。于乎皇考，永世克孝。", "念兹皇祖，陟降庭止。维予小子，夙夜敬止。于乎皇王，继序思不忘。"]'),
('shijing-286','访落','佚名','先秦','诗经','shijing','','[]','访予落止，率时昭考。于乎悠哉，朕未有艾。将予就之，继犹判涣。',62,'诗经/shijing.json','["访予落止，率时昭考。于乎悠哉，朕未有艾。将予就之，继犹判涣。", "维予小子，未堪家多难。绍庭上下，陟降厥家。休矣皇考，以保明其身。"]'),
('shijing-287','敬之','佚名','先秦','诗经','shijing','','[]','敬之敬之，天维显思，命不易哉。无曰高高在上，陟降厥士，日监在兹。',66,'诗经/shijing.json','["敬之敬之，天维显思，命不易哉。无曰高高在上，陟降厥士，日监在兹。", "维予小子，不聪敬止。日就月将，学有缉熙于光明。佛时仔肩，示我显德行。"]'),
('shijing-288','小毖','佚名','先秦','诗经','shijing','','[]','予其惩，而毖后患。莫予荓蜂，自求辛螫。肇允彼桃虫，拚飞维鸟。未堪家多难，予又集于蓼。',42,'诗经/shijing.json','["予其惩，而毖后患。莫予荓蜂，自求辛螫。肇允彼桃虫，拚飞维鸟。未堪家多难，予又集于蓼。"]'),
('shijing-289','载芟','佚名','先秦','诗经','shijing','','[]','载芟载柞，其耕泽泽。千耦其耘，徂隰徂畛。侯主侯伯，侯亚侯旅，侯彊侯以。',155,'诗经/shijing.json','["载芟载柞，其耕泽泽。千耦其耘，徂隰徂畛。侯主侯伯，侯亚侯旅，侯彊侯以。", "有嗿其馌，思媚其妇，有依其士。有略其耜，俶载南亩，播厥百谷。实函斯活，驿驿其达。", "有厌其杰，厌厌其苗，绵绵其麃。载获济济，有实其积，万亿及秭。为酒为醴，烝畀祖妣，不洽百礼。", "有飶其香。邦家之光。有椒其馨，胡考之宁。匪且有且，匪今斯今，振古如兹。"]'),
('shijing-290','良耜','佚名','先秦','诗经','shijing','','[]','畟畟良耜，俶载南亩。播厥百谷，实函斯活。或来瞻女，载筐及莒，其饟伊黍。',115,'诗经/shijing.json','["畟畟良耜，俶载南亩。播厥百谷，实函斯活。或来瞻女，载筐及莒，其饟伊黍。", "其笠伊纠，其镈斯赵，以薅荼蓼。荼蓼朽止，黍稷茂止。获之挃挃，积之栗栗。", "其崇如墉，其比如栉。以开百室，百室盈止，妇子宁止。杀时犉牡，有捄其角。以似以续，续古之人。"]'),
('shijing-291','丝衣','佚名','先秦','诗经','shijing','','[]','丝衣其紑，载弁俅俅。自堂徂基，自羊徂牛，鼐鼎及鼒，兕觥其觩。旨酒思柔。不吴不敖，胡考之休。',45,'诗经/shijing.json','["丝衣其紑，载弁俅俅。自堂徂基，自羊徂牛，鼐鼎及鼒，兕觥其觩。旨酒思柔。不吴不敖，胡考之休。"]'),
('shijing-292','酌','佚名','先秦','诗经','shijing','','[]','于铄王师，遵养时晦。时纯熙矣，是用大介。我龙受之，蹻蹻王之造。载用有嗣，实维尔公允师。',43,'诗经/shijing.json','["于铄王师，遵养时晦。时纯熙矣，是用大介。我龙受之，蹻蹻王之造。载用有嗣，实维尔公允师。"]'),
('shijing-293','桓','佚名','先秦','诗经','shijing','','[]','绥万邦，屡丰年。天命匪解，桓桓武王。保有厥士，于以四方，克定厥家。于昭于天，皇以间之。',43,'诗经/shijing.json','["绥万邦，屡丰年。天命匪解，桓桓武王。保有厥士，于以四方，克定厥家。于昭于天，皇以间之。"]'),
('shijing-294','赉','佚名','先秦','诗经','shijing','','[]','文王既勤止，我应受之。敷时绎思，我徂维求定。时周之命，于绎思。',31,'诗经/shijing.json','["文王既勤止，我应受之。敷时绎思，我徂维求定。时周之命，于绎思。"]'),
('shijing-295','般','佚名','先秦','诗经','shijing','','[]','于皇时周！陟其高山，嶞山乔岳，允犹翕河。敷天之下，裒时之对。时周之命。',35,'诗经/shijing.json','["于皇时周！陟其高山，嶞山乔岳，允犹翕河。敷天之下，裒时之对。时周之命。"]'),
('shijing-296','駉','佚名','先秦','诗经','shijing','','[]','駉駉牡马，在坰之野。薄言駉者，有驈有皇，有骊有黄，以车彭彭。思无疆思，马斯臧。',156,'诗经/shijing.json','["駉駉牡马，在坰之野。薄言駉者，有驈有皇，有骊有黄，以车彭彭。思无疆思，马斯臧。", "駉駉牡马，在坰之野。薄言駉者，有骓有駓，有骍有骐，以车伾伾。思无期思，马斯才。", "駉駉牡马，在坰之野。溥言駉者，有驒有骆，有骝有雒，以车绎绎。思无斁思，马斯作。", "駉駉牡马，在坰之野。薄言駉者，有骃有騢，有驔有鱼，以车祛祛。思无邪思，马斯徂。"]'),
('shijing-297','有駜','佚名','先秦','诗经','shijing','','[]','有駜有駜，駜彼乘黄。夙夜在公，在公明明。振振鹭，鹭于下。鼓咽咽，醉言舞。于胥乐兮！',125,'诗经/shijing.json','["有駜有駜，駜彼乘黄。夙夜在公，在公明明。振振鹭，鹭于下。鼓咽咽，醉言舞。于胥乐兮！", "有駜有駜，駜彼乘牡。夙夜在公，在公饮酒。振振鹭，鹭于飞。鼓咽咽，醉言归。于胥乐兮！", "有駜有駜，駜彼乘駽。夙夜在公，在公载燕。自今以始，岁其有。君子有穀，诒孙子。于胥乐兮！"]'),
('shijing-298','泮水','佚名','先秦','诗经','shijing','','[]','思乐泮水，薄采其芹。鲁侯戾止，言观其旂。其旂茷茷，鸾声哕哕。无小无大，从公于迈。',321,'诗经/shijing.json','["思乐泮水，薄采其芹。鲁侯戾止，言观其旂。其旂茷茷，鸾声哕哕。无小无大，从公于迈。", "思乐泮水，薄采其藻。鲁侯戾止，其马蹻蹻。其马蹻蹻，其音昭昭。载色载笑，匪怒伊教。", "思乐泮水，薄采其茆。鲁侯戾止，在泮饮酒。既饮旨酒，永锡难老。顺彼长道，屈此群丑。", "穆穆鲁侯，敬明其德。敬慎威仪，维民之则。允文允武，昭假烈祖。靡有不孝，自求伊祜。", "明明鲁侯，克明其德。既作泮宫，淮夷攸服。矫矫虎臣，在泮献馘。淑问如皋陶，在泮献囚。", "济济多士，克广德心。桓桓于征，狄彼东南。烝烝皇皇，不吴不扬。不告于訩，在泮献功。", "角弓其觩。束矢其搜。戎车孔博。徒御无斁。既克淮夷，孔淑不逆。式固尔犹，淮夷卒获。", "翩彼飞鸮，集于泮林。食我桑黮，怀我好音。憬彼淮夷，来献其琛。元龟象齿，大赂南金。"]'),
('shijing-299','閟宫','佚名','先秦','诗经','shijing','','[]','閟宫有侐，实实枚枚。赫赫姜嫄，其德不回。上帝是依，无灾无害。',612,'诗经/shijing.json','["閟宫有侐，实实枚枚。赫赫姜嫄，其德不回。上帝是依，无灾无害。", "弥月不迟，是生后稷。降之百福。黍稷重穋，稙稚菽麦。奄有下国，俾民稼穑。", "有稷有黍，有稻有秬。奄有下土，缵禹之绪。后稷之孙，实维大王。", "居岐之阳，实始剪商。至于文武，缵大王之绪，致天之届，于牧之野。", "无二无虞，上帝临女。敦商之旅，克咸厥功。王曰叔父，建尔元子，俾侯于鲁。", "大启尔宇，为周室辅。乃命鲁公，俾侯于东。锡之山川，土田附庸。", "周公之孙，庄公之子。龙旂承祀。六辔耳耳。春秋匪解，享祀不忒。", "皇皇后帝！皇祖后稷！享以骍牺，是飨是宜。降福既多，周公皇祖，亦其福女。", "秋而载尝，夏而楅衡，白牡骍刚。牺尊将将，毛炰胾羹。笾豆大房，万舞洋洋。", "孝孙有庆。俾尔炽而昌，俾尔寿而臧。保彼东方，鲁邦是尝。不亏不崩，不震不腾。", "三寿作朋，如冈如陵。公车千乘，朱英绿縢。二矛重弓。公徒三万，贝胄朱綅。", "烝徒增增，戎狄是膺，荆舒是惩，则莫我敢承！俾尔昌而炽，俾尔寿而富。", "黄发台背，寿胥与试。俾尔昌而大，俾尔耆而艾。万有千岁，眉寿无有害。", "泰山岩岩，鲁邦所詹。奄有龟蒙，遂荒大东。至于海邦，淮夷来同。", "莫不率从，鲁侯之功。保有凫绎，遂荒徐宅。至于海邦，淮夷蛮貊。", "及彼南夷，莫不率从。莫敢不诺，鲁侯是若。天锡公纯嘏，眉寿保鲁。", "居常与许，复周公之宇。鲁侯燕喜，令妻寿母。宜大夫庶士，邦国是有。", "既多受祉，黄发儿齿。徂徠之松，新甫之柏。是断是度，是寻是尺。", "松桷有舄，路寝孔硕，新庙奕奕。奚斯所作，孔曼且硕，万民是若。"]'),
('shijing-300','那','佚名','先秦','诗经','shijing','','[]','猗与那与！置我鞉鼓。奏鼓简简，衎我烈祖。汤孙奏假，绥我思成。',110,'诗经/shijing.json','["猗与那与！置我鞉鼓。奏鼓简简，衎我烈祖。汤孙奏假，绥我思成。", "鞉鼓渊渊，嘒嘒管声。既和且平，依我磬声。于赫汤孙！穆穆厥声。", "庸鼓有斁，万舞有奕。我有嘉客，亦不夷怿。自古在昔，先民有作。", "温恭朝夕，执事有恪，顾予烝尝，汤孙之将。"]'),
('shijing-301','烈祖','佚名','先秦','诗经','shijing','','[]','嗟嗟烈祖！有秩斯祜。申锡无疆，及尔斯所。既载清酤，赉我思成。',111,'诗经/shijing.json','["嗟嗟烈祖！有秩斯祜。申锡无疆，及尔斯所。既载清酤，赉我思成。", "亦有和羹，既戒既平。鬷假无言，时靡有争。绥我眉寿，黄耇无疆。", "约軧错衡，八鸾鸧鸧。以假以享，我受命溥将。自天降康，丰年穰穰。", "来假来飨，降福无疆。顾予烝尝，汤孙之将。"]'),
('shijing-302','玄鸟','佚名','先秦','诗经','shijing','','[]','天命玄鸟，降而生商，宅殷土芒芒。古帝命武汤，正域彼四方。',117,'诗经/shijing.json','["天命玄鸟，降而生商，宅殷土芒芒。古帝命武汤，正域彼四方。", "方命厥后，奄有九有。商之先后，受命不殆，在武丁孙子。武丁孙子，武王靡不胜。", "龙旂十乘，大糦是承。邦畿千里，维民所止，肇域彼四海。", "四海来假，来假祁祁。景员维河。殷受命咸宜，百禄是何。"]'),
('shijing-303','长发','佚名','先秦','诗经','shijing','','[]','浚哲维商，长发其祥。洪水芒芒，禹敷下土方。外大国是疆，幅陨既长。有娀方将，帝立子生商。',268,'诗经/shijing.json','["浚哲维商，长发其祥。洪水芒芒，禹敷下土方。外大国是疆，幅陨既长。有娀方将，帝立子生商。", "玄王桓拨，受小国是达，受大国是达。率履不越，遂视既发。相士烈烈。海外有截。", "帝命不违，至于汤齐。汤降不迟，圣敬日跻。昭假迟迟，上帝是祗，帝命式于九围。", "受小球大球，为下国缀旒，何天之休。不竞不絿，不刚不柔。敷政优优。百禄是遒。", "受小共大共，为下国骏厖。何天之龙，敷奏其勇。不震不动，不戁不竦，百禄是总。", "武王载旆，有虔秉钺。如火烈烈，则莫我敢曷。苞有三蘖，莫遂莫达。九有有截，韦顾既伐，昆吾夏桀。", "昔在中叶，有震且业。允也天子，降予卿士。实维阿衡，实左右商王。"]'),
('shijing-304','殷武','佚名','先秦','诗经','shijing','','[]','挞彼殷武，奋伐荆楚。深入其阻，裒荆之旅。有截其所，汤孙之绪。',190,'诗经/shijing.json','["挞彼殷武，奋伐荆楚。深入其阻，裒荆之旅。有截其所，汤孙之绪。", "维女荆楚，居国南乡。昔有成汤，自彼氐羌，莫敢不来享，莫敢不来王。曰商是常。", "天命多辟，设都于禹之绩。岁事来辟，勿予祸适，稼穑匪解。", "天命降监，下民有严。不僭不滥，不敢怠遑。命于下国，封建厥福。", "商邑翼翼，四方之极。赫赫厥声，濯濯厥灵。寿考且宁，以保我后生。", "陟彼景山，松伯丸丸。是断是迁，方斫是虔。松桷有梴，旅楹有闲，寝成孔安。"]');
